export function replayOperationalStatePruningPolicyAdmissionWitnessAuthorityTransitionAdmissionWitnessRecords(
  input: OperationalStatePruningPolicyAdmissionWitnessAuthorityTransitionAdmissionWitnessReplayInput,
): OperationalStatePruningPolicyAdmissionWitnessAuthorityTransitionAdmissionWitnessReplay {
  const issues: OperationalStatePruningPolicyIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const witnessHashBySequence = new Map<number, string>();
  const witnessRecordByAdmissionHash = new Map<
    string,
    OperationalStatePruningPolicyAdmissionWitnessAuthorityTransitionAdmissionWitnessRecord
  >();
  const witnessAuthorityTopology = input.witnessAuthorityTopology;
  const witnessAuthorityTransitionAdmissionReplay =
    input.witnessAuthorityTransitionAdmissionReplay;
  const principalById = new Map<string, OperationalStateAuthorityPrincipalState>(
    witnessAuthorityTopology?.principals.map((principal) => [
      principal.principalId,
      principal,
    ]) ?? [],
  );
  let expectedSequence = 1;
  let previousWitnessRecordHash: string | undefined;
  let latestWitnessRecord:
    | OperationalStatePruningPolicyAdmissionWitnessAuthorityTransitionAdmissionWitnessRecord
    | undefined;

  if (input.admissionReplay !== undefined && !input.admissionReplay.valid) {
    pushOperationalStatePruningPolicyIssue(issues, {
      code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_admission_replay_invalid",
      path: "/admissionReplay",
      message:
        "Pruning-policy admission witness authority-transition admission witness replay cannot account for invalid transition-admission history.",
      actual: input.admissionReplay.issues
        .map((issue) => issue.code)
        .join(","),
    });
  }

  if (
    (input.requireWitnessAuthorityTopology === true ||
      input.requireWitnessAuthorityTransitionAdmission === true) &&
    witnessAuthorityTopology === undefined
  ) {
    pushOperationalStatePruningPolicyIssue(issues, {
      code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_topology_missing",
      path: "/witnessAuthorityTopology",
      message:
        "Pruning-policy admission witness authority-transition admission witness replay requires a replayed witness authority topology.",
    });
  }

  if (witnessAuthorityTopology !== undefined) {
    const topologyHashValidation =
      verifyOperationalStateAuthorityTopologyHash(witnessAuthorityTopology);
    if (!topologyHashValidation.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_topology_hash_mismatch",
        path: "/witnessAuthorityTopology/topologyHash",
        message: `Pruning-policy admission witness authority-transition admission witness authority topology hash ${topologyHashValidation.actualHash} does not match recomputed hash ${topologyHashValidation.expectedHash}.`,
        expected: topologyHashValidation.expectedHash,
        actual: topologyHashValidation.actualHash,
      });
    }
    if (witnessAuthorityTopology.tenantId !== expectedTenantId) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_topology_tenant_mismatch",
        path: "/witnessAuthorityTopology/tenantId",
        message:
          "Pruning-policy admission witness authority-transition admission witness authority topology tenant does not match replay tenant.",
        expected: expectedTenantId,
        actual: witnessAuthorityTopology.tenantId,
      });
    }
    if (witnessAuthorityTopology.authorityScope !== input.authorityScope) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_topology_scope_mismatch",
        path: "/witnessAuthorityTopology/authorityScope",
        message:
          "Pruning-policy admission witness authority-transition admission witness authority topology scope does not match replay scope.",
        expected: input.authorityScope,
        actual: witnessAuthorityTopology.authorityScope,
      });
    }
    if (
      witnessAuthorityTopology.requiredWitnesses === undefined ||
      witnessAuthorityTopology.minimumWitnesses === undefined
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_quorum_missing",
        path: "/witnessAuthorityTopology/requiredWitnesses",
        message:
          "Pruning-policy admission witness authority-transition admission witness authority topology must define quorum thresholds.",
      });
    }
  }

  if (input.requireWitnessAuthorityTransitionAdmission === true) {
    if (witnessAuthorityTransitionAdmissionReplay === undefined) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Pruning-policy admission witness authority-transition admission witness replay requires its witness authority topology to replay from admitted authority-transition history.",
      });
    } else if (!witnessAuthorityTransitionAdmissionReplay.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        path: "/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Pruning-policy admission witness authority-transition admission witness replay cannot consume invalid nested witness-authority transition admission history.",
        actual: witnessAuthorityTransitionAdmissionReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      witnessAuthorityTopology !== undefined &&
      (witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology ===
        undefined ||
        !operationalStateAuthorityTopologiesMatch(
          witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology,
          witnessAuthorityTopology,
        ))
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Pruning-policy transition-admission witness authority topology must be recovered from admitted authority-transition history.",
        expected: witnessAuthorityTopology.topologyHash,
        actual:
          witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology
            ?.topologyHash ?? "none",
      });
    }
  }

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const witnessRecordHashValidation =
      verifyOperationalStatePruningPolicyAdmissionWitnessAuthorityTransitionAdmissionWitnessRecordHash(
        record,
      );
    const certificateHashValidation =
      verifyOperationalStateQuorumCertificateProofCertificateHash(
        record.admissionCertificate,
      );
    const previousWitnessHashAtSequence = witnessHashBySequence.get(
      record.witnessSequence,
    );

    if (
      previousWitnessHashAtSequence !== undefined &&
      previousWitnessHashAtSequence !== record.witnessRecordHash
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_record_fork",
        path: `${path}/witnessSequence`,
        message: `Pruning-policy admission witness authority-transition admission witness sequence ${record.witnessSequence} has more than one witness record hash.`,
        expected: previousWitnessHashAtSequence,
        actual: record.witnessRecordHash,
      });
    } else if (previousWitnessHashAtSequence === undefined) {
      witnessHashBySequence.set(
        record.witnessSequence,
        record.witnessRecordHash,
      );
    }

    if (
      record.tenantId !== expectedTenantId ||
      record.admissionCertificate.tenantId !== expectedTenantId
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_record_tenant_mismatch",
        path,
        message:
          "Pruning-policy admission witness authority-transition admission witness record and certificate must match the replay tenant.",
        expected: expectedTenantId,
      });
    }
    if (
      record.transitionAdmissionWitnessStoreId !==
        input.transitionAdmissionWitnessStoreId ||
      record.transitionAdmissionStoreId !== input.transitionAdmissionStoreId
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_record_store_mismatch",
        path,
        message:
          "Pruning-policy admission witness authority-transition admission witness record must bind the expected witness and transition-admission stores.",
        expected: `${input.transitionAdmissionWitnessStoreId}:${input.transitionAdmissionStoreId}`,
        actual: `${record.transitionAdmissionWitnessStoreId}:${record.transitionAdmissionStoreId}`,
      });
    }
    if (
      record.topologyId !== input.topologyId ||
      record.authorityScope !== input.authorityScope ||
      record.admissionCertificate.authorityScope !== input.authorityScope
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_record_scope_mismatch",
        path,
        message:
          "Pruning-policy admission witness authority-transition admission witness record must share the replay topology and authority scope.",
        expected: `${input.topologyId}:${input.authorityScope}`,
      });
    }
    if (record.witnessSequence !== expectedSequence) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_record_sequence_gap",
        path: `${path}/witnessSequence`,
        message:
          "Pruning-policy admission witness authority-transition admission witness records must replay as a contiguous witness sequence.",
        expected: expectedSequence,
        actual: record.witnessSequence,
      });
    }
    if (record.previousWitnessRecordHash !== previousWitnessRecordHash) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_record_previous_hash_mismatch",
        path: `${path}/previousWitnessRecordHash`,
        message:
          "Pruning-policy admission witness authority-transition admission witness record does not chain to the previous witness record hash.",
        expected: previousWitnessRecordHash ?? "none",
        actual: record.previousWitnessRecordHash ?? "none",
      });
    }
    if (!certificateHashValidation.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_certificate_hash_mismatch",
        path: `${path}/admissionCertificate/quorumCertificateHash`,
        message: `Pruning-policy admission witness authority-transition admission witness certificate hash ${certificateHashValidation.actualHash} does not match recomputed hash ${certificateHashValidation.expectedHash}.`,
        expected: certificateHashValidation.expectedHash,
        actual: certificateHashValidation.actualHash,
      });
    }
    if (
      !record.admissionCertificate.certified ||
      record.admissionCertificate.status !== "certified"
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_certificate_not_certified",
        path: `${path}/admissionCertificate/status`,
        message:
          "Pruning-policy admission witness authority-transition admission cannot become accountable through a non-certified witness certificate.",
        expected: "certified",
        actual: record.admissionCertificate.status,
      });
    }
    if (
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.minimumWitnesses ||
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.requiredWitnesses
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_certificate_quorum_not_met",
        path: `${path}/admissionCertificate/acceptedWitnessIds`,
        message:
          "Pruning-policy admission witness authority-transition admission witness certificate does not satisfy its declared witness quorum.",
        expected: Math.max(
          record.admissionCertificate.requiredWitnesses,
          record.admissionCertificate.minimumWitnesses,
        ),
        actual: record.admissionCertificate.acceptedWitnessIds.length,
      });
    }
    if (
      record.admissionCertificate.subjectKind !==
        OPERATIONAL_STATE_PRUNING_POLICY_ADMISSION_WITNESS_AUTHORITY_TRANSITION_ADMISSION_RECORD_SUBJECT_KIND ||
      record.admissionCertificate.subjectId !==
        `${record.transitionAdmissionStoreId}:${record.topologyId}` ||
      record.admissionCertificate.subjectSequence !==
        record.admissionSequence ||
      record.admissionCertificate.subjectHash !== record.admissionRecordHash
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_certificate_subject_mismatch",
        path: `${path}/admissionCertificate`,
        message:
          "Pruning-policy admission witness authority-transition admission witness certificate must certify the exact transition-admission store, topology id, admission sequence, and admission record hash.",
        expected: record.admissionRecordHash,
        actual: record.admissionCertificate.subjectHash,
      });
    }
    if (
      input.requiredAuthorityBoundary !== undefined &&
      record.admissionCertificate.authorityBoundary !==
        input.requiredAuthorityBoundary
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_certificate_authority_boundary_mismatch",
        path: `${path}/admissionCertificate/authorityBoundary`,
        message:
          "Pruning-policy admission witness authority-transition admission witness certificate was admitted under the wrong authority boundary.",
        expected: input.requiredAuthorityBoundary,
        actual: record.admissionCertificate.authorityBoundary,
      });
    }
    if (witnessAuthorityTopology !== undefined) {
      if (
        record.admissionCertificate.authorityTopologyHash !==
        witnessAuthorityTopology.topologyHash
      ) {
        pushOperationalStatePruningPolicyIssue(issues, {
          code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_certificate_authority_topology_mismatch",
          path: `${path}/admissionCertificate/authorityTopologyHash`,
          message:
            "Pruning-policy admission witness authority-transition admission witness certificate is not bound to the replayed witness authority topology.",
          expected: witnessAuthorityTopology.topologyHash,
          actual:
            record.admissionCertificate.authorityTopologyHash ?? "none",
        });
      }

      const acceptedWitnessIds =
        record.admissionCertificate.acceptedWitnessIds;
      const uniqueAcceptedWitnessIds = new Set(acceptedWitnessIds);
      if (uniqueAcceptedWitnessIds.size !== acceptedWitnessIds.length) {
        pushOperationalStatePruningPolicyIssue(issues, {
          code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_duplicate_witness",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Pruning-policy admission witness authority-transition admission witness authority quorum cannot be satisfied by duplicate witness ids.",
          expected: uniqueAcceptedWitnessIds.size,
          actual: acceptedWitnessIds.length,
        });
      }

      let activeAuthorizedWitnessCount = 0;
      for (const witnessId of uniqueAcceptedWitnessIds) {
        const principal = principalById.get(witnessId);
        if (principal === undefined) {
          pushOperationalStatePruningPolicyIssue(issues, {
            code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_witness_unknown",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Pruning-policy admission witness authority-transition admission witness certificate names a witness outside the replayed authority topology.",
            expected: witnessAuthorityTopology.topologyHash,
            actual: witnessId,
          });
          continue;
        }
        if (principal.status !== "active") {
          pushOperationalStatePruningPolicyIssue(issues, {
            code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_witness_not_active",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Pruning-policy admission witness authority-transition admission witness certificate names a witness that is not active in the replayed authority topology.",
            expected: "active",
            actual: `${witnessId}:${principal.status}`,
          });
          continue;
        }
        activeAuthorizedWitnessCount += 1;
      }

      const requiredAuthorizedWitnesses = Math.max(
        witnessAuthorityTopology.requiredWitnesses ?? 0,
        witnessAuthorityTopology.minimumWitnesses ?? 0,
      );
      if (activeAuthorizedWitnessCount < requiredAuthorizedWitnesses) {
        pushOperationalStatePruningPolicyIssue(issues, {
          code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_quorum_not_met",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Pruning-policy admission witness authority-transition admission witness certificate does not satisfy the replayed witness authority topology quorum.",
          expected: requiredAuthorizedWitnesses,
          actual: activeAuthorizedWitnessCount,
        });
      }
    }
    if (!witnessRecordHashValidation.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_record_hash_mismatch",
        path: `${path}/witnessRecordHash`,
        message: `Pruning-policy admission witness authority-transition admission witness record hash ${witnessRecordHashValidation.actualHash} does not match recomputed hash ${witnessRecordHashValidation.expectedHash}.`,
        expected: witnessRecordHashValidation.expectedHash,
        actual: witnessRecordHashValidation.actualHash,
      });
    }

    witnessRecordByAdmissionHash.set(record.admissionRecordHash, record);
    expectedSequence = record.witnessSequence + 1;
    previousWitnessRecordHash = record.witnessRecordHash;
    latestWitnessRecord = record;
  });

  const requiredAdmissionRecord =
    input.requiredAdmissionRecord ?? input.admissionReplay?.latestAdmittedRecord;
  let requiredAdmissionWitnessRecord:
    | OperationalStatePruningPolicyAdmissionWitnessAuthorityTransitionAdmissionWitnessRecord
    | undefined;
  if (requiredAdmissionRecord !== undefined) {
    const admissionRecordHashValidation =
      verifyOperationalStatePruningPolicyAdmissionWitnessAuthorityTransitionAdmissionRecordHash(
        requiredAdmissionRecord,
      );
    if (!admissionRecordHashValidation.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_record_hash_mismatch",
        path: "/requiredAdmissionRecord/admissionRecordHash",
        message: `Required pruning-policy admission witness authority-transition admission hash ${admissionRecordHashValidation.actualHash} does not match recomputed hash ${admissionRecordHashValidation.expectedHash}.`,
        expected: admissionRecordHashValidation.expectedHash,
        actual: admissionRecordHashValidation.actualHash,
      });
    }
    requiredAdmissionWitnessRecord = witnessRecordByAdmissionHash.get(
      requiredAdmissionRecord.admissionRecordHash,
    );
    if (requiredAdmissionWitnessRecord === undefined) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_latest_record_not_witnessed",
        path: "/requiredAdmissionRecord/admissionRecordHash",
        message:
          "Latest pruning-policy admission witness authority-transition admission record has no replayed witness certificate.",
        expected: requiredAdmissionRecord.admissionRecordHash,
      });
    } else if (
      requiredAdmissionWitnessRecord.transitionAdmissionStoreId !==
        requiredAdmissionRecord.transitionAdmissionStoreId ||
      requiredAdmissionWitnessRecord.topologyId !==
        requiredAdmissionRecord.topologyId ||
      requiredAdmissionWitnessRecord.admissionSequence !==
        requiredAdmissionRecord.admissionSequence ||
      requiredAdmissionWitnessRecord.authoritySequence !==
        requiredAdmissionRecord.authoritySequence ||
      requiredAdmissionWitnessRecord.authorityRecordHash !==
        requiredAdmissionRecord.authorityRecordHash ||
      requiredAdmissionWitnessRecord.nextAuthorityTopologyHash !==
        requiredAdmissionRecord.nextAuthorityTopologyHash
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_admission_record_mismatch",
        path: "/requiredAdmissionRecord",
        message:
          "Pruning-policy admission witness authority-transition admission witness record does not match the required admission store, topology, sequence, authority transition hash, and derived topology hash.",
        expected: requiredAdmissionRecord.admissionRecordHash,
        actual: requiredAdmissionWitnessRecord.admissionRecordHash,
      });
    }
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    transitionAdmissionWitnessStoreId:
      input.transitionAdmissionWitnessStoreId,
    transitionAdmissionStoreId: input.transitionAdmissionStoreId,
    topologyId: input.topologyId,
    authorityScope: input.authorityScope,
    witnessedRecordCount: input.records.length,
    ...(latestWitnessRecord !== undefined ? { latestWitnessRecord } : {}),
    ...(requiredAdmissionRecord !== undefined ? { requiredAdmissionRecord } : {}),
    ...(requiredAdmissionWitnessRecord !== undefined
      ? { requiredAdmissionWitnessRecord }
      : {}),
    ...(witnessAuthorityTopology !== undefined
      ? { witnessAuthorityTopology }
      : {}),
    ...(witnessAuthorityTransitionAdmissionReplay !== undefined
      ? { witnessAuthorityTransitionAdmissionReplay }
      : {}),
    issues,
  };
}

export function replayOperationalStatePruningPolicyAdmissionWitnessAuthorityTransitionAdmissionRecords(
  input: OperationalStatePruningPolicyAdmissionWitnessAuthorityTransitionAdmissionReplayInput,
): OperationalStatePruningPolicyAdmissionWitnessAuthorityTransitionAdmissionReplay {
  const issues: OperationalStatePruningPolicyIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const admissionHashBySequence = new Map<number, string>();
  const admissionRecordByAuthorityHash = new Map<
    string,
    OperationalStatePruningPolicyAdmissionWitnessAuthorityTransitionAdmissionRecord
  >();
  const admissionWitnessReplay = input.admissionWitnessReplay;
  let expectedAdmissionSequence = 1;
  let expectedAuthoritySequence = 1;
  let previousAdmissionRecordHash: string | undefined;
  let previousAuthorityRecordHash: string | undefined;
  let previousTopology: OperationalStateAuthorityTopology | undefined;
  let latestAdmittedRecord:
    | OperationalStatePruningPolicyAdmissionWitnessAuthorityTransitionAdmissionRecord
    | undefined;
  let latestAdmittedTopology: OperationalStateAuthorityTopology | undefined;

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const recordHashValidation =
      verifyOperationalStatePruningPolicyAdmissionWitnessAuthorityTransitionAdmissionRecordHash(
        record,
      );
    const transitionHashValidation =
      verifyOperationalStateAuthorityTransitionRecordHash(
        record.authorityTransition,
      );
    const certificateHashValidation =
      verifyOperationalStateQuorumCertificateProofCertificateHash(
        record.admissionCertificate,
      );
    const previousAdmissionHashAtSequence = admissionHashBySequence.get(
      record.admissionSequence,
    );

    if (
      previousAdmissionHashAtSequence !== undefined &&
      previousAdmissionHashAtSequence !== record.admissionRecordHash
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_record_sequence_gap",
        path: `${path}/admissionSequence`,
        message: `Pruning-policy admission witness authority-transition admission sequence ${record.admissionSequence} has more than one record hash.`,
        expected: previousAdmissionHashAtSequence,
        actual: record.admissionRecordHash,
      });
    } else if (previousAdmissionHashAtSequence === undefined) {
      admissionHashBySequence.set(
        record.admissionSequence,
        record.admissionRecordHash,
      );
    }

    if (
      record.tenantId !== expectedTenantId ||
      record.authorityTransition.tenantId !== expectedTenantId ||
      record.admissionCertificate.tenantId !== expectedTenantId
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_record_tenant_mismatch",
        path,
        message:
          "Pruning-policy admission witness authority-transition admission record, transition, and certificate must match the replay tenant.",
        expected: expectedTenantId,
      });
    }
    if (record.transitionAdmissionStoreId !== input.transitionAdmissionStoreId) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_record_store_mismatch",
        path: `${path}/transitionAdmissionStoreId`,
        message:
          "Pruning-policy admission witness authority-transition admission record belongs to a different admission store.",
        expected: input.transitionAdmissionStoreId,
        actual: record.transitionAdmissionStoreId,
      });
    }
    if (
      record.topologyId !== input.topologyId ||
      record.authorityTransition.topologyId !== input.topologyId
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_record_scope_mismatch",
        path: `${path}/topologyId`,
        message:
          "Pruning-policy admission witness authority-transition admission record must match the replay topology id.",
        expected: input.topologyId,
        actual: record.topologyId,
      });
    }
    if (
      record.authorityScope !== input.authorityScope ||
      record.authorityTransition.authorityScope !== input.authorityScope ||
      record.admissionCertificate.authorityScope !== input.authorityScope
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_record_scope_mismatch",
        path,
        message:
          "Pruning-policy admission witness authority-transition admission record, transition, and certificate must share the replay authority scope.",
        expected: input.authorityScope,
      });
    }
    if (record.admissionSequence !== expectedAdmissionSequence) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_record_sequence_gap",
        path: `${path}/admissionSequence`,
        message:
          "Pruning-policy admission witness authority-transition admissions must replay as a contiguous admission sequence.",
        expected: expectedAdmissionSequence,
        actual: record.admissionSequence,
      });
    }
    if (record.previousAdmissionRecordHash !== previousAdmissionRecordHash) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_record_previous_hash_mismatch",
        path: `${path}/previousAdmissionRecordHash`,
        message:
          "Pruning-policy admission witness authority-transition admission record does not chain to the previous admission record hash.",
        expected: previousAdmissionRecordHash ?? "none",
        actual: record.previousAdmissionRecordHash ?? "none",
      });
    }
    if (!recordHashValidation.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_record_hash_mismatch",
        path: `${path}/admissionRecordHash`,
        message: `Pruning-policy admission witness authority-transition admission record hash ${recordHashValidation.actualHash} does not match recomputed hash ${recordHashValidation.expectedHash}.`,
        expected: recordHashValidation.expectedHash,
        actual: recordHashValidation.actualHash,
      });
    }
    if (!transitionHashValidation.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_transition_hash_mismatch",
        path: `${path}/authorityTransition/authorityRecordHash`,
        message: `Pruning-policy admission witness authority transition hash ${transitionHashValidation.actualHash} does not match recomputed hash ${transitionHashValidation.expectedHash}.`,
        expected: transitionHashValidation.expectedHash,
        actual: transitionHashValidation.actualHash,
      });
    }
    if (
      record.authoritySequence !==
        record.authorityTransition.authoritySequence ||
      record.authorityRecordHash !==
        record.authorityTransition.authorityRecordHash ||
      record.previousAuthorityRecordHash !==
        record.authorityTransition.previousAuthorityRecordHash
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_transition_mismatch",
        path: `${path}/authorityTransition`,
        message:
          "Pruning-policy admission witness authority-transition admission record does not match its embedded authority transition sequence and hash.",
        expected: record.authorityRecordHash,
        actual: record.authorityTransition.authorityRecordHash,
      });
    }
    if (record.authoritySequence !== expectedAuthoritySequence) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_transition_sequence_gap",
        path: `${path}/authoritySequence`,
        message:
          "Pruning-policy admission witness authority transitions must be admitted in contiguous authority sequence.",
        expected: expectedAuthoritySequence,
        actual: record.authoritySequence,
      });
    }
    if (
      record.authorityTransition.previousAuthorityRecordHash !==
      previousAuthorityRecordHash
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_transition_previous_hash_mismatch",
        path: `${path}/authorityTransition/previousAuthorityRecordHash`,
        message:
          "Pruning-policy admission witness authority transition must hash-chain from the previously admitted authority transition.",
        expected: previousAuthorityRecordHash ?? "none",
        actual:
          record.authorityTransition.previousAuthorityRecordHash ?? "none",
      });
    }
    if (record.authorityTransition.effectiveFromSubjectSequence < 1) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_transition_invalid",
        path: `${path}/authorityTransition/effectiveFromSubjectSequence`,
        message:
          "Pruning-policy admission witness authority transitions must declare a positive effective policy sequence.",
        actual: record.authorityTransition.effectiveFromSubjectSequence,
      });
    }
    if (
      record.authorityTransition.transitionKind === "set_quorum" &&
      ((record.authorityTransition.requiredWitnesses ?? 0) < 1 ||
        (record.authorityTransition.minimumWitnesses ??
          record.authorityTransition.requiredWitnesses ??
          0) < 1 ||
        (record.authorityTransition.minimumWitnesses ??
          record.authorityTransition.requiredWitnesses ??
          0) > (record.authorityTransition.requiredWitnesses ?? 0))
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_transition_invalid",
        path: `${path}/authorityTransition/requiredWitnesses`,
        message:
          "Pruning-policy admission witness authority quorum transitions must declare positive and internally consistent witness thresholds.",
      });
    }
    if (
      [
        "admit_principal",
        "suspend_principal",
        "revoke_principal",
        "rotate_signature_key",
        "mark_equivocated",
      ].includes(record.authorityTransition.transitionKind) &&
      (record.authorityTransition.principalId === undefined ||
        record.authorityTransition.principalId.length === 0)
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_transition_invalid",
        path: `${path}/authorityTransition/principalId`,
        message:
          "Pruning-policy admission witness authority principal transitions must identify the affected principal.",
      });
    }
    if (
      record.authorityTransition.transitionKind === "seal_authority_epoch" &&
      ((record.authorityTransition.sealedThroughSubjectSequence ?? 0) < 1 ||
        record.authorityTransition.sealedQuorumCertificateHash === undefined ||
        record.authorityTransition.sealedQuorumCertificateHash.length === 0)
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_transition_invalid",
        path: `${path}/authorityTransition/sealedQuorumCertificateHash`,
        message:
          "Pruning-policy admission witness authority epoch seals must bind a positive sealed frontier and a quorum certificate hash.",
      });
    }

    const nextTopology = operationalStateAuthorityTopologyFromTransition(
      record.authorityTransition,
      previousTopology,
    );
    if (record.nextAuthorityTopologyHash !== nextTopology.topologyHash) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_transition_topology_hash_mismatch",
        path: `${path}/nextAuthorityTopologyHash`,
        message:
          "Pruning-policy admission witness authority-transition admission record does not derive the expected next topology hash.",
        expected: nextTopology.topologyHash,
        actual: record.nextAuthorityTopologyHash,
      });
    }
    if (previousTopology === undefined) {
      if (record.previousAuthorityTopologyHash !== undefined) {
        pushOperationalStatePruningPolicyIssue(issues, {
          code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_transition_previous_topology_hash_mismatch",
          path: `${path}/previousAuthorityTopologyHash`,
          message:
            "Genesis pruning-policy admission witness authority transition cannot cite a previous topology hash.",
          actual: record.previousAuthorityTopologyHash,
        });
      }
    } else {
      if (
        record.previousAuthorityTopologyHash !== previousTopology.topologyHash
      ) {
        pushOperationalStatePruningPolicyIssue(issues, {
          code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_transition_previous_topology_hash_mismatch",
          path: `${path}/previousAuthorityTopologyHash`,
          message:
            "Pruning-policy admission witness authority transition admission must bind the previous replayed topology hash.",
          expected: previousTopology.topologyHash,
          actual: record.previousAuthorityTopologyHash ?? "none",
        });
      }
      if (
        record.admissionCertificate.authorityTopologyHash !==
        previousTopology.topologyHash
      ) {
        pushOperationalStatePruningPolicyIssue(issues, {
          code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_certificate_authority_topology_mismatch",
          path: `${path}/admissionCertificate/authorityTopologyHash`,
          message:
            "Pruning-policy admission witness authority transition admission certificate must be bound to the previous replayed topology.",
          expected: previousTopology.topologyHash,
          actual:
            record.admissionCertificate.authorityTopologyHash ?? "none",
        });
      }

      const principalById = new Map<
        string,
        OperationalStateAuthorityPrincipalState
      >(
        previousTopology.principals.map((principal) => [
          principal.principalId,
          principal,
        ]),
      );
      const acceptedWitnessIds =
        record.admissionCertificate.acceptedWitnessIds;
      const uniqueAcceptedWitnessIds = new Set(acceptedWitnessIds);
      if (uniqueAcceptedWitnessIds.size !== acceptedWitnessIds.length) {
        pushOperationalStatePruningPolicyIssue(issues, {
          code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_authority_duplicate_witness",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Pruning-policy admission witness authority-transition admission cannot be certified by duplicate prior-topology witnesses.",
          expected: uniqueAcceptedWitnessIds.size,
          actual: acceptedWitnessIds.length,
        });
      }

      let activeAuthorizedWitnessCount = 0;
      for (const witnessId of uniqueAcceptedWitnessIds) {
        const principal = principalById.get(witnessId);
        if (principal === undefined) {
          pushOperationalStatePruningPolicyIssue(issues, {
            code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_authority_witness_unknown",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Pruning-policy admission witness authority-transition admission certificate names a witness outside the previous replayed topology.",
            expected: previousTopology.topologyHash,
            actual: witnessId,
          });
          continue;
        }
        if (principal.status !== "active") {
          pushOperationalStatePruningPolicyIssue(issues, {
            code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_authority_witness_not_active",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Pruning-policy admission witness authority-transition admission certificate names a witness that is not active in the previous replayed topology.",
            expected: "active",
            actual: `${witnessId}:${principal.status}`,
          });
          continue;
        }
        activeAuthorizedWitnessCount += 1;
      }

      const requiredAuthorizedWitnesses = Math.max(
        previousTopology.requiredWitnesses ?? 0,
        previousTopology.minimumWitnesses ?? 0,
      );
      if (activeAuthorizedWitnessCount < requiredAuthorizedWitnesses) {
        pushOperationalStatePruningPolicyIssue(issues, {
          code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_authority_quorum_not_met",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Pruning-policy admission witness authority-transition admission certificate does not satisfy previous-topology quorum.",
          expected: requiredAuthorizedWitnesses,
          actual: activeAuthorizedWitnessCount,
        });
      }
    }

    if (!certificateHashValidation.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_certificate_hash_mismatch",
        path: `${path}/admissionCertificate/quorumCertificateHash`,
        message: `Pruning-policy admission witness authority-transition admission certificate hash ${certificateHashValidation.actualHash} does not match recomputed hash ${certificateHashValidation.expectedHash}.`,
        expected: certificateHashValidation.expectedHash,
        actual: certificateHashValidation.actualHash,
      });
    }
    if (
      !record.admissionCertificate.certified ||
      record.admissionCertificate.status !== "certified"
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_certificate_not_certified",
        path: `${path}/admissionCertificate/status`,
        message:
          "Pruning-policy admission witness authority transition cannot become authority through a non-certified admission certificate.",
        expected: "certified",
        actual: record.admissionCertificate.status,
      });
    }
    if (
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.minimumWitnesses ||
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.requiredWitnesses
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_certificate_quorum_not_met",
        path: `${path}/admissionCertificate/acceptedWitnessIds`,
        message:
          "Pruning-policy admission witness authority-transition admission certificate does not satisfy its declared witness quorum.",
        expected: Math.max(
          record.admissionCertificate.requiredWitnesses,
          record.admissionCertificate.minimumWitnesses,
        ),
        actual: record.admissionCertificate.acceptedWitnessIds.length,
      });
    }
    if (
      record.admissionCertificate.subjectKind !==
        OPERATIONAL_STATE_AUTHORITY_TRANSITION_RECORD_SUBJECT_KIND ||
      record.admissionCertificate.subjectId !== record.topologyId ||
      record.admissionCertificate.subjectSequence !==
        record.authoritySequence ||
      record.admissionCertificate.subjectHash !== record.authorityRecordHash
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_certificate_subject_mismatch",
        path: `${path}/admissionCertificate`,
        message:
          "Pruning-policy admission witness authority-transition admission certificate must certify the exact topology id, authority sequence, and authority transition hash.",
        expected: record.authorityRecordHash,
        actual: record.admissionCertificate.subjectHash,
      });
    }
    if (
      input.requiredAuthorityBoundary !== undefined &&
      record.admissionCertificate.authorityBoundary !==
        input.requiredAuthorityBoundary
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_certificate_authority_boundary_mismatch",
        path: `${path}/admissionCertificate/authorityBoundary`,
        message:
          "Pruning-policy admission witness authority-transition admission certificate was admitted under the wrong authority boundary.",
        expected: input.requiredAuthorityBoundary,
        actual: record.admissionCertificate.authorityBoundary,
      });
    }

    admissionRecordByAuthorityHash.set(record.authorityRecordHash, record);
    expectedAdmissionSequence = record.admissionSequence + 1;
    expectedAuthoritySequence = record.authoritySequence + 1;
    previousAdmissionRecordHash = record.admissionRecordHash;
    previousAuthorityRecordHash = record.authorityRecordHash;
    previousTopology = nextTopology;
    latestAdmittedTopology = nextTopology;
    latestAdmittedRecord = record;
  });

  let requiredAuthorityTransitionAdmissionRecord:
    | OperationalStatePruningPolicyAdmissionWitnessAuthorityTransitionAdmissionRecord
    | undefined;
  if (input.requiredAuthorityTransition !== undefined) {
    const requiredTransitionHashValidation =
      verifyOperationalStateAuthorityTransitionRecordHash(
        input.requiredAuthorityTransition,
      );
    if (!requiredTransitionHashValidation.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_transition_hash_mismatch",
        path: "/requiredAuthorityTransition/authorityRecordHash",
        message: `Required pruning-policy admission witness authority transition hash ${requiredTransitionHashValidation.actualHash} does not match recomputed hash ${requiredTransitionHashValidation.expectedHash}.`,
        expected: requiredTransitionHashValidation.expectedHash,
        actual: requiredTransitionHashValidation.actualHash,
      });
    }
    requiredAuthorityTransitionAdmissionRecord =
      admissionRecordByAuthorityHash.get(
        input.requiredAuthorityTransition.authorityRecordHash,
      );
    if (requiredAuthorityTransitionAdmissionRecord === undefined) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_not_admitted",
        path: "/requiredAuthorityTransition/authorityRecordHash",
        message:
          "Required pruning-policy admission witness authority transition has no replayed admission certificate.",
        expected: input.requiredAuthorityTransition.authorityRecordHash,
      });
    }
  }

  if (input.requiredAuthorityTopology !== undefined) {
    const requiredTopologyHashValidation =
      verifyOperationalStateAuthorityTopologyHash(
        input.requiredAuthorityTopology,
      );
    if (!requiredTopologyHashValidation.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_topology_hash_mismatch",
        path: "/requiredAuthorityTopology/topologyHash",
        message: `Required pruning-policy admission witness authority topology hash ${requiredTopologyHashValidation.actualHash} does not match recomputed hash ${requiredTopologyHashValidation.expectedHash}.`,
        expected: requiredTopologyHashValidation.expectedHash,
        actual: requiredTopologyHashValidation.actualHash,
      });
    }
    if (
      latestAdmittedTopology === undefined ||
      !operationalStateAuthorityTopologiesMatch(
        latestAdmittedTopology,
        input.requiredAuthorityTopology,
      )
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/requiredAuthorityTopology",
        message:
          "Pruning-policy admission witness authority-transition admission replay must recover the required authority topology.",
        expected: input.requiredAuthorityTopology.topologyHash,
        actual: latestAdmittedTopology?.topologyHash ?? "none",
      });
    }
    requiredAuthorityTransitionAdmissionRecord =
      admissionRecordByAuthorityHash.get(
        input.requiredAuthorityTopology.authorityRecordHash,
      );
    if (requiredAuthorityTransitionAdmissionRecord === undefined) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_not_admitted",
        path: "/requiredAuthorityTopology/authorityRecordHash",
        message:
          "Required pruning-policy admission witness authority topology is not backed by an admitted authority transition.",
        expected: input.requiredAuthorityTopology.authorityRecordHash,
      });
    }
  }

  if (
    input.requireAdmissionWitness === true ||
    input.requireAdmissionWitnessAuthorityTopology === true ||
    input.requireAdmissionWitnessAuthorityTransitionAdmission === true
  ) {
    if (admissionWitnessReplay === undefined) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_replay_missing",
        path: "/admissionWitnessReplay",
        message:
          "Pruning-policy admission witness authority-transition admission replay requires witnessed transition-admission records.",
      });
    } else if (!admissionWitnessReplay.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_replay_invalid",
        path: "/admissionWitnessReplay",
        message:
          "Pruning-policy admission witness authority-transition admission replay cannot consume invalid transition-admission witness history.",
        actual: admissionWitnessReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      latestAdmittedRecord === undefined ||
      admissionWitnessReplay.requiredAdmissionWitnessRecord === undefined ||
      admissionWitnessReplay.requiredAdmissionWitnessRecord
        .admissionRecordHash !== latestAdmittedRecord.admissionRecordHash
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_latest_record_not_witnessed",
        path: "/admissionWitnessReplay",
        message:
          "Latest pruning-policy admission witness authority-transition admission record is not witnessed by the replayed transition-admission witness ledger.",
        expected: latestAdmittedRecord?.admissionRecordHash ?? "none",
        actual:
          admissionWitnessReplay.requiredAdmissionWitnessRecord
            ?.admissionRecordHash ?? "none",
      });
    } else if (
      (input.requireAdmissionWitnessAuthorityTopology === true ||
        input.requireAdmissionWitnessAuthorityTransitionAdmission === true) &&
      admissionWitnessReplay.witnessAuthorityTopology === undefined
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_topology_missing",
        path: "/admissionWitnessReplay/witnessAuthorityTopology",
        message:
          "Pruning-policy admission witness authority-transition admission replay requires its witness history to bind certificates to replayed witness authority topology.",
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmission === true &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay ===
        undefined
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        path: "/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Pruning-policy admission witness authority-transition admission replay requires its nested transition-admission witness authority topology to replay from admitted authority-transition history.",
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmission === true &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      !admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.valid
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        path: "/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Pruning-policy admission witness authority-transition admission replay cannot consume invalid nested transition-admission witness authority history.",
        actual:
          admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.issues
            .map((issue) => issue.code)
            .join(","),
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmission === true &&
      admissionWitnessReplay.witnessAuthorityTopology !== undefined &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      (admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .latestAdmittedTopology === undefined ||
        !operationalStateAuthorityTopologiesMatch(
          admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology,
          admissionWitnessReplay.witnessAuthorityTopology,
        ))
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Pruning-policy admission witness authority-transition admission replay requires the nested transition-admission witness authority topology to be recovered from admitted authority-transition history.",
        expected: admissionWitnessReplay.witnessAuthorityTopology.topologyHash,
        actual:
          admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology?.topologyHash ?? "none",
      });
    }
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    transitionAdmissionStoreId: input.transitionAdmissionStoreId,
    topologyId: input.topologyId,
    authorityScope: input.authorityScope,
    admittedRecordCount: input.records.length,
    ...(latestAdmittedRecord !== undefined ? { latestAdmittedRecord } : {}),
    ...(latestAdmittedTopology !== undefined ? { latestAdmittedTopology } : {}),
    ...(input.requiredAuthorityTopology !== undefined
      ? { requiredAuthorityTopology: input.requiredAuthorityTopology }
      : {}),
    ...(input.requiredAuthorityTransition !== undefined
      ? { requiredAuthorityTransition: input.requiredAuthorityTransition }
      : {}),
    ...(requiredAuthorityTransitionAdmissionRecord !== undefined
      ? { requiredAuthorityTransitionAdmissionRecord }
      : {}),
    ...(admissionWitnessReplay !== undefined ? { admissionWitnessReplay } : {}),
    issues,
  };
}

function pushOperationalStatePruningPolicyIssue(
  issues: OperationalStatePruningPolicyIssue[],
  issue: OperationalStatePruningPolicyIssue,
): void {
  issues.push(issue);
}

export function replayOperationalStatePruningPolicyAdmissionRecords(
  input: OperationalStatePruningPolicyAdmissionReplayInput,
): OperationalStatePruningPolicyAdmissionReplay {
  const issues: OperationalStatePruningPolicyIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const recordHashBySequence = new Map<number, string>();
  let expectedSequence = 1;
  let previousPolicyRecordHash: string | undefined;
  let latestAdmittedRecord:
    | OperationalStatePruningPolicyAdmissionRecord
    | undefined;

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const recordHashValidation =
      verifyOperationalStatePruningPolicyAdmissionRecordHash(record);
    const artifactHashValidation =
      verifyOperationalStatePruningPolicyArtifactHash(record.artifact);
    const compilationHashValidation =
      verifyOperationalStatePruningPolicyCompilationHash(
        record.artifact.compilation,
      );
    const previousRecordHashAtSequence = recordHashBySequence.get(
      record.policySequence,
    );

    if (
      previousRecordHashAtSequence !== undefined &&
      previousRecordHashAtSequence !== record.policyRecordHash
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_record_fork",
        path: `${path}/policySequence`,
        message: `Pruning-policy admission sequence ${record.policySequence} has more than one record hash.`,
        expected: previousRecordHashAtSequence,
        actual: record.policyRecordHash,
      });
    } else if (previousRecordHashAtSequence === undefined) {
      recordHashBySequence.set(record.policySequence, record.policyRecordHash);
    }

    if (record.tenantId !== expectedTenantId) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_record_tenant_mismatch",
        path: `${path}/tenantId`,
        message: `Pruning-policy admission record tenant ${record.tenantId} does not match replay tenant ${expectedTenantId}.`,
        expected: expectedTenantId,
        actual: record.tenantId,
      });
    }
    if (record.artifact.tenantId !== expectedTenantId) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_record_tenant_mismatch",
        path: `${path}/artifact/tenantId`,
        message: `Pruning-policy artifact tenant ${record.artifact.tenantId} does not match replay tenant ${expectedTenantId}.`,
        expected: expectedTenantId,
        actual: record.artifact.tenantId,
      });
    }
    if (record.artifact.compilation.tenantId !== expectedTenantId) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_record_tenant_mismatch",
        path: `${path}/artifact/compilation/tenantId`,
        message: `Compiled pruning policy tenant ${record.artifact.compilation.tenantId} does not match replay tenant ${expectedTenantId}.`,
        expected: expectedTenantId,
        actual: record.artifact.compilation.tenantId,
      });
    }
    if (record.policyStoreId !== input.policyStoreId) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_record_scope_mismatch",
        path: `${path}/policyStoreId`,
        message: `Pruning-policy admission record store ${record.policyStoreId} does not match replay store ${input.policyStoreId}.`,
        expected: input.policyStoreId,
        actual: record.policyStoreId,
      });
    }
    if (record.authorityScope !== input.authorityScope) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_record_scope_mismatch",
        path: `${path}/authorityScope`,
        message: `Pruning-policy admission record scope ${record.authorityScope} does not match replay scope ${input.authorityScope}.`,
        expected: input.authorityScope,
        actual: record.authorityScope,
      });
    }
    if (record.artifact.authorityScope !== input.authorityScope) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_record_scope_mismatch",
        path: `${path}/artifact/authorityScope`,
        message: `Pruning-policy artifact scope ${record.artifact.authorityScope} does not match replay scope ${input.authorityScope}.`,
        expected: input.authorityScope,
        actual: record.artifact.authorityScope,
      });
    }
    if (record.artifact.compilation.authorityScope !== input.authorityScope) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_record_scope_mismatch",
        path: `${path}/artifact/compilation/authorityScope`,
        message: `Compiled pruning policy scope ${record.artifact.compilation.authorityScope} does not match replay scope ${input.authorityScope}.`,
        expected: input.authorityScope,
        actual: record.artifact.compilation.authorityScope,
      });
    }
    if (record.policySequence !== expectedSequence) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_record_sequence_gap",
        path: `${path}/policySequence`,
        message: `Pruning-policy admission sequence ${record.policySequence} does not match expected replay sequence ${expectedSequence}.`,
        expected: expectedSequence,
        actual: record.policySequence,
      });
    }
    if (record.previousPolicyRecordHash !== previousPolicyRecordHash) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_record_previous_hash_mismatch",
        path: `${path}/previousPolicyRecordHash`,
        message:
          "Pruning-policy admission record does not chain to the previous admitted policy record hash.",
        expected: previousPolicyRecordHash ?? "none",
        actual: record.previousPolicyRecordHash ?? "none",
      });
    }
    if (!artifactHashValidation.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_record_artifact_hash_mismatch",
        path: `${path}/artifact/artifactHash`,
        message: `Pruning-policy artifact hash ${artifactHashValidation.actualHash} does not match recomputed hash ${artifactHashValidation.expectedHash}.`,
        expected: artifactHashValidation.expectedHash,
        actual: artifactHashValidation.actualHash,
      });
    }
    if (!compilationHashValidation.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_record_compilation_hash_mismatch",
        path: `${path}/artifact/compilation/policyHash`,
        message: `Compiled pruning policy hash ${compilationHashValidation.actualHash} does not match recomputed hash ${compilationHashValidation.expectedHash}.`,
        expected: compilationHashValidation.expectedHash,
        actual: compilationHashValidation.actualHash,
      });
    }
    if (!record.artifact.compilation.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_record_compilation_invalid",
        path: `${path}/artifact/compilation`,
        message:
          "Pruning-policy admission record cannot admit an invalid compiled policy.",
        actual: record.artifact.compilation.issues
          .map((issue) => issue.code)
          .join(","),
      });
    }
    if (record.artifact.policyHash !== record.artifact.compilation.policyHash) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_record_policy_hash_mismatch",
        path: `${path}/artifact/policyHash`,
        message:
          "Pruning-policy artifact policy hash does not match embedded compilation hash.",
        expected: record.artifact.compilation.policyHash,
        actual: record.artifact.policyHash,
      });
    }
    if (record.policyHash !== record.artifact.policyHash) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_record_policy_hash_mismatch",
        path: `${path}/policyHash`,
        message:
          "Pruning-policy admission record hash does not match admitted artifact policy hash.",
        expected: record.artifact.policyHash,
        actual: record.policyHash,
      });
    }
    if (record.policyId !== record.artifact.policyId) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_record_policy_hash_mismatch",
        path: `${path}/policyId`,
        message:
          "Pruning-policy admission record id does not match admitted artifact policy id.",
        expected: record.artifact.policyId,
        actual: record.policyId,
      });
    }
    if (!recordHashValidation.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_record_hash_mismatch",
        path: `${path}/policyRecordHash`,
        message: `Pruning-policy admission record hash ${recordHashValidation.actualHash} does not match recomputed hash ${recordHashValidation.expectedHash}.`,
        expected: recordHashValidation.expectedHash,
        actual: recordHashValidation.actualHash,
      });
    }

    expectedSequence = record.policySequence + 1;
    previousPolicyRecordHash = record.policyRecordHash;
    latestAdmittedRecord = record;
  });

  if (input.requiredCompilation !== undefined) {
    const requiredCompilationHashValidation =
      verifyOperationalStatePruningPolicyCompilationHash(
        input.requiredCompilation,
      );
    if (!requiredCompilationHashValidation.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_required_policy_hash_mismatch",
        path: "/requiredCompilation/policyHash",
        message: `Required pruning policy hash ${requiredCompilationHashValidation.actualHash} does not match recomputed hash ${requiredCompilationHashValidation.expectedHash}.`,
        expected: requiredCompilationHashValidation.expectedHash,
        actual: requiredCompilationHashValidation.actualHash,
      });
    }
    if (latestAdmittedRecord === undefined) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_required_policy_missing",
        path: "/records",
        message:
          "Pruning-policy admission replay has no records for the required compiled policy.",
      });
    } else if (
      latestAdmittedRecord.policyHash !== input.requiredCompilation.policyHash
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_policy_stale",
        path: "/requiredCompilation/policyHash",
        message: `Latest pruning-policy admission record admits ${latestAdmittedRecord.policyHash}, not required policy ${input.requiredCompilation.policyHash}.`,
        expected: input.requiredCompilation.policyHash,
        actual: latestAdmittedRecord.policyHash,
      });
    }
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    policyStoreId: input.policyStoreId,
    authorityScope: input.authorityScope,
    admittedRecordCount: input.records.length,
    ...(latestAdmittedRecord !== undefined ? { latestAdmittedRecord } : {}),
    ...(input.requiredCompilation !== undefined
      ? { requiredCompilation: input.requiredCompilation }
      : {}),
    issues,
  };
}

export function replayOperationalStatePruningPolicyAdmissionWitnessRecords(
  input: OperationalStatePruningPolicyAdmissionWitnessReplayInput,
): OperationalStatePruningPolicyAdmissionWitnessReplay {
  const issues: OperationalStatePruningPolicyIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const witnessHashBySequence = new Map<number, string>();
  const witnessRecordByPolicyRecordHash = new Map<
    string,
    OperationalStatePruningPolicyAdmissionWitnessRecord
  >();
  const witnessAuthorityTopology = input.witnessAuthorityTopology;
  const witnessAuthorityTransitionAdmissionReplay =
    input.witnessAuthorityTransitionAdmissionReplay;
  const principalById = new Map<string, OperationalStateAuthorityPrincipalState>(
    witnessAuthorityTopology?.principals.map((principal) => [
      principal.principalId,
      principal,
    ]) ?? [],
  );
  let expectedSequence = 1;
  let previousWitnessRecordHash: string | undefined;
  let latestWitnessRecord:
    | OperationalStatePruningPolicyAdmissionWitnessRecord
    | undefined;

  if (input.admissionReplay !== undefined && !input.admissionReplay.valid) {
    pushOperationalStatePruningPolicyIssue(issues, {
      code: "operational_state_pruning_policy_admission_witness_admission_replay_invalid",
      path: "/admissionReplay",
      message:
        "Pruning-policy admission witness replay cannot account for an invalid pruning-policy admission replay.",
      actual: input.admissionReplay.issues
        .map((issue) => issue.code)
        .join(","),
    });
  }

  if (
    (input.requireWitnessAuthorityTopology === true ||
      input.requireWitnessAuthorityTransitionAdmission === true ||
      input.requireWitnessAuthorityTransitionAdmissionWitness === true ||
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    witnessAuthorityTopology === undefined
  ) {
    pushOperationalStatePruningPolicyIssue(issues, {
      code: "operational_state_pruning_policy_admission_witness_authority_topology_missing",
      path: "/witnessAuthorityTopology",
      message:
        "Pruning-policy admission witness replay requires a replayed witness authority topology.",
    });
  }

  if (witnessAuthorityTopology !== undefined) {
    const topologyHashValidation =
      verifyOperationalStateAuthorityTopologyHash(witnessAuthorityTopology);
    if (!topologyHashValidation.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_topology_hash_mismatch",
        path: "/witnessAuthorityTopology/topologyHash",
        message: `Pruning-policy admission witness authority topology hash ${topologyHashValidation.actualHash} does not match recomputed hash ${topologyHashValidation.expectedHash}.`,
        expected: topologyHashValidation.expectedHash,
        actual: topologyHashValidation.actualHash,
      });
    }
    if (witnessAuthorityTopology.tenantId !== expectedTenantId) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_topology_tenant_mismatch",
        path: "/witnessAuthorityTopology/tenantId",
        message:
          "Pruning-policy admission witness authority topology tenant does not match replay tenant.",
        expected: expectedTenantId,
        actual: witnessAuthorityTopology.tenantId,
      });
    }
    if (witnessAuthorityTopology.authorityScope !== input.authorityScope) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_topology_scope_mismatch",
        path: "/witnessAuthorityTopology/authorityScope",
        message:
          "Pruning-policy admission witness authority topology scope does not match replay scope.",
        expected: input.authorityScope,
        actual: witnessAuthorityTopology.authorityScope,
      });
    }
    if (
      witnessAuthorityTopology.requiredWitnesses === undefined ||
      witnessAuthorityTopology.minimumWitnesses === undefined
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_quorum_missing",
        path: "/witnessAuthorityTopology/requiredWitnesses",
        message:
          "Pruning-policy admission witness authority topology must define quorum thresholds.",
      });
    }
  }

  if (
    input.requireWitnessAuthorityTransitionAdmission === true ||
    input.requireWitnessAuthorityTransitionAdmissionWitness === true ||
    input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
      true ||
    input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
      true
  ) {
    if (witnessAuthorityTransitionAdmissionReplay === undefined) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_replay_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Pruning-policy admission witness replay requires admitted policy-admission witness-authority transition history.",
      });
    } else if (!witnessAuthorityTransitionAdmissionReplay.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_replay_invalid",
        path: "/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Pruning-policy admission witness replay cannot consume invalid policy-admission witness-authority transition admission history.",
        actual: witnessAuthorityTransitionAdmissionReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      witnessAuthorityTopology !== undefined &&
      (witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology ===
        undefined ||
        !operationalStateAuthorityTopologiesMatch(
          witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology,
          witnessAuthorityTopology,
        ))
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Pruning-policy admission witness authority topology must be recovered from admitted authority-transition history.",
        expected: witnessAuthorityTopology.topologyHash,
        actual:
          witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology
            ?.topologyHash ?? "none",
      });
    }
  }
  if (
    (input.requireWitnessAuthorityTransitionAdmissionWitness === true ||
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    witnessAuthorityTransitionAdmissionReplay !== undefined
  ) {
    if (witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay === undefined) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_replay_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
        message:
          "Pruning-policy admission witness replay requires policy-admission witness authority-transition admission records to be witnessed.",
      });
    } else if (
      !witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay.valid
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_replay_invalid",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
        message:
          "Pruning-policy admission witness replay cannot consume invalid policy-admission witness authority-transition admission witness history.",
        actual:
          witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay.issues
            .map((issue) => issue.code)
            .join(","),
      });
    } else if (
      (input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
        input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
          true) &&
      witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTopology === undefined
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_topology_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTopology",
        message:
          "Pruning-policy admission witness replay requires witness authority-transition admission witness certificates to bind to replayed witness authority topology.",
      });
    } else if (
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTransitionAdmissionReplay === undefined
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Pruning-policy admission witness replay requires witness authority-transition admission witness authority topology to replay from admitted authority-transition history.",
      });
    } else if (
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTransitionAdmissionReplay !== undefined &&
      !witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTransitionAdmissionReplay.valid
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Pruning-policy admission witness replay cannot consume invalid nested policy-admission witness authority-transition admission witness authority history.",
        actual:
          witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.issues
            .map((issue) => issue.code)
            .join(","),
      });
    } else if (
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTopology !== undefined &&
      witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTransitionAdmissionReplay !== undefined &&
      (witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology ===
        undefined ||
        !operationalStateAuthorityTopologiesMatch(
          witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
            .witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology,
          witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
            .witnessAuthorityTopology,
        ))
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Pruning-policy admission witness replay requires witness authority-transition admission witness authority topology to be recovered from admitted authority-transition history.",
        expected:
          witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
            .witnessAuthorityTopology.topologyHash,
        actual:
          witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
            .witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology
            ?.topologyHash ?? "none",
      });
    }
  }

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const witnessRecordHashValidation =
      verifyOperationalStatePruningPolicyAdmissionWitnessRecordHash(record);
    const certificateHashValidation =
      verifyOperationalStateQuorumCertificateProofCertificateHash(
        record.admissionCertificate,
      );
    const previousWitnessHashAtSequence = witnessHashBySequence.get(
      record.witnessSequence,
    );

    if (
      previousWitnessHashAtSequence !== undefined &&
      previousWitnessHashAtSequence !== record.witnessRecordHash
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_record_fork",
        path: `${path}/witnessSequence`,
        message: `Pruning-policy admission witness sequence ${record.witnessSequence} has more than one witness record hash.`,
        expected: previousWitnessHashAtSequence,
        actual: record.witnessRecordHash,
      });
    } else if (previousWitnessHashAtSequence === undefined) {
      witnessHashBySequence.set(
        record.witnessSequence,
        record.witnessRecordHash,
      );
    }

    if (
      record.tenantId !== expectedTenantId ||
      record.admissionCertificate.tenantId !== expectedTenantId
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_record_tenant_mismatch",
        path,
        message:
          "Pruning-policy admission witness record and certificate must match the replay tenant.",
        expected: expectedTenantId,
      });
    }
    if (
      record.policyAdmissionWitnessStoreId !==
      input.policyAdmissionWitnessStoreId
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_record_store_mismatch",
        path: `${path}/policyAdmissionWitnessStoreId`,
        message:
          "Pruning-policy admission witness record belongs to a different witness store.",
        expected: input.policyAdmissionWitnessStoreId,
        actual: record.policyAdmissionWitnessStoreId,
      });
    }
    if (record.policyStoreId !== input.policyStoreId) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_record_store_mismatch",
        path: `${path}/policyStoreId`,
        message:
          "Pruning-policy admission witness record accounts for a different policy-admission store.",
        expected: input.policyStoreId,
        actual: record.policyStoreId,
      });
    }
    if (
      record.authorityScope !== input.authorityScope ||
      record.admissionCertificate.authorityScope !== input.authorityScope
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_record_scope_mismatch",
        path,
        message:
          "Pruning-policy admission witness record and certificate must share the replay authority scope.",
        expected: input.authorityScope,
      });
    }
    if (record.witnessSequence !== expectedSequence) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_record_sequence_gap",
        path: `${path}/witnessSequence`,
        message:
          "Pruning-policy admission witness records must replay as a contiguous witness sequence.",
        expected: expectedSequence,
        actual: record.witnessSequence,
      });
    }
    if (record.previousWitnessRecordHash !== previousWitnessRecordHash) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_record_previous_hash_mismatch",
        path: `${path}/previousWitnessRecordHash`,
        message:
          "Pruning-policy admission witness record does not chain to the previous witness record hash.",
        expected: previousWitnessRecordHash ?? "none",
        actual: record.previousWitnessRecordHash ?? "none",
      });
    }
    if (!certificateHashValidation.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_certificate_hash_mismatch",
        path: `${path}/admissionCertificate/quorumCertificateHash`,
        message: `Pruning-policy admission witness certificate hash ${certificateHashValidation.actualHash} does not match recomputed hash ${certificateHashValidation.expectedHash}.`,
        expected: certificateHashValidation.expectedHash,
        actual: certificateHashValidation.actualHash,
      });
    }
    if (
      !record.admissionCertificate.certified ||
      record.admissionCertificate.status !== "certified"
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_certificate_not_certified",
        path: `${path}/admissionCertificate/status`,
        message:
          "Pruning-policy admission cannot become accountable through a non-certified witness certificate.",
        expected: "certified",
        actual: record.admissionCertificate.status,
      });
    }
    if (
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.minimumWitnesses ||
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.requiredWitnesses
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_certificate_quorum_not_met",
        path: `${path}/admissionCertificate/acceptedWitnessIds`,
        message:
          "Pruning-policy admission witness certificate does not satisfy its witness quorum.",
        expected: Math.max(
          record.admissionCertificate.requiredWitnesses,
          record.admissionCertificate.minimumWitnesses,
        ),
        actual: record.admissionCertificate.acceptedWitnessIds.length,
      });
    }
    if (
      record.admissionCertificate.subjectKind !==
        OPERATIONAL_STATE_PRUNING_POLICY_ADMISSION_RECORD_SUBJECT_KIND ||
      record.admissionCertificate.subjectId !== record.policyStoreId ||
      record.admissionCertificate.subjectSequence !== record.policySequence ||
      record.admissionCertificate.subjectHash !== record.policyRecordHash
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_certificate_subject_mismatch",
        path: `${path}/admissionCertificate`,
        message:
          "Pruning-policy admission witness certificate must certify the exact policy store, policy sequence, and policy record hash.",
        expected: record.policyRecordHash,
        actual: record.admissionCertificate.subjectHash,
      });
    }
    if (
      input.requiredAuthorityBoundary !== undefined &&
      record.admissionCertificate.authorityBoundary !==
        input.requiredAuthorityBoundary
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_certificate_authority_boundary_mismatch",
        path: `${path}/admissionCertificate/authorityBoundary`,
        message:
          "Pruning-policy admission witness certificate was admitted under the wrong authority boundary.",
        expected: input.requiredAuthorityBoundary,
        actual: record.admissionCertificate.authorityBoundary,
      });
    }
    if (witnessAuthorityTopology !== undefined) {
      if (
        record.admissionCertificate.authorityTopologyHash !==
        witnessAuthorityTopology.topologyHash
      ) {
        pushOperationalStatePruningPolicyIssue(issues, {
          code: "operational_state_pruning_policy_admission_witness_certificate_authority_topology_mismatch",
          path: `${path}/admissionCertificate/authorityTopologyHash`,
          message:
            "Pruning-policy admission witness certificate is not bound to the replayed witness authority topology.",
          expected: witnessAuthorityTopology.topologyHash,
          actual:
            record.admissionCertificate.authorityTopologyHash ?? "none",
        });
      }

      const acceptedWitnessIds =
        record.admissionCertificate.acceptedWitnessIds;
      const uniqueAcceptedWitnessIds = new Set(acceptedWitnessIds);
      if (uniqueAcceptedWitnessIds.size !== acceptedWitnessIds.length) {
        pushOperationalStatePruningPolicyIssue(issues, {
          code: "operational_state_pruning_policy_admission_witness_authority_duplicate_witness",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Pruning-policy admission witness authority quorum cannot be satisfied by duplicate witness ids.",
          expected: uniqueAcceptedWitnessIds.size,
          actual: acceptedWitnessIds.length,
        });
      }

      let activeAuthorizedWitnessCount = 0;
      for (const witnessId of uniqueAcceptedWitnessIds) {
        const principal = principalById.get(witnessId);
        if (principal === undefined) {
          pushOperationalStatePruningPolicyIssue(issues, {
            code: "operational_state_pruning_policy_admission_witness_authority_witness_unknown",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Pruning-policy admission witness certificate names a witness that is not present in the replayed authority topology.",
            expected: witnessAuthorityTopology.topologyHash,
            actual: witnessId,
          });
          continue;
        }
        if (principal.status !== "active") {
          pushOperationalStatePruningPolicyIssue(issues, {
            code: "operational_state_pruning_policy_admission_witness_authority_witness_not_active",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Pruning-policy admission witness certificate names a witness that is not active in the replayed authority topology.",
            expected: "active",
            actual: `${witnessId}:${principal.status}`,
          });
          continue;
        }
        activeAuthorizedWitnessCount += 1;
      }

      const requiredAuthorizedWitnesses = Math.max(
        witnessAuthorityTopology.requiredWitnesses ?? 0,
        witnessAuthorityTopology.minimumWitnesses ?? 0,
      );
      if (activeAuthorizedWitnessCount < requiredAuthorizedWitnesses) {
        pushOperationalStatePruningPolicyIssue(issues, {
          code: "operational_state_pruning_policy_admission_witness_authority_quorum_not_met",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Pruning-policy admission witness certificate does not satisfy the replayed witness authority topology quorum.",
          expected: requiredAuthorizedWitnesses,
          actual: activeAuthorizedWitnessCount,
        });
      }
    }
    if (!witnessRecordHashValidation.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_record_hash_mismatch",
        path: `${path}/witnessRecordHash`,
        message: `Pruning-policy admission witness record hash ${witnessRecordHashValidation.actualHash} does not match recomputed hash ${witnessRecordHashValidation.expectedHash}.`,
        expected: witnessRecordHashValidation.expectedHash,
        actual: witnessRecordHashValidation.actualHash,
      });
    }

    witnessRecordByPolicyRecordHash.set(record.policyRecordHash, record);
    expectedSequence = record.witnessSequence + 1;
    previousWitnessRecordHash = record.witnessRecordHash;
    latestWitnessRecord = record;
  });

  const requiredAdmissionRecord =
    input.requiredAdmissionRecord ??
    input.admissionReplay?.latestAdmittedRecord;
  let requiredAdmissionWitnessRecord:
    | OperationalStatePruningPolicyAdmissionWitnessRecord
    | undefined;
  if (requiredAdmissionRecord !== undefined) {
    const policyRecordHashValidation =
      verifyOperationalStatePruningPolicyAdmissionRecordHash(
        requiredAdmissionRecord,
      );
    if (!policyRecordHashValidation.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_record_hash_mismatch",
        path: "/requiredAdmissionRecord/policyRecordHash",
        message: `Required pruning-policy admission record hash ${policyRecordHashValidation.actualHash} does not match recomputed hash ${policyRecordHashValidation.expectedHash}.`,
        expected: policyRecordHashValidation.expectedHash,
        actual: policyRecordHashValidation.actualHash,
      });
    }
    requiredAdmissionWitnessRecord = witnessRecordByPolicyRecordHash.get(
      requiredAdmissionRecord.policyRecordHash,
    );
    if (requiredAdmissionWitnessRecord === undefined) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_latest_record_not_witnessed",
        path: "/requiredAdmissionRecord/policyRecordHash",
        message:
          "Latest pruning-policy admission record has no replayed witness certificate.",
        expected: requiredAdmissionRecord.policyRecordHash,
      });
    } else if (
      requiredAdmissionWitnessRecord.policySequence !==
        requiredAdmissionRecord.policySequence ||
      requiredAdmissionWitnessRecord.policyId !==
        requiredAdmissionRecord.policyId ||
      requiredAdmissionWitnessRecord.policyHash !==
        requiredAdmissionRecord.policyHash ||
      requiredAdmissionWitnessRecord.artifactHash !==
        requiredAdmissionRecord.artifact.artifactHash
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_admission_record_mismatch",
        path: "/requiredAdmissionRecord",
        message:
          "Pruning-policy admission witness record does not match the required admitted policy, sequence, policy hash, and artifact hash.",
        expected: requiredAdmissionRecord.policyRecordHash,
        actual: requiredAdmissionWitnessRecord.policyRecordHash,
      });
    }
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    policyAdmissionWitnessStoreId: input.policyAdmissionWitnessStoreId,
    policyStoreId: input.policyStoreId,
    authorityScope: input.authorityScope,
    witnessedRecordCount: input.records.length,
    ...(latestWitnessRecord !== undefined ? { latestWitnessRecord } : {}),
    ...(requiredAdmissionRecord !== undefined ? { requiredAdmissionRecord } : {}),
    ...(requiredAdmissionWitnessRecord !== undefined
      ? { requiredAdmissionWitnessRecord }
      : {}),
    ...(witnessAuthorityTopology !== undefined
      ? { witnessAuthorityTopology }
      : {}),
    ...(witnessAuthorityTransitionAdmissionReplay !== undefined
      ? { witnessAuthorityTransitionAdmissionReplay }
      : {}),
    issues,
  };
}

export function evaluateOperationalStatePruningPolicyAdmission(
  input: OperationalStatePruningPolicyAdmissionEvaluationInput,
): OperationalStatePruningPolicyAdmissionEvaluation {
  const issues: OperationalStatePruningPolicyIssue[] = [];

  if (input.compilation === undefined) {
    pushOperationalStatePruningPolicyIssue(issues, {
      code: "operational_state_pruning_policy_admission_required_policy_missing",
      path: "/pruningPolicy",
      message:
        "Operational state cannot prove pruning-policy admission without a compiled policy artifact.",
    });
    return {
      valid: false,
      accepted: false,
      ...(input.admissionReplay !== undefined
        ? { admissionReplay: input.admissionReplay }
        : {}),
      ...(input.admissionWitnessReplay !== undefined
        ? { admissionWitnessReplay: input.admissionWitnessReplay }
        : {}),
      issues,
    };
  }

  if (input.admissionReplay === undefined) {
    pushOperationalStatePruningPolicyIssue(issues, {
      code: "operational_state_pruning_policy_admission_replay_missing",
      path: "/pruningPolicyAdmission",
      message:
        "Compiled pruning policy cannot authorize operational recovery without replay of durable policy-admission records.",
    });
    return {
      valid: false,
      accepted: false,
      policyId: input.compilation.policyId,
      policyHash: input.compilation.policyHash,
      ...(input.admissionWitnessReplay !== undefined
        ? { admissionWitnessReplay: input.admissionWitnessReplay }
        : {}),
      issues,
    };
  }

  if (!input.admissionReplay.valid) {
    pushOperationalStatePruningPolicyIssue(issues, {
      code: "operational_state_pruning_policy_admission_replay_invalid",
      path: "/pruningPolicyAdmission",
      message:
        "Compiled pruning policy has an invalid policy-admission replay.",
      actual: input.admissionReplay.issues
        .map((issue) => issue.code)
        .join(","),
    });
  }

  const latestAdmittedRecord = input.admissionReplay.latestAdmittedRecord;
  if (latestAdmittedRecord === undefined) {
    pushOperationalStatePruningPolicyIssue(issues, {
      code: "operational_state_pruning_policy_admission_policy_not_admitted",
      path: "/pruningPolicyAdmission/records",
      message:
        "Compiled pruning policy is not present in the latest replayed policy-admission history.",
    });
  } else if (latestAdmittedRecord.policyHash !== input.compilation.policyHash) {
    pushOperationalStatePruningPolicyIssue(issues, {
      code: "operational_state_pruning_policy_admission_policy_stale",
      path: "/pruningPolicy/policyHash",
      message:
        "Compiled pruning policy is stale relative to the latest admitted policy artifact.",
      expected: latestAdmittedRecord.policyHash,
      actual: input.compilation.policyHash,
    });
  }

  if (
    latestAdmittedRecord !== undefined &&
    latestAdmittedRecord.policyId !== input.compilation.policyId
  ) {
    pushOperationalStatePruningPolicyIssue(issues, {
      code: "operational_state_pruning_policy_admission_policy_not_admitted",
      path: "/pruningPolicy/policyId",
      message:
        "Compiled pruning policy id does not match the latest admitted policy artifact.",
      expected: latestAdmittedRecord.policyId,
      actual: input.compilation.policyId,
    });
  }

  const admissionWitnessReplay = input.admissionWitnessReplay;
  const latestWitnessRecord =
    admissionWitnessReplay?.requiredAdmissionWitnessRecord;
  if (
    input.requireAdmissionWitnessQuorum === true ||
    input.requireAdmissionWitnessAuthorityTopology === true ||
    input.requireAdmissionWitnessAuthorityTransitionAdmission === true ||
    input.requireAdmissionWitnessAuthorityTransitionAdmissionWitness === true ||
    input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
      true ||
    input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
      true
  ) {
    if (admissionWitnessReplay === undefined) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_replay_missing",
        path: "/pruningPolicyAdmissionWitness",
        message:
          "Compiled pruning policy requires replay of witness-certified policy-admission records.",
      });
    } else if (!admissionWitnessReplay.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_replay_invalid",
        path: "/pruningPolicyAdmissionWitness",
        message:
          "Compiled pruning policy has an invalid policy-admission witness replay.",
        actual: admissionWitnessReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      latestAdmittedRecord === undefined ||
      latestWitnessRecord === undefined ||
      latestWitnessRecord.policyRecordHash !==
        latestAdmittedRecord.policyRecordHash
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_latest_record_not_witnessed",
        path: "/pruningPolicyAdmissionWitness",
        message:
          "Latest pruning-policy admission record is not witnessed by the replayed policy-admission witness quorum.",
        expected: latestAdmittedRecord?.policyRecordHash ?? "none",
        actual: latestWitnessRecord?.policyRecordHash ?? "none",
      });
    }
  }
  if (
    (input.requireAdmissionWitnessAuthorityTopology === true ||
      input.requireAdmissionWitnessAuthorityTransitionAdmission === true ||
      input.requireAdmissionWitnessAuthorityTransitionAdmissionWitness ===
        true ||
      input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    admissionWitnessReplay !== undefined &&
    admissionWitnessReplay.witnessAuthorityTopology === undefined
  ) {
    pushOperationalStatePruningPolicyIssue(issues, {
      code: "operational_state_pruning_policy_admission_witness_authority_topology_missing",
      path: "/pruningPolicyAdmissionWitness/witnessAuthorityTopology",
      message:
        "Compiled pruning policy requires policy-admission witness replay to bind certificates to replayed witness authority topology.",
    });
  }
  if (
    (input.requireAdmissionWitnessAuthorityTransitionAdmission === true ||
      input.requireAdmissionWitnessAuthorityTransitionAdmissionWitness ===
        true ||
      input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    admissionWitnessReplay !== undefined &&
    admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay ===
      undefined
  ) {
    pushOperationalStatePruningPolicyIssue(issues, {
      code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_replay_missing",
      path: "/pruningPolicyAdmissionWitness/witnessAuthorityTransitionAdmissionReplay",
      message:
        "Compiled pruning policy requires policy-admission witness authority topology to come from admitted authority-transition history.",
    });
  }
  if (
    (input.requireAdmissionWitnessAuthorityTransitionAdmissionWitness === true ||
      input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    admissionWitnessReplay !== undefined &&
    admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
      undefined
  ) {
    const admissionTransitionWitnessReplay =
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .admissionWitnessReplay;
    if (admissionTransitionWitnessReplay === undefined) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_replay_missing",
        path: "/pruningPolicyAdmissionWitness/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
        message:
          "Compiled pruning policy requires policy-admission witness authority-transition admission records to be witnessed.",
      });
    } else if (!admissionTransitionWitnessReplay.valid) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_replay_invalid",
        path: "/pruningPolicyAdmissionWitness/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
        message:
          "Compiled pruning policy cannot consume invalid policy-admission witness authority-transition admission witness history.",
        actual: admissionTransitionWitnessReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      (input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
        input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
          true) &&
      admissionTransitionWitnessReplay.witnessAuthorityTopology === undefined
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_topology_missing",
        path: "/pruningPolicyAdmissionWitness/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTopology",
        message:
          "Compiled pruning policy requires policy-admission witness authority-transition admission witness certificates to bind to replayed witness authority topology.",
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay ===
        undefined
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        path: "/pruningPolicyAdmissionWitness/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Compiled pruning policy requires policy-admission witness authority-transition admission witness authority topology to replay from admitted authority-transition history.",
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      !admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .valid
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        path: "/pruningPolicyAdmissionWitness/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Compiled pruning policy cannot consume invalid nested policy-admission witness authority-transition admission witness authority history.",
        actual:
          admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.issues
            .map((issue) => issue.code)
            .join(","),
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      admissionTransitionWitnessReplay.witnessAuthorityTopology !== undefined &&
      admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      (admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .latestAdmittedTopology === undefined ||
        !operationalStateAuthorityTopologiesMatch(
          admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology,
          admissionTransitionWitnessReplay.witnessAuthorityTopology,
        ))
    ) {
      pushOperationalStatePruningPolicyIssue(issues, {
        code: "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/pruningPolicyAdmissionWitness/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Compiled pruning policy requires policy-admission witness authority-transition admission witness authority topology to be recovered from admitted authority-transition history.",
        expected:
          admissionTransitionWitnessReplay.witnessAuthorityTopology.topologyHash,
        actual:
          admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology?.topologyHash ?? "none",
      });
    }
  }

  return {
    valid: issues.length === 0,
    accepted: issues.length === 0,
    policyId: input.compilation.policyId,
    policyHash: input.compilation.policyHash,
    admissionReplay: input.admissionReplay,
    ...(admissionWitnessReplay !== undefined ? { admissionWitnessReplay } : {}),
    ...(latestAdmittedRecord !== undefined ? { latestAdmittedRecord } : {}),
    ...(latestWitnessRecord !== undefined ? { latestWitnessRecord } : {}),
    issues,
  };
}

const postgresIdentifierPattern = /^[a-z_][a-z0-9_]*$/;

function operationalStateStorageMutationGuardIdentifierIssue(
  field: string,
  value: string,
): OperationalStateStorageMutationGuardIssue | undefined {
  if (postgresIdentifierPattern.test(value)) return undefined;
  return {
    code: "operational_state_storage_mutation_guard_identifier_invalid",
    path: `/${field}`,
    message: `Operational state storage mutation guard ${field} must be a safe PostgreSQL identifier.`,
    actual: value,
  };
}

function quotePostgresIdentifier(identifier: string): string {
  return `"${identifier.replace(/"/g, '""')}"`;
}

function quotePostgresLiteral(value: string): string {
  return `'${value.replace(/'/g, "''")}'`;
}

function uniqueStorageMutationOperations(
  operations: readonly OperationalStateStorageMutationOperation[],
): readonly OperationalStateStorageMutationOperation[] {
  const unique = new Set<OperationalStateStorageMutationOperation>();
  operations.forEach((operation) => unique.add(operation));
  return [...unique].sort();
}

export function computeOperationalStateStorageMutationGuardHash(
  guard: Omit<
    OperationalStateStorageMutationGuardCompilation,
    "valid" | "guardHash" | "triggerName" | "sql" | "issues"
  >,
): string {
  return fingerprint64(canonicalStringify(guard));
}

export function compileOperationalStateStorageMutationGuard(
  spec: OperationalStateStorageMutationGuardSpec,
): OperationalStateStorageMutationGuardCompilation {
  const issues: OperationalStateStorageMutationGuardIssue[] = [];
  const operations = uniqueStorageMutationOperations(spec.operations);
  const authorizationSettingName =
    spec.authorizationSettingName ??
    "pm_substrate.storage_mutation_authorization_hash";

  const identifierFields: readonly (readonly [string, string])[] = [
    ["protectedSchema", spec.protectedSchema],
    ["protectedTable", spec.protectedTable],
    ["tenantColumn", spec.tenantColumn],
    ["sequenceColumn", spec.sequenceColumn],
  ];
  identifierFields.forEach(([field, value]) => {
    const issue = operationalStateStorageMutationGuardIdentifierIssue(
      field,
      value,
    );
    if (issue !== undefined) issues.push(issue);
  });

  if (operations.length === 0) {
    issues.push({
      code: "operational_state_storage_mutation_guard_operation_missing",
      path: "/operations",
      message:
        "Operational state storage mutation guard must cover at least one mutation operation.",
    });
  }
  if (operations.length !== spec.operations.length) {
    issues.push({
      code: "operational_state_storage_mutation_guard_operation_duplicate",
      path: "/operations",
      message:
        "Operational state storage mutation guard operations must not be duplicated.",
    });
  }

  const payload: Omit<
    OperationalStateStorageMutationGuardCompilation,
    "valid" | "guardHash" | "triggerName" | "sql" | "issues"
  > = {
    guardId: spec.guardId,
    protectedSchema: spec.protectedSchema,
    protectedTable: spec.protectedTable,
    tenantColumn: spec.tenantColumn,
    sequenceColumn: spec.sequenceColumn,
    operations,
    authorizationSettingName,
  };
  const guardHash = computeOperationalStateStorageMutationGuardHash(payload);
  const triggerName = `storage_mutation_guard_${guardHash.slice(0, 16)}`;
  const triggerOperations = operations.join(" OR ");
  const sql =
    issues.length === 0
      ? [
          `DROP TRIGGER IF EXISTS ${quotePostgresIdentifier(triggerName)} ON ${quotePostgresIdentifier(spec.protectedSchema)}.${quotePostgresIdentifier(spec.protectedTable)};`,
          `CREATE TRIGGER ${quotePostgresIdentifier(triggerName)}`,
          `  BEFORE ${triggerOperations} ON ${quotePostgresIdentifier(spec.protectedSchema)}.${quotePostgresIdentifier(spec.protectedTable)}`,
          "  FOR EACH ROW",
          "  EXECUTE FUNCTION agent_state.enforce_storage_mutation_guard(",
          `    ${quotePostgresLiteral(spec.guardId)},`,
          `    ${quotePostgresLiteral(spec.tenantColumn)},`,
          `    ${quotePostgresLiteral(spec.sequenceColumn)},`,
          `    ${quotePostgresLiteral(authorizationSettingName)}`,
          "  );",
        ].join("\n")
      : "";

  return {
    ...payload,
    valid: issues.length === 0,
    guardHash,
    triggerName,
    sql,
    issues,
  };
}

