export function replayOperationalStateStorageMutationGuardAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitnessRecords(
  input: OperationalStateStorageMutationGuardAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitnessReplayInput,
): OperationalStateStorageMutationGuardAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitnessReplay {
  const issues: OperationalStateStorageMutationGuardIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const witnessHashBySequence = new Map<number, string>();
  const witnessRecordByAdmissionHash = new Map<
    string,
    OperationalStateStorageMutationGuardAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitnessRecord
  >();
  const witnessAuthorityTopology = input.witnessAuthorityTopology;
  const witnessAuthorityTransitionAdmissionReplay =
    input.witnessAuthorityTransitionAdmissionReplay;
  const principalById = new Map<string, OperationalStateAuthorityPrincipalState>(
    witnessAuthorityTopology?.principals.map((principal) => [
      principal.principalId,
      principal,
    ]) ?? [],
  );
  let expectedSequence = 1;
  let previousWitnessRecordHash: string | undefined;
  let latestWitnessRecord:
    | OperationalStateStorageMutationGuardAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitnessRecord
    | undefined;

  if (input.admissionReplay !== undefined && !input.admissionReplay.valid) {
    pushOperationalStateStorageMutationGuardIssue(issues, {
      code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_admission_replay_invalid",
      path: "/admissionReplay",
      message:
        "Storage mutation guard admission witness authority-transition admission witness replay cannot account for invalid transition-admission history.",
      actual: input.admissionReplay.issues
        .map((issue) => issue.code)
        .join(","),
    });
  }

  if (
    (input.requireWitnessAuthorityTopology === true ||
      input.requireWitnessAuthorityTransitionAdmission === true) &&
    witnessAuthorityTopology === undefined
  ) {
    pushOperationalStateStorageMutationGuardIssue(issues, {
      code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_topology_missing",
      path: "/witnessAuthorityTopology",
      message:
        "Storage mutation guard admission witness authority-transition admission witness replay requires a replayed witness authority topology.",
    });
  }

  if (witnessAuthorityTopology !== undefined) {
    const topologyHashValidation =
      verifyOperationalStateAuthorityTopologyHash(witnessAuthorityTopology);
    if (!topologyHashValidation.valid) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_topology_hash_mismatch",
        path: "/witnessAuthorityTopology/topologyHash",
        message: `Storage mutation guard admission witness authority-transition admission witness authority topology hash ${topologyHashValidation.actualHash} does not match recomputed hash ${topologyHashValidation.expectedHash}.`,
        expected: topologyHashValidation.expectedHash,
        actual: topologyHashValidation.actualHash,
      });
    }
    if (witnessAuthorityTopology.tenantId !== expectedTenantId) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_topology_tenant_mismatch",
        path: "/witnessAuthorityTopology/tenantId",
        message:
          "Storage mutation guard admission witness authority-transition admission witness authority topology tenant does not match replay tenant.",
        expected: expectedTenantId,
        actual: witnessAuthorityTopology.tenantId,
      });
    }
    if (witnessAuthorityTopology.authorityScope !== input.authorityScope) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_topology_scope_mismatch",
        path: "/witnessAuthorityTopology/authorityScope",
        message:
          "Storage mutation guard admission witness authority-transition admission witness authority topology scope does not match replay scope.",
        expected: input.authorityScope,
        actual: witnessAuthorityTopology.authorityScope,
      });
    }
    if (
      witnessAuthorityTopology.requiredWitnesses === undefined ||
      witnessAuthorityTopology.minimumWitnesses === undefined
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_quorum_missing",
        path: "/witnessAuthorityTopology/requiredWitnesses",
        message:
          "Storage mutation guard admission witness authority-transition admission witness authority topology must define quorum thresholds.",
      });
    }
  }

  if (input.requireWitnessAuthorityTransitionAdmission === true) {
    if (witnessAuthorityTransitionAdmissionReplay === undefined) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Storage mutation guard admission witness authority-transition admission witness replay requires its witness authority topology to replay from admitted authority-transition history.",
      });
    } else if (!witnessAuthorityTransitionAdmissionReplay.valid) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        path: "/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Storage mutation guard admission witness authority-transition admission witness replay cannot consume invalid nested witness-authority transition admission history.",
        actual: witnessAuthorityTransitionAdmissionReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      witnessAuthorityTopology !== undefined &&
      (witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology ===
        undefined ||
        !operationalStateAuthorityTopologiesMatch(
          witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology,
          witnessAuthorityTopology,
        ))
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Storage mutation guard transition-admission witness authority topology must be recovered from admitted authority-transition history.",
        expected: witnessAuthorityTopology.topologyHash,
        actual:
          witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology
            ?.topologyHash ?? "none",
      });
    }
  }

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const witnessRecordHashValidation =
      verifyOperationalStateStorageMutationGuardAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitnessRecordHash(
        record,
      );
    const certificateHashValidation =
      verifyOperationalStateQuorumCertificateProofCertificateHash(
        record.admissionCertificate,
      );
    const previousWitnessHashAtSequence = witnessHashBySequence.get(
      record.witnessSequence,
    );

    if (
      previousWitnessHashAtSequence !== undefined &&
      previousWitnessHashAtSequence !== record.witnessRecordHash
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_record_fork",
        path: `${path}/witnessSequence`,
        message: `Storage mutation guard admission witness authority-transition admission witness sequence ${record.witnessSequence} has more than one witness record hash.`,
        expected: previousWitnessHashAtSequence,
        actual: record.witnessRecordHash,
      });
    } else if (previousWitnessHashAtSequence === undefined) {
      witnessHashBySequence.set(
        record.witnessSequence,
        record.witnessRecordHash,
      );
    }

    if (
      record.tenantId !== expectedTenantId ||
      record.admissionCertificate.tenantId !== expectedTenantId
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_record_tenant_mismatch",
        path,
        message:
          "Storage mutation guard admission witness authority-transition admission witness record and certificate must match the replay tenant.",
        expected: expectedTenantId,
      });
    }
    if (
      record.transitionAdmissionWitnessStoreId !==
        input.transitionAdmissionWitnessStoreId ||
      record.transitionAdmissionStoreId !== input.transitionAdmissionStoreId
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_record_store_mismatch",
        path,
        message:
          "Storage mutation guard admission witness authority-transition admission witness record must bind the expected witness and transition-admission stores.",
        expected: `${input.transitionAdmissionWitnessStoreId}:${input.transitionAdmissionStoreId}`,
        actual: `${record.transitionAdmissionWitnessStoreId}:${record.transitionAdmissionStoreId}`,
      });
    }
    if (
      record.topologyId !== input.topologyId ||
      record.authorityScope !== input.authorityScope ||
      record.admissionCertificate.authorityScope !== input.authorityScope
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_record_scope_mismatch",
        path,
        message:
          "Storage mutation guard admission witness authority-transition admission witness record must share the replay topology and authority scope.",
        expected: `${input.topologyId}:${input.authorityScope}`,
      });
    }
    if (record.witnessSequence !== expectedSequence) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_record_sequence_gap",
        path: `${path}/witnessSequence`,
        message:
          "Storage mutation guard admission witness authority-transition admission witness records must replay as a contiguous witness sequence.",
        expected: expectedSequence,
        actual: record.witnessSequence,
      });
    }
    if (record.previousWitnessRecordHash !== previousWitnessRecordHash) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_record_previous_hash_mismatch",
        path: `${path}/previousWitnessRecordHash`,
        message:
          "Storage mutation guard admission witness authority-transition admission witness record does not chain to the previous witness record hash.",
        expected: previousWitnessRecordHash ?? "none",
        actual: record.previousWitnessRecordHash ?? "none",
      });
    }
    if (!certificateHashValidation.valid) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_certificate_hash_mismatch",
        path: `${path}/admissionCertificate/quorumCertificateHash`,
        message: `Storage mutation guard admission witness authority-transition admission witness certificate hash ${certificateHashValidation.actualHash} does not match recomputed hash ${certificateHashValidation.expectedHash}.`,
        expected: certificateHashValidation.expectedHash,
        actual: certificateHashValidation.actualHash,
      });
    }
    if (
      !record.admissionCertificate.certified ||
      record.admissionCertificate.status !== "certified"
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_certificate_not_certified",
        path: `${path}/admissionCertificate/status`,
        message:
          "Storage mutation guard admission witness authority-transition admission cannot become accountable through a non-certified witness certificate.",
        expected: "certified",
        actual: record.admissionCertificate.status,
      });
    }
    if (
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.minimumWitnesses ||
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.requiredWitnesses
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_certificate_quorum_not_met",
        path: `${path}/admissionCertificate/acceptedWitnessIds`,
        message:
          "Storage mutation guard admission witness authority-transition admission witness certificate does not satisfy its declared witness quorum.",
        expected: Math.max(
          record.admissionCertificate.requiredWitnesses,
          record.admissionCertificate.minimumWitnesses,
        ),
        actual: record.admissionCertificate.acceptedWitnessIds.length,
      });
    }
    if (
      record.admissionCertificate.subjectKind !==
        OPERATIONAL_STATE_STORAGE_MUTATION_GUARD_AUTHORIZATION_ADMISSION_WITNESS_AUTHORITY_TRANSITION_ADMISSION_RECORD_SUBJECT_KIND ||
      record.admissionCertificate.subjectId !==
        `${record.transitionAdmissionStoreId}:${record.topologyId}` ||
      record.admissionCertificate.subjectSequence !==
        record.admissionSequence ||
      record.admissionCertificate.subjectHash !== record.admissionRecordHash
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_certificate_subject_mismatch",
        path: `${path}/admissionCertificate`,
        message:
          "Storage mutation guard admission witness authority-transition admission witness certificate must certify the exact transition-admission store, topology id, admission sequence, and admission record hash.",
        expected: record.admissionRecordHash,
        actual: record.admissionCertificate.subjectHash,
      });
    }
    if (
      input.requiredAuthorityBoundary !== undefined &&
      record.admissionCertificate.authorityBoundary !==
        input.requiredAuthorityBoundary
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_certificate_authority_boundary_mismatch",
        path: `${path}/admissionCertificate/authorityBoundary`,
        message:
          "Storage mutation guard admission witness authority-transition admission witness certificate was admitted under the wrong authority boundary.",
        expected: input.requiredAuthorityBoundary,
        actual: record.admissionCertificate.authorityBoundary,
      });
    }
    if (witnessAuthorityTopology !== undefined) {
      if (
        record.admissionCertificate.authorityTopologyHash !==
        witnessAuthorityTopology.topologyHash
      ) {
        pushOperationalStateStorageMutationGuardIssue(issues, {
          code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_certificate_authority_topology_mismatch",
          path: `${path}/admissionCertificate/authorityTopologyHash`,
          message:
            "Storage mutation guard admission witness authority-transition admission witness certificate is not bound to the replayed witness authority topology.",
          expected: witnessAuthorityTopology.topologyHash,
          actual:
            record.admissionCertificate.authorityTopologyHash ?? "none",
        });
      }

      const acceptedWitnessIds =
        record.admissionCertificate.acceptedWitnessIds;
      const uniqueAcceptedWitnessIds = new Set(acceptedWitnessIds);
      if (uniqueAcceptedWitnessIds.size !== acceptedWitnessIds.length) {
        pushOperationalStateStorageMutationGuardIssue(issues, {
          code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_duplicate_witness",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Storage mutation guard admission witness authority-transition admission witness authority quorum cannot be satisfied by duplicate witness ids.",
          expected: uniqueAcceptedWitnessIds.size,
          actual: acceptedWitnessIds.length,
        });
      }

      let activeAuthorizedWitnessCount = 0;
      for (const witnessId of uniqueAcceptedWitnessIds) {
        const principal = principalById.get(witnessId);
        if (principal === undefined) {
          pushOperationalStateStorageMutationGuardIssue(issues, {
            code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_witness_unknown",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Storage mutation guard admission witness authority-transition admission witness certificate names a witness outside the replayed authority topology.",
            expected: witnessAuthorityTopology.topologyHash,
            actual: witnessId,
          });
          continue;
        }
        if (principal.status !== "active") {
          pushOperationalStateStorageMutationGuardIssue(issues, {
            code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_witness_not_active",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Storage mutation guard admission witness authority-transition admission witness certificate names a witness that is not active in the replayed authority topology.",
            expected: "active",
            actual: `${witnessId}:${principal.status}`,
          });
          continue;
        }
        activeAuthorizedWitnessCount += 1;
      }

      const requiredAuthorizedWitnesses = Math.max(
        witnessAuthorityTopology.requiredWitnesses ?? 0,
        witnessAuthorityTopology.minimumWitnesses ?? 0,
      );
      if (activeAuthorizedWitnessCount < requiredAuthorizedWitnesses) {
        pushOperationalStateStorageMutationGuardIssue(issues, {
          code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_quorum_not_met",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Storage mutation guard admission witness authority-transition admission witness certificate does not satisfy the replayed witness authority topology quorum.",
          expected: requiredAuthorizedWitnesses,
          actual: activeAuthorizedWitnessCount,
        });
      }
    }
    if (!witnessRecordHashValidation.valid) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_record_hash_mismatch",
        path: `${path}/witnessRecordHash`,
        message: `Storage mutation guard admission witness authority-transition admission witness record hash ${witnessRecordHashValidation.actualHash} does not match recomputed hash ${witnessRecordHashValidation.expectedHash}.`,
        expected: witnessRecordHashValidation.expectedHash,
        actual: witnessRecordHashValidation.actualHash,
      });
    }

    witnessRecordByAdmissionHash.set(record.admissionRecordHash, record);
    expectedSequence = record.witnessSequence + 1;
    previousWitnessRecordHash = record.witnessRecordHash;
    latestWitnessRecord = record;
  });

  const requiredAdmissionRecord =
    input.requiredAdmissionRecord ?? input.admissionReplay?.latestAdmittedRecord;
  let requiredAdmissionWitnessRecord:
    | OperationalStateStorageMutationGuardAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitnessRecord
    | undefined;
  if (requiredAdmissionRecord !== undefined) {
    const admissionRecordHashValidation =
      verifyOperationalStateStorageMutationGuardAuthorizationAdmissionWitnessAuthorityTransitionAdmissionRecordHash(
        requiredAdmissionRecord,
      );
    if (!admissionRecordHashValidation.valid) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_record_hash_mismatch",
        path: "/requiredAdmissionRecord/admissionRecordHash",
        message: `Required storage mutation guard admission witness authority-transition admission hash ${admissionRecordHashValidation.actualHash} does not match recomputed hash ${admissionRecordHashValidation.expectedHash}.`,
        expected: admissionRecordHashValidation.expectedHash,
        actual: admissionRecordHashValidation.actualHash,
      });
    }
    requiredAdmissionWitnessRecord = witnessRecordByAdmissionHash.get(
      requiredAdmissionRecord.admissionRecordHash,
    );
    if (requiredAdmissionWitnessRecord === undefined) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_latest_record_not_witnessed",
        path: "/requiredAdmissionRecord/admissionRecordHash",
        message:
          "Latest storage mutation guard admission witness authority-transition admission record has no replayed witness certificate.",
        expected: requiredAdmissionRecord.admissionRecordHash,
      });
    } else if (
      requiredAdmissionWitnessRecord.transitionAdmissionStoreId !==
        requiredAdmissionRecord.transitionAdmissionStoreId ||
      requiredAdmissionWitnessRecord.topologyId !==
        requiredAdmissionRecord.topologyId ||
      requiredAdmissionWitnessRecord.admissionSequence !==
        requiredAdmissionRecord.admissionSequence ||
      requiredAdmissionWitnessRecord.authoritySequence !==
        requiredAdmissionRecord.authoritySequence ||
      requiredAdmissionWitnessRecord.authorityRecordHash !==
        requiredAdmissionRecord.authorityRecordHash ||
      requiredAdmissionWitnessRecord.nextAuthorityTopologyHash !==
        requiredAdmissionRecord.nextAuthorityTopologyHash
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_admission_record_mismatch",
        path: "/requiredAdmissionRecord",
        message:
          "Storage mutation guard admission witness authority-transition admission witness record does not match the required admission store, topology, sequence, authority transition hash, and derived topology hash.",
        expected: requiredAdmissionRecord.admissionRecordHash,
        actual: requiredAdmissionWitnessRecord.admissionRecordHash,
      });
    }
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    transitionAdmissionWitnessStoreId:
      input.transitionAdmissionWitnessStoreId,
    transitionAdmissionStoreId: input.transitionAdmissionStoreId,
    topologyId: input.topologyId,
    authorityScope: input.authorityScope,
    witnessedRecordCount: input.records.length,
    ...(latestWitnessRecord !== undefined ? { latestWitnessRecord } : {}),
    ...(requiredAdmissionRecord !== undefined ? { requiredAdmissionRecord } : {}),
    ...(requiredAdmissionWitnessRecord !== undefined
      ? { requiredAdmissionWitnessRecord }
      : {}),
    ...(witnessAuthorityTopology !== undefined
      ? { witnessAuthorityTopology }
      : {}),
    ...(witnessAuthorityTransitionAdmissionReplay !== undefined
      ? { witnessAuthorityTransitionAdmissionReplay }
      : {}),
    issues,
  };
}

function pushOperationalStateStorageMutationGuardIssue(
  issues: OperationalStateStorageMutationGuardIssue[],
  issue: OperationalStateStorageMutationGuardIssue,
): void {
  issues.push(issue);
}

export function replayOperationalStateStorageMutationGuardAuthorizationAdmissionWitnessAuthorityTransitionAdmissionRecords(
  input: OperationalStateStorageMutationGuardAuthorizationAdmissionWitnessAuthorityTransitionAdmissionReplayInput,
): OperationalStateStorageMutationGuardAuthorizationAdmissionWitnessAuthorityTransitionAdmissionReplay {
  const issues: OperationalStateStorageMutationGuardIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const admissionHashBySequence = new Map<number, string>();
  const admissionRecordByAuthorityHash = new Map<
    string,
    OperationalStateStorageMutationGuardAuthorizationAdmissionWitnessAuthorityTransitionAdmissionRecord
  >();
  const admissionWitnessReplay = input.admissionWitnessReplay;
  let expectedAdmissionSequence = 1;
  let expectedAuthoritySequence = 1;
  let previousAdmissionRecordHash: string | undefined;
  let previousAuthorityRecordHash: string | undefined;
  let previousTopology: OperationalStateAuthorityTopology | undefined;
  let latestAdmittedRecord:
    | OperationalStateStorageMutationGuardAuthorizationAdmissionWitnessAuthorityTransitionAdmissionRecord
    | undefined;
  let latestAdmittedTopology: OperationalStateAuthorityTopology | undefined;

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const recordHashValidation =
      verifyOperationalStateStorageMutationGuardAuthorizationAdmissionWitnessAuthorityTransitionAdmissionRecordHash(
        record,
      );
    const transitionHashValidation =
      verifyOperationalStateAuthorityTransitionRecordHash(
        record.authorityTransition,
      );
    const certificateHashValidation =
      verifyOperationalStateQuorumCertificateProofCertificateHash(
        record.admissionCertificate,
      );
    const previousAdmissionHashAtSequence = admissionHashBySequence.get(
      record.admissionSequence,
    );

    if (
      previousAdmissionHashAtSequence !== undefined &&
      previousAdmissionHashAtSequence !== record.admissionRecordHash
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_record_sequence_gap",
        path: `${path}/admissionSequence`,
        message: `Storage mutation guard admission witness authority-transition admission sequence ${record.admissionSequence} has more than one record hash.`,
        expected: previousAdmissionHashAtSequence,
        actual: record.admissionRecordHash,
      });
    } else if (previousAdmissionHashAtSequence === undefined) {
      admissionHashBySequence.set(
        record.admissionSequence,
        record.admissionRecordHash,
      );
    }

    if (
      record.tenantId !== expectedTenantId ||
      record.authorityTransition.tenantId !== expectedTenantId ||
      record.admissionCertificate.tenantId !== expectedTenantId
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_record_tenant_mismatch",
        path,
        message:
          "Storage mutation guard admission witness authority-transition admission record, transition, and certificate must match the replay tenant.",
        expected: expectedTenantId,
      });
    }
    if (record.transitionAdmissionStoreId !== input.transitionAdmissionStoreId) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_record_store_mismatch",
        path: `${path}/transitionAdmissionStoreId`,
        message:
          "Storage mutation guard admission witness authority-transition admission record belongs to a different admission store.",
        expected: input.transitionAdmissionStoreId,
        actual: record.transitionAdmissionStoreId,
      });
    }
    if (
      record.topologyId !== input.topologyId ||
      record.authorityTransition.topologyId !== input.topologyId
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_record_scope_mismatch",
        path: `${path}/topologyId`,
        message:
          "Storage mutation guard admission witness authority-transition admission record must match the replay topology id.",
        expected: input.topologyId,
        actual: record.topologyId,
      });
    }
    if (
      record.authorityScope !== input.authorityScope ||
      record.authorityTransition.authorityScope !== input.authorityScope ||
      record.admissionCertificate.authorityScope !== input.authorityScope
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_record_scope_mismatch",
        path,
        message:
          "Storage mutation guard admission witness authority-transition admission record, transition, and certificate must share the replay authority scope.",
        expected: input.authorityScope,
      });
    }
    if (record.admissionSequence !== expectedAdmissionSequence) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_record_sequence_gap",
        path: `${path}/admissionSequence`,
        message:
          "Storage mutation guard admission witness authority-transition admissions must replay as a contiguous admission sequence.",
        expected: expectedAdmissionSequence,
        actual: record.admissionSequence,
      });
    }
    if (record.previousAdmissionRecordHash !== previousAdmissionRecordHash) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_record_previous_hash_mismatch",
        path: `${path}/previousAdmissionRecordHash`,
        message:
          "Storage mutation guard admission witness authority-transition admission record does not chain to the previous admission record hash.",
        expected: previousAdmissionRecordHash ?? "none",
        actual: record.previousAdmissionRecordHash ?? "none",
      });
    }
    if (!recordHashValidation.valid) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_record_hash_mismatch",
        path: `${path}/admissionRecordHash`,
        message: `Storage mutation guard admission witness authority-transition admission record hash ${recordHashValidation.actualHash} does not match recomputed hash ${recordHashValidation.expectedHash}.`,
        expected: recordHashValidation.expectedHash,
        actual: recordHashValidation.actualHash,
      });
    }
    if (!transitionHashValidation.valid) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_transition_hash_mismatch",
        path: `${path}/authorityTransition/authorityRecordHash`,
        message: `Storage mutation guard admission witness authority transition hash ${transitionHashValidation.actualHash} does not match recomputed hash ${transitionHashValidation.expectedHash}.`,
        expected: transitionHashValidation.expectedHash,
        actual: transitionHashValidation.actualHash,
      });
    }
    if (
      record.authoritySequence !==
        record.authorityTransition.authoritySequence ||
      record.authorityRecordHash !==
        record.authorityTransition.authorityRecordHash ||
      record.previousAuthorityRecordHash !==
        record.authorityTransition.previousAuthorityRecordHash
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_transition_mismatch",
        path: `${path}/authorityTransition`,
        message:
          "Storage mutation guard admission witness authority-transition admission record does not match its embedded authority transition sequence and hash.",
        expected: record.authorityRecordHash,
        actual: record.authorityTransition.authorityRecordHash,
      });
    }
    if (record.authoritySequence !== expectedAuthoritySequence) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_transition_sequence_gap",
        path: `${path}/authoritySequence`,
        message:
          "Storage mutation guard admission witness authority transitions must be admitted in contiguous authority sequence.",
        expected: expectedAuthoritySequence,
        actual: record.authoritySequence,
      });
    }
    if (
      record.authorityTransition.previousAuthorityRecordHash !==
      previousAuthorityRecordHash
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_transition_previous_hash_mismatch",
        path: `${path}/authorityTransition/previousAuthorityRecordHash`,
        message:
          "Storage mutation guard admission witness authority transition must hash-chain from the previously admitted authority transition.",
        expected: previousAuthorityRecordHash ?? "none",
        actual:
          record.authorityTransition.previousAuthorityRecordHash ?? "none",
      });
    }
    if (record.authorityTransition.effectiveFromSubjectSequence < 1) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_transition_invalid",
        path: `${path}/authorityTransition/effectiveFromSubjectSequence`,
        message:
          "Storage mutation guard admission witness authority transitions must declare a positive effective admission sequence.",
        actual: record.authorityTransition.effectiveFromSubjectSequence,
      });
    }
    if (
      record.authorityTransition.transitionKind === "set_quorum" &&
      ((record.authorityTransition.requiredWitnesses ?? 0) < 1 ||
        (record.authorityTransition.minimumWitnesses ??
          record.authorityTransition.requiredWitnesses ??
          0) < 1 ||
        (record.authorityTransition.minimumWitnesses ??
          record.authorityTransition.requiredWitnesses ??
          0) > (record.authorityTransition.requiredWitnesses ?? 0))
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_transition_invalid",
        path: `${path}/authorityTransition/requiredWitnesses`,
        message:
          "Storage mutation guard admission witness authority quorum transitions must declare positive and internally consistent witness thresholds.",
      });
    }
    if (
      [
        "admit_principal",
        "suspend_principal",
        "revoke_principal",
        "rotate_signature_key",
        "mark_equivocated",
      ].includes(record.authorityTransition.transitionKind) &&
      (record.authorityTransition.principalId === undefined ||
        record.authorityTransition.principalId.length === 0)
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_transition_invalid",
        path: `${path}/authorityTransition/principalId`,
        message:
          "Storage mutation guard admission witness authority principal transitions must identify the affected principal.",
      });
    }
    if (
      record.authorityTransition.transitionKind === "seal_authority_epoch" &&
      ((record.authorityTransition.sealedThroughSubjectSequence ?? 0) < 1 ||
        record.authorityTransition.sealedQuorumCertificateHash === undefined ||
        record.authorityTransition.sealedQuorumCertificateHash.length === 0)
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_transition_invalid",
        path: `${path}/authorityTransition/sealedQuorumCertificateHash`,
        message:
          "Storage mutation guard admission witness authority epoch seals must bind a positive sealed frontier and a quorum certificate hash.",
      });
    }

    const nextTopology = operationalStateAuthorityTopologyFromTransition(
      record.authorityTransition,
      previousTopology,
    );
    if (record.nextAuthorityTopologyHash !== nextTopology.topologyHash) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_transition_topology_hash_mismatch",
        path: `${path}/nextAuthorityTopologyHash`,
        message:
          "Storage mutation guard admission witness authority-transition admission record does not derive the expected next topology hash.",
        expected: nextTopology.topologyHash,
        actual: record.nextAuthorityTopologyHash,
      });
    }
    if (previousTopology === undefined) {
      if (record.previousAuthorityTopologyHash !== undefined) {
        pushOperationalStateStorageMutationGuardIssue(issues, {
          code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_transition_previous_topology_hash_mismatch",
          path: `${path}/previousAuthorityTopologyHash`,
          message:
            "Genesis storage mutation guard admission witness authority transition cannot cite a previous topology hash.",
          actual: record.previousAuthorityTopologyHash,
        });
      }
    } else {
      if (
        record.previousAuthorityTopologyHash !== previousTopology.topologyHash
      ) {
        pushOperationalStateStorageMutationGuardIssue(issues, {
          code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_transition_previous_topology_hash_mismatch",
          path: `${path}/previousAuthorityTopologyHash`,
          message:
            "Storage mutation guard admission witness authority transition admission must bind the previous replayed topology hash.",
          expected: previousTopology.topologyHash,
          actual: record.previousAuthorityTopologyHash ?? "none",
        });
      }
      if (
        record.admissionCertificate.authorityTopologyHash !==
        previousTopology.topologyHash
      ) {
        pushOperationalStateStorageMutationGuardIssue(issues, {
          code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_certificate_authority_topology_mismatch",
          path: `${path}/admissionCertificate/authorityTopologyHash`,
          message:
            "Storage mutation guard admission witness authority transition admission certificate must be bound to the previous replayed topology.",
          expected: previousTopology.topologyHash,
          actual:
            record.admissionCertificate.authorityTopologyHash ?? "none",
        });
      }

      const principalById = new Map<
        string,
        OperationalStateAuthorityPrincipalState
      >(
        previousTopology.principals.map((principal) => [
          principal.principalId,
          principal,
        ]),
      );
      const acceptedWitnessIds =
        record.admissionCertificate.acceptedWitnessIds;
      const uniqueAcceptedWitnessIds = new Set(acceptedWitnessIds);
      if (uniqueAcceptedWitnessIds.size !== acceptedWitnessIds.length) {
        pushOperationalStateStorageMutationGuardIssue(issues, {
          code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_authority_duplicate_witness",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Storage mutation guard admission witness authority-transition admission cannot be certified by duplicate prior-topology witnesses.",
          expected: uniqueAcceptedWitnessIds.size,
          actual: acceptedWitnessIds.length,
        });
      }

      let activeAuthorizedWitnessCount = 0;
      for (const witnessId of uniqueAcceptedWitnessIds) {
        const principal = principalById.get(witnessId);
        if (principal === undefined) {
          pushOperationalStateStorageMutationGuardIssue(issues, {
            code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_authority_witness_unknown",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Storage mutation guard admission witness authority-transition admission certificate names a witness outside the previous replayed topology.",
            expected: previousTopology.topologyHash,
            actual: witnessId,
          });
          continue;
        }
        if (principal.status !== "active") {
          pushOperationalStateStorageMutationGuardIssue(issues, {
            code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_authority_witness_not_active",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Storage mutation guard admission witness authority-transition admission certificate names a witness that is not active in the previous replayed topology.",
            expected: "active",
            actual: `${witnessId}:${principal.status}`,
          });
          continue;
        }
        activeAuthorizedWitnessCount += 1;
      }

      const requiredAuthorizedWitnesses = Math.max(
        previousTopology.requiredWitnesses ?? 0,
        previousTopology.minimumWitnesses ?? 0,
      );
      if (activeAuthorizedWitnessCount < requiredAuthorizedWitnesses) {
        pushOperationalStateStorageMutationGuardIssue(issues, {
          code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_authority_quorum_not_met",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Storage mutation guard admission witness authority-transition admission certificate does not satisfy previous-topology quorum.",
          expected: requiredAuthorizedWitnesses,
          actual: activeAuthorizedWitnessCount,
        });
      }
    }

    if (!certificateHashValidation.valid) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_certificate_hash_mismatch",
        path: `${path}/admissionCertificate/quorumCertificateHash`,
        message: `Storage mutation guard admission witness authority-transition admission certificate hash ${certificateHashValidation.actualHash} does not match recomputed hash ${certificateHashValidation.expectedHash}.`,
        expected: certificateHashValidation.expectedHash,
        actual: certificateHashValidation.actualHash,
      });
    }
    if (
      !record.admissionCertificate.certified ||
      record.admissionCertificate.status !== "certified"
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_certificate_not_certified",
        path: `${path}/admissionCertificate/status`,
        message:
          "Storage mutation guard admission witness authority transition cannot become authority through a non-certified admission certificate.",
        expected: "certified",
        actual: record.admissionCertificate.status,
      });
    }
    if (
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.minimumWitnesses ||
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.requiredWitnesses
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_certificate_quorum_not_met",
        path: `${path}/admissionCertificate/acceptedWitnessIds`,
        message:
          "Storage mutation guard admission witness authority-transition admission certificate does not satisfy its declared witness quorum.",
        expected: Math.max(
          record.admissionCertificate.requiredWitnesses,
          record.admissionCertificate.minimumWitnesses,
        ),
        actual: record.admissionCertificate.acceptedWitnessIds.length,
      });
    }
    if (
      record.admissionCertificate.subjectKind !==
        OPERATIONAL_STATE_AUTHORITY_TRANSITION_RECORD_SUBJECT_KIND ||
      record.admissionCertificate.subjectId !== record.topologyId ||
      record.admissionCertificate.subjectSequence !==
        record.authoritySequence ||
      record.admissionCertificate.subjectHash !== record.authorityRecordHash
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_certificate_subject_mismatch",
        path: `${path}/admissionCertificate`,
        message:
          "Storage mutation guard admission witness authority-transition admission certificate must certify the exact topology id, authority sequence, and authority transition hash.",
        expected: record.authorityRecordHash,
        actual: record.admissionCertificate.subjectHash,
      });
    }
    if (
      input.requiredAuthorityBoundary !== undefined &&
      record.admissionCertificate.authorityBoundary !==
        input.requiredAuthorityBoundary
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_certificate_authority_boundary_mismatch",
        path: `${path}/admissionCertificate/authorityBoundary`,
        message:
          "Storage mutation guard admission witness authority-transition admission certificate was admitted under the wrong authority boundary.",
        expected: input.requiredAuthorityBoundary,
        actual: record.admissionCertificate.authorityBoundary,
      });
    }

    admissionRecordByAuthorityHash.set(record.authorityRecordHash, record);
    expectedAdmissionSequence = record.admissionSequence + 1;
    expectedAuthoritySequence = record.authoritySequence + 1;
    previousAdmissionRecordHash = record.admissionRecordHash;
    previousAuthorityRecordHash = record.authorityRecordHash;
    previousTopology = nextTopology;
    latestAdmittedTopology = nextTopology;
    latestAdmittedRecord = record;
  });

  let requiredAuthorityTransitionAdmissionRecord:
    | OperationalStateStorageMutationGuardAuthorizationAdmissionWitnessAuthorityTransitionAdmissionRecord
    | undefined;
  if (input.requiredAuthorityTransition !== undefined) {
    const requiredTransitionHashValidation =
      verifyOperationalStateAuthorityTransitionRecordHash(
        input.requiredAuthorityTransition,
      );
    if (!requiredTransitionHashValidation.valid) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_transition_hash_mismatch",
        path: "/requiredAuthorityTransition/authorityRecordHash",
        message: `Required storage mutation guard admission witness authority transition hash ${requiredTransitionHashValidation.actualHash} does not match recomputed hash ${requiredTransitionHashValidation.expectedHash}.`,
        expected: requiredTransitionHashValidation.expectedHash,
        actual: requiredTransitionHashValidation.actualHash,
      });
    }
    requiredAuthorityTransitionAdmissionRecord =
      admissionRecordByAuthorityHash.get(
        input.requiredAuthorityTransition.authorityRecordHash,
      );
    if (requiredAuthorityTransitionAdmissionRecord === undefined) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_not_admitted",
        path: "/requiredAuthorityTransition/authorityRecordHash",
        message:
          "Required storage mutation guard admission witness authority transition has no replayed admission certificate.",
        expected: input.requiredAuthorityTransition.authorityRecordHash,
      });
    }
  }

  if (input.requiredAuthorityTopology !== undefined) {
    const requiredTopologyHashValidation =
      verifyOperationalStateAuthorityTopologyHash(
        input.requiredAuthorityTopology,
      );
    if (!requiredTopologyHashValidation.valid) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_topology_hash_mismatch",
        path: "/requiredAuthorityTopology/topologyHash",
        message: `Required storage mutation guard admission witness authority topology hash ${requiredTopologyHashValidation.actualHash} does not match recomputed hash ${requiredTopologyHashValidation.expectedHash}.`,
        expected: requiredTopologyHashValidation.expectedHash,
        actual: requiredTopologyHashValidation.actualHash,
      });
    }
    if (
      latestAdmittedTopology === undefined ||
      !operationalStateAuthorityTopologiesMatch(
        latestAdmittedTopology,
        input.requiredAuthorityTopology,
      )
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/requiredAuthorityTopology",
        message:
          "Storage mutation guard admission witness authority-transition admission replay must recover the required authority topology.",
        expected: input.requiredAuthorityTopology.topologyHash,
        actual: latestAdmittedTopology?.topologyHash ?? "none",
      });
    }
    requiredAuthorityTransitionAdmissionRecord =
      admissionRecordByAuthorityHash.get(
        input.requiredAuthorityTopology.authorityRecordHash,
      );
    if (requiredAuthorityTransitionAdmissionRecord === undefined) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_not_admitted",
        path: "/requiredAuthorityTopology/authorityRecordHash",
        message:
          "Required storage mutation guard admission witness authority topology is not backed by an admitted authority transition.",
        expected: input.requiredAuthorityTopology.authorityRecordHash,
      });
    }
  }

  if (
    input.requireAdmissionWitness === true ||
    input.requireAdmissionWitnessAuthorityTopology === true ||
    input.requireAdmissionWitnessAuthorityTransitionAdmission === true
  ) {
    if (admissionWitnessReplay === undefined) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_replay_missing",
        path: "/admissionWitnessReplay",
        message:
          "Storage mutation guard admission witness authority-transition admission replay requires transition-admission records to be witnessed.",
      });
    } else if (!admissionWitnessReplay.valid) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_replay_invalid",
        path: "/admissionWitnessReplay",
        message:
          "Storage mutation guard admission witness authority-transition admission replay cannot consume invalid transition-admission witness history.",
        actual: admissionWitnessReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      latestAdmittedRecord === undefined ||
      admissionWitnessReplay.requiredAdmissionWitnessRecord === undefined ||
      admissionWitnessReplay.requiredAdmissionWitnessRecord
        .admissionRecordHash !== latestAdmittedRecord.admissionRecordHash
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_latest_record_not_witnessed",
        path: "/admissionWitnessReplay/requiredAdmissionWitnessRecord",
        message:
          "Latest storage mutation guard admission witness authority-transition admission record is not witnessed by the replayed transition-admission witness ledger.",
        expected: latestAdmittedRecord?.admissionRecordHash ?? "none",
        actual:
          admissionWitnessReplay.requiredAdmissionWitnessRecord
            ?.admissionRecordHash ?? "none",
      });
    } else if (
      (input.requireAdmissionWitnessAuthorityTopology === true ||
        input.requireAdmissionWitnessAuthorityTransitionAdmission === true) &&
      admissionWitnessReplay.witnessAuthorityTopology === undefined
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_topology_missing",
        path: "/admissionWitnessReplay/witnessAuthorityTopology",
        message:
          "Storage mutation guard admission witness authority-transition admission replay requires its witness history to bind certificates to replayed witness authority topology.",
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmission === true &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay ===
        undefined
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        path: "/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Storage mutation guard admission witness authority-transition admission replay requires its nested transition-admission witness authority topology to replay from admitted authority-transition history.",
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmission === true &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      !admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.valid
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        path: "/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Storage mutation guard admission witness authority-transition admission replay cannot consume invalid nested transition-admission witness authority history.",
        actual:
          admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.issues
            .map((issue) => issue.code)
            .join(","),
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmission === true &&
      admissionWitnessReplay.witnessAuthorityTopology !== undefined &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      (admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .latestAdmittedTopology === undefined ||
        !operationalStateAuthorityTopologiesMatch(
          admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology,
          admissionWitnessReplay.witnessAuthorityTopology,
        ))
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Storage mutation guard admission witness authority-transition admission replay requires the nested transition-admission witness authority topology to be recovered from admitted authority-transition history.",
        expected: admissionWitnessReplay.witnessAuthorityTopology.topologyHash,
        actual:
          admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology?.topologyHash ?? "none",
      });
    }
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    transitionAdmissionStoreId: input.transitionAdmissionStoreId,
    topologyId: input.topologyId,
    authorityScope: input.authorityScope,
    admittedRecordCount: input.records.length,
    ...(latestAdmittedRecord !== undefined ? { latestAdmittedRecord } : {}),
    ...(latestAdmittedTopology !== undefined ? { latestAdmittedTopology } : {}),
    ...(input.requiredAuthorityTopology !== undefined
      ? { requiredAuthorityTopology: input.requiredAuthorityTopology }
      : {}),
    ...(input.requiredAuthorityTransition !== undefined
      ? { requiredAuthorityTransition: input.requiredAuthorityTransition }
      : {}),
    ...(requiredAuthorityTransitionAdmissionRecord !== undefined
      ? { requiredAuthorityTransitionAdmissionRecord }
      : {}),
    ...(admissionWitnessReplay !== undefined ? { admissionWitnessReplay } : {}),
    issues,
  };
}

export function replayOperationalStateStorageMutationGuardAuthorizationAdmissionRecords(
  input: OperationalStateStorageMutationGuardAuthorizationAdmissionReplayInput,
): OperationalStateStorageMutationGuardAuthorizationAdmissionReplay {
  const issues: OperationalStateStorageMutationGuardIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const recordHashBySequence = new Map<number, string>();
  let expectedSequence = 1;
  let previousAdmissionRecordHash: string | undefined;
  let latestAdmittedRecord:
    | OperationalStateStorageMutationGuardAuthorizationAdmissionRecord
    | undefined;

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const recordHashValidation =
      verifyOperationalStateStorageMutationGuardAuthorizationAdmissionRecordHash(
        record,
      );
    const authorizationHashValidation =
      verifyOperationalStateStorageMutationGuardAuthorizationHash(
        record.authorization,
      );
    const previousRecordHashAtSequence = recordHashBySequence.get(
      record.admissionSequence,
    );

    if (
      previousRecordHashAtSequence !== undefined &&
      previousRecordHashAtSequence !== record.admissionRecordHash
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_record_fork",
        path: `${path}/admissionSequence`,
        message: `Storage mutation guard authorization admission sequence ${record.admissionSequence} has more than one record hash.`,
        expected: previousRecordHashAtSequence,
        actual: record.admissionRecordHash,
      });
    } else if (previousRecordHashAtSequence === undefined) {
      recordHashBySequence.set(
        record.admissionSequence,
        record.admissionRecordHash,
      );
    }

    if (record.tenantId !== expectedTenantId) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_record_tenant_mismatch",
        path: `${path}/tenantId`,
        message: `Storage mutation guard authorization admission tenant ${record.tenantId} does not match replay tenant ${expectedTenantId}.`,
        expected: expectedTenantId,
        actual: record.tenantId,
      });
    }
    if (record.authorization.tenantId !== expectedTenantId) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_record_tenant_mismatch",
        path: `${path}/authorization/tenantId`,
        message: `Embedded storage mutation guard authorization tenant ${record.authorization.tenantId} does not match replay tenant ${expectedTenantId}.`,
        expected: expectedTenantId,
        actual: record.authorization.tenantId,
      });
    }
    if (record.guardId !== input.guardId) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_record_guard_mismatch",
        path: `${path}/guardId`,
        message: `Storage mutation guard authorization admission guard ${record.guardId} does not match replay guard ${input.guardId}.`,
        expected: input.guardId,
        actual: record.guardId,
      });
    }
    if (record.authorization.guardId !== input.guardId) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_record_guard_mismatch",
        path: `${path}/authorization/guardId`,
        message: `Embedded storage mutation guard authorization guard ${record.authorization.guardId} does not match replay guard ${input.guardId}.`,
        expected: input.guardId,
        actual: record.authorization.guardId,
      });
    }
    if (
      record.protectedSchema !== input.protectedSchema ||
      record.protectedTable !== input.protectedTable
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_record_table_mismatch",
        path: `${path}/protectedTable`,
        message:
          "Storage mutation guard authorization admission record protects a different table than the replay target.",
        expected: `${input.protectedSchema}.${input.protectedTable}`,
        actual: `${record.protectedSchema}.${record.protectedTable}`,
      });
    }
    if (
      record.authorization.protectedSchema !== input.protectedSchema ||
      record.authorization.protectedTable !== input.protectedTable
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_record_table_mismatch",
        path: `${path}/authorization/protectedTable`,
        message:
          "Embedded storage mutation guard authorization protects a different table than the replay target.",
        expected: `${input.protectedSchema}.${input.protectedTable}`,
        actual: `${record.authorization.protectedSchema}.${record.authorization.protectedTable}`,
      });
    }
    if (record.operation !== input.operation) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_record_operation_mismatch",
        path: `${path}/operation`,
        message: `Storage mutation guard authorization admission operation ${record.operation} does not match replay operation ${input.operation}.`,
        expected: input.operation,
        actual: record.operation,
      });
    }
    if (record.authorization.operation !== input.operation) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_record_operation_mismatch",
        path: `${path}/authorization/operation`,
        message: `Embedded storage mutation guard authorization operation ${record.authorization.operation} does not match replay operation ${input.operation}.`,
        expected: input.operation,
        actual: record.authorization.operation,
      });
    }
    if (record.admissionSequence !== expectedSequence) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_record_sequence_gap",
        path: `${path}/admissionSequence`,
        message: `Storage mutation guard authorization admission sequence ${record.admissionSequence} does not match expected replay sequence ${expectedSequence}.`,
        expected: expectedSequence,
        actual: record.admissionSequence,
      });
    }
    if (record.previousAdmissionRecordHash !== previousAdmissionRecordHash) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_record_previous_hash_mismatch",
        path: `${path}/previousAdmissionRecordHash`,
        message:
          "Storage mutation guard authorization admission record does not chain to the previous record hash.",
        expected: previousAdmissionRecordHash ?? "none",
        actual: record.previousAdmissionRecordHash ?? "none",
      });
    }
    if (!authorizationHashValidation.valid) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_record_authorization_hash_mismatch",
        path: `${path}/authorization/authorizationHash`,
        message: `Embedded storage mutation guard authorization hash ${authorizationHashValidation.actualHash} does not match recomputed hash ${authorizationHashValidation.expectedHash}.`,
        expected: authorizationHashValidation.expectedHash,
        actual: authorizationHashValidation.actualHash,
      });
    }
    if (record.authorizationHash !== record.authorization.authorizationHash) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_record_authorization_hash_mismatch",
        path: `${path}/authorizationHash`,
        message:
          "Storage mutation guard authorization admission record hash does not match embedded authorization hash.",
        expected: record.authorization.authorizationHash,
        actual: record.authorizationHash,
      });
    }
    if (
      input.requiredAdmissionProcedureId !== undefined &&
      record.admissionProcedureId !== input.requiredAdmissionProcedureId
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_procedure_mismatch",
        path: `${path}/admissionProcedureId`,
        message:
          "Storage mutation guard authorization admission was not produced by the required admission procedure.",
        expected: input.requiredAdmissionProcedureId,
        actual: record.admissionProcedureId,
      });
    }
    if (
      input.requiredAdmissionRole !== undefined &&
      record.admissionRole !== input.requiredAdmissionRole
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_role_mismatch",
        path: `${path}/admissionRole`,
        message:
          "Storage mutation guard authorization admission was not produced under the required database role.",
        expected: input.requiredAdmissionRole,
        actual: record.admissionRole,
      });
    }
    if (!recordHashValidation.valid) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_record_hash_mismatch",
        path: `${path}/admissionRecordHash`,
        message: `Storage mutation guard authorization admission record hash ${recordHashValidation.actualHash} does not match recomputed hash ${recordHashValidation.expectedHash}.`,
        expected: recordHashValidation.expectedHash,
        actual: recordHashValidation.actualHash,
      });
    }

    expectedSequence = record.admissionSequence + 1;
    previousAdmissionRecordHash = record.admissionRecordHash;
    latestAdmittedRecord = record;
  });

  if (input.requiredAuthorization !== undefined) {
    const requiredAuthorizationHashValidation =
      verifyOperationalStateStorageMutationGuardAuthorizationHash(
        input.requiredAuthorization,
      );
    if (!requiredAuthorizationHashValidation.valid) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_record_authorization_hash_mismatch",
        path: "/requiredAuthorization/authorizationHash",
        message: `Required storage mutation guard authorization hash ${requiredAuthorizationHashValidation.actualHash} does not match recomputed hash ${requiredAuthorizationHashValidation.expectedHash}.`,
        expected: requiredAuthorizationHashValidation.expectedHash,
        actual: requiredAuthorizationHashValidation.actualHash,
      });
    }
    if (latestAdmittedRecord === undefined) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_not_admitted",
        path: "/records",
        message:
          "Storage mutation guard authorization admission replay has no records for the required authorization.",
      });
    } else if (
      latestAdmittedRecord.authorizationHash !==
      input.requiredAuthorization.authorizationHash
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_not_admitted",
        path: "/requiredAuthorization/authorizationHash",
        message:
          "Required storage mutation guard authorization is not the latest admitted authorization.",
        expected: input.requiredAuthorization.authorizationHash,
        actual: latestAdmittedRecord.authorizationHash,
      });
    }
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    guardId: input.guardId,
    protectedSchema: input.protectedSchema,
    protectedTable: input.protectedTable,
    operation: input.operation,
    admittedRecordCount: input.records.length,
    ...(latestAdmittedRecord !== undefined ? { latestAdmittedRecord } : {}),
    ...(input.requiredAuthorization !== undefined
      ? { requiredAuthorization: input.requiredAuthorization }
      : {}),
    issues,
  };
}

export function replayOperationalStateStorageMutationGuardAuthorizationAdmissionWitnessRecords(
  input: OperationalStateStorageMutationGuardAuthorizationAdmissionWitnessReplayInput,
): OperationalStateStorageMutationGuardAuthorizationAdmissionWitnessReplay {
  const issues: OperationalStateStorageMutationGuardIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const witnessHashBySequence = new Map<number, string>();
  const witnessRecordByAdmissionHash = new Map<
    string,
    OperationalStateStorageMutationGuardAuthorizationAdmissionWitnessRecord
  >();
  const witnessAuthorityTopology = input.witnessAuthorityTopology;
  const witnessAuthorityTransitionAdmissionReplay =
    input.witnessAuthorityTransitionAdmissionReplay;
  const principalById = new Map<string, OperationalStateAuthorityPrincipalState>(
    witnessAuthorityTopology?.principals.map((principal) => [
      principal.principalId,
      principal,
    ]) ?? [],
  );
  let expectedSequence = 1;
  let previousWitnessRecordHash: string | undefined;
  let latestWitnessRecord:
    | OperationalStateStorageMutationGuardAuthorizationAdmissionWitnessRecord
    | undefined;

  if (input.admissionReplay !== undefined && !input.admissionReplay.valid) {
    pushOperationalStateStorageMutationGuardIssue(issues, {
      code: "operational_state_storage_mutation_authorization_admission_witness_admission_replay_invalid",
      path: "/admissionReplay",
      message:
        "Storage mutation guard authorization admission witness replay cannot account for an invalid guard authorization admission replay.",
      actual: input.admissionReplay.issues
        .map((issue) => issue.code)
        .join(","),
    });
  }

  if (
    (input.requireWitnessAuthorityTopology === true ||
      input.requireWitnessAuthorityTransitionAdmission === true ||
      input.requireWitnessAuthorityTransitionAdmissionWitness === true ||
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    witnessAuthorityTopology === undefined
  ) {
    pushOperationalStateStorageMutationGuardIssue(issues, {
      code: "operational_state_storage_mutation_authorization_admission_witness_authority_topology_missing",
      path: "/witnessAuthorityTopology",
      message:
        "Storage mutation guard authorization admission witness replay requires a replayed witness authority topology.",
    });
  }

  if (witnessAuthorityTopology !== undefined) {
    const topologyHashValidation =
      verifyOperationalStateAuthorityTopologyHash(witnessAuthorityTopology);
    if (!topologyHashValidation.valid) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_topology_hash_mismatch",
        path: "/witnessAuthorityTopology/topologyHash",
        message: `Storage mutation guard authorization admission witness authority topology hash ${topologyHashValidation.actualHash} does not match recomputed hash ${topologyHashValidation.expectedHash}.`,
        expected: topologyHashValidation.expectedHash,
        actual: topologyHashValidation.actualHash,
      });
    }
    if (witnessAuthorityTopology.tenantId !== expectedTenantId) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_topology_tenant_mismatch",
        path: "/witnessAuthorityTopology/tenantId",
        message:
          "Storage mutation guard authorization admission witness authority topology tenant does not match replay tenant.",
        expected: expectedTenantId,
        actual: witnessAuthorityTopology.tenantId,
      });
    }
    if (witnessAuthorityTopology.authorityScope !== input.authorityScope) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_topology_scope_mismatch",
        path: "/witnessAuthorityTopology/authorityScope",
        message:
          "Storage mutation guard authorization admission witness authority topology scope does not match replay scope.",
        expected: input.authorityScope,
        actual: witnessAuthorityTopology.authorityScope,
      });
    }
    if (
      witnessAuthorityTopology.requiredWitnesses === undefined ||
      witnessAuthorityTopology.minimumWitnesses === undefined
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_quorum_missing",
        path: "/witnessAuthorityTopology/requiredWitnesses",
        message:
          "Storage mutation guard authorization admission witness authority topology must define quorum thresholds.",
      });
    }
  }

  if (
    input.requireWitnessAuthorityTransitionAdmission === true ||
    input.requireWitnessAuthorityTransitionAdmissionWitness === true ||
    input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
      true ||
    input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
      true
  ) {
    if (witnessAuthorityTransitionAdmissionReplay === undefined) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_replay_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Storage mutation guard authorization admission witness replay requires admitted guard-admission witness-authority transition history.",
      });
    } else if (!witnessAuthorityTransitionAdmissionReplay.valid) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_replay_invalid",
        path: "/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Storage mutation guard authorization admission witness replay cannot consume invalid guard-admission witness-authority transition admission history.",
        actual: witnessAuthorityTransitionAdmissionReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      witnessAuthorityTopology !== undefined &&
      (witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology ===
        undefined ||
        !operationalStateAuthorityTopologiesMatch(
          witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology,
          witnessAuthorityTopology,
        ))
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Storage mutation guard authorization admission witness authority topology must be recovered from admitted authority-transition history.",
        expected: witnessAuthorityTopology.topologyHash,
        actual:
          witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology
            ?.topologyHash ?? "none",
      });
    }
  }
  if (
    (input.requireWitnessAuthorityTransitionAdmissionWitness === true ||
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    witnessAuthorityTransitionAdmissionReplay !== undefined
  ) {
    if (
      witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay ===
      undefined
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_replay_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
        message:
          "Storage mutation guard authorization admission witness replay requires guard-admission witness authority-transition admission records to be witnessed.",
      });
    } else if (
      !witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay.valid
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_replay_invalid",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
        message:
          "Storage mutation guard authorization admission witness replay cannot consume invalid guard-admission witness authority-transition admission witness history.",
        actual:
          witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay.issues
            .map((issue) => issue.code)
            .join(","),
      });
    } else if (
      (input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
        input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
          true) &&
      witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTopology === undefined
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_topology_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTopology",
        message:
          "Storage mutation guard authorization admission witness replay requires witness authority-transition admission witness certificates to bind to replayed witness authority topology.",
      });
    } else if (
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTransitionAdmissionReplay === undefined
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Storage mutation guard authorization admission witness replay requires witness authority-transition admission witness authority topology to replay from admitted authority-transition history.",
      });
    } else if (
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTransitionAdmissionReplay !== undefined &&
      !witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTransitionAdmissionReplay.valid
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Storage mutation guard authorization admission witness replay cannot consume invalid nested guard-admission witness authority-transition admission witness authority history.",
        actual:
          witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.issues
            .map((issue) => issue.code)
            .join(","),
      });
    } else if (
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTopology !== undefined &&
      witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTransitionAdmissionReplay !== undefined &&
      (witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology ===
        undefined ||
        !operationalStateAuthorityTopologiesMatch(
          witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
            .witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology,
          witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
            .witnessAuthorityTopology,
        ))
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Storage mutation guard authorization admission witness replay requires witness authority-transition admission witness authority topology to be recovered from admitted authority-transition history.",
        expected:
          witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
            .witnessAuthorityTopology.topologyHash,
        actual:
          witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
            .witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology
            ?.topologyHash ?? "none",
      });
    }
  }

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const witnessRecordHashValidation =
      verifyOperationalStateStorageMutationGuardAuthorizationAdmissionWitnessRecordHash(
        record,
      );
    const certificateHashValidation =
      verifyOperationalStateQuorumCertificateProofCertificateHash(
        record.admissionCertificate,
      );
    const previousWitnessHashAtSequence = witnessHashBySequence.get(
      record.witnessSequence,
    );
    const expectedSubjectId =
      operationalStateStorageMutationGuardAuthorizationAdmissionSubjectId(
        record,
      );

    if (
      previousWitnessHashAtSequence !== undefined &&
      previousWitnessHashAtSequence !== record.witnessRecordHash
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_record_fork",
        path: `${path}/witnessSequence`,
        message: `Storage mutation guard authorization admission witness sequence ${record.witnessSequence} has more than one witness record hash.`,
        expected: previousWitnessHashAtSequence,
        actual: record.witnessRecordHash,
      });
    } else if (previousWitnessHashAtSequence === undefined) {
      witnessHashBySequence.set(
        record.witnessSequence,
        record.witnessRecordHash,
      );
    }

    if (
      record.tenantId !== expectedTenantId ||
      record.admissionCertificate.tenantId !== expectedTenantId
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_record_tenant_mismatch",
        path,
        message:
          "Storage mutation guard authorization admission witness record and certificate must match the replay tenant.",
        expected: expectedTenantId,
      });
    }
    if (
      record.guardAuthorizationAdmissionWitnessStoreId !==
      input.guardAuthorizationAdmissionWitnessStoreId
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_record_store_mismatch",
        path: `${path}/guardAuthorizationAdmissionWitnessStoreId`,
        message:
          "Storage mutation guard authorization admission witness record belongs to a different witness store.",
        expected: input.guardAuthorizationAdmissionWitnessStoreId,
        actual: record.guardAuthorizationAdmissionWitnessStoreId,
      });
    }
    if (
      record.authorityScope !== input.authorityScope ||
      record.admissionCertificate.authorityScope !== input.authorityScope
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_record_scope_mismatch",
        path,
        message:
          "Storage mutation guard authorization admission witness record and certificate must share the replay authority scope.",
        expected: input.authorityScope,
      });
    }
    if (record.guardId !== input.guardId) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_record_guard_mismatch",
        path: `${path}/guardId`,
        message:
          "Storage mutation guard authorization admission witness record accounts for a different guard.",
        expected: input.guardId,
        actual: record.guardId,
      });
    }
    if (
      record.protectedSchema !== input.protectedSchema ||
      record.protectedTable !== input.protectedTable
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_record_table_mismatch",
        path: `${path}/protectedTable`,
        message:
          "Storage mutation guard authorization admission witness record accounts for a different protected table.",
        expected: `${input.protectedSchema}.${input.protectedTable}`,
        actual: `${record.protectedSchema}.${record.protectedTable}`,
      });
    }
    if (record.operation !== input.operation) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_record_operation_mismatch",
        path: `${path}/operation`,
        message:
          "Storage mutation guard authorization admission witness record accounts for a different operation.",
        expected: input.operation,
        actual: record.operation,
      });
    }
    if (record.witnessSequence !== expectedSequence) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_record_sequence_gap",
        path: `${path}/witnessSequence`,
        message:
          "Storage mutation guard authorization admission witness records must replay as a contiguous witness sequence.",
        expected: expectedSequence,
        actual: record.witnessSequence,
      });
    }
    if (record.previousWitnessRecordHash !== previousWitnessRecordHash) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_record_previous_hash_mismatch",
        path: `${path}/previousWitnessRecordHash`,
        message:
          "Storage mutation guard authorization admission witness record does not chain to the previous witness record hash.",
        expected: previousWitnessRecordHash ?? "none",
        actual: record.previousWitnessRecordHash ?? "none",
      });
    }
    if (!certificateHashValidation.valid) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_certificate_hash_mismatch",
        path: `${path}/admissionCertificate/quorumCertificateHash`,
        message: `Storage mutation guard authorization admission witness certificate hash ${certificateHashValidation.actualHash} does not match recomputed hash ${certificateHashValidation.expectedHash}.`,
        expected: certificateHashValidation.expectedHash,
        actual: certificateHashValidation.actualHash,
      });
    }
    if (
      !record.admissionCertificate.certified ||
      record.admissionCertificate.status !== "certified"
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_certificate_not_certified",
        path: `${path}/admissionCertificate/status`,
        message:
          "Storage mutation guard authorization admission cannot become accountable through a non-certified witness certificate.",
        expected: "certified",
        actual: record.admissionCertificate.status,
      });
    }
    if (
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.minimumWitnesses ||
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.requiredWitnesses
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_certificate_quorum_not_met",
        path: `${path}/admissionCertificate/acceptedWitnessIds`,
        message:
          "Storage mutation guard authorization admission witness certificate does not satisfy its witness quorum.",
        expected: Math.max(
          record.admissionCertificate.requiredWitnesses,
          record.admissionCertificate.minimumWitnesses,
        ),
        actual: record.admissionCertificate.acceptedWitnessIds.length,
      });
    }
    if (
      record.admissionCertificate.subjectKind !==
        OPERATIONAL_STATE_STORAGE_MUTATION_GUARD_AUTHORIZATION_ADMISSION_RECORD_SUBJECT_KIND ||
      record.admissionCertificate.subjectId !== expectedSubjectId ||
      record.admissionCertificate.subjectSequence !==
        record.admissionSequence ||
      record.admissionCertificate.subjectHash !== record.admissionRecordHash
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_certificate_subject_mismatch",
        path: `${path}/admissionCertificate`,
        message:
          "Storage mutation guard authorization admission witness certificate must certify the exact guard/table/operation admission sequence and admission record hash.",
        expected: record.admissionRecordHash,
        actual: record.admissionCertificate.subjectHash,
      });
    }
    if (
      input.requiredAuthorityBoundary !== undefined &&
      record.admissionCertificate.authorityBoundary !==
        input.requiredAuthorityBoundary
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_certificate_authority_boundary_mismatch",
        path: `${path}/admissionCertificate/authorityBoundary`,
        message:
          "Storage mutation guard authorization admission witness certificate was admitted under the wrong authority boundary.",
        expected: input.requiredAuthorityBoundary,
        actual: record.admissionCertificate.authorityBoundary,
      });
    }
    if (witnessAuthorityTopology !== undefined) {
      if (
        record.admissionCertificate.authorityTopologyHash !==
        witnessAuthorityTopology.topologyHash
      ) {
        pushOperationalStateStorageMutationGuardIssue(issues, {
          code: "operational_state_storage_mutation_authorization_admission_witness_certificate_authority_topology_mismatch",
          path: `${path}/admissionCertificate/authorityTopologyHash`,
          message:
            "Storage mutation guard authorization admission witness certificate is not bound to the replayed witness authority topology.",
          expected: witnessAuthorityTopology.topologyHash,
          actual:
            record.admissionCertificate.authorityTopologyHash ?? "none",
        });
      }

      const acceptedWitnessIds =
        record.admissionCertificate.acceptedWitnessIds;
      const uniqueAcceptedWitnessIds = new Set(acceptedWitnessIds);
      if (uniqueAcceptedWitnessIds.size !== acceptedWitnessIds.length) {
        pushOperationalStateStorageMutationGuardIssue(issues, {
          code: "operational_state_storage_mutation_authorization_admission_witness_authority_duplicate_witness",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Storage mutation guard authorization admission witness authority quorum cannot be satisfied by duplicate witness ids.",
          expected: uniqueAcceptedWitnessIds.size,
          actual: acceptedWitnessIds.length,
        });
      }

      let activeAuthorizedWitnessCount = 0;
      for (const witnessId of uniqueAcceptedWitnessIds) {
        const principal = principalById.get(witnessId);
        if (principal === undefined) {
          pushOperationalStateStorageMutationGuardIssue(issues, {
            code: "operational_state_storage_mutation_authorization_admission_witness_authority_witness_unknown",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Storage mutation guard authorization admission witness certificate names a witness that is not present in the replayed authority topology.",
            expected: witnessAuthorityTopology.topologyHash,
            actual: witnessId,
          });
          continue;
        }
        if (principal.status !== "active") {
          pushOperationalStateStorageMutationGuardIssue(issues, {
            code: "operational_state_storage_mutation_authorization_admission_witness_authority_witness_not_active",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Storage mutation guard authorization admission witness certificate names a witness that is not active in the replayed authority topology.",
            expected: "active",
            actual: `${witnessId}:${principal.status}`,
          });
          continue;
        }
        activeAuthorizedWitnessCount += 1;
      }

      const requiredAuthorizedWitnesses = Math.max(
        witnessAuthorityTopology.requiredWitnesses ?? 0,
        witnessAuthorityTopology.minimumWitnesses ?? 0,
      );
      if (activeAuthorizedWitnessCount < requiredAuthorizedWitnesses) {
        pushOperationalStateStorageMutationGuardIssue(issues, {
          code: "operational_state_storage_mutation_authorization_admission_witness_authority_quorum_not_met",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Storage mutation guard authorization admission witness certificate does not satisfy the replayed witness authority topology quorum.",
          expected: requiredAuthorizedWitnesses,
          actual: activeAuthorizedWitnessCount,
        });
      }
    }
    if (!witnessRecordHashValidation.valid) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_record_hash_mismatch",
        path: `${path}/witnessRecordHash`,
        message: `Storage mutation guard authorization admission witness record hash ${witnessRecordHashValidation.actualHash} does not match recomputed hash ${witnessRecordHashValidation.expectedHash}.`,
        expected: witnessRecordHashValidation.expectedHash,
        actual: witnessRecordHashValidation.actualHash,
      });
    }

    witnessRecordByAdmissionHash.set(record.admissionRecordHash, record);
    expectedSequence = record.witnessSequence + 1;
    previousWitnessRecordHash = record.witnessRecordHash;
    latestWitnessRecord = record;
  });

  const requiredAdmissionRecord =
    input.requiredAdmissionRecord ??
    input.admissionReplay?.latestAdmittedRecord;
  let requiredAdmissionWitnessRecord:
    | OperationalStateStorageMutationGuardAuthorizationAdmissionWitnessRecord
    | undefined;
  if (requiredAdmissionRecord !== undefined) {
    const admissionRecordHashValidation =
      verifyOperationalStateStorageMutationGuardAuthorizationAdmissionRecordHash(
        requiredAdmissionRecord,
      );
    if (!admissionRecordHashValidation.valid) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_record_hash_mismatch",
        path: "/requiredAdmissionRecord/admissionRecordHash",
        message: `Required storage mutation guard authorization admission record hash ${admissionRecordHashValidation.actualHash} does not match recomputed hash ${admissionRecordHashValidation.expectedHash}.`,
        expected: admissionRecordHashValidation.expectedHash,
        actual: admissionRecordHashValidation.actualHash,
      });
    }
    requiredAdmissionWitnessRecord = witnessRecordByAdmissionHash.get(
      requiredAdmissionRecord.admissionRecordHash,
    );
    if (requiredAdmissionWitnessRecord === undefined) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_latest_record_not_witnessed",
        path: "/requiredAdmissionRecord/admissionRecordHash",
        message:
          "Latest storage mutation guard authorization admission record has no replayed witness certificate.",
        expected: requiredAdmissionRecord.admissionRecordHash,
      });
    } else if (
      requiredAdmissionWitnessRecord.admissionSequence !==
        requiredAdmissionRecord.admissionSequence ||
      requiredAdmissionWitnessRecord.authorizationHash !==
        requiredAdmissionRecord.authorizationHash ||
      requiredAdmissionWitnessRecord.guardId !== requiredAdmissionRecord.guardId ||
      requiredAdmissionWitnessRecord.protectedSchema !==
        requiredAdmissionRecord.protectedSchema ||
      requiredAdmissionWitnessRecord.protectedTable !==
        requiredAdmissionRecord.protectedTable ||
      requiredAdmissionWitnessRecord.operation !== requiredAdmissionRecord.operation
    ) {
      pushOperationalStateStorageMutationGuardIssue(issues, {
        code: "operational_state_storage_mutation_authorization_admission_witness_admission_record_mismatch",
        path: "/requiredAdmissionRecord",
        message:
          "Storage mutation guard authorization admission witness record does not match the required admitted authorization, guard, table, operation, and sequence.",
        expected: requiredAdmissionRecord.admissionRecordHash,
        actual: requiredAdmissionWitnessRecord.admissionRecordHash,
      });
    }
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    guardAuthorizationAdmissionWitnessStoreId:
      input.guardAuthorizationAdmissionWitnessStoreId,
    authorityScope: input.authorityScope,
    guardId: input.guardId,
    protectedSchema: input.protectedSchema,
    protectedTable: input.protectedTable,
    operation: input.operation,
    witnessedRecordCount: input.records.length,
    ...(latestWitnessRecord !== undefined ? { latestWitnessRecord } : {}),
    ...(requiredAdmissionRecord !== undefined ? { requiredAdmissionRecord } : {}),
    ...(requiredAdmissionWitnessRecord !== undefined
      ? { requiredAdmissionWitnessRecord }
      : {}),
    ...(witnessAuthorityTopology !== undefined
      ? { witnessAuthorityTopology }
      : {}),
    ...(witnessAuthorityTransitionAdmissionReplay !== undefined
      ? { witnessAuthorityTransitionAdmissionReplay }
      : {}),
    issues,
  };
}

export function evaluateOperationalStateStorageMutationGuard(
  input: OperationalStateStorageMutationGuardEvaluationInput,
): OperationalStateStorageMutationGuardEvaluation {
  const issues: OperationalStateStorageMutationGuardIssue[] = [];
  const { request } = input;
  let latestAdmittedRecord:
    | OperationalStateStorageMutationGuardAuthorizationAdmissionRecord
    | undefined;
  let latestAdmissionWitnessRecord:
    | OperationalStateStorageMutationGuardAuthorizationAdmissionWitnessRecord
    | undefined;

  if (request.authorizationHash === undefined) {
    return {
      valid: false,
      issues: [
        {
          code: "operational_state_storage_mutation_authorization_missing",
          path: "/authorizationHash",
          message:
            "Storage mutation cannot update or delete operational state without a tombstone-derived mutation authorization.",
        },
      ],
    };
  }

  const matchedAuthorization = input.authorizations.find(
    (authorization) =>
      authorization.authorizationHash === request.authorizationHash,
  );
  if (matchedAuthorization === undefined) {
    return {
      valid: false,
      issues: [
        {
          code: "operational_state_storage_mutation_authorization_missing",
          path: "/authorizationHash",
          message:
            "Storage mutation authorization hash is not present in admitted guard authorizations.",
          actual: request.authorizationHash,
        },
      ],
    };
  }

  const hashValidation =
    verifyOperationalStateStorageMutationGuardAuthorizationHash(
      matchedAuthorization,
    );
  if (!hashValidation.valid) {
    issues.push({
      code: "operational_state_storage_mutation_authorization_hash_mismatch",
      path: "/authorizationHash",
      message: `Storage mutation authorization hash ${hashValidation.actualHash} does not match recomputed hash ${hashValidation.expectedHash}.`,
      expected: hashValidation.expectedHash,
      actual: hashValidation.actualHash,
    });
  }
  if (matchedAuthorization.tenantId !== request.tenantId) {
    issues.push({
      code: "operational_state_storage_mutation_authorization_tenant_mismatch",
      path: "/tenantId",
      message: `Storage mutation authorization tenant ${matchedAuthorization.tenantId} does not match mutation tenant ${request.tenantId}.`,
      expected: String(request.tenantId),
      actual: matchedAuthorization.tenantId,
    });
  }
  if (matchedAuthorization.guardId !== request.guardId) {
    issues.push({
      code: "operational_state_storage_mutation_authorization_guard_mismatch",
      path: "/guardId",
      message: `Storage mutation authorization guard ${matchedAuthorization.guardId} does not match mutation guard ${request.guardId}.`,
      expected: request.guardId,
      actual: matchedAuthorization.guardId,
    });
  }
  if (
    matchedAuthorization.protectedSchema !== request.protectedSchema ||
    matchedAuthorization.protectedTable !== request.protectedTable
  ) {
    issues.push({
      code: "operational_state_storage_mutation_authorization_table_mismatch",
      path: "/protectedTable",
      message:
        "Storage mutation authorization does not apply to the protected table being mutated.",
      expected: `${request.protectedSchema}.${request.protectedTable}`,
      actual: `${matchedAuthorization.protectedSchema}.${matchedAuthorization.protectedTable}`,
    });
  }
  if (matchedAuthorization.operation !== request.operation) {
    issues.push({
      code: "operational_state_storage_mutation_authorization_operation_mismatch",
      path: "/operation",
      message: `Storage mutation authorization operation ${matchedAuthorization.operation} does not match requested ${request.operation}.`,
      expected: request.operation,
      actual: matchedAuthorization.operation,
    });
  }
  if (matchedAuthorization.authorizedThroughSequence < request.targetSequence) {
    issues.push({
      code: "operational_state_storage_mutation_authorization_sequence_gap",
      path: "/targetSequence",
      message: `Storage mutation targets sequence ${request.targetSequence}, but authorization only covers through ${matchedAuthorization.authorizedThroughSequence}.`,
      expected: request.targetSequence,
      actual: matchedAuthorization.authorizedThroughSequence,
    });
  }
  if (
    input.requireAuthorizationAdmission === true ||
    input.requireAuthorizationAdmissionWitnessQuorum === true ||
    input.requireAuthorizationAdmissionWitnessAuthorityTopology === true ||
    input.requireAuthorizationAdmissionWitnessAuthorityTransitionAdmission ===
      true ||
    input
      .requireAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitness ===
      true ||
    input
      .requireAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
      true ||
    input
      .requireAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
      true
  ) {
    const admissionReplay = input.authorizationAdmissionReplay;
    if (admissionReplay === undefined) {
      issues.push({
        code: "operational_state_storage_mutation_authorization_admission_replay_missing",
        path: "/authorizationAdmissionReplay",
        message:
          "Storage mutation guard authorization rows cannot authorize mutation unless they replay from guard authorization admission history.",
      });
    } else {
      if (!admissionReplay.valid) {
        issues.push({
          code: "operational_state_storage_mutation_authorization_admission_replay_invalid",
          path: "/authorizationAdmissionReplay",
          message:
            "Storage mutation guard authorization admission replay is invalid.",
          actual: admissionReplay.issues
            .map((issue) => issue.code)
            .join(","),
        });
      }
      latestAdmittedRecord = admissionReplay.latestAdmittedRecord;
      if (
        latestAdmittedRecord === undefined ||
        latestAdmittedRecord.authorizationHash !==
          matchedAuthorization.authorizationHash
      ) {
        issues.push({
          code: "operational_state_storage_mutation_authorization_not_admitted",
          path: "/authorizationHash",
          message:
            "Storage mutation guard authorization is not the latest authorization admitted by replayed guard authorization history.",
          expected: matchedAuthorization.authorizationHash,
          actual: latestAdmittedRecord?.authorizationHash ?? "none",
        });
      }
    }
  }

  const admissionWitnessReplay = input.authorizationAdmissionWitnessReplay;
  latestAdmissionWitnessRecord =
    admissionWitnessReplay?.requiredAdmissionWitnessRecord;
  if (
    input.requireAuthorizationAdmissionWitnessQuorum === true ||
    input.requireAuthorizationAdmissionWitnessAuthorityTopology === true ||
    input.requireAuthorizationAdmissionWitnessAuthorityTransitionAdmission ===
      true ||
    input
      .requireAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitness ===
      true ||
    input
      .requireAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
      true ||
    input
      .requireAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
      true
  ) {
    if (admissionWitnessReplay === undefined) {
      issues.push({
        code: "operational_state_storage_mutation_authorization_admission_witness_replay_missing",
        path: "/authorizationAdmissionWitnessReplay",
        message:
          "Storage mutation guard authorization admission requires replay of witness-certified guard admission records.",
      });
    } else if (!admissionWitnessReplay.valid) {
      issues.push({
        code: "operational_state_storage_mutation_authorization_admission_witness_replay_invalid",
        path: "/authorizationAdmissionWitnessReplay",
        message:
          "Storage mutation guard authorization admission witness replay is invalid.",
        actual: admissionWitnessReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      latestAdmittedRecord === undefined ||
      latestAdmissionWitnessRecord === undefined ||
      latestAdmissionWitnessRecord.admissionRecordHash !==
        latestAdmittedRecord.admissionRecordHash
    ) {
      issues.push({
        code: "operational_state_storage_mutation_authorization_admission_latest_record_not_witnessed",
        path: "/authorizationAdmissionWitnessReplay",
        message:
          "Latest storage mutation guard authorization admission record is not witnessed by the replayed guard-admission witness quorum.",
        expected: latestAdmittedRecord?.admissionRecordHash ?? "none",
        actual: latestAdmissionWitnessRecord?.admissionRecordHash ?? "none",
      });
    }
  }
  if (
    (input.requireAuthorizationAdmissionWitnessAuthorityTopology === true ||
      input.requireAuthorizationAdmissionWitnessAuthorityTransitionAdmission ===
        true ||
      input
        .requireAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitness ===
        true ||
      input
        .requireAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input
        .requireAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    admissionWitnessReplay !== undefined &&
    admissionWitnessReplay.witnessAuthorityTopology === undefined
  ) {
    issues.push({
      code: "operational_state_storage_mutation_authorization_admission_witness_authority_topology_missing",
      path: "/authorizationAdmissionWitnessReplay/witnessAuthorityTopology",
      message:
        "Storage mutation guard authorization admission requires witness replay to bind certificates to replayed witness authority topology.",
    });
  }
  if (
    (input.requireAuthorizationAdmissionWitnessAuthorityTransitionAdmission ===
      true ||
      input
        .requireAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitness ===
        true ||
      input
        .requireAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input
        .requireAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    admissionWitnessReplay !== undefined &&
    admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay ===
      undefined
  ) {
    issues.push({
      code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_replay_missing",
      path: "/authorizationAdmissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
      message:
        "Storage mutation guard authorization admission requires witness authority topology to come from admitted authority-transition history.",
    });
  }
  if (
    (input
      .requireAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitness ===
      true ||
      input
        .requireAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input
        .requireAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    admissionWitnessReplay !== undefined &&
    admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
      undefined
  ) {
    const admissionTransitionWitnessReplay =
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .admissionWitnessReplay;
    if (admissionTransitionWitnessReplay === undefined) {
      issues.push({
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_replay_missing",
        path: "/authorizationAdmissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
        message:
          "Storage mutation guard authorization admission requires guard-admission witness authority-transition admission records to be witnessed.",
      });
    } else if (!admissionTransitionWitnessReplay.valid) {
      issues.push({
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_replay_invalid",
        path: "/authorizationAdmissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
        message:
          "Storage mutation guard authorization admission cannot consume invalid guard-admission witness authority-transition admission witness history.",
        actual: admissionTransitionWitnessReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      (input
        .requireAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
        input
          .requireAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
          true) &&
      admissionTransitionWitnessReplay.witnessAuthorityTopology === undefined
    ) {
      issues.push({
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_topology_missing",
        path: "/authorizationAdmissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTopology",
        message:
          "Storage mutation guard authorization admission requires guard-admission witness authority-transition admission witness certificates to bind to replayed witness authority topology.",
      });
    } else if (
      input
        .requireAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay ===
        undefined
    ) {
      issues.push({
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        path: "/authorizationAdmissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Storage mutation guard authorization admission requires guard-admission witness authority-transition admission witness authority topology to replay from admitted authority-transition history.",
      });
    } else if (
      input
        .requireAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      !admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .valid
    ) {
      issues.push({
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        path: "/authorizationAdmissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Storage mutation guard authorization admission cannot consume invalid nested guard-admission witness authority-transition admission witness authority history.",
        actual:
          admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.issues
            .map((issue) => issue.code)
            .join(","),
      });
    } else if (
      input
        .requireAuthorizationAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      admissionTransitionWitnessReplay.witnessAuthorityTopology !== undefined &&
      admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      (admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .latestAdmittedTopology === undefined ||
        !operationalStateAuthorityTopologiesMatch(
          admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology,
          admissionTransitionWitnessReplay.witnessAuthorityTopology,
        ))
    ) {
      issues.push({
        code: "operational_state_storage_mutation_authorization_admission_witness_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/authorizationAdmissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Storage mutation guard authorization admission requires guard-admission witness authority-transition admission witness authority topology to be recovered from admitted authority-transition history.",
        expected: admissionTransitionWitnessReplay.witnessAuthorityTopology
          .topologyHash,
        actual:
          admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology?.topologyHash ?? "none",
      });
    }
  }

  return {
    valid: issues.length === 0,
    matchedAuthorization,
    ...(input.authorizationAdmissionReplay !== undefined
      ? { authorizationAdmissionReplay: input.authorizationAdmissionReplay }
      : {}),
    ...(admissionWitnessReplay !== undefined
      ? { authorizationAdmissionWitnessReplay: admissionWitnessReplay }
      : {}),
    ...(latestAdmittedRecord !== undefined ? { latestAdmittedRecord } : {}),
    ...(latestAdmissionWitnessRecord !== undefined
      ? { latestAdmissionWitnessRecord }
      : {}),
    issues,
  };
}

export function computeOperationalStateTombstoneHistoryRecordHash(
  record: Omit<OperationalStateTombstoneHistoryRecord, "recordHash">,
): string {
  return fingerprint64(canonicalStringify(record));
}

export function buildOperationalStateTombstoneHistoryRecord(
  input: OperationalStateTombstoneHistoryRecordInput,
): OperationalStateTombstoneHistoryRecord {
  const payload: Omit<OperationalStateTombstoneHistoryRecord, "recordHash"> = {
    schemaVersion: OPERATIONAL_STATE_TOMBSTONE_HISTORY_COMPACTION_SCHEMA_VERSION,
    tenantId: tenantId(String(input.tenantId)),
    storeId: input.storeId,
    authorityScope: input.authorityScope,
    sequence: input.sequence,
    ...(input.previousRecordHash !== undefined
      ? { previousRecordHash: input.previousRecordHash }
      : {}),
    tombstoneHash: input.tombstoneHash,
    pruningAdmissionHash: input.pruningAdmissionHash,
    prunedThroughSequence: input.prunedThroughSequence,
    recordedAt: input.recordedAt,
  };
  return {
    ...payload,
    recordHash: computeOperationalStateTombstoneHistoryRecordHash(payload),
  };
}

export function verifyOperationalStateTombstoneHistoryRecordHash(
  record: OperationalStateTombstoneHistoryRecord,
): StateReviewArtifactHashValidation {
  const { recordHash, ...payload } = record;
  const expectedHash = computeOperationalStateTombstoneHistoryRecordHash(payload);
  return {
    valid: recordHash === expectedHash,
    expectedHash,
    actualHash: recordHash,
  };
}

export function computeOperationalStateTombstoneHistoryStoreHeadHash(
  head: Omit<OperationalStateTombstoneHistoryStoreHead, "headHash">,
): string {
  return fingerprint64(canonicalStringify(head));
}

export function operationalStateTombstoneHistoryStoreHeadFromRecord(
  record: OperationalStateTombstoneHistoryRecord,
): OperationalStateTombstoneHistoryStoreHead {
  const payload: Omit<OperationalStateTombstoneHistoryStoreHead, "headHash"> = {
    schemaVersion: OPERATIONAL_STATE_TOMBSTONE_HISTORY_COMPACTION_SCHEMA_VERSION,
    tenantId: record.tenantId,
    storeId: record.storeId,
    authorityScope: record.authorityScope,
    sequence: record.sequence,
    recordHash: record.recordHash,
  };
  return {
    ...payload,
    headHash: computeOperationalStateTombstoneHistoryStoreHeadHash(payload),
  };
}

export function verifyOperationalStateTombstoneHistoryStoreHeadHash(
  head: OperationalStateTombstoneHistoryStoreHead,
): StateReviewArtifactHashValidation {
  const { headHash, ...payload } = head;
  const expectedHash =
    computeOperationalStateTombstoneHistoryStoreHeadHash(payload);
  return {
    valid: headHash === expectedHash,
    expectedHash,
    actualHash: headHash,
  };
}

