export function replayOperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitnessRecords(
  input: OperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitnessReplayInput,
): OperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitnessReplay {
  const issues: OperationalStateWitnessLedgerCompactionIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const witnessHashBySequence = new Map<number, string>();
  const witnessRecordByAdmissionHash = new Map<
    string,
    OperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitnessRecord
  >();
  const witnessAuthorityTopology = input.witnessAuthorityTopology;
  const witnessAuthorityTransitionAdmissionReplay =
    input.witnessAuthorityTransitionAdmissionReplay;
  const principalById = new Map<string, OperationalStateAuthorityPrincipalState>(
    witnessAuthorityTopology?.principals.map((principal) => [
      principal.principalId,
      principal,
    ]) ?? [],
  );
  let expectedSequence = 1;
  let previousWitnessRecordHash: string | undefined;
  let latestWitnessRecord:
    | OperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitnessRecord
    | undefined;

  if (input.admissionReplay !== undefined && !input.admissionReplay.valid) {
    pushOperationalStateWitnessLedgerCompactionIssue(issues, {
      code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_admission_replay_invalid",
      path: "/admissionReplay",
      message:
        "Witness-ledger checkpoint admission witness authority-transition admission witness replay cannot account for invalid transition-admission history.",
      actual: input.admissionReplay.issues
        .map((issue) => issue.code)
        .join(","),
    });
  }

  if (
    (input.requireWitnessAuthorityTopology === true ||
      input.requireWitnessAuthorityTransitionAdmission === true) &&
    witnessAuthorityTopology === undefined
  ) {
    pushOperationalStateWitnessLedgerCompactionIssue(issues, {
      code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_topology_missing",
      path: "/witnessAuthorityTopology",
      message:
        "Witness-ledger checkpoint admission witness authority-transition admission witness replay requires a replayed witness authority topology.",
    });
  }

  if (witnessAuthorityTopology !== undefined) {
    const topologyHashValidation =
      verifyOperationalStateAuthorityTopologyHash(witnessAuthorityTopology);
    if (!topologyHashValidation.valid) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_topology_hash_mismatch",
        path: "/witnessAuthorityTopology/topologyHash",
        message: `Witness-ledger checkpoint admission witness authority-transition admission witness authority topology hash ${topologyHashValidation.actualHash} does not match recomputed hash ${topologyHashValidation.expectedHash}.`,
        expected: topologyHashValidation.expectedHash,
        actual: topologyHashValidation.actualHash,
      });
    }
    if (witnessAuthorityTopology.tenantId !== expectedTenantId) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_topology_tenant_mismatch",
        path: "/witnessAuthorityTopology/tenantId",
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission witness authority topology tenant does not match replay tenant.",
        expected: expectedTenantId,
        actual: witnessAuthorityTopology.tenantId,
      });
    }
    if (witnessAuthorityTopology.authorityScope !== input.authorityScope) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_topology_scope_mismatch",
        path: "/witnessAuthorityTopology/authorityScope",
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission witness authority topology scope does not match replay scope.",
        expected: input.authorityScope,
        actual: witnessAuthorityTopology.authorityScope,
      });
    }
    if (
      witnessAuthorityTopology.requiredWitnesses === undefined ||
      witnessAuthorityTopology.minimumWitnesses === undefined
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_quorum_missing",
        path: "/witnessAuthorityTopology/requiredWitnesses",
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission witness authority topology must define quorum thresholds.",
      });
    }
  }

  if (input.requireWitnessAuthorityTransitionAdmission === true) {
    if (witnessAuthorityTransitionAdmissionReplay === undefined) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission witness replay requires its witness authority topology to replay from admitted authority-transition history.",
      });
    } else if (!witnessAuthorityTransitionAdmissionReplay.valid) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        path: "/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission witness replay cannot consume invalid nested witness-authority transition admission history.",
        actual: witnessAuthorityTransitionAdmissionReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      witnessAuthorityTopology !== undefined &&
      (witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology ===
        undefined ||
        !operationalStateAuthorityTopologiesMatch(
          witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology,
          witnessAuthorityTopology,
        ))
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Witness-ledger transition-admission witness authority topology must be recovered from admitted authority-transition history.",
        expected: witnessAuthorityTopology.topologyHash,
        actual:
          witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology
            ?.topologyHash ?? "none",
      });
    }
  }

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const witnessRecordHashValidation =
      verifyOperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitnessRecordHash(
        record,
      );
    const certificateHashValidation =
      verifyOperationalStateQuorumCertificateProofCertificateHash(
        record.admissionCertificate,
      );
    const previousWitnessHashAtSequence = witnessHashBySequence.get(
      record.witnessSequence,
    );

    if (
      previousWitnessHashAtSequence !== undefined &&
      previousWitnessHashAtSequence !== record.witnessRecordHash
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_record_fork",
        path: `${path}/witnessSequence`,
        message: `Witness-ledger checkpoint admission witness authority-transition admission witness sequence ${record.witnessSequence} has more than one witness record hash.`,
        expected: previousWitnessHashAtSequence,
        actual: record.witnessRecordHash,
      });
    } else if (previousWitnessHashAtSequence === undefined) {
      witnessHashBySequence.set(
        record.witnessSequence,
        record.witnessRecordHash,
      );
    }

    if (
      record.tenantId !== expectedTenantId ||
      record.admissionCertificate.tenantId !== expectedTenantId
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_record_tenant_mismatch",
        path,
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission witness record and certificate must match the replay tenant.",
        expected: expectedTenantId,
      });
    }
    if (
      record.transitionAdmissionWitnessStoreId !==
        input.transitionAdmissionWitnessStoreId ||
      record.transitionAdmissionStoreId !== input.transitionAdmissionStoreId
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_record_store_mismatch",
        path,
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission witness record must bind the expected witness and transition-admission stores.",
        expected: `${input.transitionAdmissionWitnessStoreId}:${input.transitionAdmissionStoreId}`,
        actual: `${record.transitionAdmissionWitnessStoreId}:${record.transitionAdmissionStoreId}`,
      });
    }
    if (
      record.topologyId !== input.topologyId ||
      record.authorityScope !== input.authorityScope ||
      record.admissionCertificate.authorityScope !== input.authorityScope
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_record_scope_mismatch",
        path,
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission witness record must share the replay topology and authority scope.",
        expected: `${input.topologyId}:${input.authorityScope}`,
      });
    }
    if (record.witnessSequence !== expectedSequence) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_record_sequence_gap",
        path: `${path}/witnessSequence`,
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission witness records must replay as a contiguous witness sequence.",
        expected: expectedSequence,
        actual: record.witnessSequence,
      });
    }
    if (record.previousWitnessRecordHash !== previousWitnessRecordHash) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_record_previous_hash_mismatch",
        path: `${path}/previousWitnessRecordHash`,
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission witness record does not chain to the previous witness record hash.",
        expected: previousWitnessRecordHash ?? "none",
        actual: record.previousWitnessRecordHash ?? "none",
      });
    }
    if (!certificateHashValidation.valid) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_certificate_hash_mismatch",
        path: `${path}/admissionCertificate/quorumCertificateHash`,
        message: `Witness-ledger checkpoint admission witness authority-transition admission witness certificate hash ${certificateHashValidation.actualHash} does not match recomputed hash ${certificateHashValidation.expectedHash}.`,
        expected: certificateHashValidation.expectedHash,
        actual: certificateHashValidation.actualHash,
      });
    }
    if (
      !record.admissionCertificate.certified ||
      record.admissionCertificate.status !== "certified"
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_certificate_not_certified",
        path: `${path}/admissionCertificate/status`,
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission cannot become accountable through a non-certified witness certificate.",
        expected: "certified",
        actual: record.admissionCertificate.status,
      });
    }
    if (
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.minimumWitnesses ||
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.requiredWitnesses
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_certificate_quorum_not_met",
        path: `${path}/admissionCertificate/acceptedWitnessIds`,
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission witness certificate does not satisfy its declared witness quorum.",
        expected: Math.max(
          record.admissionCertificate.requiredWitnesses,
          record.admissionCertificate.minimumWitnesses,
        ),
        actual: record.admissionCertificate.acceptedWitnessIds.length,
      });
    }
    if (
      record.admissionCertificate.subjectKind !==
        OPERATIONAL_STATE_WITNESS_LEDGER_COMPACTION_CHECKPOINT_ADMISSION_WITNESS_AUTHORITY_TRANSITION_ADMISSION_RECORD_SUBJECT_KIND ||
      record.admissionCertificate.subjectId !==
        operationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionSubjectId(
          record,
        ) ||
      record.admissionCertificate.subjectSequence !==
        record.admissionSequence ||
      record.admissionCertificate.subjectHash !== record.admissionRecordHash
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_certificate_subject_mismatch",
        path: `${path}/admissionCertificate`,
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission witness certificate must certify the exact transition-admission store, topology id, admission sequence, and admission record hash.",
        expected: record.admissionRecordHash,
        actual: record.admissionCertificate.subjectHash,
      });
    }
    if (
      input.requiredAuthorityBoundary !== undefined &&
      record.admissionCertificate.authorityBoundary !==
        input.requiredAuthorityBoundary
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_certificate_authority_boundary_mismatch",
        path: `${path}/admissionCertificate/authorityBoundary`,
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission witness certificate was admitted under the wrong authority boundary.",
        expected: input.requiredAuthorityBoundary,
        actual: record.admissionCertificate.authorityBoundary,
      });
    }
    if (witnessAuthorityTopology !== undefined) {
      if (
        record.admissionCertificate.authorityTopologyHash !==
        witnessAuthorityTopology.topologyHash
      ) {
        pushOperationalStateWitnessLedgerCompactionIssue(issues, {
          code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_certificate_authority_topology_mismatch",
          path: `${path}/admissionCertificate/authorityTopologyHash`,
          message:
            "Witness-ledger checkpoint admission witness authority-transition admission witness certificate is not bound to the replayed witness authority topology.",
          expected: witnessAuthorityTopology.topologyHash,
          actual:
            record.admissionCertificate.authorityTopologyHash ?? "none",
        });
      }

      const acceptedWitnessIds =
        record.admissionCertificate.acceptedWitnessIds;
      const uniqueAcceptedWitnessIds = new Set(acceptedWitnessIds);
      if (uniqueAcceptedWitnessIds.size !== acceptedWitnessIds.length) {
        pushOperationalStateWitnessLedgerCompactionIssue(issues, {
          code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_duplicate_witness",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Witness-ledger checkpoint admission witness authority-transition admission witness authority quorum cannot be satisfied by duplicate witness ids.",
          expected: uniqueAcceptedWitnessIds.size,
          actual: acceptedWitnessIds.length,
        });
      }

      let activeAuthorizedWitnessCount = 0;
      for (const witnessId of uniqueAcceptedWitnessIds) {
        const principal = principalById.get(witnessId);
        if (principal === undefined) {
          pushOperationalStateWitnessLedgerCompactionIssue(issues, {
            code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_witness_unknown",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Witness-ledger checkpoint admission witness authority-transition admission witness certificate names a witness outside the replayed authority topology.",
            expected: witnessAuthorityTopology.topologyHash,
            actual: witnessId,
          });
          continue;
        }
        if (principal.status !== "active") {
          pushOperationalStateWitnessLedgerCompactionIssue(issues, {
            code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_witness_not_active",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Witness-ledger checkpoint admission witness authority-transition admission witness certificate names a witness that is not active in the replayed authority topology.",
            expected: "active",
            actual: `${witnessId}:${principal.status}`,
          });
          continue;
        }
        activeAuthorizedWitnessCount += 1;
      }

      const requiredAuthorizedWitnesses = Math.max(
        witnessAuthorityTopology.requiredWitnesses ?? 0,
        witnessAuthorityTopology.minimumWitnesses ?? 0,
      );
      if (activeAuthorizedWitnessCount < requiredAuthorizedWitnesses) {
        pushOperationalStateWitnessLedgerCompactionIssue(issues, {
          code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_quorum_not_met",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Witness-ledger checkpoint admission witness authority-transition admission witness certificate does not satisfy the replayed witness authority topology quorum.",
          expected: requiredAuthorizedWitnesses,
          actual: activeAuthorizedWitnessCount,
        });
      }
    }
    if (!witnessRecordHashValidation.valid) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_record_hash_mismatch",
        path: `${path}/witnessRecordHash`,
        message: `Witness-ledger checkpoint admission witness authority-transition admission witness record hash ${witnessRecordHashValidation.actualHash} does not match recomputed hash ${witnessRecordHashValidation.expectedHash}.`,
        expected: witnessRecordHashValidation.expectedHash,
        actual: witnessRecordHashValidation.actualHash,
      });
    }

    witnessRecordByAdmissionHash.set(record.admissionRecordHash, record);
    expectedSequence = record.witnessSequence + 1;
    previousWitnessRecordHash = record.witnessRecordHash;
    latestWitnessRecord = record;
  });

  const requiredAdmissionRecord =
    input.requiredAdmissionRecord ?? input.admissionReplay?.latestAdmittedRecord;
  let requiredAdmissionWitnessRecord:
    | OperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitnessRecord
    | undefined;
  if (requiredAdmissionRecord !== undefined) {
    const admissionRecordHashValidation =
      verifyOperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionRecordHash(
        requiredAdmissionRecord,
      );
    if (!admissionRecordHashValidation.valid) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_record_hash_mismatch",
        path: "/requiredAdmissionRecord/admissionRecordHash",
        message: `Required witness-ledger checkpoint admission witness authority-transition admission hash ${admissionRecordHashValidation.actualHash} does not match recomputed hash ${admissionRecordHashValidation.expectedHash}.`,
        expected: admissionRecordHashValidation.expectedHash,
        actual: admissionRecordHashValidation.actualHash,
      });
    }
    requiredAdmissionWitnessRecord = witnessRecordByAdmissionHash.get(
      requiredAdmissionRecord.admissionRecordHash,
    );
    if (requiredAdmissionWitnessRecord === undefined) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_latest_record_not_witnessed",
        path: "/requiredAdmissionRecord/admissionRecordHash",
        message:
          "Latest witness-ledger checkpoint admission witness authority-transition admission record has no replayed witness certificate.",
        expected: requiredAdmissionRecord.admissionRecordHash,
      });
    } else if (
      requiredAdmissionWitnessRecord.transitionAdmissionStoreId !==
        requiredAdmissionRecord.transitionAdmissionStoreId ||
      requiredAdmissionWitnessRecord.topologyId !==
        requiredAdmissionRecord.topologyId ||
      requiredAdmissionWitnessRecord.admissionSequence !==
        requiredAdmissionRecord.admissionSequence ||
      requiredAdmissionWitnessRecord.authoritySequence !==
        requiredAdmissionRecord.authoritySequence ||
      requiredAdmissionWitnessRecord.authorityRecordHash !==
        requiredAdmissionRecord.authorityRecordHash ||
      requiredAdmissionWitnessRecord.nextAuthorityTopologyHash !==
        requiredAdmissionRecord.nextAuthorityTopologyHash
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_admission_record_mismatch",
        path: "/requiredAdmissionRecord",
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission witness record does not match the required admission store, topology, sequence, authority transition hash, and derived topology hash.",
        expected: requiredAdmissionRecord.admissionRecordHash,
        actual: requiredAdmissionWitnessRecord.admissionRecordHash,
      });
    }
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    transitionAdmissionWitnessStoreId:
      input.transitionAdmissionWitnessStoreId,
    transitionAdmissionStoreId: input.transitionAdmissionStoreId,
    topologyId: input.topologyId,
    authorityScope: input.authorityScope,
    witnessedRecordCount: input.records.length,
    ...(latestWitnessRecord !== undefined ? { latestWitnessRecord } : {}),
    ...(requiredAdmissionRecord !== undefined ? { requiredAdmissionRecord } : {}),
    ...(requiredAdmissionWitnessRecord !== undefined
      ? { requiredAdmissionWitnessRecord }
      : {}),
    ...(witnessAuthorityTopology !== undefined
      ? { witnessAuthorityTopology }
      : {}),
    ...(witnessAuthorityTransitionAdmissionReplay !== undefined
      ? { witnessAuthorityTransitionAdmissionReplay }
      : {}),
    issues,
  };
}

export function computeOperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionRecordHash(
  record: Omit<
    OperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionRecord,
    "admissionRecordHash"
  >,
): string {
  return fingerprint64(canonicalStringify(record));
}

export function buildOperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionRecord(
  input: OperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionRecordInput,
): OperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionRecord {
  const nextAuthorityTopology = operationalStateAuthorityTopologyFromTransition(
    input.authorityTransition,
    input.previousAuthorityTopology,
  );
  const payload: Omit<
    OperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionRecord,
    "admissionRecordHash"
  > = {
    schemaVersion:
      OPERATIONAL_STATE_WITNESS_LEDGER_COMPACTION_CHECKPOINT_ADMISSION_WITNESS_AUTHORITY_TRANSITION_ADMISSION_SCHEMA_VERSION,
    tenantId: tenantId(String(input.tenantId)),
    transitionAdmissionStoreId: input.transitionAdmissionStoreId,
    topologyId: input.topologyId,
    authorityScope: input.authorityScope,
    admissionSequence: input.admissionSequence,
    authoritySequence: input.authorityTransition.authoritySequence,
    authorityRecordHash: input.authorityTransition.authorityRecordHash,
    ...(input.authorityTransition.previousAuthorityRecordHash !== undefined
      ? {
          previousAuthorityRecordHash:
            input.authorityTransition.previousAuthorityRecordHash,
        }
      : {}),
    ...(input.previousAuthorityTopology !== undefined
      ? {
          previousAuthorityTopologyHash:
            input.previousAuthorityTopology.topologyHash,
        }
      : {}),
    nextAuthorityTopologyHash: nextAuthorityTopology.topologyHash,
    authorityTransition: input.authorityTransition,
    admissionCertificate: input.admissionCertificate,
    ...(input.previousAdmissionRecordHash !== undefined
      ? { previousAdmissionRecordHash: input.previousAdmissionRecordHash }
      : {}),
    admittedAt: input.admittedAt,
    admittedBy: input.admittedBy,
    ...(input.admissionReason !== undefined
      ? { admissionReason: input.admissionReason }
      : {}),
  };
  return {
    ...payload,
    admissionRecordHash:
      computeOperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionRecordHash(
        payload,
      ),
  };
}

export function verifyOperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionRecordHash(
  record: OperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionRecord,
): StateReviewArtifactHashValidation {
  const { admissionRecordHash, ...payload } = record;
  const expectedHash =
    computeOperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionRecordHash(
      payload,
    );
  return {
    valid: admissionRecordHash === expectedHash,
    expectedHash,
    actualHash: admissionRecordHash,
  };
}

function pushOperationalStateWitnessLedgerCompactionIssue(
  issues: OperationalStateWitnessLedgerCompactionIssue[],
  issue: OperationalStateWitnessLedgerCompactionIssue,
): void {
  issues.push(issue);
}

export function replayOperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionRecords(
  input: OperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionReplayInput,
): OperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionReplay {
  const issues: OperationalStateWitnessLedgerCompactionIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const admissionHashBySequence = new Map<number, string>();
  const admissionRecordByAuthorityHash = new Map<
    string,
    OperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionRecord
  >();
  const admissionWitnessReplay = input.admissionWitnessReplay;
  let expectedAdmissionSequence = 1;
  let expectedAuthoritySequence = 1;
  let previousAdmissionRecordHash: string | undefined;
  let previousAuthorityRecordHash: string | undefined;
  let previousTopology: OperationalStateAuthorityTopology | undefined;
  let latestAdmittedRecord:
    | OperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionRecord
    | undefined;
  let latestAdmittedTopology: OperationalStateAuthorityTopology | undefined;

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const recordHashValidation =
      verifyOperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionRecordHash(
        record,
      );
    const transitionHashValidation =
      verifyOperationalStateAuthorityTransitionRecordHash(
        record.authorityTransition,
      );
    const certificateHashValidation =
      verifyOperationalStateQuorumCertificateProofCertificateHash(
        record.admissionCertificate,
      );
    const previousAdmissionHashAtSequence = admissionHashBySequence.get(
      record.admissionSequence,
    );

    if (
      previousAdmissionHashAtSequence !== undefined &&
      previousAdmissionHashAtSequence !== record.admissionRecordHash
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_record_sequence_gap",
        path: `${path}/admissionSequence`,
        message: `Witness-ledger checkpoint admission witness authority-transition admission sequence ${record.admissionSequence} has more than one record hash.`,
        expected: previousAdmissionHashAtSequence,
        actual: record.admissionRecordHash,
      });
    } else if (previousAdmissionHashAtSequence === undefined) {
      admissionHashBySequence.set(
        record.admissionSequence,
        record.admissionRecordHash,
      );
    }

    if (
      record.tenantId !== expectedTenantId ||
      record.authorityTransition.tenantId !== expectedTenantId ||
      record.admissionCertificate.tenantId !== expectedTenantId
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_record_tenant_mismatch",
        path,
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission record, transition, and certificate must match the replay tenant.",
        expected: expectedTenantId,
      });
    }
    if (record.transitionAdmissionStoreId !== input.transitionAdmissionStoreId) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_record_store_mismatch",
        path: `${path}/transitionAdmissionStoreId`,
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission record belongs to a different admission store.",
        expected: input.transitionAdmissionStoreId,
        actual: record.transitionAdmissionStoreId,
      });
    }
    if (
      record.topologyId !== input.topologyId ||
      record.authorityTransition.topologyId !== input.topologyId
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_record_scope_mismatch",
        path: `${path}/topologyId`,
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission record must match the replay topology id.",
        expected: input.topologyId,
        actual: record.topologyId,
      });
    }
    if (
      record.authorityScope !== input.authorityScope ||
      record.authorityTransition.authorityScope !== input.authorityScope ||
      record.admissionCertificate.authorityScope !== input.authorityScope
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_record_scope_mismatch",
        path,
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission record, transition, and certificate must share the replay authority scope.",
        expected: input.authorityScope,
      });
    }
    if (record.admissionSequence !== expectedAdmissionSequence) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_record_sequence_gap",
        path: `${path}/admissionSequence`,
        message:
          "Witness-ledger checkpoint admission witness authority-transition admissions must replay as a contiguous admission sequence.",
        expected: expectedAdmissionSequence,
        actual: record.admissionSequence,
      });
    }
    if (record.previousAdmissionRecordHash !== previousAdmissionRecordHash) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_record_previous_hash_mismatch",
        path: `${path}/previousAdmissionRecordHash`,
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission record does not chain to the previous admission record hash.",
        expected: previousAdmissionRecordHash ?? "none",
        actual: record.previousAdmissionRecordHash ?? "none",
      });
    }
    if (!recordHashValidation.valid) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_record_hash_mismatch",
        path: `${path}/admissionRecordHash`,
        message: `Witness-ledger checkpoint admission witness authority-transition admission record hash ${recordHashValidation.actualHash} does not match recomputed hash ${recordHashValidation.expectedHash}.`,
        expected: recordHashValidation.expectedHash,
        actual: recordHashValidation.actualHash,
      });
    }
    if (!transitionHashValidation.valid) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_transition_hash_mismatch",
        path: `${path}/authorityTransition/authorityRecordHash`,
        message: `Witness-ledger checkpoint admission witness authority transition hash ${transitionHashValidation.actualHash} does not match recomputed hash ${transitionHashValidation.expectedHash}.`,
        expected: transitionHashValidation.expectedHash,
        actual: transitionHashValidation.actualHash,
      });
    }
    if (
      record.authoritySequence !==
        record.authorityTransition.authoritySequence ||
      record.authorityRecordHash !==
        record.authorityTransition.authorityRecordHash ||
      record.previousAuthorityRecordHash !==
        record.authorityTransition.previousAuthorityRecordHash
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_transition_mismatch",
        path: `${path}/authorityTransition`,
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission record does not match its embedded authority transition sequence and hash.",
        expected: record.authorityRecordHash,
        actual: record.authorityTransition.authorityRecordHash,
      });
    }
    if (record.authoritySequence !== expectedAuthoritySequence) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_transition_sequence_gap",
        path: `${path}/authoritySequence`,
        message:
          "Witness-ledger checkpoint admission witness authority transitions must be admitted in contiguous authority sequence.",
        expected: expectedAuthoritySequence,
        actual: record.authoritySequence,
      });
    }
    if (
      record.authorityTransition.previousAuthorityRecordHash !==
      previousAuthorityRecordHash
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_transition_previous_hash_mismatch",
        path: `${path}/authorityTransition/previousAuthorityRecordHash`,
        message:
          "Witness-ledger checkpoint admission witness authority transition must hash-chain from the previously admitted authority transition.",
        expected: previousAuthorityRecordHash ?? "none",
        actual:
          record.authorityTransition.previousAuthorityRecordHash ?? "none",
      });
    }
    if (record.authorityTransition.effectiveFromSubjectSequence < 1) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_transition_invalid",
        path: `${path}/authorityTransition/effectiveFromSubjectSequence`,
        message:
          "Witness-ledger checkpoint admission witness authority transitions must declare a positive effective admission sequence.",
        actual: record.authorityTransition.effectiveFromSubjectSequence,
      });
    }
    if (
      record.authorityTransition.transitionKind === "set_quorum" &&
      ((record.authorityTransition.requiredWitnesses ?? 0) < 1 ||
        (record.authorityTransition.minimumWitnesses ??
          record.authorityTransition.requiredWitnesses ??
          0) < 1 ||
        (record.authorityTransition.minimumWitnesses ??
          record.authorityTransition.requiredWitnesses ??
          0) > (record.authorityTransition.requiredWitnesses ?? 0))
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_transition_invalid",
        path: `${path}/authorityTransition/requiredWitnesses`,
        message:
          "Witness-ledger checkpoint admission witness authority quorum transitions must declare positive and internally consistent witness thresholds.",
      });
    }
    if (
      [
        "admit_principal",
        "suspend_principal",
        "revoke_principal",
        "rotate_signature_key",
        "mark_equivocated",
      ].includes(record.authorityTransition.transitionKind) &&
      (record.authorityTransition.principalId === undefined ||
        record.authorityTransition.principalId.length === 0)
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_transition_invalid",
        path: `${path}/authorityTransition/principalId`,
        message:
          "Witness-ledger checkpoint admission witness authority principal transitions must identify the affected principal.",
      });
    }
    if (
      record.authorityTransition.transitionKind === "seal_authority_epoch" &&
      ((record.authorityTransition.sealedThroughSubjectSequence ?? 0) < 1 ||
        record.authorityTransition.sealedQuorumCertificateHash === undefined ||
        record.authorityTransition.sealedQuorumCertificateHash.length === 0)
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_transition_invalid",
        path: `${path}/authorityTransition/sealedQuorumCertificateHash`,
        message:
          "Witness-ledger checkpoint admission witness authority epoch seals must bind a positive sealed frontier and a quorum certificate hash.",
      });
    }

    const nextTopology = operationalStateAuthorityTopologyFromTransition(
      record.authorityTransition,
      previousTopology,
    );
    if (record.nextAuthorityTopologyHash !== nextTopology.topologyHash) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_transition_topology_hash_mismatch",
        path: `${path}/nextAuthorityTopologyHash`,
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission record does not derive the expected next topology hash.",
        expected: nextTopology.topologyHash,
        actual: record.nextAuthorityTopologyHash,
      });
    }
    if (previousTopology === undefined) {
      if (record.previousAuthorityTopologyHash !== undefined) {
        pushOperationalStateWitnessLedgerCompactionIssue(issues, {
          code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_transition_previous_topology_hash_mismatch",
          path: `${path}/previousAuthorityTopologyHash`,
          message:
            "Genesis witness-ledger checkpoint admission witness authority transition cannot cite a previous topology hash.",
          actual: record.previousAuthorityTopologyHash,
        });
      }
    } else {
      if (
        record.previousAuthorityTopologyHash !== previousTopology.topologyHash
      ) {
        pushOperationalStateWitnessLedgerCompactionIssue(issues, {
          code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_transition_previous_topology_hash_mismatch",
          path: `${path}/previousAuthorityTopologyHash`,
          message:
            "Witness-ledger checkpoint admission witness authority transition admission must bind the previous replayed topology hash.",
          expected: previousTopology.topologyHash,
          actual: record.previousAuthorityTopologyHash ?? "none",
        });
      }
      if (
        record.admissionCertificate.authorityTopologyHash !==
        previousTopology.topologyHash
      ) {
        pushOperationalStateWitnessLedgerCompactionIssue(issues, {
          code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_certificate_authority_topology_mismatch",
          path: `${path}/admissionCertificate/authorityTopologyHash`,
          message:
            "Witness-ledger checkpoint admission witness authority transition admission certificate must be bound to the previous replayed topology.",
          expected: previousTopology.topologyHash,
          actual:
            record.admissionCertificate.authorityTopologyHash ?? "none",
        });
      }

      const principalById = new Map<
        string,
        OperationalStateAuthorityPrincipalState
      >(
        previousTopology.principals.map((principal) => [
          principal.principalId,
          principal,
        ]),
      );
      const acceptedWitnessIds =
        record.admissionCertificate.acceptedWitnessIds;
      const uniqueAcceptedWitnessIds = new Set(acceptedWitnessIds);
      if (uniqueAcceptedWitnessIds.size !== acceptedWitnessIds.length) {
        pushOperationalStateWitnessLedgerCompactionIssue(issues, {
          code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_authority_duplicate_witness",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Witness-ledger checkpoint admission witness authority-transition admission cannot be certified by duplicate prior-topology witnesses.",
          expected: uniqueAcceptedWitnessIds.size,
          actual: acceptedWitnessIds.length,
        });
      }

      let activeAuthorizedWitnessCount = 0;
      for (const witnessId of uniqueAcceptedWitnessIds) {
        const principal = principalById.get(witnessId);
        if (principal === undefined) {
          pushOperationalStateWitnessLedgerCompactionIssue(issues, {
            code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_authority_witness_unknown",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Witness-ledger checkpoint admission witness authority-transition admission certificate names a witness outside the previous replayed topology.",
            expected: previousTopology.topologyHash,
            actual: witnessId,
          });
          continue;
        }
        if (principal.status !== "active") {
          pushOperationalStateWitnessLedgerCompactionIssue(issues, {
            code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_authority_witness_not_active",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Witness-ledger checkpoint admission witness authority-transition admission certificate names a witness that is not active in the previous replayed topology.",
            expected: "active",
            actual: `${witnessId}:${principal.status}`,
          });
          continue;
        }
        activeAuthorizedWitnessCount += 1;
      }

      const requiredAuthorizedWitnesses = Math.max(
        previousTopology.requiredWitnesses ?? 0,
        previousTopology.minimumWitnesses ?? 0,
      );
      if (activeAuthorizedWitnessCount < requiredAuthorizedWitnesses) {
        pushOperationalStateWitnessLedgerCompactionIssue(issues, {
          code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_authority_quorum_not_met",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Witness-ledger checkpoint admission witness authority-transition admission certificate does not satisfy previous-topology quorum.",
          expected: requiredAuthorizedWitnesses,
          actual: activeAuthorizedWitnessCount,
        });
      }
    }

    if (!certificateHashValidation.valid) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_certificate_hash_mismatch",
        path: `${path}/admissionCertificate/quorumCertificateHash`,
        message: `Witness-ledger checkpoint admission witness authority-transition admission certificate hash ${certificateHashValidation.actualHash} does not match recomputed hash ${certificateHashValidation.expectedHash}.`,
        expected: certificateHashValidation.expectedHash,
        actual: certificateHashValidation.actualHash,
      });
    }
    if (
      !record.admissionCertificate.certified ||
      record.admissionCertificate.status !== "certified"
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_certificate_not_certified",
        path: `${path}/admissionCertificate/status`,
        message:
          "Witness-ledger checkpoint admission witness authority transition cannot become authority through a non-certified admission certificate.",
        expected: "certified",
        actual: record.admissionCertificate.status,
      });
    }
    if (
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.minimumWitnesses ||
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.requiredWitnesses
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_certificate_quorum_not_met",
        path: `${path}/admissionCertificate/acceptedWitnessIds`,
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission certificate does not satisfy its declared witness quorum.",
        expected: Math.max(
          record.admissionCertificate.requiredWitnesses,
          record.admissionCertificate.minimumWitnesses,
        ),
        actual: record.admissionCertificate.acceptedWitnessIds.length,
      });
    }
    if (
      record.admissionCertificate.subjectKind !==
        OPERATIONAL_STATE_AUTHORITY_TRANSITION_RECORD_SUBJECT_KIND ||
      record.admissionCertificate.subjectId !== record.topologyId ||
      record.admissionCertificate.subjectSequence !==
        record.authoritySequence ||
      record.admissionCertificate.subjectHash !== record.authorityRecordHash
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_certificate_subject_mismatch",
        path: `${path}/admissionCertificate`,
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission certificate must certify the exact topology id, authority sequence, and authority transition hash.",
        expected: record.authorityRecordHash,
        actual: record.admissionCertificate.subjectHash,
      });
    }
    if (
      input.requiredAuthorityBoundary !== undefined &&
      record.admissionCertificate.authorityBoundary !==
        input.requiredAuthorityBoundary
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_certificate_authority_boundary_mismatch",
        path: `${path}/admissionCertificate/authorityBoundary`,
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission certificate was admitted under the wrong authority boundary.",
        expected: input.requiredAuthorityBoundary,
        actual: record.admissionCertificate.authorityBoundary,
      });
    }

    admissionRecordByAuthorityHash.set(record.authorityRecordHash, record);
    expectedAdmissionSequence = record.admissionSequence + 1;
    expectedAuthoritySequence = record.authoritySequence + 1;
    previousAdmissionRecordHash = record.admissionRecordHash;
    previousAuthorityRecordHash = record.authorityRecordHash;
    previousTopology = nextTopology;
    latestAdmittedTopology = nextTopology;
    latestAdmittedRecord = record;
  });

  let requiredAuthorityTransitionAdmissionRecord:
    | OperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessAuthorityTransitionAdmissionRecord
    | undefined;
  if (input.requiredAuthorityTransition !== undefined) {
    const requiredTransitionHashValidation =
      verifyOperationalStateAuthorityTransitionRecordHash(
        input.requiredAuthorityTransition,
      );
    if (!requiredTransitionHashValidation.valid) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_transition_hash_mismatch",
        path: "/requiredAuthorityTransition/authorityRecordHash",
        message: `Required witness-ledger checkpoint admission witness authority transition hash ${requiredTransitionHashValidation.actualHash} does not match recomputed hash ${requiredTransitionHashValidation.expectedHash}.`,
        expected: requiredTransitionHashValidation.expectedHash,
        actual: requiredTransitionHashValidation.actualHash,
      });
    }
    requiredAuthorityTransitionAdmissionRecord =
      admissionRecordByAuthorityHash.get(
        input.requiredAuthorityTransition.authorityRecordHash,
      );
    if (requiredAuthorityTransitionAdmissionRecord === undefined) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_not_admitted",
        path: "/requiredAuthorityTransition/authorityRecordHash",
        message:
          "Required witness-ledger checkpoint admission witness authority transition has no replayed admission certificate.",
        expected: input.requiredAuthorityTransition.authorityRecordHash,
      });
    }
  }

  if (input.requiredAuthorityTopology !== undefined) {
    const requiredTopologyHashValidation =
      verifyOperationalStateAuthorityTopologyHash(
        input.requiredAuthorityTopology,
      );
    if (!requiredTopologyHashValidation.valid) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_topology_hash_mismatch",
        path: "/requiredAuthorityTopology/topologyHash",
        message: `Required witness-ledger checkpoint admission witness authority topology hash ${requiredTopologyHashValidation.actualHash} does not match recomputed hash ${requiredTopologyHashValidation.expectedHash}.`,
        expected: requiredTopologyHashValidation.expectedHash,
        actual: requiredTopologyHashValidation.actualHash,
      });
    }
    if (
      latestAdmittedTopology === undefined ||
      !operationalStateAuthorityTopologiesMatch(
        latestAdmittedTopology,
        input.requiredAuthorityTopology,
      )
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/requiredAuthorityTopology",
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission replay must recover the required authority topology.",
        expected: input.requiredAuthorityTopology.topologyHash,
        actual: latestAdmittedTopology?.topologyHash ?? "none",
      });
    }
    requiredAuthorityTransitionAdmissionRecord =
      admissionRecordByAuthorityHash.get(
        input.requiredAuthorityTopology.authorityRecordHash,
      );
    if (requiredAuthorityTransitionAdmissionRecord === undefined) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_not_admitted",
        path: "/requiredAuthorityTopology/authorityRecordHash",
        message:
          "Required witness-ledger checkpoint admission witness authority topology is not backed by an admitted authority transition.",
        expected: input.requiredAuthorityTopology.authorityRecordHash,
      });
    }
  }

  if (
    input.requireAdmissionWitness === true ||
    input.requireAdmissionWitnessAuthorityTopology === true ||
    input.requireAdmissionWitnessAuthorityTransitionAdmission === true
  ) {
    if (admissionWitnessReplay === undefined) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_replay_missing",
        path: "/admissionWitnessReplay",
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission replay requires transition-admission records to be witnessed.",
      });
    } else if (!admissionWitnessReplay.valid) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_replay_invalid",
        path: "/admissionWitnessReplay",
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission replay cannot consume invalid transition-admission witness history.",
        actual: admissionWitnessReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      latestAdmittedRecord === undefined ||
      admissionWitnessReplay.requiredAdmissionWitnessRecord === undefined ||
      admissionWitnessReplay.requiredAdmissionWitnessRecord
        .admissionRecordHash !== latestAdmittedRecord.admissionRecordHash
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_latest_record_not_witnessed",
        path: "/admissionWitnessReplay/requiredAdmissionWitnessRecord",
        message:
          "Latest witness-ledger checkpoint admission witness authority-transition admission record is not witnessed by the replayed transition-admission witness ledger.",
        expected: latestAdmittedRecord?.admissionRecordHash ?? "none",
        actual:
          admissionWitnessReplay.requiredAdmissionWitnessRecord
            ?.admissionRecordHash ?? "none",
      });
    } else if (
      (input.requireAdmissionWitnessAuthorityTopology === true ||
        input.requireAdmissionWitnessAuthorityTransitionAdmission === true) &&
      admissionWitnessReplay.witnessAuthorityTopology === undefined
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_topology_missing",
        path: "/admissionWitnessReplay/witnessAuthorityTopology",
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission replay requires its witness history to bind certificates to replayed witness authority topology.",
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmission === true &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay ===
        undefined
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        path: "/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission replay requires its witness authority topology to replay from admitted authority-transition history.",
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmission === true &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      !admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.valid
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        path: "/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission replay cannot consume invalid nested witness-authority transition admission history.",
        actual:
          admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.issues
            .map((issue) => issue.code)
            .join(","),
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmission === true &&
      admissionWitnessReplay.witnessAuthorityTopology !== undefined &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      (admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .latestAdmittedTopology === undefined ||
        !operationalStateAuthorityTopologiesMatch(
          admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology,
          admissionWitnessReplay.witnessAuthorityTopology,
        ))
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Witness-ledger checkpoint admission witness authority-transition admission witness authority topology must be recovered from admitted authority-transition history.",
        expected: admissionWitnessReplay.witnessAuthorityTopology.topologyHash,
        actual:
          admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology?.topologyHash ?? "none",
      });
    }
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    transitionAdmissionStoreId: input.transitionAdmissionStoreId,
    topologyId: input.topologyId,
    authorityScope: input.authorityScope,
    admittedRecordCount: input.records.length,
    ...(latestAdmittedRecord !== undefined ? { latestAdmittedRecord } : {}),
    ...(latestAdmittedTopology !== undefined ? { latestAdmittedTopology } : {}),
    ...(input.requiredAuthorityTopology !== undefined
      ? { requiredAuthorityTopology: input.requiredAuthorityTopology }
      : {}),
    ...(input.requiredAuthorityTransition !== undefined
      ? { requiredAuthorityTransition: input.requiredAuthorityTransition }
      : {}),
    ...(requiredAuthorityTransitionAdmissionRecord !== undefined
      ? { requiredAuthorityTransitionAdmissionRecord }
      : {}),
    ...(admissionWitnessReplay !== undefined ? { admissionWitnessReplay } : {}),
    issues,
  };
}

export function replayOperationalStateWitnessLedgerCompactionCheckpointAdmissionRecords(
  input: OperationalStateWitnessLedgerCompactionCheckpointAdmissionReplayInput,
): OperationalStateWitnessLedgerCompactionCheckpointAdmissionReplay {
  const issues: OperationalStateWitnessLedgerCompactionIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const recordHashBySequence = new Map<number, string>();
  let expectedSequence = 1;
  let previousAdmissionRecordHash: string | undefined;
  let latestAdmittedRecord:
    | OperationalStateWitnessLedgerCompactionCheckpointAdmissionRecord
    | undefined;

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const recordHashValidation =
      verifyOperationalStateWitnessLedgerCompactionCheckpointAdmissionRecordHash(
        record,
      );
    const checkpointHashValidation =
      verifyOperationalStateWitnessLedgerCompactionCheckpointHash(
        record.checkpoint,
      );
    const compactedLedgerHeadHashValidation =
      verifyOperationalStateWitnessLedgerHeadHash(
        record.checkpoint.compactedLedgerHead,
      );
    const certificateHashValidation =
      verifyOperationalStateQuorumCertificateProofCertificateHash(
        record.quorumCertificate,
      );
    const previousRecordHashAtSequence = recordHashBySequence.get(
      record.admissionSequence,
    );

    if (
      previousRecordHashAtSequence !== undefined &&
      previousRecordHashAtSequence !== record.admissionRecordHash
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_record_fork",
        path: `${path}/admissionSequence`,
        message: `Witness-ledger checkpoint admission sequence ${record.admissionSequence} has more than one record hash.`,
        expected: previousRecordHashAtSequence,
        actual: record.admissionRecordHash,
      });
    } else if (previousRecordHashAtSequence === undefined) {
      recordHashBySequence.set(
        record.admissionSequence,
        record.admissionRecordHash,
      );
    }

    if (
      record.tenantId !== expectedTenantId ||
      record.checkpoint.tenantId !== expectedTenantId ||
      record.quorumCertificate.tenantId !== expectedTenantId
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_record_tenant_mismatch",
        path,
        message:
          "Witness-ledger checkpoint admission record, checkpoint, and certificate must match the replay tenant.",
        expected: expectedTenantId,
      });
    }
    if (record.checkpointAdmissionStoreId !== input.checkpointAdmissionStoreId) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_record_store_mismatch",
        path: `${path}/checkpointAdmissionStoreId`,
        message:
          "Witness-ledger checkpoint admission record belongs to a different admission store.",
        expected: input.checkpointAdmissionStoreId,
        actual: record.checkpointAdmissionStoreId,
      });
    }
    if (
      record.witnessLedgerId !== input.witnessLedgerId ||
      record.checkpoint.ledgerId !== input.witnessLedgerId
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_record_ledger_mismatch",
        path: `${path}/witnessLedgerId`,
        message:
          "Witness-ledger checkpoint admission record must bind the expected witness ledger.",
        expected: input.witnessLedgerId,
        actual: record.witnessLedgerId,
      });
    }
    if (
      record.authorityScope !== input.authorityScope ||
      record.checkpoint.authorityScope !== input.authorityScope ||
      record.quorumCertificate.authorityScope !== input.authorityScope
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_record_scope_mismatch",
        path,
        message:
          "Witness-ledger checkpoint admission record, checkpoint, and certificate must share the replay authority scope.",
        expected: input.authorityScope,
      });
    }
    if (record.admissionSequence !== expectedSequence) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_record_sequence_gap",
        path: `${path}/admissionSequence`,
        message:
          "Witness-ledger checkpoint admission records must replay as a contiguous sequence.",
        expected: expectedSequence,
        actual: record.admissionSequence,
      });
    }
    if (record.previousAdmissionRecordHash !== previousAdmissionRecordHash) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_record_previous_hash_mismatch",
        path: `${path}/previousAdmissionRecordHash`,
        message:
          "Witness-ledger checkpoint admission record does not chain to the previous admission record hash.",
        expected: previousAdmissionRecordHash ?? "none",
        actual: record.previousAdmissionRecordHash ?? "none",
      });
    }
    if (
      record.checkpointId !== record.checkpoint.checkpointId ||
      record.checkpointHash !== record.checkpoint.checkpointHash ||
      !checkpointHashValidation.valid ||
      !compactedLedgerHeadHashValidation.valid
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_record_checkpoint_hash_mismatch",
        path: `${path}/checkpointHash`,
        message:
          "Witness-ledger checkpoint admission record must hash-bind the exact embedded checkpoint and compacted ledger head.",
        expected: checkpointHashValidation.expectedHash,
        actual: record.checkpointHash,
      });
    }
    if (!certificateHashValidation.valid) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_record_certificate_hash_mismatch",
        path: `${path}/quorumCertificate/quorumCertificateHash`,
        message: `Witness-ledger checkpoint admission certificate hash ${certificateHashValidation.actualHash} does not match recomputed hash ${certificateHashValidation.expectedHash}.`,
        expected: certificateHashValidation.expectedHash,
        actual: certificateHashValidation.actualHash,
      });
    }
    if (
      !record.quorumCertificate.certified ||
      record.quorumCertificate.status !== "certified"
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_record_certificate_not_certified",
        path: `${path}/quorumCertificate/status`,
        message:
          "Witness-ledger compaction checkpoint cannot be admitted by a non-certified quorum certificate.",
        expected: "certified",
        actual: record.quorumCertificate.status,
      });
    }
    if (
      record.quorumCertificate.acceptedWitnessIds.length <
        record.quorumCertificate.minimumWitnesses ||
      record.quorumCertificate.acceptedWitnessIds.length <
        record.quorumCertificate.requiredWitnesses
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_record_certificate_quorum_not_met",
        path: `${path}/quorumCertificate/acceptedWitnessIds`,
        message:
          "Witness-ledger compaction checkpoint certificate does not satisfy its witness quorum.",
        expected: Math.max(
          record.quorumCertificate.requiredWitnesses,
          record.quorumCertificate.minimumWitnesses,
        ),
        actual: record.quorumCertificate.acceptedWitnessIds.length,
      });
    }
    if (
      record.quorumCertificate.subjectKind !==
        OPERATIONAL_STATE_WITNESS_LEDGER_COMPACTION_CHECKPOINT_SUBJECT_KIND ||
      record.quorumCertificate.subjectId !== record.checkpoint.checkpointId ||
      record.quorumCertificate.subjectSequence !==
        record.checkpoint.compactedThroughSequence ||
      record.quorumCertificate.subjectHash !== record.checkpoint.checkpointHash
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_record_certificate_subject_mismatch",
        path: `${path}/quorumCertificate`,
        message:
          "Witness-ledger compaction checkpoint certificate must certify the exact checkpoint hash and compacted frontier.",
        expected: record.checkpoint.checkpointHash,
        actual: record.quorumCertificate.subjectHash,
      });
    }
    if (
      input.requiredAuthorityBoundary !== undefined &&
      record.quorumCertificate.authorityBoundary !==
        input.requiredAuthorityBoundary
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_record_certificate_authority_boundary_mismatch",
        path: `${path}/quorumCertificate/authorityBoundary`,
        message:
          "Witness-ledger compaction checkpoint certificate was admitted under the wrong authority boundary.",
        expected: input.requiredAuthorityBoundary,
        actual: record.quorumCertificate.authorityBoundary,
      });
    }
    if (!recordHashValidation.valid) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_record_hash_mismatch",
        path: `${path}/admissionRecordHash`,
        message: `Witness-ledger checkpoint admission record hash ${recordHashValidation.actualHash} does not match recomputed hash ${recordHashValidation.expectedHash}.`,
        expected: recordHashValidation.expectedHash,
        actual: recordHashValidation.actualHash,
      });
    }

    expectedSequence = record.admissionSequence + 1;
    previousAdmissionRecordHash = record.admissionRecordHash;
    latestAdmittedRecord = record;
  });

  if (input.requiredCheckpoint !== undefined) {
    const requiredCheckpointHashValidation =
      verifyOperationalStateWitnessLedgerCompactionCheckpointHash(
        input.requiredCheckpoint,
      );
    if (!requiredCheckpointHashValidation.valid) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_record_checkpoint_hash_mismatch",
        path: "/requiredCheckpoint/checkpointHash",
        message: `Required witness-ledger checkpoint hash ${requiredCheckpointHashValidation.actualHash} does not match recomputed hash ${requiredCheckpointHashValidation.expectedHash}.`,
        expected: requiredCheckpointHashValidation.expectedHash,
        actual: requiredCheckpointHashValidation.actualHash,
      });
    }
    if (latestAdmittedRecord === undefined) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_not_admitted",
        path: "/records",
        message:
          "Witness-ledger checkpoint admission replay has no records for the required checkpoint.",
        expected: input.requiredCheckpoint.checkpointHash,
      });
    } else if (
      latestAdmittedRecord.checkpointHash !==
      input.requiredCheckpoint.checkpointHash
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_not_admitted",
        path: "/requiredCheckpoint/checkpointHash",
        message:
          "Required witness-ledger compaction checkpoint is not the latest admitted checkpoint.",
        expected: input.requiredCheckpoint.checkpointHash,
        actual: latestAdmittedRecord.checkpointHash,
      });
    }
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    checkpointAdmissionStoreId: input.checkpointAdmissionStoreId,
    witnessLedgerId: input.witnessLedgerId,
    authorityScope: input.authorityScope,
    admittedRecordCount: input.records.length,
    ...(latestAdmittedRecord !== undefined ? { latestAdmittedRecord } : {}),
    ...(input.requiredCheckpoint !== undefined
      ? { requiredCheckpoint: input.requiredCheckpoint }
      : {}),
    issues,
  };
}

export function replayOperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessRecords(
  input: OperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessReplayInput,
): OperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessReplay {
  const issues: OperationalStateWitnessLedgerCompactionIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const witnessHashBySequence = new Map<number, string>();
  const witnessRecordByAdmissionHash = new Map<
    string,
    OperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessRecord
  >();
  const witnessAuthorityTopology = input.witnessAuthorityTopology;
  const witnessAuthorityTransitionAdmissionReplay =
    input.witnessAuthorityTransitionAdmissionReplay;
  const principalById = new Map<string, OperationalStateAuthorityPrincipalState>(
    witnessAuthorityTopology?.principals.map((principal) => [
      principal.principalId,
      principal,
    ]) ?? [],
  );
  let expectedSequence = 1;
  let previousWitnessRecordHash: string | undefined;
  let latestWitnessRecord:
    | OperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessRecord
    | undefined;

  if (input.admissionReplay !== undefined && !input.admissionReplay.valid) {
    issues.push({
      code: "operational_state_witness_ledger_checkpoint_admission_witness_admission_replay_invalid",
      path: "/admissionReplay",
      message:
        "Witness-ledger checkpoint admission witness replay cannot account for an invalid checkpoint-admission replay.",
      actual: input.admissionReplay.issues
        .map((issue) => issue.code)
        .join(","),
      });
  }

  if (
    (input.requireWitnessAuthorityTopology === true ||
      input.requireWitnessAuthorityTransitionAdmission === true ||
      input.requireWitnessAuthorityTransitionAdmissionWitness === true ||
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input
        .requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    witnessAuthorityTopology === undefined
  ) {
    issues.push({
      code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_topology_missing",
      path: "/witnessAuthorityTopology",
      message:
        "Witness-ledger checkpoint admission witness replay requires a replayed witness authority topology.",
    });
  }

  if (witnessAuthorityTopology !== undefined) {
    const topologyHashValidation =
      verifyOperationalStateAuthorityTopologyHash(witnessAuthorityTopology);
    if (!topologyHashValidation.valid) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_topology_hash_mismatch",
        path: "/witnessAuthorityTopology/topologyHash",
        message: `Witness-ledger checkpoint admission witness authority topology hash ${topologyHashValidation.actualHash} does not match recomputed hash ${topologyHashValidation.expectedHash}.`,
        expected: topologyHashValidation.expectedHash,
        actual: topologyHashValidation.actualHash,
      });
    }
    if (witnessAuthorityTopology.tenantId !== expectedTenantId) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_topology_tenant_mismatch",
        path: "/witnessAuthorityTopology/tenantId",
        message:
          "Witness-ledger checkpoint admission witness authority topology tenant does not match replay tenant.",
        expected: expectedTenantId,
        actual: witnessAuthorityTopology.tenantId,
      });
    }
    if (witnessAuthorityTopology.authorityScope !== input.authorityScope) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_topology_scope_mismatch",
        path: "/witnessAuthorityTopology/authorityScope",
        message:
          "Witness-ledger checkpoint admission witness authority topology scope does not match replay scope.",
        expected: input.authorityScope,
        actual: witnessAuthorityTopology.authorityScope,
      });
    }
    if (
      witnessAuthorityTopology.requiredWitnesses === undefined ||
      witnessAuthorityTopology.minimumWitnesses === undefined
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_quorum_missing",
        path: "/witnessAuthorityTopology/requiredWitnesses",
        message:
          "Witness-ledger checkpoint admission witness authority topology must define quorum thresholds.",
      });
    }
  }

  if (
    input.requireWitnessAuthorityTransitionAdmission === true ||
    input.requireWitnessAuthorityTransitionAdmissionWitness === true ||
    input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
      true ||
    input
      .requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
      true
  ) {
    if (witnessAuthorityTransitionAdmissionReplay === undefined) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_replay_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Witness-ledger checkpoint admission witness replay requires admitted checkpoint-admission witness-authority transition history.",
      });
    } else if (!witnessAuthorityTransitionAdmissionReplay.valid) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_replay_invalid",
        path: "/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Witness-ledger checkpoint admission witness replay cannot consume invalid checkpoint-admission witness-authority transition admission history.",
        actual: witnessAuthorityTransitionAdmissionReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      witnessAuthorityTopology !== undefined &&
      (witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology ===
        undefined ||
        !operationalStateAuthorityTopologiesMatch(
          witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology,
          witnessAuthorityTopology,
        ))
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Witness-ledger checkpoint admission witness authority topology must be recovered from admitted authority-transition history.",
        expected: witnessAuthorityTopology.topologyHash,
        actual:
          witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology
            ?.topologyHash ?? "none",
      });
    }
  }

  if (
    (input.requireWitnessAuthorityTransitionAdmissionWitness === true ||
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input
        .requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    witnessAuthorityTransitionAdmissionReplay !== undefined
  ) {
    if (witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay === undefined) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_replay_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
        message:
          "Witness-ledger checkpoint admission witness replay requires checkpoint-admission witness authority-transition admission records to be witnessed.",
      });
    } else if (
      !witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay.valid
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_replay_invalid",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
        message:
          "Witness-ledger checkpoint admission witness replay cannot consume invalid checkpoint-admission witness authority-transition admission witness history.",
        actual:
          witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay.issues
            .map((issue) => issue.code)
            .join(","),
      });
    } else if (
      (input
        .requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
        input
          .requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
          true) &&
      witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTopology === undefined
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_topology_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTopology",
        message:
          "Witness-ledger checkpoint admission witness replay requires checkpoint-admission witness authority-transition admission witness certificates to bind to replayed witness authority topology.",
      });
    } else if (
      input
        .requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTransitionAdmissionReplay === undefined
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Witness-ledger checkpoint admission witness replay requires checkpoint-admission witness authority-transition admission witness authority topology to replay from admitted authority-transition history.",
      });
    } else if (
      input
        .requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTransitionAdmissionReplay !== undefined &&
      !witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTransitionAdmissionReplay.valid
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Witness-ledger checkpoint admission witness replay cannot consume invalid nested checkpoint-admission witness authority-transition admission witness authority history.",
        actual:
          witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.issues
            .map((issue) => issue.code)
            .join(","),
      });
    } else if (
      input
        .requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTopology !== undefined &&
      witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTransitionAdmissionReplay !== undefined &&
      (witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology ===
        undefined ||
        !operationalStateAuthorityTopologiesMatch(
          witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
            .witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology,
          witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
            .witnessAuthorityTopology,
        ))
    ) {
      pushOperationalStateWitnessLedgerCompactionIssue(issues, {
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Witness-ledger checkpoint admission witness replay requires checkpoint-admission witness authority-transition admission witness authority topology to be recovered from admitted authority-transition history.",
        expected:
          witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
            .witnessAuthorityTopology.topologyHash,
        actual:
          witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
            .witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology
            ?.topologyHash ?? "none",
      });
    }
  }

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const witnessRecordHashValidation =
      verifyOperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessRecordHash(
        record,
      );
    const certificateHashValidation =
      verifyOperationalStateQuorumCertificateProofCertificateHash(
        record.admissionCertificate,
      );
    const previousWitnessHashAtSequence = witnessHashBySequence.get(
      record.witnessSequence,
    );
    const expectedSubjectId =
      operationalStateWitnessLedgerCompactionCheckpointAdmissionSubjectId(
        record,
      );

    if (
      previousWitnessHashAtSequence !== undefined &&
      previousWitnessHashAtSequence !== record.witnessRecordHash
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_record_fork",
        path: `${path}/witnessSequence`,
        message: `Witness-ledger checkpoint admission witness sequence ${record.witnessSequence} has more than one witness record hash.`,
        expected: previousWitnessHashAtSequence,
        actual: record.witnessRecordHash,
      });
    } else if (previousWitnessHashAtSequence === undefined) {
      witnessHashBySequence.set(
        record.witnessSequence,
        record.witnessRecordHash,
      );
    }

    if (
      record.tenantId !== expectedTenantId ||
      record.admissionCertificate.tenantId !== expectedTenantId
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_record_tenant_mismatch",
        path,
        message:
          "Witness-ledger checkpoint admission witness record and certificate must match the replay tenant.",
        expected: expectedTenantId,
      });
    }
    if (
      record.checkpointAdmissionWitnessStoreId !==
        input.checkpointAdmissionWitnessStoreId ||
      record.checkpointAdmissionStoreId !== input.checkpointAdmissionStoreId
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_record_store_mismatch",
        path,
        message:
          "Witness-ledger checkpoint admission witness record must bind the expected witness store and admission store.",
        expected: `${input.checkpointAdmissionWitnessStoreId}:${input.checkpointAdmissionStoreId}`,
        actual: `${record.checkpointAdmissionWitnessStoreId}:${record.checkpointAdmissionStoreId}`,
      });
    }
    if (record.witnessLedgerId !== input.witnessLedgerId) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_record_ledger_mismatch",
        path: `${path}/witnessLedgerId`,
        message:
          "Witness-ledger checkpoint admission witness record must bind the expected witness ledger.",
        expected: input.witnessLedgerId,
        actual: record.witnessLedgerId,
      });
    }
    if (
      record.authorityScope !== input.authorityScope ||
      record.admissionCertificate.authorityScope !== input.authorityScope
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_record_scope_mismatch",
        path,
        message:
          "Witness-ledger checkpoint admission witness record and certificate must share the replay authority scope.",
        expected: input.authorityScope,
      });
    }
    if (record.witnessSequence !== expectedSequence) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_record_sequence_gap",
        path: `${path}/witnessSequence`,
        message:
          "Witness-ledger checkpoint admission witness records must replay as a contiguous witness sequence.",
        expected: expectedSequence,
        actual: record.witnessSequence,
      });
    }
    if (record.previousWitnessRecordHash !== previousWitnessRecordHash) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_record_previous_hash_mismatch",
        path: `${path}/previousWitnessRecordHash`,
        message:
          "Witness-ledger checkpoint admission witness record does not chain to the previous witness record hash.",
        expected: previousWitnessRecordHash ?? "none",
        actual: record.previousWitnessRecordHash ?? "none",
      });
    }
    if (!certificateHashValidation.valid) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_certificate_hash_mismatch",
        path: `${path}/admissionCertificate/quorumCertificateHash`,
        message: `Witness-ledger checkpoint admission witness certificate hash ${certificateHashValidation.actualHash} does not match recomputed hash ${certificateHashValidation.expectedHash}.`,
        expected: certificateHashValidation.expectedHash,
        actual: certificateHashValidation.actualHash,
      });
    }
    if (
      !record.admissionCertificate.certified ||
      record.admissionCertificate.status !== "certified"
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_certificate_not_certified",
        path: `${path}/admissionCertificate/status`,
        message:
          "Witness-ledger checkpoint admission cannot become accountable through a non-certified witness certificate.",
        expected: "certified",
        actual: record.admissionCertificate.status,
      });
    }
    if (
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.minimumWitnesses ||
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.requiredWitnesses
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_certificate_quorum_not_met",
        path: `${path}/admissionCertificate/acceptedWitnessIds`,
        message:
          "Witness-ledger checkpoint admission witness certificate does not satisfy its witness quorum.",
        expected: Math.max(
          record.admissionCertificate.requiredWitnesses,
          record.admissionCertificate.minimumWitnesses,
        ),
        actual: record.admissionCertificate.acceptedWitnessIds.length,
      });
    }
    if (
      record.admissionCertificate.subjectKind !==
        OPERATIONAL_STATE_WITNESS_LEDGER_COMPACTION_CHECKPOINT_ADMISSION_RECORD_SUBJECT_KIND ||
      record.admissionCertificate.subjectId !== expectedSubjectId ||
      record.admissionCertificate.subjectSequence !==
        record.admissionSequence ||
      record.admissionCertificate.subjectHash !== record.admissionRecordHash
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_certificate_subject_mismatch",
        path: `${path}/admissionCertificate`,
        message:
          "Witness-ledger checkpoint admission witness certificate must certify the exact checkpoint admission sequence and admission record hash.",
        expected: record.admissionRecordHash,
        actual: record.admissionCertificate.subjectHash,
      });
    }
    if (
      input.requiredAuthorityBoundary !== undefined &&
      record.admissionCertificate.authorityBoundary !==
        input.requiredAuthorityBoundary
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_certificate_authority_boundary_mismatch",
        path: `${path}/admissionCertificate/authorityBoundary`,
        message:
          "Witness-ledger checkpoint admission witness certificate was admitted under the wrong authority boundary.",
        expected: input.requiredAuthorityBoundary,
        actual: record.admissionCertificate.authorityBoundary,
      });
    }
    if (witnessAuthorityTopology !== undefined) {
      if (
        record.admissionCertificate.authorityTopologyHash !==
        witnessAuthorityTopology.topologyHash
      ) {
        issues.push({
          code: "operational_state_witness_ledger_checkpoint_admission_witness_certificate_authority_topology_mismatch",
          path: `${path}/admissionCertificate/authorityTopologyHash`,
          message:
            "Witness-ledger checkpoint admission witness certificate is not bound to the replayed witness authority topology.",
          expected: witnessAuthorityTopology.topologyHash,
          actual:
            record.admissionCertificate.authorityTopologyHash ?? "none",
        });
      }

      const acceptedWitnessIds =
        record.admissionCertificate.acceptedWitnessIds;
      const uniqueAcceptedWitnessIds = new Set(acceptedWitnessIds);
      if (uniqueAcceptedWitnessIds.size !== acceptedWitnessIds.length) {
        issues.push({
          code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_duplicate_witness",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Witness-ledger checkpoint admission witness authority quorum cannot be satisfied by duplicate witness ids.",
          expected: uniqueAcceptedWitnessIds.size,
          actual: acceptedWitnessIds.length,
        });
      }

      let activeAuthorizedWitnessCount = 0;
      for (const witnessId of uniqueAcceptedWitnessIds) {
        const principal = principalById.get(witnessId);
        if (principal === undefined) {
          issues.push({
            code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_witness_unknown",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Witness-ledger checkpoint admission witness certificate names a witness that is not present in the replayed authority topology.",
            expected: witnessAuthorityTopology.topologyHash,
            actual: witnessId,
          });
          continue;
        }
        if (principal.status !== "active") {
          issues.push({
            code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_witness_not_active",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Witness-ledger checkpoint admission witness certificate names a witness that is not active in the replayed authority topology.",
            expected: "active",
            actual: `${witnessId}:${principal.status}`,
          });
          continue;
        }
        activeAuthorizedWitnessCount += 1;
      }

      const requiredAuthorizedWitnesses = Math.max(
        witnessAuthorityTopology.requiredWitnesses ?? 0,
        witnessAuthorityTopology.minimumWitnesses ?? 0,
      );
      if (activeAuthorizedWitnessCount < requiredAuthorizedWitnesses) {
        issues.push({
          code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_quorum_not_met",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Witness-ledger checkpoint admission witness certificate does not satisfy the replayed witness authority topology quorum.",
          expected: requiredAuthorizedWitnesses,
          actual: activeAuthorizedWitnessCount,
        });
      }
    }
    if (!witnessRecordHashValidation.valid) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_record_hash_mismatch",
        path: `${path}/witnessRecordHash`,
        message: `Witness-ledger checkpoint admission witness record hash ${witnessRecordHashValidation.actualHash} does not match recomputed hash ${witnessRecordHashValidation.expectedHash}.`,
        expected: witnessRecordHashValidation.expectedHash,
        actual: witnessRecordHashValidation.actualHash,
      });
    }

    witnessRecordByAdmissionHash.set(record.admissionRecordHash, record);
    expectedSequence = record.witnessSequence + 1;
    previousWitnessRecordHash = record.witnessRecordHash;
    latestWitnessRecord = record;
  });

  const requiredAdmissionRecord =
    input.requiredAdmissionRecord ??
    input.admissionReplay?.latestAdmittedRecord;
  let requiredAdmissionWitnessRecord:
    | OperationalStateWitnessLedgerCompactionCheckpointAdmissionWitnessRecord
    | undefined;
  if (requiredAdmissionRecord !== undefined) {
    const admissionRecordHashValidation =
      verifyOperationalStateWitnessLedgerCompactionCheckpointAdmissionRecordHash(
        requiredAdmissionRecord,
      );
    if (!admissionRecordHashValidation.valid) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_record_hash_mismatch",
        path: "/requiredAdmissionRecord/admissionRecordHash",
        message: `Required witness-ledger checkpoint admission record hash ${admissionRecordHashValidation.actualHash} does not match recomputed hash ${admissionRecordHashValidation.expectedHash}.`,
        expected: admissionRecordHashValidation.expectedHash,
        actual: admissionRecordHashValidation.actualHash,
      });
    }
    requiredAdmissionWitnessRecord = witnessRecordByAdmissionHash.get(
      requiredAdmissionRecord.admissionRecordHash,
    );
    if (requiredAdmissionWitnessRecord === undefined) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_latest_record_not_witnessed",
        path: "/requiredAdmissionRecord/admissionRecordHash",
        message:
          "Latest witness-ledger checkpoint admission record has no replayed witness certificate.",
        expected: requiredAdmissionRecord.admissionRecordHash,
      });
    } else if (
      requiredAdmissionWitnessRecord.admissionSequence !==
        requiredAdmissionRecord.admissionSequence ||
      requiredAdmissionWitnessRecord.checkpointId !==
        requiredAdmissionRecord.checkpointId ||
      requiredAdmissionWitnessRecord.checkpointHash !==
        requiredAdmissionRecord.checkpointHash ||
      requiredAdmissionWitnessRecord.checkpointAdmissionStoreId !==
        requiredAdmissionRecord.checkpointAdmissionStoreId ||
      requiredAdmissionWitnessRecord.witnessLedgerId !==
        requiredAdmissionRecord.witnessLedgerId
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_admission_record_mismatch",
        path: "/requiredAdmissionRecord",
        message:
          "Witness-ledger checkpoint admission witness record does not match the required checkpoint admission, ledger, checkpoint, and sequence.",
        expected: requiredAdmissionRecord.admissionRecordHash,
        actual: requiredAdmissionWitnessRecord.admissionRecordHash,
      });
    }
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    checkpointAdmissionWitnessStoreId:
      input.checkpointAdmissionWitnessStoreId,
    checkpointAdmissionStoreId: input.checkpointAdmissionStoreId,
    witnessLedgerId: input.witnessLedgerId,
    authorityScope: input.authorityScope,
    witnessedRecordCount: input.records.length,
    ...(latestWitnessRecord !== undefined ? { latestWitnessRecord } : {}),
    ...(requiredAdmissionRecord !== undefined ? { requiredAdmissionRecord } : {}),
    ...(requiredAdmissionWitnessRecord !== undefined
      ? { requiredAdmissionWitnessRecord }
      : {}),
    ...(witnessAuthorityTopology !== undefined
      ? { witnessAuthorityTopology }
      : {}),
    ...(witnessAuthorityTransitionAdmissionReplay !== undefined
      ? { witnessAuthorityTransitionAdmissionReplay }
      : {}),
    issues,
  };
}

function operationalStateAdmissibleHeadsMatch(
  left: OperationalStateAdmissibleHead,
  right: OperationalStateAdmissibleHead,
): boolean {
  return (
    left.tenantId === right.tenantId &&
    left.storeId === right.storeId &&
    left.authorityScope === right.authorityScope &&
    left.sequence === right.sequence &&
    left.headHash === right.headHash &&
    left.recordHash === right.recordHash
  );
}

export function evaluateOperationalStateWitnessLedgerCompaction(
  input: OperationalStateWitnessLedgerCompactionEvaluationInput,
): OperationalStateWitnessLedgerCompactionEvaluation {
  const issues: OperationalStateWitnessLedgerCompactionIssue[] = [];
  const checkpoint = input.checkpoint;

  if (checkpoint === undefined) {
    return {
      valid: false,
      acceptedRecordCount: 0,
      obstructionCount: 0,
      ...(input.requiredHead !== undefined
        ? { requiredHead: input.requiredHead }
        : {}),
      issues: [
        {
          code: "operational_state_witness_ledger_checkpoint_missing",
          path: "/checkpoint",
          message:
            "Compacted witness-ledger history cannot recover accepted required-head authority without a replayable compaction checkpoint.",
        },
      ],
    };
  }

  const checkpointHashValidation =
    verifyOperationalStateWitnessLedgerCompactionCheckpointHash(checkpoint);
  if (!checkpointHashValidation.valid) {
    issues.push({
      code: "operational_state_witness_ledger_checkpoint_hash_mismatch",
      path: "/checkpoint/checkpointHash",
      message: `Witness-ledger compaction checkpoint hash ${checkpointHashValidation.actualHash} does not match recomputed hash ${checkpointHashValidation.expectedHash}.`,
      expected: checkpointHashValidation.expectedHash,
      actual: checkpointHashValidation.actualHash,
    });
  }

  const compactedHeadHashValidation =
    verifyOperationalStateWitnessLedgerHeadHash(checkpoint.compactedLedgerHead);
  if (!compactedHeadHashValidation.valid) {
    issues.push({
      code: "operational_state_witness_ledger_compacted_head_hash_mismatch",
      path: "/checkpoint/compactedLedgerHead/headHash",
      message: `Compacted witness-ledger head hash ${compactedHeadHashValidation.actualHash} does not match recomputed hash ${compactedHeadHashValidation.expectedHash}.`,
      expected: compactedHeadHashValidation.expectedHash,
      actual: compactedHeadHashValidation.actualHash,
    });
  }

  if (
    checkpoint.compactedLedgerHead.tenantId !== checkpoint.tenantId ||
    checkpoint.compactedLedgerHead.ledgerId !== checkpoint.ledgerId ||
    checkpoint.compactedLedgerHead.authorityScope !== checkpoint.authorityScope
  ) {
    issues.push({
      code: "operational_state_witness_ledger_checkpoint_scope_mismatch",
      path: "/checkpoint/compactedLedgerHead",
      message:
        "Witness-ledger compaction checkpoint head must match checkpoint tenant, ledger, and authority scope.",
    });
  }
  if (
    checkpoint.compactedLedgerHead.sequence !==
    checkpoint.compactedThroughSequence
  ) {
    issues.push({
      code: "operational_state_witness_ledger_checkpoint_sequence_mismatch",
      path: "/checkpoint/compactedThroughSequence",
      message:
        "Witness-ledger compaction checkpoint must compact exactly through its compacted ledger-head sequence.",
      expected: checkpoint.compactedLedgerHead.sequence,
      actual: checkpoint.compactedThroughSequence,
    });
  }
  if (
    checkpoint.retainedFromSequence !==
    checkpoint.compactedThroughSequence + 1
  ) {
    issues.push({
      code: "operational_state_witness_ledger_retained_from_mismatch",
      path: "/checkpoint/retainedFromSequence",
      message:
        "Witness-ledger retained suffix must begin immediately after the compacted checkpoint frontier.",
      expected: checkpoint.compactedThroughSequence + 1,
      actual: checkpoint.retainedFromSequence,
    });
  }

  const checkpointAdmissionReplay = input.checkpointAdmissionReplay;
  const latestCheckpointAdmissionRecord =
    checkpointAdmissionReplay?.latestAdmittedRecord;
  if (
    input.requireCheckpointAdmission === true ||
    input.requireCheckpointAdmissionWitnessQuorum === true ||
    input.requireCheckpointAdmissionWitnessAuthorityTopology === true ||
    input.requireCheckpointAdmissionWitnessAuthorityTransitionAdmission ===
      true ||
    input.requireCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitness ===
      true ||
    input
      .requireCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
      true ||
    input
      .requireCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
      true
  ) {
    if (checkpointAdmissionReplay === undefined) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_replay_missing",
        path: "/checkpointAdmissionReplay",
        message:
          "Compacted witness-ledger checkpoint cannot seed replay without checkpoint-admission history.",
      });
    } else if (!checkpointAdmissionReplay.valid) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_replay_invalid",
        path: "/checkpointAdmissionReplay",
        message:
          "Compacted witness-ledger checkpoint has an invalid checkpoint-admission replay.",
        actual: checkpointAdmissionReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      latestCheckpointAdmissionRecord === undefined ||
      latestCheckpointAdmissionRecord.checkpointHash !== checkpoint.checkpointHash
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_not_admitted",
        path: "/checkpoint/checkpointHash",
        message:
          "Compacted witness-ledger checkpoint is not the latest admitted checkpoint for its admission history.",
        expected:
          latestCheckpointAdmissionRecord?.checkpointHash ??
          "admitted-checkpoint",
        actual: checkpoint.checkpointHash,
      });
    }
  }

  const checkpointAdmissionWitnessReplay =
    input.checkpointAdmissionWitnessReplay;
  const latestCheckpointAdmissionWitnessRecord =
    checkpointAdmissionWitnessReplay?.requiredAdmissionWitnessRecord;
  if (
    input.requireCheckpointAdmissionWitnessQuorum === true ||
    input.requireCheckpointAdmissionWitnessAuthorityTopology === true ||
    input.requireCheckpointAdmissionWitnessAuthorityTransitionAdmission ===
      true ||
    input.requireCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitness ===
      true ||
    input
      .requireCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
      true ||
    input
      .requireCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
      true
  ) {
    if (checkpointAdmissionWitnessReplay === undefined) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_replay_missing",
        path: "/checkpointAdmissionWitnessReplay",
        message:
          "Compacted witness-ledger checkpoint requires replay of witness-certified checkpoint-admission records.",
      });
    } else if (!checkpointAdmissionWitnessReplay.valid) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_replay_invalid",
        path: "/checkpointAdmissionWitnessReplay",
        message:
          "Compacted witness-ledger checkpoint has an invalid checkpoint-admission witness replay.",
        actual: checkpointAdmissionWitnessReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      latestCheckpointAdmissionRecord === undefined ||
      latestCheckpointAdmissionWitnessRecord === undefined ||
      latestCheckpointAdmissionWitnessRecord.admissionRecordHash !==
        latestCheckpointAdmissionRecord.admissionRecordHash
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_latest_record_not_witnessed",
        path: "/checkpointAdmissionWitnessReplay",
        message:
          "Latest witness-ledger checkpoint admission record is not witnessed by the replayed checkpoint-admission witness quorum.",
        expected: latestCheckpointAdmissionRecord?.admissionRecordHash ?? "none",
        actual:
          latestCheckpointAdmissionWitnessRecord?.admissionRecordHash ?? "none",
      });
    }
  }
  if (
    (input.requireCheckpointAdmissionWitnessAuthorityTopology === true ||
      input.requireCheckpointAdmissionWitnessAuthorityTransitionAdmission ===
        true ||
      input.requireCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitness ===
        true ||
      input
        .requireCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input
        .requireCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    checkpointAdmissionWitnessReplay?.witnessAuthorityTopology === undefined
  ) {
    issues.push({
      code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_topology_missing",
      path: "/checkpointAdmissionWitnessReplay/witnessAuthorityTopology",
      message:
        "Compacted witness-ledger checkpoint requires replayed checkpoint-admission witness authority topology.",
    });
  }
  if (
    (input.requireCheckpointAdmissionWitnessAuthorityTransitionAdmission ===
      true ||
      input.requireCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitness ===
        true ||
      input
        .requireCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input
        .requireCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    checkpointAdmissionWitnessReplay?.witnessAuthorityTransitionAdmissionReplay ===
      undefined
  ) {
    issues.push({
      code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_replay_missing",
      path:
        "/checkpointAdmissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
      message:
        "Compacted witness-ledger checkpoint requires admitted checkpoint-admission witness authority-transition history.",
    });
  }
  if (
    (input.requireCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitness ===
      true ||
      input
        .requireCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input
        .requireCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    checkpointAdmissionWitnessReplay !== undefined &&
    checkpointAdmissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
      undefined
  ) {
    const admissionTransitionWitnessReplay =
      checkpointAdmissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .admissionWitnessReplay;
    if (admissionTransitionWitnessReplay === undefined) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_replay_missing",
        path: "/checkpointAdmissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
        message:
          "Compacted witness-ledger checkpoint requires checkpoint-admission witness authority-transition admission records to be witnessed.",
      });
    } else if (!admissionTransitionWitnessReplay.valid) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_replay_invalid",
        path: "/checkpointAdmissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
        message:
          "Compacted witness-ledger checkpoint cannot consume invalid checkpoint-admission witness authority-transition admission witness history.",
        actual: admissionTransitionWitnessReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      (input
        .requireCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
        input
          .requireCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
          true) &&
      admissionTransitionWitnessReplay.witnessAuthorityTopology === undefined
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_topology_missing",
        path: "/checkpointAdmissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTopology",
        message:
          "Compacted witness-ledger checkpoint requires checkpoint-admission witness authority-transition admission witness certificates to bind to replayed witness authority topology.",
      });
    } else if (
      input
        .requireCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay ===
        undefined
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        path: "/checkpointAdmissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Compacted witness-ledger checkpoint requires checkpoint-admission witness authority-transition admission witness authority topology to replay from admitted authority-transition history.",
      });
    } else if (
      input
        .requireCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      !admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .valid
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        path: "/checkpointAdmissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Compacted witness-ledger checkpoint cannot consume invalid nested checkpoint-admission witness authority-transition admission witness authority history.",
        actual:
          admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.issues
            .map((issue) => issue.code)
            .join(","),
      });
    } else if (
      input
        .requireCheckpointAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      admissionTransitionWitnessReplay.witnessAuthorityTopology !== undefined &&
      admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      (admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .latestAdmittedTopology === undefined ||
        !operationalStateAuthorityTopologiesMatch(
          admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology,
          admissionTransitionWitnessReplay.witnessAuthorityTopology,
        ))
    ) {
      issues.push({
        code: "operational_state_witness_ledger_checkpoint_admission_witness_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/checkpointAdmissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Compacted witness-ledger checkpoint requires checkpoint-admission witness authority-transition admission witness authority topology to be recovered from admitted authority-transition history.",
        expected: admissionTransitionWitnessReplay.witnessAuthorityTopology
          .topologyHash,
        actual:
          admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology?.topologyHash ?? "none",
      });
    }
  }

  let acceptedRecordCount = 0;
  let previousSequence = checkpoint.compactedThroughSequence;
  let previousRecordHash = checkpoint.compactedLedgerHead.recordHash;
  let currentLedgerHead = checkpoint.compactedLedgerHead;

  input.retainedRecords.forEach((record, index) => {
    const path = `/retainedRecords/${index}`;
    const hashValidation = verifyOperationalStateWitnessLedgerRecordHash(record);
    if (!hashValidation.valid) {
      issues.push({
        code: "operational_state_witness_ledger_record_hash_mismatch",
        path: `${path}/recordHash`,
        message: `Retained witness-ledger record hash ${hashValidation.actualHash} does not match recomputed hash ${hashValidation.expectedHash}.`,
        expected: hashValidation.expectedHash,
        actual: hashValidation.actualHash,
      });
    }
    if (
      record.tenantId !== checkpoint.tenantId ||
      record.ledgerId !== checkpoint.ledgerId ||
      record.authorityScope !== checkpoint.authorityScope
    ) {
      issues.push({
        code: "operational_state_witness_ledger_record_scope_mismatch",
        path,
        message:
          "Retained witness-ledger record must match checkpoint tenant, ledger, and authority scope.",
      });
    }
    if (
      record.observedHead.tenantId !== record.tenantId ||
      record.observedHead.authorityScope !== record.authorityScope
    ) {
      issues.push({
        code: "operational_state_witness_ledger_record_observed_head_scope_mismatch",
        path: `${path}/observedHead`,
        message:
          "Witness-ledger records cannot witness a head from another tenant or authority scope.",
      });
    }
    if (record.sequence !== previousSequence + 1) {
      issues.push({
        code: "operational_state_witness_ledger_retained_suffix_gap",
        path: `${path}/sequence`,
        message:
          "Retained witness-ledger suffix must be sequence-contiguous from the compacted checkpoint frontier.",
        expected: previousSequence + 1,
        actual: record.sequence,
      });
    }
    if (record.previousRecordHash !== previousRecordHash) {
      issues.push({
        code: "operational_state_witness_ledger_retained_suffix_previous_hash_mismatch",
        path: `${path}/previousRecordHash`,
        message:
          "Retained witness-ledger suffix must hash-chain from the compacted ledger head.",
        expected: previousRecordHash,
        actual: record.previousRecordHash ?? "none",
      });
    }

    currentLedgerHead = operationalStateWitnessLedgerHeadFromRecord(
      record,
      currentLedgerHead,
    );
    previousSequence = record.sequence;
    previousRecordHash = record.recordHash;
    if (record.decision === "accepted") acceptedRecordCount += 1;
  });

  const latestAcceptedHead = currentLedgerHead.latestAcceptedHead;
  const requiredHead = input.requiredHead;
  if (requiredHead === undefined) {
    issues.push({
      code: "operational_state_witness_ledger_required_head_missing",
      path: "/requiredHead",
      message:
        "Compacted witness-ledger recovery cannot prove required-head currentness without the required admissible head.",
    });
  } else if (latestAcceptedHead === undefined) {
    issues.push({
      code: "operational_state_witness_ledger_required_head_unaccepted",
      path: "/requiredHead",
      message:
        "Compacted witness-ledger recovery has no accepted head to compare with the required admissible head.",
      expected: requiredHead.headHash,
    });
  } else {
    if (latestAcceptedHead.sequence !== requiredHead.sequence) {
      issues.push({
        code: "operational_state_witness_ledger_required_head_sequence_mismatch",
        path: "/requiredHead/sequence",
        message:
          "Compacted witness-ledger replay must recover the required admissible head sequence.",
        expected: requiredHead.sequence,
        actual: latestAcceptedHead.sequence,
      });
    }
    if (!operationalStateAdmissibleHeadsMatch(latestAcceptedHead, requiredHead)) {
      issues.push({
        code: "operational_state_witness_ledger_required_head_hash_mismatch",
        path: "/requiredHead",
        message:
          "Compacted witness-ledger replay must recover the exact required admissible head.",
        expected: requiredHead.headHash,
        actual: latestAcceptedHead.headHash,
      });
    }
  }

  return {
    valid: issues.length === 0,
    acceptedRecordCount,
    obstructionCount: currentLedgerHead.obstructionCount,
    compactedLedgerHead: checkpoint.compactedLedgerHead,
    currentLedgerHead,
    ...(latestAcceptedHead !== undefined ? { latestAcceptedHead } : {}),
    ...(requiredHead !== undefined ? { requiredHead } : {}),
    ...(checkpointAdmissionReplay !== undefined
      ? { checkpointAdmissionReplay }
      : {}),
    ...(checkpointAdmissionWitnessReplay !== undefined
      ? { checkpointAdmissionWitnessReplay }
      : {}),
    ...(latestCheckpointAdmissionRecord !== undefined
      ? { latestCheckpointAdmissionRecord }
      : {}),
    ...(latestCheckpointAdmissionWitnessRecord !== undefined
      ? { latestCheckpointAdmissionWitnessRecord }
      : {}),
    issues,
  };
}

export function computeOperationalStateQuorumCertificateProofCertificateHash(
  certificate: Omit<
    OperationalStateQuorumCertificateProofCertificate,
    "quorumCertificateHash"
  >,
): string {
  return fingerprint64(canonicalStringify(certificate));
}

export function buildOperationalStateQuorumCertificateProofCertificate(
  input: OperationalStateQuorumCertificateProofCertificateInput,
): OperationalStateQuorumCertificateProofCertificate {
  const payload: Omit<
    OperationalStateQuorumCertificateProofCertificate,
    "quorumCertificateHash"
  > = {
    schemaVersion: OPERATIONAL_STATE_QUORUM_CERTIFICATE_PROOF_RECORD_SCHEMA_VERSION,
    tenantId: tenantId(String(input.tenantId)),
    authorityScope: input.authorityScope,
    authorityBoundary: input.authorityBoundary,
    subjectKind: input.subjectKind,
    subjectId: input.subjectId,
    subjectSequence: input.subjectSequence,
    subjectHash: input.subjectHash,
    status: input.status,
    certified: input.certified,
    acceptedWitnessIds: input.acceptedWitnessIds,
    obstructingWitnessIds: input.obstructingWitnessIds ?? [],
    invalidWitnessIds: input.invalidWitnessIds ?? [],
    ...(input.authorityTopologyHash !== undefined
      ? { authorityTopologyHash: input.authorityTopologyHash }
      : {}),
    requiredWitnesses: input.requiredWitnesses,
    minimumWitnesses: input.minimumWitnesses ?? input.requiredWitnesses,
    ...(input.certifiedAt !== undefined ? { certifiedAt: input.certifiedAt } : {}),
    ...(input.certifiedBy !== undefined ? { certifiedBy: input.certifiedBy } : {}),
  };
  return {
    ...payload,
    quorumCertificateHash:
      computeOperationalStateQuorumCertificateProofCertificateHash(payload),
  };
}

export function verifyOperationalStateQuorumCertificateProofCertificateHash(
  certificate: OperationalStateQuorumCertificateProofCertificate,
): StateReviewArtifactHashValidation {
  const { quorumCertificateHash, ...payload } = certificate;
  const expectedHash =
    computeOperationalStateQuorumCertificateProofCertificateHash(payload);
  return {
    valid: quorumCertificateHash === expectedHash,
    expectedHash,
    actualHash: quorumCertificateHash,
  };
}

export function computeOperationalStateQuorumCertificateProofRecordHash(
  record: Omit<OperationalStateQuorumCertificateProofRecord, "proofRecordHash">,
): string {
  return fingerprint64(canonicalStringify(record));
}

export function buildOperationalStateQuorumCertificateProofRecord(
  input: OperationalStateQuorumCertificateProofRecordInput,
): OperationalStateQuorumCertificateProofRecord {
  const payload: Omit<
    OperationalStateQuorumCertificateProofRecord,
    "proofRecordHash"
  > = {
    schemaVersion: OPERATIONAL_STATE_QUORUM_CERTIFICATE_PROOF_RECORD_SCHEMA_VERSION,
    tenantId: tenantId(String(input.tenantId)),
    proofLedgerId: input.proofLedgerId,
    authorityScope: input.authorityScope,
    proofSequence: input.proofSequence,
    certificate: input.certificate,
    acceptedWitnessEvidence: input.acceptedWitnessEvidence,
    ...(input.authorityEpochSeal !== undefined
      ? { authorityEpochSeal: input.authorityEpochSeal }
      : {}),
    ...(input.previousProofRecordHash !== undefined
      ? { previousProofRecordHash: input.previousProofRecordHash }
      : {}),
    recordedAt: input.recordedAt,
    recordedBy: input.recordedBy,
  };
  return {
    ...payload,
    proofRecordHash: computeOperationalStateQuorumCertificateProofRecordHash(
      payload,
    ),
  };
}

export function verifyOperationalStateQuorumCertificateProofRecordHash(
  record: OperationalStateQuorumCertificateProofRecord,
): StateReviewArtifactHashValidation {
  const { proofRecordHash, ...payload } = record;
  const expectedHash =
    computeOperationalStateQuorumCertificateProofRecordHash(payload);
  return {
    valid: proofRecordHash === expectedHash,
    expectedHash,
    actualHash: proofRecordHash,
  };
}

