export function replayOperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitnessRecords(
  input: OperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitnessReplayInput,
): OperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitnessReplay {
  const issues: OperationalStateAuthorityEpochSealFinalizerIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const witnessHashBySequence = new Map<number, string>();
  const witnessRecordByAdmissionHash = new Map<
    string,
    OperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitnessRecord
  >();
  const witnessAuthorityTopology = input.witnessAuthorityTopology;
  const principalById = new Map<string, OperationalStateAuthorityPrincipalState>(
    witnessAuthorityTopology?.principals.map((principal) => [
      principal.principalId,
      principal,
    ]) ?? [],
  );
  let expectedSequence = 1;
  let previousWitnessRecordHash: string | undefined;
  let latestWitnessRecord:
    | OperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitnessRecord
    | undefined;
  const witnessAuthorityTransitionAdmissionReplay =
    input.witnessAuthorityTransitionAdmissionReplay;

  if (input.admissionReplay !== undefined && !input.admissionReplay.valid) {
    issues.push({
      code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_admission_replay_invalid",
      path: "/admissionReplay",
      message:
        "Authority epoch seal finalizer-proof admission witness authority-transition admission witness replay cannot account for invalid transition-admission history.",
      actual: input.admissionReplay.issues
        .map((issue) => issue.code)
        .join(","),
    });
  }

  if (
    (input.requireWitnessAuthorityTopology === true ||
      input.requireWitnessAuthorityTransitionAdmission === true) &&
    witnessAuthorityTopology === undefined
  ) {
    issues.push({
      code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_topology_missing",
      path: "/witnessAuthorityTopology",
      message:
        "Authority epoch seal finalizer-proof admission witness authority-transition admission witness replay requires a replayed witness authority topology.",
    });
  }

  if (witnessAuthorityTopology !== undefined) {
    const topologyHashValidation =
      verifyOperationalStateAuthorityTopologyHash(witnessAuthorityTopology);
    if (!topologyHashValidation.valid) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_topology_hash_mismatch",
        path: "/witnessAuthorityTopology/topologyHash",
        message: `Authority epoch seal finalizer-proof admission witness authority-transition admission witness authority topology hash ${topologyHashValidation.actualHash} does not match recomputed hash ${topologyHashValidation.expectedHash}.`,
        expected: topologyHashValidation.expectedHash,
        actual: topologyHashValidation.actualHash,
      });
    }
    if (witnessAuthorityTopology.tenantId !== expectedTenantId) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_topology_tenant_mismatch",
        path: "/witnessAuthorityTopology/tenantId",
        message:
          "Authority epoch seal finalizer-proof admission witness authority-transition admission witness authority topology tenant does not match replay tenant.",
        expected: expectedTenantId,
        actual: witnessAuthorityTopology.tenantId,
      });
    }
    if (witnessAuthorityTopology.authorityScope !== input.authorityScope) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_topology_scope_mismatch",
        path: "/witnessAuthorityTopology/authorityScope",
        message:
          "Authority epoch seal finalizer-proof admission witness authority-transition admission witness authority topology scope does not match replay scope.",
        expected: input.authorityScope,
        actual: witnessAuthorityTopology.authorityScope,
      });
    }
    if (
      witnessAuthorityTopology.requiredWitnesses === undefined ||
      witnessAuthorityTopology.minimumWitnesses === undefined
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_quorum_missing",
        path: "/witnessAuthorityTopology/requiredWitnesses",
        message:
          "Authority epoch seal finalizer-proof admission witness authority-transition admission witness authority topology must define quorum thresholds.",
      });
    }
  }

  if (input.requireWitnessAuthorityTransitionAdmission === true) {
    if (witnessAuthorityTransitionAdmissionReplay === undefined) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Authority epoch seal finalizer-proof admission witness authority-transition admission witness replay requires the witness authority topology to replay from admitted authority-transition history.",
      });
    } else if (!witnessAuthorityTransitionAdmissionReplay.valid) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        path: "/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Authority epoch seal finalizer-proof admission witness authority-transition admission witness replay cannot consume invalid nested witness-authority transition admission history.",
        actual: witnessAuthorityTransitionAdmissionReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      witnessAuthorityTopology !== undefined &&
      (witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology ===
        undefined ||
        !operationalStateAuthorityTopologiesMatch(
          witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology,
          witnessAuthorityTopology,
        ))
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Authority epoch seal finalizer-proof admission witness authority-transition admission witness authority topology must be recovered from admitted authority-transition history.",
        expected: witnessAuthorityTopology.topologyHash,
        actual:
          witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology
            ?.topologyHash ?? "none",
      });
    }
  }

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const witnessRecordHashValidation =
      verifyOperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitnessRecordHash(
        record,
      );
    const certificateHashValidation =
      verifyOperationalStateQuorumCertificateProofCertificateHash(
        record.admissionCertificate,
      );
    const previousWitnessHashAtSequence = witnessHashBySequence.get(
      record.witnessSequence,
    );

    if (
      previousWitnessHashAtSequence !== undefined &&
      previousWitnessHashAtSequence !== record.witnessRecordHash
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_record_fork",
        path: `${path}/witnessSequence`,
        message: `Authority epoch seal finalizer-proof admission witness authority-transition admission witness sequence ${record.witnessSequence} has more than one witness record hash.`,
        expected: previousWitnessHashAtSequence,
        actual: record.witnessRecordHash,
      });
    } else if (previousWitnessHashAtSequence === undefined) {
      witnessHashBySequence.set(
        record.witnessSequence,
        record.witnessRecordHash,
      );
    }

    if (
      record.tenantId !== expectedTenantId ||
      record.admissionCertificate.tenantId !== expectedTenantId
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_record_tenant_mismatch",
        path,
        message:
          "Authority epoch seal finalizer-proof admission witness authority-transition admission witness record and certificate must match the replay tenant.",
        expected: expectedTenantId,
      });
    }
    if (
      record.transitionAdmissionWitnessStoreId !==
        input.transitionAdmissionWitnessStoreId ||
      record.transitionAdmissionStoreId !== input.transitionAdmissionStoreId
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_record_store_mismatch",
        path,
        message:
          "Authority epoch seal finalizer-proof admission witness authority-transition admission witness record must bind the expected witness and transition-admission stores.",
        expected: `${input.transitionAdmissionWitnessStoreId}:${input.transitionAdmissionStoreId}`,
        actual: `${record.transitionAdmissionWitnessStoreId}:${record.transitionAdmissionStoreId}`,
      });
    }
    if (
      record.topologyId !== input.topologyId ||
      record.authorityScope !== input.authorityScope ||
      record.admissionCertificate.authorityScope !== input.authorityScope
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_record_scope_mismatch",
        path,
        message:
          "Authority epoch seal finalizer-proof admission witness authority-transition admission witness record must share the replay topology and authority scope.",
        expected: `${input.topologyId}:${input.authorityScope}`,
      });
    }
    if (record.witnessSequence !== expectedSequence) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_record_sequence_gap",
        path: `${path}/witnessSequence`,
        message:
          "Authority epoch seal finalizer-proof admission witness authority-transition admission witness records must replay as a contiguous witness sequence.",
        expected: expectedSequence,
        actual: record.witnessSequence,
      });
    }
    if (record.previousWitnessRecordHash !== previousWitnessRecordHash) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_record_previous_hash_mismatch",
        path: `${path}/previousWitnessRecordHash`,
        message:
          "Authority epoch seal finalizer-proof admission witness authority-transition admission witness record does not chain to the previous witness record hash.",
        expected: previousWitnessRecordHash ?? "none",
        actual: record.previousWitnessRecordHash ?? "none",
      });
    }
    if (!certificateHashValidation.valid) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_certificate_hash_mismatch",
        path: `${path}/admissionCertificate/quorumCertificateHash`,
        message: `Authority epoch seal finalizer-proof admission witness authority-transition admission witness certificate hash ${certificateHashValidation.actualHash} does not match recomputed hash ${certificateHashValidation.expectedHash}.`,
        expected: certificateHashValidation.expectedHash,
        actual: certificateHashValidation.actualHash,
      });
    }
    if (
      !record.admissionCertificate.certified ||
      record.admissionCertificate.status !== "certified"
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_certificate_not_certified",
        path: `${path}/admissionCertificate/status`,
        message:
          "Authority epoch seal finalizer-proof admission witness authority-transition admission cannot become accountable through a non-certified witness certificate.",
        expected: "certified",
        actual: record.admissionCertificate.status,
      });
    }
    if (
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.minimumWitnesses ||
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.requiredWitnesses
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_certificate_quorum_not_met",
        path: `${path}/admissionCertificate/acceptedWitnessIds`,
        message:
          "Authority epoch seal finalizer-proof admission witness authority-transition admission witness certificate does not satisfy its declared witness quorum.",
        expected: Math.max(
          record.admissionCertificate.requiredWitnesses,
          record.admissionCertificate.minimumWitnesses,
        ),
        actual: record.admissionCertificate.acceptedWitnessIds.length,
      });
    }
    if (
      record.admissionCertificate.subjectKind !==
        OPERATIONAL_STATE_AUTHORITY_EPOCH_SEAL_FINALIZER_PROOF_ADMISSION_WITNESS_AUTHORITY_TRANSITION_ADMISSION_RECORD_SUBJECT_KIND ||
      record.admissionCertificate.subjectId !==
        operationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionSubjectId(
          record,
        ) ||
      record.admissionCertificate.subjectSequence !==
        record.admissionSequence ||
      record.admissionCertificate.subjectHash !== record.admissionRecordHash
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_certificate_subject_mismatch",
        path: `${path}/admissionCertificate`,
        message:
          "Authority epoch seal finalizer-proof admission witness authority-transition admission witness certificate must certify the exact transition-admission store, topology id, admission sequence, and admission record hash.",
        expected: record.admissionRecordHash,
        actual: record.admissionCertificate.subjectHash,
      });
    }
    if (
      input.requiredAuthorityBoundary !== undefined &&
      record.admissionCertificate.authorityBoundary !==
        input.requiredAuthorityBoundary
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_certificate_authority_boundary_mismatch",
        path: `${path}/admissionCertificate/authorityBoundary`,
        message:
          "Authority epoch seal finalizer-proof admission witness authority-transition admission witness certificate was admitted under the wrong authority boundary.",
        expected: input.requiredAuthorityBoundary,
        actual: record.admissionCertificate.authorityBoundary,
      });
    }
    if (witnessAuthorityTopology !== undefined) {
      if (
        record.admissionCertificate.authorityTopologyHash !==
        witnessAuthorityTopology.topologyHash
      ) {
        issues.push({
          code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_certificate_authority_topology_mismatch",
          path: `${path}/admissionCertificate/authorityTopologyHash`,
          message:
            "Authority epoch seal finalizer-proof admission witness authority-transition admission witness certificate must be bound to the replayed witness authority topology.",
          expected: witnessAuthorityTopology.topologyHash,
          actual:
            record.admissionCertificate.authorityTopologyHash ?? "none",
        });
      }

      const acceptedWitnessIds =
        record.admissionCertificate.acceptedWitnessIds;
      const uniqueAcceptedWitnessIds = new Set(acceptedWitnessIds);
      if (uniqueAcceptedWitnessIds.size !== acceptedWitnessIds.length) {
        issues.push({
          code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_duplicate_witness",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Authority epoch seal finalizer-proof admission witness authority-transition admission witness certificate cannot be certified by duplicate topology witnesses.",
          expected: uniqueAcceptedWitnessIds.size,
          actual: acceptedWitnessIds.length,
        });
      }

      let activeAuthorizedWitnessCount = 0;
      for (const witnessId of uniqueAcceptedWitnessIds) {
        const principal = principalById.get(witnessId);
        if (principal === undefined) {
          issues.push({
            code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_witness_unknown",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Authority epoch seal finalizer-proof admission witness authority-transition admission witness certificate names a witness outside the replayed witness authority topology.",
            expected: witnessAuthorityTopology.topologyHash,
            actual: witnessId,
          });
          continue;
        }
        if (principal.status !== "active") {
          issues.push({
            code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_witness_not_active",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Authority epoch seal finalizer-proof admission witness authority-transition admission witness certificate names a witness that is not active in the replayed witness authority topology.",
            expected: "active",
            actual: `${witnessId}:${principal.status}`,
          });
          continue;
        }
        activeAuthorizedWitnessCount += 1;
      }

      const requiredAuthorizedWitnesses = Math.max(
        witnessAuthorityTopology.requiredWitnesses ?? 0,
        witnessAuthorityTopology.minimumWitnesses ?? 0,
      );
      if (activeAuthorizedWitnessCount < requiredAuthorizedWitnesses) {
        issues.push({
          code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_quorum_not_met",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Authority epoch seal finalizer-proof admission witness authority-transition admission witness certificate does not satisfy replayed witness authority quorum.",
          expected: requiredAuthorizedWitnesses,
          actual: activeAuthorizedWitnessCount,
        });
      }
    }
    if (!witnessRecordHashValidation.valid) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_record_hash_mismatch",
        path: `${path}/witnessRecordHash`,
        message: `Authority epoch seal finalizer-proof admission witness authority-transition admission witness record hash ${witnessRecordHashValidation.actualHash} does not match recomputed hash ${witnessRecordHashValidation.expectedHash}.`,
        expected: witnessRecordHashValidation.expectedHash,
        actual: witnessRecordHashValidation.actualHash,
      });
    }

    witnessRecordByAdmissionHash.set(record.admissionRecordHash, record);
    expectedSequence = record.witnessSequence + 1;
    previousWitnessRecordHash = record.witnessRecordHash;
    latestWitnessRecord = record;
  });

  const requiredAdmissionRecord =
    input.requiredAdmissionRecord ?? input.admissionReplay?.latestAdmittedRecord;
  let requiredAdmissionWitnessRecord:
    | OperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitnessRecord
    | undefined;
  if (requiredAdmissionRecord !== undefined) {
    const admissionRecordHashValidation =
      verifyOperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionRecordHash(
        requiredAdmissionRecord,
      );
    if (!admissionRecordHashValidation.valid) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_record_hash_mismatch",
        path: "/requiredAdmissionRecord/admissionRecordHash",
        message: `Required authority epoch seal finalizer-proof admission witness authority-transition admission hash ${admissionRecordHashValidation.actualHash} does not match recomputed hash ${admissionRecordHashValidation.expectedHash}.`,
        expected: admissionRecordHashValidation.expectedHash,
        actual: admissionRecordHashValidation.actualHash,
      });
    }
    requiredAdmissionWitnessRecord = witnessRecordByAdmissionHash.get(
      requiredAdmissionRecord.admissionRecordHash,
    );
    if (requiredAdmissionWitnessRecord === undefined) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_latest_record_not_witnessed",
        path: "/requiredAdmissionRecord/admissionRecordHash",
        message:
          "Latest authority epoch seal finalizer-proof admission witness authority-transition admission record has no replayed witness certificate.",
        expected: requiredAdmissionRecord.admissionRecordHash,
      });
    } else if (
      requiredAdmissionWitnessRecord.transitionAdmissionStoreId !==
        requiredAdmissionRecord.transitionAdmissionStoreId ||
      requiredAdmissionWitnessRecord.topologyId !==
        requiredAdmissionRecord.topologyId ||
      requiredAdmissionWitnessRecord.admissionSequence !==
        requiredAdmissionRecord.admissionSequence ||
      requiredAdmissionWitnessRecord.authoritySequence !==
        requiredAdmissionRecord.authoritySequence ||
      requiredAdmissionWitnessRecord.authorityRecordHash !==
        requiredAdmissionRecord.authorityRecordHash ||
      requiredAdmissionWitnessRecord.nextAuthorityTopologyHash !==
        requiredAdmissionRecord.nextAuthorityTopologyHash
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_admission_record_mismatch",
        path: "/requiredAdmissionRecord",
        message:
          "Authority epoch seal finalizer-proof admission witness authority-transition admission witness record does not match the required admission store, topology, sequence, authority transition hash, and derived topology hash.",
        expected: requiredAdmissionRecord.admissionRecordHash,
        actual: requiredAdmissionWitnessRecord.admissionRecordHash,
      });
    }
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    transitionAdmissionWitnessStoreId:
      input.transitionAdmissionWitnessStoreId,
    transitionAdmissionStoreId: input.transitionAdmissionStoreId,
    topologyId: input.topologyId,
    authorityScope: input.authorityScope,
    witnessedRecordCount: input.records.length,
    ...(latestWitnessRecord !== undefined ? { latestWitnessRecord } : {}),
    ...(requiredAdmissionRecord !== undefined ? { requiredAdmissionRecord } : {}),
    ...(requiredAdmissionWitnessRecord !== undefined
      ? { requiredAdmissionWitnessRecord }
      : {}),
    ...(witnessAuthorityTopology !== undefined ? { witnessAuthorityTopology } : {}),
    ...(witnessAuthorityTransitionAdmissionReplay !== undefined
      ? { witnessAuthorityTransitionAdmissionReplay }
      : {}),
    issues,
  };
}

export function computeOperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionRecordHash(
  record: Omit<
    OperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionRecord,
    "admissionRecordHash"
  >,
): string {
  return fingerprint64(canonicalStringify(record));
}

export function buildOperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionRecord(
  input: OperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionRecordInput,
): OperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionRecord {
  const nextAuthorityTopology = operationalStateAuthorityTopologyFromTransition(
    input.authorityTransition,
    input.previousAuthorityTopology,
  );
  const payload: Omit<
    OperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionRecord,
    "admissionRecordHash"
  > = {
    schemaVersion:
      OPERATIONAL_STATE_AUTHORITY_EPOCH_SEAL_FINALIZER_PROOF_ADMISSION_WITNESS_AUTHORITY_TRANSITION_ADMISSION_SCHEMA_VERSION,
    tenantId: tenantId(String(input.tenantId)),
    transitionAdmissionStoreId: input.transitionAdmissionStoreId,
    topologyId: input.topologyId,
    authorityScope: input.authorityScope,
    admissionSequence: input.admissionSequence,
    authoritySequence: input.authorityTransition.authoritySequence,
    authorityRecordHash: input.authorityTransition.authorityRecordHash,
    ...(input.authorityTransition.previousAuthorityRecordHash !== undefined
      ? {
          previousAuthorityRecordHash:
            input.authorityTransition.previousAuthorityRecordHash,
        }
      : {}),
    ...(input.previousAuthorityTopology !== undefined
      ? {
          previousAuthorityTopologyHash:
            input.previousAuthorityTopology.topologyHash,
        }
      : {}),
    nextAuthorityTopologyHash: nextAuthorityTopology.topologyHash,
    authorityTransition: input.authorityTransition,
    admissionCertificate: input.admissionCertificate,
    ...(input.previousAdmissionRecordHash !== undefined
      ? { previousAdmissionRecordHash: input.previousAdmissionRecordHash }
      : {}),
    admittedAt: input.admittedAt,
    admittedBy: input.admittedBy,
    ...(input.admissionReason !== undefined
      ? { admissionReason: input.admissionReason }
      : {}),
  };
  return {
    ...payload,
    admissionRecordHash:
      computeOperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionRecordHash(
        payload,
      ),
  };
}

export function verifyOperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionRecordHash(
  record: OperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionRecord,
): StateReviewArtifactHashValidation {
  const { admissionRecordHash, ...payload } = record;
  const expectedHash =
    computeOperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionRecordHash(
      payload,
    );
  return {
    valid: admissionRecordHash === expectedHash,
    expectedHash,
    actualHash: admissionRecordHash,
  };
}

export function replayOperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionRecords(
  input: OperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionReplayInput,
): OperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionReplay {
  const issues: OperationalStateAuthorityEpochSealFinalizerIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const admissionHashBySequence = new Map<number, string>();
  const admissionRecordByAuthorityHash = new Map<
    string,
    OperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionRecord
  >();
  const bootstrapCertificate = input.bootstrapCertificate;
  const bootstrapSettlementReplay = input.bootstrapSettlementReplay;
  const admissionWitnessReplay = input.admissionWitnessReplay;
  const pushIssue = (
    code: OperationalStateAuthorityEpochSealFinalizerIssueCode,
    path: string,
    message: string,
    details: Partial<
      Pick<OperationalStateAuthorityEpochSealFinalizerIssue, "expected" | "actual">
    > = {},
  ) => issues.push({ code, path, message, ...details });
  let expectedAdmissionSequence = 1;
  let expectedAuthoritySequence = 1;
  let previousAdmissionRecordHash: string | undefined;
  let previousAuthorityRecordHash: string | undefined;
  let previousTopology: OperationalStateAuthorityTopology | undefined;
  let latestAdmittedRecord:
    | OperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionRecord
    | undefined;
  let latestAdmittedTopology: OperationalStateAuthorityTopology | undefined;

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const recordHashValidation =
      verifyOperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionRecordHash(
        record,
      );
    const transitionHashValidation =
      verifyOperationalStateAuthorityTransitionRecordHash(
        record.authorityTransition,
      );
    const certificateHashValidation =
      verifyOperationalStateQuorumCertificateProofCertificateHash(
        record.admissionCertificate,
      );
    const previousAdmissionHashAtSequence = admissionHashBySequence.get(
      record.admissionSequence,
    );

    if (
      previousAdmissionHashAtSequence !== undefined &&
      previousAdmissionHashAtSequence !== record.admissionRecordHash
    ) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_record_sequence_gap",
        `${path}/admissionSequence`,
        `Authority epoch seal finalizer-proof admission witness authority-transition admission sequence ${record.admissionSequence} has more than one record hash.`,
        {
          expected: previousAdmissionHashAtSequence,
          actual: record.admissionRecordHash,
        },
      );
    } else if (previousAdmissionHashAtSequence === undefined) {
      admissionHashBySequence.set(
        record.admissionSequence,
        record.admissionRecordHash,
      );
    }

    if (
      record.tenantId !== expectedTenantId ||
      record.authorityTransition.tenantId !== expectedTenantId ||
      record.admissionCertificate.tenantId !== expectedTenantId
    ) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_record_tenant_mismatch",
        path,
        "Authority epoch seal finalizer-proof admission witness authority-transition admission record, transition, and certificate must match the replay tenant.",
        { expected: expectedTenantId },
      );
    }
    if (record.transitionAdmissionStoreId !== input.transitionAdmissionStoreId) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_record_store_mismatch",
        `${path}/transitionAdmissionStoreId`,
        "Authority epoch seal finalizer-proof admission witness authority-transition admission record belongs to a different admission store.",
        {
          expected: input.transitionAdmissionStoreId,
          actual: record.transitionAdmissionStoreId,
        },
      );
    }
    if (
      record.topologyId !== input.topologyId ||
      record.authorityTransition.topologyId !== input.topologyId
    ) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_record_scope_mismatch",
        `${path}/topologyId`,
        "Authority epoch seal finalizer-proof admission witness authority-transition admission record must match the replay topology id.",
        { expected: input.topologyId, actual: record.topologyId },
      );
    }
    if (
      record.authorityScope !== input.authorityScope ||
      record.authorityTransition.authorityScope !== input.authorityScope ||
      record.admissionCertificate.authorityScope !== input.authorityScope
    ) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_record_scope_mismatch",
        path,
        "Authority epoch seal finalizer-proof admission witness authority-transition admission record, transition, and certificate must share the replay authority scope.",
        { expected: input.authorityScope },
      );
    }
    if (record.admissionSequence !== expectedAdmissionSequence) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_record_sequence_gap",
        `${path}/admissionSequence`,
        "Authority epoch seal finalizer-proof admission witness authority-transition admissions must replay as a contiguous admission sequence.",
        {
          expected: expectedAdmissionSequence,
          actual: record.admissionSequence,
        },
      );
    }
    if (record.previousAdmissionRecordHash !== previousAdmissionRecordHash) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_record_previous_hash_mismatch",
        `${path}/previousAdmissionRecordHash`,
        "Authority epoch seal finalizer-proof admission witness authority-transition admission record does not chain to the previous admission record hash.",
        {
          expected: previousAdmissionRecordHash ?? "none",
          actual: record.previousAdmissionRecordHash ?? "none",
        },
      );
    }
    if (!recordHashValidation.valid) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_record_hash_mismatch",
        `${path}/admissionRecordHash`,
        `Authority epoch seal finalizer-proof admission witness authority-transition admission record hash ${recordHashValidation.actualHash} does not match recomputed hash ${recordHashValidation.expectedHash}.`,
        {
          expected: recordHashValidation.expectedHash,
          actual: recordHashValidation.actualHash,
        },
      );
    }
    if (!transitionHashValidation.valid) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_transition_hash_mismatch",
        `${path}/authorityTransition/authorityRecordHash`,
        `Authority epoch seal finalizer-proof admission witness authority transition hash ${transitionHashValidation.actualHash} does not match recomputed hash ${transitionHashValidation.expectedHash}.`,
        {
          expected: transitionHashValidation.expectedHash,
          actual: transitionHashValidation.actualHash,
        },
      );
    }
    if (
      record.authoritySequence !==
        record.authorityTransition.authoritySequence ||
      record.authorityRecordHash !==
        record.authorityTransition.authorityRecordHash ||
      record.previousAuthorityRecordHash !==
        record.authorityTransition.previousAuthorityRecordHash
    ) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_transition_mismatch",
        `${path}/authorityTransition`,
        "Authority epoch seal finalizer-proof admission witness authority-transition admission record does not match its embedded authority transition sequence and hash.",
        {
          expected: record.authorityRecordHash,
          actual: record.authorityTransition.authorityRecordHash,
        },
      );
    }
    if (record.authoritySequence !== expectedAuthoritySequence) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_transition_sequence_gap",
        `${path}/authoritySequence`,
        "Authority epoch seal finalizer-proof admission witness authority transitions must be admitted in contiguous authority sequence.",
        {
          expected: expectedAuthoritySequence,
          actual: record.authoritySequence,
        },
      );
    }
    if (
      record.authorityTransition.previousAuthorityRecordHash !==
      previousAuthorityRecordHash
    ) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_transition_previous_hash_mismatch",
        `${path}/authorityTransition/previousAuthorityRecordHash`,
        "Authority epoch seal finalizer-proof admission witness authority transition must hash-chain from the previously admitted authority transition.",
        {
          expected: previousAuthorityRecordHash ?? "none",
          actual:
            record.authorityTransition.previousAuthorityRecordHash ?? "none",
        },
      );
    }
    if (record.authorityTransition.effectiveFromSubjectSequence < 1) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_transition_invalid",
        `${path}/authorityTransition/effectiveFromSubjectSequence`,
        "Authority epoch seal finalizer-proof admission witness authority transitions must declare a positive effective admission sequence.",
        { actual: record.authorityTransition.effectiveFromSubjectSequence },
      );
    }
    if (
      record.authorityTransition.transitionKind === "set_quorum" &&
      ((record.authorityTransition.requiredWitnesses ?? 0) < 1 ||
        (record.authorityTransition.minimumWitnesses ??
          record.authorityTransition.requiredWitnesses ??
          0) < 1 ||
        (record.authorityTransition.minimumWitnesses ??
          record.authorityTransition.requiredWitnesses ??
          0) > (record.authorityTransition.requiredWitnesses ?? 0))
    ) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_transition_invalid",
        `${path}/authorityTransition/requiredWitnesses`,
        "Authority epoch seal finalizer-proof admission witness authority quorum transitions must declare positive and internally consistent witness thresholds.",
      );
    }
    if (
      [
        "admit_principal",
        "suspend_principal",
        "revoke_principal",
        "rotate_signature_key",
        "mark_equivocated",
      ].includes(record.authorityTransition.transitionKind) &&
      (record.authorityTransition.principalId === undefined ||
        record.authorityTransition.principalId.length === 0)
    ) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_transition_invalid",
        `${path}/authorityTransition/principalId`,
        "Authority epoch seal finalizer-proof admission witness authority principal transitions must identify the affected principal.",
      );
    }
    if (
      record.authorityTransition.transitionKind === "seal_authority_epoch" &&
      ((record.authorityTransition.sealedThroughSubjectSequence ?? 0) < 1 ||
        record.authorityTransition.sealedQuorumCertificateHash === undefined ||
        record.authorityTransition.sealedQuorumCertificateHash.length === 0)
    ) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_transition_invalid",
        `${path}/authorityTransition/sealedQuorumCertificateHash`,
        "Authority epoch seal finalizer-proof admission witness authority epoch seals must bind a positive sealed frontier and a quorum certificate hash.",
      );
    }

    const nextTopology = operationalStateAuthorityTopologyFromTransition(
      record.authorityTransition,
      previousTopology,
    );
    if (record.nextAuthorityTopologyHash !== nextTopology.topologyHash) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_transition_topology_hash_mismatch",
        `${path}/nextAuthorityTopologyHash`,
        "Authority epoch seal finalizer-proof admission witness authority-transition admission record does not derive the expected next topology hash.",
        {
          expected: nextTopology.topologyHash,
          actual: record.nextAuthorityTopologyHash,
        },
      );
    }
    if (previousTopology === undefined) {
      if (record.previousAuthorityTopologyHash !== undefined) {
        pushIssue(
          "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_transition_previous_topology_hash_mismatch",
          `${path}/previousAuthorityTopologyHash`,
          "Genesis authority epoch seal finalizer-proof admission witness authority transition cannot cite a previous topology hash.",
          { actual: record.previousAuthorityTopologyHash },
        );
      }
      if (
        input.requireBootstrapCertificate === true ||
        bootstrapCertificate !== undefined
      ) {
        if (bootstrapCertificate === undefined) {
          pushIssue(
            "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_bootstrap_certificate_missing",
            "/bootstrapCertificate",
            "Genesis authority epoch seal finalizer-proof admission witness authority transition admission requires a replayable root-authority bootstrap certificate.",
          );
        } else {
          const bootstrapHashValidation =
            verifyOperationalStateAuthorityBootstrapCertificateHash(
              bootstrapCertificate,
            );
          if (!bootstrapHashValidation.valid) {
            pushIssue(
              "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_bootstrap_certificate_hash_mismatch",
              "/bootstrapCertificate/bootstrapCertificateHash",
              `Authority bootstrap certificate hash ${bootstrapHashValidation.actualHash} does not match recomputed hash ${bootstrapHashValidation.expectedHash}.`,
              {
                expected: bootstrapHashValidation.expectedHash,
                actual: bootstrapHashValidation.actualHash,
              },
            );
          }
          if (
            bootstrapCertificate.tenantId !== expectedTenantId ||
            bootstrapCertificate.authorityScope !== input.authorityScope ||
            bootstrapCertificate.transitionAdmissionStoreId !==
              input.transitionAdmissionStoreId ||
            bootstrapCertificate.topologyId !== input.topologyId ||
            bootstrapCertificate.authorityBoundary !==
              record.admissionCertificate.authorityBoundary ||
            (input.requiredAuthorityBoundary !== undefined &&
              bootstrapCertificate.authorityBoundary !==
                input.requiredAuthorityBoundary) ||
            bootstrapCertificate.bootstrapTopologyHash !==
              record.admissionCertificate.authorityTopologyHash ||
            bootstrapCertificate.authorizedAdmissionSequence !==
              record.admissionSequence ||
            bootstrapCertificate.authorizedAdmissionRecordHash !==
              record.admissionRecordHash ||
            bootstrapCertificate.authorizedAuthoritySequence !==
              record.authoritySequence ||
            bootstrapCertificate.authorizedAuthorityRecordHash !==
              record.authorityRecordHash ||
            bootstrapCertificate.authorizedNextAuthorityTopologyHash !==
              nextTopology.topologyHash ||
            !record.admissionCertificate.acceptedWitnessIds.includes(
              bootstrapCertificate.rootAuthorityId,
            )
          ) {
            pushIssue(
              "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_bootstrap_certificate_mismatch",
              "/bootstrapCertificate",
              "Authority bootstrap certificate must bind the replay tenant, scope, boundary, topology, bootstrap topology hash, root authority, first admission record, and first derived authority topology.",
              {
                expected: record.admissionRecordHash,
                actual:
                  bootstrapCertificate.authorizedAdmissionRecordHash,
              },
            );
          }
          if (bootstrapCertificate.rootEvidenceRefs.length === 0) {
            pushIssue(
              "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_bootstrap_certificate_root_evidence_missing",
              "/bootstrapCertificate/rootEvidenceRefs",
              "Authority bootstrap certificate must carry replayable root evidence references rather than relying on private bootstrap belief.",
            );
          }
          if (
            bootstrapCertificate.signatureKeyId.length === 0 ||
            bootstrapCertificate.signatureHash.length === 0
          ) {
            pushIssue(
              "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_bootstrap_certificate_signature_missing",
              "/bootstrapCertificate/signatureHash",
              "Authority bootstrap certificate must carry signature identity and signature hash material.",
            );
          }
          if (
            input.requireBootstrapSettlement === true ||
            bootstrapSettlementReplay !== undefined
          ) {
            if (bootstrapSettlementReplay === undefined) {
              pushIssue(
                "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_bootstrap_settlement_replay_missing",
                "/bootstrapSettlementReplay",
                "Genesis authority epoch seal finalizer-proof admission witness authority transition admission requires replayed bootstrap settlement before root authority can be consumed.",
              );
            } else if (!bootstrapSettlementReplay.valid) {
              pushIssue(
                "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_bootstrap_settlement_replay_invalid",
                "/bootstrapSettlementReplay",
                "Genesis authority epoch seal finalizer-proof admission witness authority transition admission cannot consume invalid bootstrap settlement replay.",
                { actual: bootstrapSettlementReplay.issues.length },
              );
            } else if (
              bootstrapSettlementReplay.requiredSettlementRecord ===
                undefined ||
              bootstrapSettlementReplay.requiredSettlementRecord
                .bootstrapCertificateHash !==
                bootstrapCertificate.bootstrapCertificateHash
            ) {
              pushIssue(
                "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_bootstrap_certificate_not_settled",
                "/bootstrapSettlementReplay/requiredSettlementRecord",
                "Genesis authority epoch seal finalizer-proof admission witness authority transition admission requires its bootstrap certificate to replay from the bootstrap settlement history.",
                {
                  expected: bootstrapCertificate.bootstrapCertificateHash,
                  actual:
                    bootstrapSettlementReplay.requiredSettlementRecord
                      ?.bootstrapCertificateHash ?? "none",
                },
              );
            }
          }
        }
      }
    } else {
      if (
        record.previousAuthorityTopologyHash !== previousTopology.topologyHash
      ) {
        pushIssue(
          "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_transition_previous_topology_hash_mismatch",
          `${path}/previousAuthorityTopologyHash`,
          "Authority epoch seal finalizer-proof admission witness authority transition admission must bind the previous replayed topology hash.",
          {
            expected: previousTopology.topologyHash,
            actual: record.previousAuthorityTopologyHash ?? "none",
          },
        );
      }
      if (
        record.admissionCertificate.authorityTopologyHash !==
        previousTopology.topologyHash
      ) {
        pushIssue(
          "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_certificate_authority_topology_mismatch",
          `${path}/admissionCertificate/authorityTopologyHash`,
          "Authority epoch seal finalizer-proof admission witness authority transition admission certificate must be bound to the previous replayed topology.",
          {
            expected: previousTopology.topologyHash,
            actual: record.admissionCertificate.authorityTopologyHash ?? "none",
          },
        );
      }

      const principalById = new Map<
        string,
        OperationalStateAuthorityPrincipalState
      >(
        previousTopology.principals.map((principal) => [
          principal.principalId,
          principal,
        ]),
      );
      const acceptedWitnessIds =
        record.admissionCertificate.acceptedWitnessIds;
      const uniqueAcceptedWitnessIds = new Set(acceptedWitnessIds);
      if (uniqueAcceptedWitnessIds.size !== acceptedWitnessIds.length) {
        pushIssue(
          "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_authority_duplicate_witness",
          `${path}/admissionCertificate/acceptedWitnessIds`,
          "Authority epoch seal finalizer-proof admission witness authority-transition admission cannot be certified by duplicate prior-topology witnesses.",
          {
            expected: uniqueAcceptedWitnessIds.size,
            actual: acceptedWitnessIds.length,
          },
        );
      }

      let activeAuthorizedWitnessCount = 0;
      for (const witnessId of uniqueAcceptedWitnessIds) {
        const principal = principalById.get(witnessId);
        if (principal === undefined) {
          pushIssue(
            "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_authority_witness_unknown",
            `${path}/admissionCertificate/acceptedWitnessIds`,
            "Authority epoch seal finalizer-proof admission witness authority-transition admission certificate names a witness outside the previous replayed topology.",
            { expected: previousTopology.topologyHash, actual: witnessId },
          );
          continue;
        }
        if (principal.status !== "active") {
          pushIssue(
            "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_authority_witness_not_active",
            `${path}/admissionCertificate/acceptedWitnessIds`,
            "Authority epoch seal finalizer-proof admission witness authority-transition admission certificate names a witness that is not active in the previous replayed topology.",
            { expected: "active", actual: `${witnessId}:${principal.status}` },
          );
          continue;
        }
        activeAuthorizedWitnessCount += 1;
      }

      const requiredAuthorizedWitnesses = Math.max(
        previousTopology.requiredWitnesses ?? 0,
        previousTopology.minimumWitnesses ?? 0,
      );
      if (activeAuthorizedWitnessCount < requiredAuthorizedWitnesses) {
        pushIssue(
          "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_authority_quorum_not_met",
          `${path}/admissionCertificate/acceptedWitnessIds`,
          "Authority epoch seal finalizer-proof admission witness authority-transition admission certificate does not satisfy previous-topology quorum.",
          {
            expected: requiredAuthorizedWitnesses,
            actual: activeAuthorizedWitnessCount,
          },
        );
      }
    }

    if (!certificateHashValidation.valid) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_certificate_hash_mismatch",
        `${path}/admissionCertificate/quorumCertificateHash`,
        `Authority epoch seal finalizer-proof admission witness authority-transition admission certificate hash ${certificateHashValidation.actualHash} does not match recomputed hash ${certificateHashValidation.expectedHash}.`,
        {
          expected: certificateHashValidation.expectedHash,
          actual: certificateHashValidation.actualHash,
        },
      );
    }
    if (
      !record.admissionCertificate.certified ||
      record.admissionCertificate.status !== "certified"
    ) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_certificate_not_certified",
        `${path}/admissionCertificate/status`,
        "Authority epoch seal finalizer-proof admission witness authority transition cannot become authority through a non-certified admission certificate.",
        { expected: "certified", actual: record.admissionCertificate.status },
      );
    }
    if (
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.minimumWitnesses ||
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.requiredWitnesses
    ) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_certificate_quorum_not_met",
        `${path}/admissionCertificate/acceptedWitnessIds`,
        "Authority epoch seal finalizer-proof admission witness authority-transition admission certificate does not satisfy its declared witness quorum.",
        {
          expected: Math.max(
            record.admissionCertificate.requiredWitnesses,
            record.admissionCertificate.minimumWitnesses,
          ),
          actual: record.admissionCertificate.acceptedWitnessIds.length,
        },
      );
    }
    if (
      record.admissionCertificate.subjectKind !==
        OPERATIONAL_STATE_AUTHORITY_TRANSITION_RECORD_SUBJECT_KIND ||
      record.admissionCertificate.subjectId !== record.topologyId ||
      record.admissionCertificate.subjectSequence !==
        record.authoritySequence ||
      record.admissionCertificate.subjectHash !== record.authorityRecordHash
    ) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_certificate_subject_mismatch",
        `${path}/admissionCertificate`,
        "Authority epoch seal finalizer-proof admission witness authority-transition admission certificate must certify the exact topology id, authority sequence, and authority transition hash.",
        {
          expected: record.authorityRecordHash,
          actual: record.admissionCertificate.subjectHash,
        },
      );
    }
    if (
      input.requiredAuthorityBoundary !== undefined &&
      record.admissionCertificate.authorityBoundary !==
        input.requiredAuthorityBoundary
    ) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_certificate_authority_boundary_mismatch",
        `${path}/admissionCertificate/authorityBoundary`,
        "Authority epoch seal finalizer-proof admission witness authority-transition admission certificate was admitted under the wrong authority boundary.",
        {
          expected: input.requiredAuthorityBoundary,
          actual: record.admissionCertificate.authorityBoundary,
        },
      );
    }

    admissionRecordByAuthorityHash.set(record.authorityRecordHash, record);
    expectedAdmissionSequence = record.admissionSequence + 1;
    expectedAuthoritySequence = record.authoritySequence + 1;
    previousAdmissionRecordHash = record.admissionRecordHash;
    previousAuthorityRecordHash = record.authorityRecordHash;
    previousTopology = nextTopology;
    latestAdmittedTopology = nextTopology;
    latestAdmittedRecord = record;
  });

  let requiredAuthorityTransitionAdmissionRecord:
    | OperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionRecord
    | undefined;
  if (input.requiredAuthorityTransition !== undefined) {
    const requiredTransitionHashValidation =
      verifyOperationalStateAuthorityTransitionRecordHash(
        input.requiredAuthorityTransition,
      );
    if (!requiredTransitionHashValidation.valid) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_transition_hash_mismatch",
        "/requiredAuthorityTransition/authorityRecordHash",
        `Required authority epoch seal finalizer-proof admission witness authority transition hash ${requiredTransitionHashValidation.actualHash} does not match recomputed hash ${requiredTransitionHashValidation.expectedHash}.`,
        {
          expected: requiredTransitionHashValidation.expectedHash,
          actual: requiredTransitionHashValidation.actualHash,
        },
      );
    }
    requiredAuthorityTransitionAdmissionRecord =
      admissionRecordByAuthorityHash.get(
        input.requiredAuthorityTransition.authorityRecordHash,
      );
    if (requiredAuthorityTransitionAdmissionRecord === undefined) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_not_admitted",
        "/requiredAuthorityTransition/authorityRecordHash",
        "Required authority epoch seal finalizer-proof admission witness authority transition has no replayed admission certificate.",
        { expected: input.requiredAuthorityTransition.authorityRecordHash },
      );
    }
  }

  if (input.requiredAuthorityTopology !== undefined) {
    const requiredTopologyHashValidation =
      verifyOperationalStateAuthorityTopologyHash(
        input.requiredAuthorityTopology,
      );
    if (!requiredTopologyHashValidation.valid) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_topology_hash_mismatch",
        "/requiredAuthorityTopology/topologyHash",
        `Required authority epoch seal finalizer-proof admission witness authority topology hash ${requiredTopologyHashValidation.actualHash} does not match recomputed hash ${requiredTopologyHashValidation.expectedHash}.`,
        {
          expected: requiredTopologyHashValidation.expectedHash,
          actual: requiredTopologyHashValidation.actualHash,
        },
      );
    }
    if (
      latestAdmittedTopology === undefined ||
      !operationalStateAuthorityTopologiesMatch(
        latestAdmittedTopology,
        input.requiredAuthorityTopology,
      )
    ) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_topology_mismatch",
        "/requiredAuthorityTopology",
        "Authority epoch seal finalizer-proof admission witness authority-transition admission replay must recover the required authority topology.",
        {
          expected: input.requiredAuthorityTopology.topologyHash,
          actual: latestAdmittedTopology?.topologyHash ?? "none",
        },
      );
    }
    requiredAuthorityTransitionAdmissionRecord =
      admissionRecordByAuthorityHash.get(
        input.requiredAuthorityTopology.authorityRecordHash,
      );
    if (requiredAuthorityTransitionAdmissionRecord === undefined) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_not_admitted",
        "/requiredAuthorityTopology/authorityRecordHash",
        "Required authority epoch seal finalizer-proof admission witness authority topology is not backed by an admitted authority transition.",
        { expected: input.requiredAuthorityTopology.authorityRecordHash },
      );
    }
  }

  if (
    input.requireAdmissionWitness === true ||
    input.requireAdmissionWitnessAuthorityTopology === true ||
    input.requireAdmissionWitnessAuthorityTransitionAdmission === true
  ) {
    if (admissionWitnessReplay === undefined) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_replay_missing",
        "/admissionWitnessReplay",
        "Authority epoch seal finalizer-proof admission witness authority-transition admission replay requires witnessed transition-admission records.",
      );
    } else if (!admissionWitnessReplay.valid) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_replay_invalid",
        "/admissionWitnessReplay",
        "Authority epoch seal finalizer-proof admission witness authority-transition admission replay cannot consume invalid transition-admission witness history.",
        {
          actual: admissionWitnessReplay.issues
            .map((issue) => issue.code)
            .join(","),
        },
      );
    } else if (
      (input.requireAdmissionWitnessAuthorityTopology === true ||
        input.requireAdmissionWitnessAuthorityTransitionAdmission === true) &&
      admissionWitnessReplay.witnessAuthorityTopology === undefined
    ) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_topology_missing",
        "/admissionWitnessReplay/witnessAuthorityTopology",
        "Authority epoch seal finalizer-proof admission witness authority-transition admission replay requires its witness ledger to bind certificates to replayed witness authority topology.",
      );
    } else if (
      latestAdmittedRecord === undefined ||
      admissionWitnessReplay.requiredAdmissionWitnessRecord === undefined ||
      admissionWitnessReplay.requiredAdmissionWitnessRecord
        .admissionRecordHash !== latestAdmittedRecord.admissionRecordHash
    ) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_latest_record_not_witnessed",
        "/admissionWitnessReplay/requiredAdmissionWitnessRecord",
        "Latest authority epoch seal finalizer-proof admission witness authority-transition admission record is not witnessed by the replayed transition-admission witness ledger.",
        {
          expected: latestAdmittedRecord?.admissionRecordHash ?? "none",
          actual:
          admissionWitnessReplay.requiredAdmissionWitnessRecord
            ?.admissionRecordHash ?? "none",
        },
      );
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmission === true &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay ===
        undefined
    ) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        "/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        "Authority epoch seal finalizer-proof admission witness authority-transition admission replay requires its witness authority topology to replay from admitted authority-transition history.",
      );
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmission === true &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      !admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.valid
    ) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        "/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        "Authority epoch seal finalizer-proof admission witness authority-transition admission replay cannot consume invalid nested witness-authority transition admission history.",
        {
          actual:
            admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.issues
              .map((issue) => issue.code)
              .join(","),
        },
      );
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmission === true &&
      admissionWitnessReplay.witnessAuthorityTopology !== undefined &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      (admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .latestAdmittedTopology === undefined ||
        !operationalStateAuthorityTopologiesMatch(
          admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology,
          admissionWitnessReplay.witnessAuthorityTopology,
        ))
    ) {
      pushIssue(
        "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        "/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        "Authority epoch seal finalizer-proof admission witness authority-transition admission witness authority topology must be recovered from admitted authority-transition history.",
        {
          expected: admissionWitnessReplay.witnessAuthorityTopology.topologyHash,
          actual:
            admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
              .latestAdmittedTopology?.topologyHash ?? "none",
        },
      );
    }
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    transitionAdmissionStoreId: input.transitionAdmissionStoreId,
    topologyId: input.topologyId,
    authorityScope: input.authorityScope,
    admittedRecordCount: input.records.length,
    ...(latestAdmittedRecord !== undefined ? { latestAdmittedRecord } : {}),
    ...(latestAdmittedTopology !== undefined ? { latestAdmittedTopology } : {}),
    ...(input.requiredAuthorityTopology !== undefined
      ? { requiredAuthorityTopology: input.requiredAuthorityTopology }
      : {}),
    ...(input.requiredAuthorityTransition !== undefined
      ? { requiredAuthorityTransition: input.requiredAuthorityTransition }
      : {}),
    ...(requiredAuthorityTransitionAdmissionRecord !== undefined
      ? { requiredAuthorityTransitionAdmissionRecord }
      : {}),
    ...(bootstrapCertificate !== undefined ? { bootstrapCertificate } : {}),
    ...(bootstrapSettlementReplay !== undefined
      ? { bootstrapSettlementReplay }
      : {}),
    ...(admissionWitnessReplay !== undefined ? { admissionWitnessReplay } : {}),
    issues,
  };
}

export function replayOperationalStateAuthorityEpochSealFinalizerProofAdmissionRecords(
  input: OperationalStateAuthorityEpochSealFinalizerProofAdmissionReplayInput,
): OperationalStateAuthorityEpochSealFinalizerProofAdmissionReplay {
  const issues: OperationalStateAuthorityEpochSealFinalizerIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const recordHashBySequence = new Map<number, string>();
  const latestRecordBySealId = new Map<
    string,
    OperationalStateAuthorityEpochSealFinalizerProofAdmissionRecord
  >();
  let expectedSequence = 1;
  let previousAdmissionRecordHash: string | undefined;
  let latestAdmittedRecord:
    | OperationalStateAuthorityEpochSealFinalizerProofAdmissionRecord
    | undefined;

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const admissionRecordHashValidation =
      verifyOperationalStateAuthorityEpochSealFinalizerProofAdmissionRecordHash(
        record,
      );
    const finalizerProofHashValidation =
      verifyOperationalStateAuthorityEpochSealFinalizerProofHash(
        record.finalizerProof,
      );
    const admissionCertificateHashValidation =
      verifyOperationalStateQuorumCertificateProofCertificateHash(
        record.admissionCertificate,
      );
    const previousRecordHashAtSequence = recordHashBySequence.get(
      record.admissionSequence,
    );

    if (
      previousRecordHashAtSequence !== undefined &&
      previousRecordHashAtSequence !== record.admissionRecordHash
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_record_fork",
        path: `${path}/admissionSequence`,
        message: `Authority epoch seal finalizer-proof admission sequence ${record.admissionSequence} has more than one record hash.`,
        expected: previousRecordHashAtSequence,
        actual: record.admissionRecordHash,
      });
    } else if (previousRecordHashAtSequence === undefined) {
      recordHashBySequence.set(
        record.admissionSequence,
        record.admissionRecordHash,
      );
    }

    if (
      record.tenantId !== expectedTenantId ||
      record.finalizerProof.tenantId !== expectedTenantId ||
      record.admissionCertificate.tenantId !== expectedTenantId
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_record_tenant_mismatch",
        path,
        message:
          "Finalizer-proof admission record, embedded proof, and admission certificate must match the replay tenant.",
        expected: expectedTenantId,
      });
    }
    if (
      record.finalizerProofAdmissionStoreId !==
      input.finalizerProofAdmissionStoreId
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_record_store_mismatch",
        path: `${path}/finalizerProofAdmissionStoreId`,
        message:
          "Authority epoch seal finalizer-proof admission belongs to a different admission store.",
        expected: input.finalizerProofAdmissionStoreId,
        actual: record.finalizerProofAdmissionStoreId,
      });
    }
    if (
      record.authorityScope !== input.authorityScope ||
      record.finalizerProof.authorityScope !== input.authorityScope ||
      record.admissionCertificate.authorityScope !== input.authorityScope
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_record_scope_mismatch",
        path,
        message:
          "Finalizer-proof admission record, embedded proof, and admission certificate must share the replay authority scope.",
        expected: input.authorityScope,
      });
    }
    if (record.admissionSequence !== expectedSequence) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_record_sequence_gap",
        path: `${path}/admissionSequence`,
        message:
          "Authority epoch seal finalizer-proof admissions must replay as a contiguous sequence.",
        expected: expectedSequence,
        actual: record.admissionSequence,
      });
    }
    if (record.previousAdmissionRecordHash !== previousAdmissionRecordHash) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_record_previous_hash_mismatch",
        path: `${path}/previousAdmissionRecordHash`,
        message:
          "Authority epoch seal finalizer-proof admission does not chain to the previous admission record hash.",
        expected: previousAdmissionRecordHash ?? "none",
        actual: record.previousAdmissionRecordHash ?? "none",
      });
    }
    if (
      record.sealId !== record.finalizerProof.sealId ||
      record.finalizerProofHash !== record.finalizerProof.finalizerProofHash ||
      !finalizerProofHashValidation.valid
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_record_proof_hash_mismatch",
        path: `${path}/finalizerProofHash`,
        message:
          "Finalizer-proof admission must hash-bind the exact embedded authority epoch seal finalizer proof.",
        expected: finalizerProofHashValidation.expectedHash,
        actual: record.finalizerProofHash,
      });
    }
    if (!admissionCertificateHashValidation.valid) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_record_certificate_hash_mismatch",
        path: `${path}/admissionCertificate/quorumCertificateHash`,
        message: `Finalizer-proof admission certificate hash ${admissionCertificateHashValidation.actualHash} does not match recomputed hash ${admissionCertificateHashValidation.expectedHash}.`,
        expected: admissionCertificateHashValidation.expectedHash,
        actual: admissionCertificateHashValidation.actualHash,
      });
    }
    if (
      !record.admissionCertificate.certified ||
      record.admissionCertificate.status !== "certified"
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_record_certificate_not_certified",
        path: `${path}/admissionCertificate/status`,
        message:
          "Authority epoch seal finalizer proof cannot be admitted by a non-certified admission certificate.",
        expected: "certified",
        actual: record.admissionCertificate.status,
      });
    }
    if (
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.minimumWitnesses ||
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.requiredWitnesses
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_record_certificate_quorum_not_met",
        path: `${path}/admissionCertificate/acceptedWitnessIds`,
        message:
          "Authority epoch seal finalizer-proof admission certificate does not satisfy its witness quorum.",
        expected: Math.max(
          record.admissionCertificate.requiredWitnesses,
          record.admissionCertificate.minimumWitnesses,
        ),
        actual: record.admissionCertificate.acceptedWitnessIds.length,
      });
    }
    if (
      record.admissionCertificate.subjectKind !==
        OPERATIONAL_STATE_AUTHORITY_EPOCH_SEAL_FINALIZER_PROOF_SUBJECT_KIND ||
      record.admissionCertificate.subjectId !== record.sealId ||
      record.admissionCertificate.subjectSequence !==
        record.admissionSequence ||
      record.admissionCertificate.subjectHash !== record.finalizerProofHash
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_record_certificate_subject_mismatch",
        path: `${path}/admissionCertificate`,
        message:
          "Finalizer-proof admission certificate must certify the exact seal id, admission sequence, and finalizer-proof hash.",
        expected: record.finalizerProofHash,
        actual: record.admissionCertificate.subjectHash,
      });
    }
    if (
      input.requiredAuthorityBoundary !== undefined &&
      record.admissionCertificate.authorityBoundary !==
        input.requiredAuthorityBoundary
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_record_certificate_authority_boundary_mismatch",
        path: `${path}/admissionCertificate/authorityBoundary`,
        message:
          "Authority epoch seal finalizer-proof admission certificate was admitted under the wrong authority boundary.",
        expected: input.requiredAuthorityBoundary,
        actual: record.admissionCertificate.authorityBoundary,
      });
    }
    if (!admissionRecordHashValidation.valid) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_record_hash_mismatch",
        path: `${path}/admissionRecordHash`,
        message: `Finalizer-proof admission record hash ${admissionRecordHashValidation.actualHash} does not match recomputed hash ${admissionRecordHashValidation.expectedHash}.`,
        expected: admissionRecordHashValidation.expectedHash,
        actual: admissionRecordHashValidation.actualHash,
      });
    }

    expectedSequence = record.admissionSequence + 1;
    previousAdmissionRecordHash = record.admissionRecordHash;
    latestAdmittedRecord = record;
    latestRecordBySealId.set(record.sealId, record);
  });

  let requiredFinalizerProofAdmissionRecord:
    | OperationalStateAuthorityEpochSealFinalizerProofAdmissionRecord
    | undefined;
  if (input.requiredFinalizerProof !== undefined) {
    const requiredProofHashValidation =
      verifyOperationalStateAuthorityEpochSealFinalizerProofHash(
        input.requiredFinalizerProof,
      );
    if (!requiredProofHashValidation.valid) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_record_proof_hash_mismatch",
        path: "/requiredFinalizerProof/finalizerProofHash",
        message: `Required authority epoch seal finalizer proof hash ${requiredProofHashValidation.actualHash} does not match recomputed hash ${requiredProofHashValidation.expectedHash}.`,
        expected: requiredProofHashValidation.expectedHash,
        actual: requiredProofHashValidation.actualHash,
      });
    }
    requiredFinalizerProofAdmissionRecord = latestRecordBySealId.get(
      input.requiredFinalizerProof.sealId,
    );
    if (requiredFinalizerProofAdmissionRecord === undefined) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_not_admitted",
        path: "/records",
        message:
          "Authority epoch seal finalizer-proof admission replay has no records for the required finalizer proof.",
        expected: input.requiredFinalizerProof.finalizerProofHash,
      });
    } else if (
      requiredFinalizerProofAdmissionRecord.finalizerProofHash !==
      input.requiredFinalizerProof.finalizerProofHash
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_not_admitted",
        path: "/requiredFinalizerProof/finalizerProofHash",
        message:
          "Required authority epoch seal finalizer proof is not the latest admitted proof for its seal id.",
        expected: input.requiredFinalizerProof.finalizerProofHash,
        actual: requiredFinalizerProofAdmissionRecord.finalizerProofHash,
      });
    }
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    finalizerProofAdmissionStoreId: input.finalizerProofAdmissionStoreId,
    authorityScope: input.authorityScope,
    admittedRecordCount: input.records.length,
    ...(latestAdmittedRecord !== undefined ? { latestAdmittedRecord } : {}),
    ...(input.requiredFinalizerProof !== undefined
      ? { requiredFinalizerProof: input.requiredFinalizerProof }
      : {}),
    ...(requiredFinalizerProofAdmissionRecord !== undefined
      ? { requiredFinalizerProofAdmissionRecord }
      : {}),
    issues,
  };
}

export function replayOperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessRecords(
  input: OperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessReplayInput,
): OperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessReplay {
  const issues: OperationalStateAuthorityEpochSealFinalizerIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const witnessHashBySequence = new Map<number, string>();
  const witnessRecordByAdmissionHash = new Map<
    string,
    OperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessRecord
  >();
  const witnessAuthorityTopology = input.witnessAuthorityTopology;
  const witnessAuthorityTransitionAdmissionReplay =
    input.witnessAuthorityTransitionAdmissionReplay;
  const principalById = new Map<string, OperationalStateAuthorityPrincipalState>(
    witnessAuthorityTopology?.principals.map((principal) => [
      principal.principalId,
      principal,
    ]) ?? [],
  );
  let expectedSequence = 1;
  let previousWitnessRecordHash: string | undefined;
  let latestWitnessRecord:
    | OperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessRecord
    | undefined;

  if (input.admissionReplay !== undefined && !input.admissionReplay.valid) {
    issues.push({
      code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_admission_replay_invalid",
      path: "/admissionReplay",
      message:
        "Authority epoch seal finalizer-proof admission witness replay cannot account for an invalid finalizer-proof admission replay.",
      actual: input.admissionReplay.issues
        .map((issue) => issue.code)
        .join(","),
    });
  }

  if (
    (input.requireWitnessAuthorityTopology === true ||
      input.requireWitnessAuthorityTransitionAdmission === true ||
      input.requireWitnessAuthorityTransitionAdmissionWitness === true ||
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    witnessAuthorityTopology === undefined
  ) {
    issues.push({
      code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_topology_missing",
      path: "/witnessAuthorityTopology",
      message:
        "Authority epoch seal finalizer-proof admission witness replay requires a replayed witness authority topology.",
    });
  }

  if (witnessAuthorityTopology !== undefined) {
    const topologyHashValidation =
      verifyOperationalStateAuthorityTopologyHash(witnessAuthorityTopology);
    if (!topologyHashValidation.valid) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_topology_hash_mismatch",
        path: "/witnessAuthorityTopology/topologyHash",
        message: `Authority epoch seal finalizer-proof admission witness authority topology hash ${topologyHashValidation.actualHash} does not match recomputed hash ${topologyHashValidation.expectedHash}.`,
        expected: topologyHashValidation.expectedHash,
        actual: topologyHashValidation.actualHash,
      });
    }
    if (witnessAuthorityTopology.tenantId !== expectedTenantId) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_topology_tenant_mismatch",
        path: "/witnessAuthorityTopology/tenantId",
        message:
          "Authority epoch seal finalizer-proof admission witness authority topology tenant does not match replay tenant.",
        expected: expectedTenantId,
        actual: witnessAuthorityTopology.tenantId,
      });
    }
    if (witnessAuthorityTopology.authorityScope !== input.authorityScope) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_topology_scope_mismatch",
        path: "/witnessAuthorityTopology/authorityScope",
        message:
          "Authority epoch seal finalizer-proof admission witness authority topology scope does not match replay scope.",
        expected: input.authorityScope,
        actual: witnessAuthorityTopology.authorityScope,
      });
    }
    if (
      witnessAuthorityTopology.requiredWitnesses === undefined ||
      witnessAuthorityTopology.minimumWitnesses === undefined
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_quorum_missing",
        path: "/witnessAuthorityTopology/requiredWitnesses",
        message:
          "Authority epoch seal finalizer-proof admission witness authority topology must define quorum thresholds.",
      });
    }
  }

  if (
    input.requireWitnessAuthorityTransitionAdmission === true ||
    input.requireWitnessAuthorityTransitionAdmissionWitness === true ||
    input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
      true ||
    input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
      true
  ) {
    if (witnessAuthorityTransitionAdmissionReplay === undefined) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_replay_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Authority epoch seal finalizer-proof admission witness replay requires admitted finalizer-proof admission witness authority-transition history.",
      });
    } else if (!witnessAuthorityTransitionAdmissionReplay.valid) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_replay_invalid",
        path: "/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Authority epoch seal finalizer-proof admission witness replay cannot consume invalid finalizer-proof admission witness authority-transition admission history.",
        actual: witnessAuthorityTransitionAdmissionReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      witnessAuthorityTopology !== undefined &&
      (witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology ===
        undefined ||
        !operationalStateAuthorityTopologiesMatch(
          witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology,
          witnessAuthorityTopology,
        ))
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Authority epoch seal finalizer-proof admission witness authority topology must be recovered from admitted authority-transition history.",
        expected: witnessAuthorityTopology.topologyHash,
        actual:
          witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology
            ?.topologyHash ?? "none",
      });
    }
  }

  if (
    (input.requireWitnessAuthorityTransitionAdmissionWitness === true ||
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    witnessAuthorityTransitionAdmissionReplay !== undefined
  ) {
    if (witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay === undefined) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_replay_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
        message:
          "Authority epoch seal finalizer-proof admission witness replay requires finalizer-proof admission witness authority-transition admission records to be witnessed.",
      });
    } else if (
      !witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay.valid
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_replay_invalid",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
        message:
          "Authority epoch seal finalizer-proof admission witness replay cannot consume invalid finalizer-proof admission witness authority-transition admission witness history.",
        actual:
          witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay.issues
            .map((issue) => issue.code)
            .join(","),
      });
    } else if (
      (input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
        input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
          true) &&
      witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTopology === undefined
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_topology_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTopology",
        message:
          "Authority epoch seal finalizer-proof admission witness replay requires the transition-admission witness ledger to bind certificates to replayed witness authority topology.",
      });
    }
    if (
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay !==
        undefined &&
      witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay.valid
    ) {
      const transitionAdmissionWitnessReplay =
        witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay;
      if (
        transitionAdmissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay ===
        undefined
      ) {
        issues.push({
          code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_missing",
          path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
          message:
            "Authority epoch seal finalizer-proof admission witness replay requires the transition-admission witness authority topology to replay from admitted authority-transition history.",
        });
      } else if (
        !transitionAdmissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
          .valid
      ) {
        issues.push({
          code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
          path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
          message:
            "Authority epoch seal finalizer-proof admission witness replay cannot consume invalid nested transition-admission witness authority-transition admission history.",
          actual:
            transitionAdmissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.issues
              .map((issue) => issue.code)
              .join(","),
        });
      } else if (
        transitionAdmissionWitnessReplay.witnessAuthorityTopology !==
          undefined &&
        (transitionAdmissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
          .latestAdmittedTopology === undefined ||
          !operationalStateAuthorityTopologiesMatch(
            transitionAdmissionWitnessReplay
              .witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology,
            transitionAdmissionWitnessReplay.witnessAuthorityTopology,
          ))
      ) {
        issues.push({
          code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
          path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
          message:
            "Authority epoch seal finalizer-proof admission witness authority-transition admission witness authority topology must be recovered from admitted authority-transition history.",
          expected:
            transitionAdmissionWitnessReplay.witnessAuthorityTopology
              .topologyHash,
          actual:
            transitionAdmissionWitnessReplay
              .witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology
              ?.topologyHash ?? "none",
        });
      }
    }
  }

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const witnessRecordHashValidation =
      verifyOperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessRecordHash(
        record,
      );
    const certificateHashValidation =
      verifyOperationalStateQuorumCertificateProofCertificateHash(
        record.admissionCertificate,
      );
    const previousWitnessHashAtSequence = witnessHashBySequence.get(
      record.witnessSequence,
    );
    const expectedSubjectId =
      operationalStateAuthorityEpochSealFinalizerProofAdmissionSubjectId(record);

    if (
      previousWitnessHashAtSequence !== undefined &&
      previousWitnessHashAtSequence !== record.witnessRecordHash
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_record_fork",
        path: `${path}/witnessSequence`,
        message: `Authority epoch seal finalizer-proof admission witness sequence ${record.witnessSequence} has more than one witness record hash.`,
        expected: previousWitnessHashAtSequence,
        actual: record.witnessRecordHash,
      });
    } else if (previousWitnessHashAtSequence === undefined) {
      witnessHashBySequence.set(
        record.witnessSequence,
        record.witnessRecordHash,
      );
    }

    if (
      record.tenantId !== expectedTenantId ||
      record.admissionCertificate.tenantId !== expectedTenantId
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_record_tenant_mismatch",
        path,
        message:
          "Authority epoch seal finalizer-proof admission witness record and certificate must match the replay tenant.",
        expected: expectedTenantId,
      });
    }
    if (
      record.finalizerProofAdmissionWitnessStoreId !==
        input.finalizerProofAdmissionWitnessStoreId ||
      record.finalizerProofAdmissionStoreId !==
        input.finalizerProofAdmissionStoreId
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_record_store_mismatch",
        path,
        message:
          "Authority epoch seal finalizer-proof admission witness record must bind the expected witness and proof-admission stores.",
        expected: `${input.finalizerProofAdmissionWitnessStoreId}:${input.finalizerProofAdmissionStoreId}`,
        actual: `${record.finalizerProofAdmissionWitnessStoreId}:${record.finalizerProofAdmissionStoreId}`,
      });
    }
    if (
      record.authorityScope !== input.authorityScope ||
      record.admissionCertificate.authorityScope !== input.authorityScope
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_record_scope_mismatch",
        path,
        message:
          "Authority epoch seal finalizer-proof admission witness record and certificate must share the replay authority scope.",
        expected: input.authorityScope,
      });
    }
    if (record.witnessSequence !== expectedSequence) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_record_sequence_gap",
        path: `${path}/witnessSequence`,
        message:
          "Authority epoch seal finalizer-proof admission witness records must replay as a contiguous witness sequence.",
        expected: expectedSequence,
        actual: record.witnessSequence,
      });
    }
    if (record.previousWitnessRecordHash !== previousWitnessRecordHash) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_record_previous_hash_mismatch",
        path: `${path}/previousWitnessRecordHash`,
        message:
          "Authority epoch seal finalizer-proof admission witness record does not chain to the previous witness record hash.",
        expected: previousWitnessRecordHash ?? "none",
        actual: record.previousWitnessRecordHash ?? "none",
      });
    }
    if (!certificateHashValidation.valid) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_certificate_hash_mismatch",
        path: `${path}/admissionCertificate/quorumCertificateHash`,
        message: `Authority epoch seal finalizer-proof admission witness certificate hash ${certificateHashValidation.actualHash} does not match recomputed hash ${certificateHashValidation.expectedHash}.`,
        expected: certificateHashValidation.expectedHash,
        actual: certificateHashValidation.actualHash,
      });
    }
    if (
      !record.admissionCertificate.certified ||
      record.admissionCertificate.status !== "certified"
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_certificate_not_certified",
        path: `${path}/admissionCertificate/status`,
        message:
          "Authority epoch seal finalizer-proof admission cannot become accountable through a non-certified witness certificate.",
        expected: "certified",
        actual: record.admissionCertificate.status,
      });
    }
    if (
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.minimumWitnesses ||
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.requiredWitnesses
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_certificate_quorum_not_met",
        path: `${path}/admissionCertificate/acceptedWitnessIds`,
        message:
          "Authority epoch seal finalizer-proof admission witness certificate does not satisfy its witness quorum.",
        expected: Math.max(
          record.admissionCertificate.requiredWitnesses,
          record.admissionCertificate.minimumWitnesses,
        ),
        actual: record.admissionCertificate.acceptedWitnessIds.length,
      });
    }
    if (
      record.admissionCertificate.subjectKind !==
        OPERATIONAL_STATE_AUTHORITY_EPOCH_SEAL_FINALIZER_PROOF_ADMISSION_RECORD_SUBJECT_KIND ||
      record.admissionCertificate.subjectId !== expectedSubjectId ||
      record.admissionCertificate.subjectSequence !==
        record.admissionSequence ||
      record.admissionCertificate.subjectHash !== record.admissionRecordHash
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_certificate_subject_mismatch",
        path: `${path}/admissionCertificate`,
        message:
          "Authority epoch seal finalizer-proof admission witness certificate must certify the exact finalizer-proof admission store, seal id, admission sequence, and admission record hash.",
        expected: record.admissionRecordHash,
        actual: record.admissionCertificate.subjectHash,
      });
    }
    if (
      input.requiredAuthorityBoundary !== undefined &&
      record.admissionCertificate.authorityBoundary !==
        input.requiredAuthorityBoundary
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_certificate_authority_boundary_mismatch",
        path: `${path}/admissionCertificate/authorityBoundary`,
        message:
          "Authority epoch seal finalizer-proof admission witness certificate was admitted under the wrong authority boundary.",
        expected: input.requiredAuthorityBoundary,
        actual: record.admissionCertificate.authorityBoundary,
      });
    }
    if (witnessAuthorityTopology !== undefined) {
      if (
        record.admissionCertificate.authorityTopologyHash !==
        witnessAuthorityTopology.topologyHash
      ) {
        issues.push({
          code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_certificate_authority_topology_mismatch",
          path: `${path}/admissionCertificate/authorityTopologyHash`,
          message:
            "Authority epoch seal finalizer-proof admission witness certificate is not bound to the replayed witness authority topology.",
          expected: witnessAuthorityTopology.topologyHash,
          actual:
            record.admissionCertificate.authorityTopologyHash ?? "none",
        });
      }

      const acceptedWitnessIds =
        record.admissionCertificate.acceptedWitnessIds;
      const uniqueAcceptedWitnessIds = new Set(acceptedWitnessIds);
      if (uniqueAcceptedWitnessIds.size !== acceptedWitnessIds.length) {
        issues.push({
          code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_duplicate_witness",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Authority epoch seal finalizer-proof admission witness authority quorum cannot be satisfied by duplicate witness ids.",
          expected: uniqueAcceptedWitnessIds.size,
          actual: acceptedWitnessIds.length,
        });
      }

      let activeAuthorizedWitnessCount = 0;
      for (const witnessId of uniqueAcceptedWitnessIds) {
        const principal = principalById.get(witnessId);
        if (principal === undefined) {
          issues.push({
            code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_witness_unknown",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Authority epoch seal finalizer-proof admission witness certificate names a witness that is not present in the replayed authority topology.",
            expected: witnessAuthorityTopology.topologyHash,
            actual: witnessId,
          });
          continue;
        }
        if (principal.status !== "active") {
          issues.push({
            code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_witness_not_active",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Authority epoch seal finalizer-proof admission witness certificate names a witness that is not active in the replayed authority topology.",
            expected: "active",
            actual: `${witnessId}:${principal.status}`,
          });
          continue;
        }
        activeAuthorizedWitnessCount += 1;
      }

      const requiredAuthorizedWitnesses = Math.max(
        witnessAuthorityTopology.requiredWitnesses ?? 0,
        witnessAuthorityTopology.minimumWitnesses ?? 0,
      );
      if (activeAuthorizedWitnessCount < requiredAuthorizedWitnesses) {
        issues.push({
          code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_quorum_not_met",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Authority epoch seal finalizer-proof admission witness certificate does not satisfy the replayed witness authority topology quorum.",
          expected: requiredAuthorizedWitnesses,
          actual: activeAuthorizedWitnessCount,
        });
      }
    }
    if (!witnessRecordHashValidation.valid) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_record_hash_mismatch",
        path: `${path}/witnessRecordHash`,
        message: `Authority epoch seal finalizer-proof admission witness record hash ${witnessRecordHashValidation.actualHash} does not match recomputed hash ${witnessRecordHashValidation.expectedHash}.`,
        expected: witnessRecordHashValidation.expectedHash,
        actual: witnessRecordHashValidation.actualHash,
      });
    }

    witnessRecordByAdmissionHash.set(record.admissionRecordHash, record);
    expectedSequence = record.witnessSequence + 1;
    previousWitnessRecordHash = record.witnessRecordHash;
    latestWitnessRecord = record;
  });

  const requiredFinalizerProofAdmissionRecord =
    input.requiredFinalizerProofAdmissionRecord ??
    input.admissionReplay?.requiredFinalizerProofAdmissionRecord;
  let requiredFinalizerProofAdmissionWitnessRecord:
    | OperationalStateAuthorityEpochSealFinalizerProofAdmissionWitnessRecord
    | undefined;
  if (requiredFinalizerProofAdmissionRecord !== undefined) {
    const admissionRecordHashValidation =
      verifyOperationalStateAuthorityEpochSealFinalizerProofAdmissionRecordHash(
        requiredFinalizerProofAdmissionRecord,
      );
    if (!admissionRecordHashValidation.valid) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_record_hash_mismatch",
        path: "/requiredFinalizerProofAdmissionRecord/admissionRecordHash",
        message: `Required authority epoch seal finalizer-proof admission hash ${admissionRecordHashValidation.actualHash} does not match recomputed hash ${admissionRecordHashValidation.expectedHash}.`,
        expected: admissionRecordHashValidation.expectedHash,
        actual: admissionRecordHashValidation.actualHash,
      });
    }
    requiredFinalizerProofAdmissionWitnessRecord =
      witnessRecordByAdmissionHash.get(
        requiredFinalizerProofAdmissionRecord.admissionRecordHash,
      );
    if (requiredFinalizerProofAdmissionWitnessRecord === undefined) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_latest_record_not_witnessed",
        path: "/requiredFinalizerProofAdmissionRecord/admissionRecordHash",
        message:
          "Latest authority epoch seal finalizer-proof admission record has no replayed witness certificate.",
        expected: requiredFinalizerProofAdmissionRecord.admissionRecordHash,
      });
    } else if (
      requiredFinalizerProofAdmissionWitnessRecord
        .finalizerProofAdmissionStoreId !==
        requiredFinalizerProofAdmissionRecord.finalizerProofAdmissionStoreId ||
      requiredFinalizerProofAdmissionWitnessRecord.admissionSequence !==
        requiredFinalizerProofAdmissionRecord.admissionSequence ||
      requiredFinalizerProofAdmissionWitnessRecord.sealId !==
        requiredFinalizerProofAdmissionRecord.sealId ||
      requiredFinalizerProofAdmissionWitnessRecord.finalizerProofHash !==
        requiredFinalizerProofAdmissionRecord.finalizerProofHash
    ) {
      issues.push({
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_admission_record_mismatch",
        path: "/requiredFinalizerProofAdmissionRecord",
        message:
          "Authority epoch seal finalizer-proof admission witness record does not match the required admission store, sequence, seal id, and proof hash.",
        expected: requiredFinalizerProofAdmissionRecord.admissionRecordHash,
        actual:
          requiredFinalizerProofAdmissionWitnessRecord.admissionRecordHash,
      });
    }
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    finalizerProofAdmissionWitnessStoreId:
      input.finalizerProofAdmissionWitnessStoreId,
    finalizerProofAdmissionStoreId: input.finalizerProofAdmissionStoreId,
    authorityScope: input.authorityScope,
    witnessedRecordCount: input.records.length,
    ...(latestWitnessRecord !== undefined ? { latestWitnessRecord } : {}),
    ...(requiredFinalizerProofAdmissionRecord !== undefined
      ? { requiredFinalizerProofAdmissionRecord }
      : {}),
    ...(requiredFinalizerProofAdmissionWitnessRecord !== undefined
      ? { requiredFinalizerProofAdmissionWitnessRecord }
      : {}),
    ...(witnessAuthorityTopology !== undefined
      ? { witnessAuthorityTopology }
      : {}),
    ...(witnessAuthorityTransitionAdmissionReplay !== undefined
      ? { witnessAuthorityTransitionAdmissionReplay }
      : {}),
    issues,
  };
}

function pushOperationalStateAuthorityEpochSealFinalizerIssue(
  issues: OperationalStateAuthorityEpochSealFinalizerIssue[],
  issue: OperationalStateAuthorityEpochSealFinalizerIssue,
): void {
  issues.push(issue);
}

function expectedOperationalStateAuthorityEpochSealPayloadHash(
  proof: OperationalStateAuthorityEpochSealFinalizerProof,
  input: OperationalStateAuthorityEpochSealFinalizerEvaluationInput,
): string {
  return computeOperationalStateAuthorityEpochSealPayloadHash({
    tenantId: input.expectedTenantId ?? proof.tenantId,
    authorityScope: input.expectedAuthorityScope ?? proof.authorityScope,
    sealId: input.expectedSealId ?? proof.sealId,
    authorityBoundary:
      input.expectedAuthorityBoundary ?? proof.authorityBoundary,
    sealedSubjectKind:
      input.expectedSealedSubjectKind ?? proof.sealedSubjectKind,
    sealedSubjectId: input.expectedSealedSubjectId ?? proof.sealedSubjectId,
    sealedSubjectSequence:
      input.expectedSealedSubjectSequence ?? proof.sealedSubjectSequence,
    sealedAuthorityTopologyHash:
      input.expectedSealedAuthorityTopologyHash ??
      proof.sealedAuthorityTopologyHash,
    sealedQuorumCertificateHash:
      input.expectedSealedQuorumCertificateHash ??
      proof.sealedQuorumCertificateHash,
    ...(input.expectedAuthorityTransitionHash !== undefined
      ? { authorityTransitionHash: input.expectedAuthorityTransitionHash }
      : proof.authorityTransitionHash !== undefined
        ? { authorityTransitionHash: proof.authorityTransitionHash }
        : {}),
    finalizedAt: input.expectedFinalizedAt ?? proof.finalizedAt,
    finalizerPrincipalId:
      input.expectedFinalizerPrincipalId ?? proof.finalizerPrincipalId,
  });
}

export function evaluateOperationalStateAuthorityEpochSealFinalizer(
  input: OperationalStateAuthorityEpochSealFinalizerEvaluationInput,
): OperationalStateAuthorityEpochSealFinalizerEvaluation {
  const issues: OperationalStateAuthorityEpochSealFinalizerIssue[] = [];
  const finalizerProof = input.finalizerProof;

  if (finalizerProof === undefined) {
    return {
      valid: false,
      accepted: false,
      issues: [
        {
          code: "operational_state_authority_epoch_seal_finalizer_missing",
          path: "/finalizerProof",
          message:
            "Authority epoch seals cannot become final operational state without a replayable finalizer signature proof.",
        },
      ],
    };
  }

  const proofHashValidation =
    verifyOperationalStateAuthorityEpochSealFinalizerProofHash(finalizerProof);
  if (!proofHashValidation.valid) {
    pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
      code: "operational_state_authority_epoch_seal_finalizer_hash_mismatch",
      path: "/finalizerProof/finalizerProofHash",
      message: `Authority epoch seal finalizer proof hash ${proofHashValidation.actualHash} does not match recomputed hash ${proofHashValidation.expectedHash}.`,
      expected: proofHashValidation.expectedHash,
      actual: proofHashValidation.actualHash,
    });
  }

  const recomputedSealPayloadHash =
    computeOperationalStateAuthorityEpochSealPayloadHash(finalizerProof);
  if (finalizerProof.sealPayloadHash !== recomputedSealPayloadHash) {
    pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
      code: "operational_state_authority_epoch_seal_finalizer_seal_payload_mismatch",
      path: "/finalizerProof/sealPayloadHash",
      message:
        "Authority epoch seal finalizer proof must bind the exact canonical seal payload.",
      expected: recomputedSealPayloadHash,
      actual: finalizerProof.sealPayloadHash,
    });
  }

  const expectedSealPayloadHash =
    expectedOperationalStateAuthorityEpochSealPayloadHash(finalizerProof, input);
  if (finalizerProof.sealPayloadHash !== expectedSealPayloadHash) {
    pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
      code: "operational_state_authority_epoch_seal_finalizer_seal_payload_mismatch",
      path: "/expectedSealPayload",
      message:
        "Authority epoch seal finalizer proof does not match the seal payload required by replay.",
      expected: expectedSealPayloadHash,
      actual: finalizerProof.sealPayloadHash,
    });
  }

  if (finalizerProof.sealedSubjectSequence < 1) {
    pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
      code: "operational_state_authority_epoch_seal_finalizer_sealed_frontier_invalid",
      path: "/finalizerProof/sealedSubjectSequence",
      message:
        "Authority epoch seal finalizer proof must seal a positive subject frontier.",
      expected: 1,
      actual: finalizerProof.sealedSubjectSequence,
    });
  }

  if (
    input.expectedTenantId !== undefined &&
    finalizerProof.tenantId !== tenantId(String(input.expectedTenantId))
  ) {
    pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
      code: "operational_state_authority_epoch_seal_finalizer_tenant_mismatch",
      path: "/expectedTenantId",
      message:
        "Authority epoch seal finalizer tenant must match replay context.",
      expected: String(input.expectedTenantId),
      actual: finalizerProof.tenantId,
    });
  }
  if (
    input.expectedAuthorityScope !== undefined &&
    finalizerProof.authorityScope !== input.expectedAuthorityScope
  ) {
    pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
      code: "operational_state_authority_epoch_seal_finalizer_authority_scope_mismatch",
      path: "/expectedAuthorityScope",
      message:
        "Authority epoch seal finalizer scope must match replay context.",
      expected: input.expectedAuthorityScope,
      actual: finalizerProof.authorityScope,
    });
  }
  if (
    input.expectedFinalizerPrincipalId !== undefined &&
    finalizerProof.finalizerPrincipalId !==
      input.expectedFinalizerPrincipalId
  ) {
    pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
      code: "operational_state_authority_epoch_seal_finalizer_finalizer_principal_mismatch",
      path: "/expectedFinalizerPrincipalId",
      message:
        "Authority epoch seal finalizer principal must match replay context.",
      expected: input.expectedFinalizerPrincipalId,
      actual: finalizerProof.finalizerPrincipalId,
    });
  }
  if (
    input.expectedAuthorityTransitionHash !== undefined &&
    finalizerProof.authorityTransitionHash !==
      input.expectedAuthorityTransitionHash
  ) {
    pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
      code: "operational_state_authority_epoch_seal_finalizer_transition_hash_mismatch",
      path: "/expectedAuthorityTransitionHash",
      message:
        "Authority epoch seal finalizer proof must bind the exact authority-transition hash required by replay.",
      expected: input.expectedAuthorityTransitionHash,
      actual: finalizerProof.authorityTransitionHash ?? "none",
    });
  }

  const keyBinding = finalizerProof.finalizerKeyBinding;
  if (keyBinding.tenantId !== finalizerProof.tenantId) {
    pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
      code: "operational_state_authority_epoch_seal_finalizer_tenant_mismatch",
      path: "/finalizerProof/finalizerKeyBinding/tenantId",
      message:
        "Authority epoch seal finalizer key binding tenant must match the sealed payload tenant.",
      expected: finalizerProof.tenantId,
      actual: keyBinding.tenantId,
    });
  }
  if (keyBinding.authorityScope !== finalizerProof.authorityScope) {
    pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
      code: "operational_state_authority_epoch_seal_finalizer_authority_scope_mismatch",
      path: "/finalizerProof/finalizerKeyBinding/authorityScope",
      message:
        "Authority epoch seal finalizer key binding scope must match the sealed payload scope.",
      expected: finalizerProof.authorityScope,
      actual: keyBinding.authorityScope,
    });
  }
  if (keyBinding.principalId !== finalizerProof.finalizerPrincipalId) {
    pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
      code: "operational_state_authority_epoch_seal_finalizer_finalizer_principal_mismatch",
      path: "/finalizerProof/finalizerKeyBinding/principalId",
      message:
        "Authority epoch seal finalizer key binding principal must match the finalizer principal.",
      expected: finalizerProof.finalizerPrincipalId,
      actual: keyBinding.principalId,
    });
  }
  if (
    keyBinding.authorityTopologyHash !==
    finalizerProof.sealedAuthorityTopologyHash
  ) {
    pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
      code: "operational_state_authority_epoch_seal_finalizer_key_binding_scope_mismatch",
      path: "/finalizerProof/finalizerKeyBinding/authorityTopologyHash",
      message:
        "Authority epoch seal finalizer key binding must be replay-current for the sealed authority topology.",
      expected: finalizerProof.sealedAuthorityTopologyHash,
      actual: keyBinding.authorityTopologyHash ?? "none",
    });
  }

  const verifierEvaluation =
    evaluateOperationalStateSignatureVerifierAdapterProof({
      keyBinding,
      proof: finalizerProof.verifierProof,
      expectedTenantId: finalizerProof.tenantId,
      expectedAuthorityScope: finalizerProof.authorityScope,
      expectedPrincipalId: finalizerProof.finalizerPrincipalId,
      expectedKeyId: keyBinding.keyId,
      expectedAlgorithm: keyBinding.algorithm,
      expectedPayloadHash: finalizerProof.sealPayloadHash,
      expectedSignatureHash:
        input.expectedSignatureHash ??
        finalizerProof.verifierProof.signatureHash,
      ...(input.allowedVerifierIds !== undefined
        ? { allowedVerifierIds: input.allowedVerifierIds }
        : {}),
      ...(input.requireVerifierProofAdmission !== undefined
        ? { requireProofAdmission: input.requireVerifierProofAdmission }
        : {}),
      ...(input.verifierProofAdmissionReplay !== undefined
        ? { proofAdmissionReplay: input.verifierProofAdmissionReplay }
        : {}),
    });
  if (!verifierEvaluation.valid) {
    pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
      code: "operational_state_authority_epoch_seal_finalizer_verifier_proof_invalid",
      path: "/finalizerProof/verifierProof",
      message:
        "Authority epoch seal finalizer signature must verify through the constrained verifier-proof boundary.",
      actual: verifierEvaluation.issues.map((issue) => issue.code).join(","),
    });
  }

  const finalizerProofAdmissionReplay = input.finalizerProofAdmissionReplay;
  const requiredFinalizerProofAdmissionRecord =
    finalizerProofAdmissionReplay?.requiredFinalizerProofAdmissionRecord;
  const finalizerProofAdmissionWitnessReplay =
    input.finalizerProofAdmissionWitnessReplay;
  const requiredFinalizerProofAdmissionWitnessRecord =
    finalizerProofAdmissionWitnessReplay
      ?.requiredFinalizerProofAdmissionWitnessRecord;
  const requireFinalizerProofAdmission =
    input.requireFinalizerProofAdmission === true ||
    input.requireFinalizerProofAdmissionWitnessQuorum === true ||
    input.requireFinalizerProofAdmissionWitnessAuthorityTopology === true ||
    input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmission ===
      true ||
    input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitness ===
      true ||
    input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
      true ||
    input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
      true;
  if (requireFinalizerProofAdmission) {
    if (finalizerProofAdmissionReplay === undefined) {
      pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_replay_missing",
        path: "/finalizerProofAdmissionReplay",
        message:
          "Authority epoch seal finalizer proof cannot constitute finality without finalizer-proof admission history.",
      });
    } else if (!finalizerProofAdmissionReplay.valid) {
      pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_replay_invalid",
        path: "/finalizerProofAdmissionReplay",
        message:
          "Authority epoch seal finalizer-proof admission replay is invalid.",
        actual: finalizerProofAdmissionReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      finalizerProofAdmissionReplay.requiredFinalizerProof === undefined ||
      requiredFinalizerProofAdmissionRecord === undefined ||
      finalizerProofAdmissionReplay.requiredFinalizerProof
        .finalizerProofHash !== finalizerProof.finalizerProofHash ||
      requiredFinalizerProofAdmissionRecord.finalizerProofHash !==
        finalizerProof.finalizerProofHash
    ) {
      pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
        code: "operational_state_authority_epoch_seal_finalizer_proof_not_admitted",
        path: "/finalizerProof/finalizerProofHash",
        message:
          "Authority epoch seal finalizer proof is not the replay-current admitted proof for its seal id.",
        expected: finalizerProof.finalizerProofHash,
        actual:
          requiredFinalizerProofAdmissionRecord?.finalizerProofHash ?? "none",
      });
    }
  }
  if (
    input.requireFinalizerProofAdmissionWitnessQuorum === true ||
    input.requireFinalizerProofAdmissionWitnessAuthorityTopology === true ||
    input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmission ===
      true ||
    input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitness ===
      true ||
    input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
      true ||
    input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
      true
  ) {
    if (finalizerProofAdmissionWitnessReplay === undefined) {
      pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_replay_missing",
        path: "/finalizerProofAdmissionWitnessReplay",
        message:
          "Authority epoch seal finalizer proof cannot constitute finality from a self-authored proof-admission row.",
      });
    } else if (!finalizerProofAdmissionWitnessReplay.valid) {
      pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_replay_invalid",
        path: "/finalizerProofAdmissionWitnessReplay",
        message:
          "Authority epoch seal finalizer-proof admission witness replay is invalid.",
        actual: finalizerProofAdmissionWitnessReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      requiredFinalizerProofAdmissionRecord === undefined ||
      requiredFinalizerProofAdmissionWitnessRecord === undefined ||
      requiredFinalizerProofAdmissionWitnessRecord.admissionRecordHash !==
        requiredFinalizerProofAdmissionRecord.admissionRecordHash
    ) {
      pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_latest_record_not_witnessed",
        path: "/finalizerProofAdmissionWitnessReplay",
        message:
          "Latest authority epoch seal finalizer-proof admission record is not witnessed by the replayed proof-admission witness quorum.",
        expected:
          requiredFinalizerProofAdmissionRecord?.admissionRecordHash ??
          "finalizer-proof-admission-record",
        actual:
          requiredFinalizerProofAdmissionWitnessRecord?.admissionRecordHash ??
          "none",
      });
    }
  }
  if (
    (input.requireFinalizerProofAdmissionWitnessAuthorityTopology === true ||
      input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmission ===
        true ||
      input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitness ===
        true ||
      input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    finalizerProofAdmissionWitnessReplay?.witnessAuthorityTopology === undefined
  ) {
    pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
      code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_topology_missing",
      path: "/finalizerProofAdmissionWitnessReplay/witnessAuthorityTopology",
      message:
        "Authority epoch seal finalizer proof requires replayed finalizer-proof admission witness authority topology.",
    });
  }
  if (
    (input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmission ===
      true ||
    input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitness ===
      true ||
    input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
      true ||
    input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
      true) &&
    finalizerProofAdmissionWitnessReplay !== undefined &&
    finalizerProofAdmissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay ===
      undefined
  ) {
    pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
      code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_replay_missing",
      path: "/finalizerProofAdmissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
      message:
        "Authority epoch seal finalizer proof requires finalizer-proof admission witness authority topology to replay from admitted authority-transition history.",
    });
  }
  if (
    (input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitness ===
      true ||
      input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    finalizerProofAdmissionWitnessReplay?.witnessAuthorityTransitionAdmissionReplay !==
      undefined
  ) {
    const admissionWitnessReplay =
      finalizerProofAdmissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .admissionWitnessReplay;
    if (admissionWitnessReplay === undefined) {
      pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_replay_missing",
        path: "/finalizerProofAdmissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
        message:
          "Authority epoch seal finalizer proof requires finalizer-proof admission witness authority-transition admission records to be witnessed before seal finality.",
      });
    } else if (!admissionWitnessReplay.valid) {
      pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_replay_invalid",
        path: "/finalizerProofAdmissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
        message:
          "Authority epoch seal finalizer proof cannot consume invalid finalizer-proof admission witness authority-transition admission witness history.",
        actual: admissionWitnessReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      (input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
        input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
          true) &&
      admissionWitnessReplay.witnessAuthorityTopology === undefined
    ) {
      pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_topology_missing",
        path: "/finalizerProofAdmissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTopology",
        message:
          "Authority epoch seal finalizer proof requires finalizer-proof admission witness authority-transition admission witness certificates to bind to replayed witness authority topology.",
      });
    } else if (
      input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay ===
        undefined
    ) {
      pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        path: "/finalizerProofAdmissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Authority epoch seal finalizer proof requires finalizer-proof admission witness authority-transition admission witness authority topology to replay from admitted authority-transition history.",
      });
    } else if (
      input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      !admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.valid
    ) {
      pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        path: "/finalizerProofAdmissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Authority epoch seal finalizer proof cannot consume invalid nested finalizer-proof admission witness authority-transition admission witness authority history.",
        actual:
          admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.issues
            .map((issue) => issue.code)
            .join(","),
      });
    } else if (
      input.requireFinalizerProofAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      admissionWitnessReplay.witnessAuthorityTopology !== undefined &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      (admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .latestAdmittedTopology === undefined ||
        !operationalStateAuthorityTopologiesMatch(
          admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology,
          admissionWitnessReplay.witnessAuthorityTopology,
        ))
    ) {
      pushOperationalStateAuthorityEpochSealFinalizerIssue(issues, {
        code: "operational_state_authority_epoch_seal_finalizer_proof_admission_witness_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/finalizerProofAdmissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Authority epoch seal finalizer proof requires finalizer-proof admission witness authority-transition admission witness authority topology to be recovered from admitted authority-transition history.",
        expected: admissionWitnessReplay.witnessAuthorityTopology.topologyHash,
        actual:
          admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology?.topologyHash ?? "none",
      });
    }
  }

  return {
    valid: issues.length === 0,
    accepted: issues.length === 0 && verifierEvaluation.accepted,
    finalizerProof,
    verifierEvaluation,
    ...(finalizerProofAdmissionReplay !== undefined
      ? { finalizerProofAdmissionReplay }
      : {}),
    ...(requiredFinalizerProofAdmissionRecord !== undefined
      ? { requiredFinalizerProofAdmissionRecord }
      : {}),
    ...(finalizerProofAdmissionWitnessReplay !== undefined
      ? { finalizerProofAdmissionWitnessReplay }
      : {}),
    ...(requiredFinalizerProofAdmissionWitnessRecord !== undefined
      ? { requiredFinalizerProofAdmissionWitnessRecord }
      : {}),
    sealPayloadHash: finalizerProof.sealPayloadHash,
    issues,
  };
}

export function buildOperationalStateRecoveryCut(
  input: OperationalStateRecoveryCutInput,
): OperationalStateRecoveryCut {
  const payload: Omit<OperationalStateRecoveryCut, "cutHash"> = {
    schemaVersion: OPERATIONAL_STATE_RECOVERY_CUT_SCHEMA_VERSION,
    cutId: input.cutId,
    tenantId: tenantId(String(input.tenantId)),
    subject: input.subject,
    recoveredAt: input.recoveredAt,
    recoveredBy: input.recoveredBy,
    authorityScope: input.authorityScope,
    lanes: input.lanes,
  };
  return {
    ...payload,
    cutHash: computeOperationalStateRecoveryCutHash(payload),
  };
}

export function computeOperationalStateRecoveryCutHash(
  cut: Omit<OperationalStateRecoveryCut, "cutHash">,
): string {
  return fingerprint64(canonicalStringify(cut));
}

export function verifyOperationalStateRecoveryCutHash(
  cut: OperationalStateRecoveryCut,
): StateReviewArtifactHashValidation {
  const { cutHash, ...payload } = cut;
  const expectedHash = computeOperationalStateRecoveryCutHash(payload);
  return {
    valid: cutHash === expectedHash,
    expectedHash,
    actualHash: cutHash,
  };
}

export function evaluateOperationalStateRecoveryCut(
  view: CurrentStateView,
  options: OperationalStateRecoveryCutEvaluationOptions = {},
): OperationalStateRecoveryCutEvaluation {
  const cut = view.recoveryCut;
  if (cut === undefined) {
    return {
      valid: false,
      replayableLaneCount: 0,
      requiredLaneCount: 0,
      projectionLaneCount: 0,
      excludedPrivateLaneCount: 0,
      issues: [
        {
          code: "operational_state_recovery_cut_missing",
          path: "/recoveryCut",
          message:
            "CurrentStateView cannot authorize recovered operational state without a recovery cut when recovery proof is required.",
        },
      ],
    };
  }
  return evaluateOperationalStateRecoveryCutAgainstView(cut, view, options);
}

export function evaluateOperationalStateRecoveryCutAgainstView(
  cut: OperationalStateRecoveryCut,
  view: CurrentStateView,
  options: OperationalStateRecoveryCutEvaluationOptions = {},
): OperationalStateRecoveryCutEvaluation {
  const issues: OperationalStateRecoveryCutIssue[] = [];
  const hashValidation = verifyOperationalStateRecoveryCutHash(cut);
  const lanesById = new Map<string, OperationalStateRecoveryLane>();
  const seenLaneIds = new Set<string>();
  let replayableLaneCount = 0;
  let requiredLaneCount = 0;
  let projectionLaneCount = 0;
  let excludedPrivateLaneCount = 0;

  if (!hashValidation.valid) {
    issues.push({
      code: "operational_state_recovery_cut_hash_mismatch",
      path: "/recoveryCut/cutHash",
      message: `Operational state recovery cut hash ${hashValidation.actualHash} does not match recomputed hash ${hashValidation.expectedHash}.`,
      expected: hashValidation.expectedHash,
      actual: hashValidation.actualHash,
    });
  }
  if (cut.tenantId !== view.tenantId) {
    issues.push({
      code: "operational_state_recovery_tenant_mismatch",
      path: "/recoveryCut/tenantId",
      message: `Operational state recovery cut tenant ${cut.tenantId} does not match current state view tenant ${view.tenantId}.`,
      expected: view.tenantId,
      actual: cut.tenantId,
    });
  }
  if (canonicalStringify(cut.subject) !== canonicalStringify(view.subject)) {
    issues.push({
      code: "operational_state_recovery_subject_mismatch",
      path: "/recoveryCut/subject",
      message:
        "Operational state recovery cut subject does not match current state view subject.",
    });
  }
  if (
    options.expectedAuthorityScope !== undefined &&
    cut.authorityScope !== options.expectedAuthorityScope
  ) {
    issues.push({
      code: "operational_state_recovery_authority_scope_mismatch",
      path: "/recoveryCut/authorityScope",
      message: `Operational state recovery cut authority scope ${cut.authorityScope} does not match expected scope ${options.expectedAuthorityScope}.`,
      expected: options.expectedAuthorityScope,
      actual: cut.authorityScope,
    });
  }
  if (cut.lanes.length === 0) {
    issues.push({
      code: "operational_state_recovery_lane_missing",
      path: "/recoveryCut/lanes",
      message:
        "Operational state recovery cut has no lanes, so recovered state would rely on unstated representation.",
    });
  }

  cut.lanes.forEach((lane, index) => {
    const path = `/recoveryCut/lanes/${index}`;
    if (seenLaneIds.has(lane.laneId)) {
      issues.push({
        code: "operational_state_recovery_lane_duplicate",
        path: `${path}/laneId`,
        message: `Operational state recovery lane ${lane.laneId} appears more than once.`,
        actual: lane.laneId,
      });
    } else {
      seenLaneIds.add(lane.laneId);
      lanesById.set(lane.laneId, lane);
    }

    if (lane.required) requiredLaneCount += 1;
    if (lane.laneKind === "projection") projectionLaneCount += 1;
    if (privateOperationalStateRecoverySources.has(lane.source)) {
      excludedPrivateLaneCount += 1;
    }
    if (replayableOperationalStateRecoverySources.has(lane.source)) {
      replayableLaneCount += 1;
    }

    if (lane.authorityScope !== cut.authorityScope) {
      issues.push({
        code: "operational_state_recovery_authority_scope_mismatch",
        path: `${path}/authorityScope`,
        message: `Operational state recovery lane ${lane.laneId} authority scope ${lane.authorityScope} does not match cut scope ${cut.authorityScope}.`,
        expected: cut.authorityScope,
        actual: lane.authorityScope,
      });
    }

    if (lane.required && privateOperationalStateRecoverySources.has(lane.source)) {
      issues.push({
        code: "operational_state_recovery_lane_private_authority",
        path: `${path}/source`,
        message: `Operational state recovery lane ${lane.laneId} tries to make ${lane.source} operational authority.`,
        actual: lane.source,
      });
    }

    if (
      lane.required &&
      (options.requireAllRequiredLanesReplayable ?? true) &&
      !replayableOperationalStateRecoverySources.has(lane.source)
    ) {
      issues.push({
        code: "operational_state_recovery_lane_not_replayable",
        path: `${path}/source`,
        message: `Operational state recovery lane ${lane.laneId} source ${lane.source} is not an admitted replay source.`,
        actual: lane.source,
      });
    }

    if (lane.required && !operationalStateRecoveryLaneHasHash(lane)) {
      issues.push({
        code: "operational_state_recovery_lane_hash_missing",
        path,
        message: `Operational state recovery lane ${lane.laneId} is required but has no replay, head, projection, store-root, or authority hash.`,
      });
    }

    if (
      lane.laneKind === "projection" &&
      lane.source !== "current_admissible_projection"
    ) {
      issues.push({
        code: "operational_state_recovery_lane_not_replayable",
        path: `${path}/source`,
        message: `Projection recovery lane ${lane.laneId} must be a current admissible projection, not ${lane.source}.`,
        expected: "current_admissible_projection",
        actual: lane.source,
      });
    }
    if (lane.laneKind === "projection" && lane.dependencies.length === 0) {
      issues.push({
        code: "operational_state_recovery_projection_unclosed",
        path: `${path}/dependencies`,
        message: `Projection recovery lane ${lane.laneId} has no dependencies, so it does not prove replay closure.`,
      });
    }
  });

  if ((options.requireCurrentProjection ?? true) && projectionLaneCount === 0) {
    issues.push({
      code: "operational_state_recovery_projection_missing",
      path: "/recoveryCut/lanes",
      message:
        "Operational state recovery cut has no current admissible projection lane.",
    });
  }

  cut.lanes.forEach((lane, laneIndex) => {
    lane.dependencies.forEach((dependency, dependencyIndex) => {
      const dependencyPath = `/recoveryCut/lanes/${laneIndex}/dependencies/${dependencyIndex}`;
      const target = lanesById.get(dependency.laneId);
      if (target === undefined) {
        issues.push({
          code: "operational_state_recovery_dependency_missing",
          path: `${dependencyPath}/laneId`,
          message: `Operational state recovery lane ${lane.laneId} depends on missing lane ${dependency.laneId}.`,
          actual: dependency.laneId,
        });
        return;
      }
      if (
        dependency.minimumSequence !== undefined &&
        (target.sequence === undefined ||
          target.sequence < dependency.minimumSequence)
      ) {
        issues.push({
          code: "operational_state_recovery_dependency_sequence_regression",
          path: `${dependencyPath}/minimumSequence`,
          message: `Operational state recovery lane ${dependency.laneId} sequence ${target.sequence ?? "none"} is below required sequence ${dependency.minimumSequence}.`,
          expected: dependency.minimumSequence,
          actual: target.sequence ?? "none",
        });
      }
      if (
        dependency.requiredHeadHash !== undefined &&
        target.headHash !== dependency.requiredHeadHash
      ) {
        issues.push({
          code: "operational_state_recovery_dependency_head_mismatch",
          path: `${dependencyPath}/requiredHeadHash`,
          message: `Operational state recovery lane ${dependency.laneId} head hash ${target.headHash ?? "none"} does not match required head hash ${dependency.requiredHeadHash}.`,
          expected: dependency.requiredHeadHash,
          actual: target.headHash ?? "none",
        });
      }
      if (
        dependency.requiredHistoryHash !== undefined &&
        target.historyHash !== dependency.requiredHistoryHash
      ) {
        issues.push({
          code: "operational_state_recovery_dependency_history_mismatch",
          path: `${dependencyPath}/requiredHistoryHash`,
          message: `Operational state recovery lane ${dependency.laneId} history hash ${target.historyHash ?? "none"} does not match required history hash ${dependency.requiredHistoryHash}.`,
          expected: dependency.requiredHistoryHash,
          actual: target.historyHash ?? "none",
        });
      }
      if (
        dependency.requiredAuthorityHash !== undefined &&
        target.authorityHash !== dependency.requiredAuthorityHash
      ) {
        issues.push({
          code: "operational_state_recovery_dependency_authority_mismatch",
          path: `${dependencyPath}/requiredAuthorityHash`,
          message: `Operational state recovery lane ${dependency.laneId} authority hash ${target.authorityHash ?? "none"} does not match required authority hash ${dependency.requiredAuthorityHash}.`,
          expected: dependency.requiredAuthorityHash,
          actual: target.authorityHash ?? "none",
        });
      }
    });
  });

  return {
    valid: issues.length === 0,
    cutId: cut.cutId,
    cutHash: cut.cutHash,
    replayableLaneCount,
    requiredLaneCount,
    projectionLaneCount,
    excludedPrivateLaneCount,
    issues,
  };
}

