export function replayOperationalStateRecoveryCutAdmissionWitnessAuthorityTransitionAdmissionWitnessRecords(
  input: OperationalStateRecoveryCutAdmissionWitnessAuthorityTransitionAdmissionWitnessReplayInput,
): OperationalStateRecoveryCutAdmissionWitnessAuthorityTransitionAdmissionWitnessReplay {
  const issues: OperationalStateRecoveryCutAdmissionIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const witnessHashBySequence = new Map<number, string>();
  const witnessRecordByAdmissionHash = new Map<
    string,
    OperationalStateRecoveryCutAdmissionWitnessAuthorityTransitionAdmissionWitnessRecord
  >();
  const witnessAuthorityTopology = input.witnessAuthorityTopology;
  const witnessAuthorityTransitionAdmissionReplay =
    input.witnessAuthorityTransitionAdmissionReplay;
  const principalById = new Map<string, OperationalStateAuthorityPrincipalState>(
    witnessAuthorityTopology?.principals.map((principal) => [
      principal.principalId,
      principal,
    ]) ?? [],
  );
  let expectedSequence = 1;
  let previousWitnessRecordHash: string | undefined;
  let latestWitnessRecord:
    | OperationalStateRecoveryCutAdmissionWitnessAuthorityTransitionAdmissionWitnessRecord
    | undefined;

  if (input.admissionReplay !== undefined && !input.admissionReplay.valid) {
    pushOperationalStateRecoveryCutAdmissionIssue(issues, {
      code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_admission_replay_invalid",
      path: "/admissionReplay",
      message:
        "Recovery-cut admission witness authority-transition admission witness replay cannot account for invalid transition-admission history.",
      actual: input.admissionReplay.issues
        .map((issue) => issue.code)
        .join(","),
    });
  }

  if (
    (input.requireWitnessAuthorityTopology === true ||
      input.requireWitnessAuthorityTransitionAdmission === true) &&
    witnessAuthorityTopology === undefined
  ) {
    pushOperationalStateRecoveryCutAdmissionIssue(issues, {
      code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_topology_missing",
      path: "/witnessAuthorityTopology",
      message:
        "Recovery-cut admission witness authority-transition admission witness replay requires a replayed witness authority topology.",
    });
  }

  if (witnessAuthorityTopology !== undefined) {
    const topologyHashValidation =
      verifyOperationalStateAuthorityTopologyHash(witnessAuthorityTopology);
    if (!topologyHashValidation.valid) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_topology_hash_mismatch",
        path: "/witnessAuthorityTopology/topologyHash",
        message: `Recovery-cut admission witness authority-transition admission witness authority topology hash ${topologyHashValidation.actualHash} does not match recomputed hash ${topologyHashValidation.expectedHash}.`,
        expected: topologyHashValidation.expectedHash,
        actual: topologyHashValidation.actualHash,
      });
    }
    if (witnessAuthorityTopology.tenantId !== expectedTenantId) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_topology_tenant_mismatch",
        path: "/witnessAuthorityTopology/tenantId",
        message:
          "Recovery-cut admission witness authority-transition admission witness authority topology tenant does not match replay tenant.",
        expected: expectedTenantId,
        actual: witnessAuthorityTopology.tenantId,
      });
    }
    if (witnessAuthorityTopology.authorityScope !== input.authorityScope) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_topology_scope_mismatch",
        path: "/witnessAuthorityTopology/authorityScope",
        message:
          "Recovery-cut admission witness authority-transition admission witness authority topology scope does not match replay scope.",
        expected: input.authorityScope,
        actual: witnessAuthorityTopology.authorityScope,
      });
    }
    if (
      witnessAuthorityTopology.requiredWitnesses === undefined ||
      witnessAuthorityTopology.minimumWitnesses === undefined
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_quorum_missing",
        path: "/witnessAuthorityTopology/requiredWitnesses",
        message:
          "Recovery-cut admission witness authority-transition admission witness authority topology must define quorum thresholds.",
      });
    }
  }

  if (input.requireWitnessAuthorityTransitionAdmission === true) {
    if (witnessAuthorityTransitionAdmissionReplay === undefined) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Recovery-cut admission witness authority-transition admission witness replay requires its witness authority topology to replay from admitted authority-transition history.",
      });
    } else if (!witnessAuthorityTransitionAdmissionReplay.valid) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        path: "/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Recovery-cut admission witness authority-transition admission witness replay cannot consume invalid nested witness-authority transition admission history.",
        actual: witnessAuthorityTransitionAdmissionReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      witnessAuthorityTopology !== undefined &&
      (witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology ===
        undefined ||
        !operationalStateAuthorityTopologiesMatch(
          witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology,
          witnessAuthorityTopology,
        ))
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Recovery-cut transition-admission witness authority topology must be recovered from admitted authority-transition history.",
        expected: witnessAuthorityTopology.topologyHash,
        actual:
          witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology
            ?.topologyHash ?? "none",
      });
    }
  }

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const witnessRecordHashValidation =
      verifyOperationalStateRecoveryCutAdmissionWitnessAuthorityTransitionAdmissionWitnessRecordHash(
        record,
      );
    const certificateHashValidation =
      verifyOperationalStateQuorumCertificateProofCertificateHash(
        record.admissionCertificate,
      );
    const previousWitnessHashAtSequence = witnessHashBySequence.get(
      record.witnessSequence,
    );

    if (
      previousWitnessHashAtSequence !== undefined &&
      previousWitnessHashAtSequence !== record.witnessRecordHash
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_record_fork",
        path: `${path}/witnessSequence`,
        message: `Recovery-cut admission witness authority-transition admission witness sequence ${record.witnessSequence} has more than one witness record hash.`,
        expected: previousWitnessHashAtSequence,
        actual: record.witnessRecordHash,
      });
    } else if (previousWitnessHashAtSequence === undefined) {
      witnessHashBySequence.set(
        record.witnessSequence,
        record.witnessRecordHash,
      );
    }

    if (
      record.tenantId !== expectedTenantId ||
      record.admissionCertificate.tenantId !== expectedTenantId
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_record_tenant_mismatch",
        path,
        message:
          "Recovery-cut admission witness authority-transition admission witness record and certificate must match the replay tenant.",
        expected: expectedTenantId,
      });
    }
    if (
      record.transitionAdmissionWitnessStoreId !==
        input.transitionAdmissionWitnessStoreId ||
      record.transitionAdmissionStoreId !== input.transitionAdmissionStoreId
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_record_store_mismatch",
        path,
        message:
          "Recovery-cut admission witness authority-transition admission witness record must bind the expected witness and transition-admission stores.",
        expected: `${input.transitionAdmissionWitnessStoreId}:${input.transitionAdmissionStoreId}`,
        actual: `${record.transitionAdmissionWitnessStoreId}:${record.transitionAdmissionStoreId}`,
      });
    }
    if (
      record.topologyId !== input.topologyId ||
      record.authorityScope !== input.authorityScope ||
      record.admissionCertificate.authorityScope !== input.authorityScope
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_record_scope_mismatch",
        path,
        message:
          "Recovery-cut admission witness authority-transition admission witness record must share the replay topology and authority scope.",
        expected: `${input.topologyId}:${input.authorityScope}`,
      });
    }
    if (record.witnessSequence !== expectedSequence) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_record_sequence_gap",
        path: `${path}/witnessSequence`,
        message:
          "Recovery-cut admission witness authority-transition admission witness records must replay as a contiguous witness sequence.",
        expected: expectedSequence,
        actual: record.witnessSequence,
      });
    }
    if (record.previousWitnessRecordHash !== previousWitnessRecordHash) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_record_previous_hash_mismatch",
        path: `${path}/previousWitnessRecordHash`,
        message:
          "Recovery-cut admission witness authority-transition admission witness record does not chain to the previous witness record hash.",
        expected: previousWitnessRecordHash ?? "none",
        actual: record.previousWitnessRecordHash ?? "none",
      });
    }
    if (!certificateHashValidation.valid) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_certificate_hash_mismatch",
        path: `${path}/admissionCertificate/quorumCertificateHash`,
        message: `Recovery-cut admission witness authority-transition admission witness certificate hash ${certificateHashValidation.actualHash} does not match recomputed hash ${certificateHashValidation.expectedHash}.`,
        expected: certificateHashValidation.expectedHash,
        actual: certificateHashValidation.actualHash,
      });
    }
    if (
      !record.admissionCertificate.certified ||
      record.admissionCertificate.status !== "certified"
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_certificate_not_certified",
        path: `${path}/admissionCertificate/status`,
        message:
          "Recovery-cut admission witness authority-transition admission cannot become accountable through a non-certified witness certificate.",
        expected: "certified",
        actual: record.admissionCertificate.status,
      });
    }
    if (
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.minimumWitnesses ||
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.requiredWitnesses
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_certificate_quorum_not_met",
        path: `${path}/admissionCertificate/acceptedWitnessIds`,
        message:
          "Recovery-cut admission witness authority-transition admission witness certificate does not satisfy its declared witness quorum.",
        expected: Math.max(
          record.admissionCertificate.requiredWitnesses,
          record.admissionCertificate.minimumWitnesses,
        ),
        actual: record.admissionCertificate.acceptedWitnessIds.length,
      });
    }
    if (
      record.admissionCertificate.subjectKind !==
        OPERATIONAL_STATE_RECOVERY_CUT_ADMISSION_WITNESS_AUTHORITY_TRANSITION_ADMISSION_RECORD_SUBJECT_KIND ||
      record.admissionCertificate.subjectId !==
        `${record.transitionAdmissionStoreId}:${record.topologyId}` ||
      record.admissionCertificate.subjectSequence !==
        record.admissionSequence ||
      record.admissionCertificate.subjectHash !== record.admissionRecordHash
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_certificate_subject_mismatch",
        path: `${path}/admissionCertificate`,
        message:
          "Recovery-cut admission witness authority-transition admission witness certificate must certify the exact transition-admission store, topology id, admission sequence, and admission record hash.",
        expected: record.admissionRecordHash,
        actual: record.admissionCertificate.subjectHash,
      });
    }
    if (
      input.requiredAuthorityBoundary !== undefined &&
      record.admissionCertificate.authorityBoundary !==
        input.requiredAuthorityBoundary
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_certificate_authority_boundary_mismatch",
        path: `${path}/admissionCertificate/authorityBoundary`,
        message:
          "Recovery-cut admission witness authority-transition admission witness certificate was admitted under the wrong authority boundary.",
        expected: input.requiredAuthorityBoundary,
        actual: record.admissionCertificate.authorityBoundary,
      });
    }
    if (witnessAuthorityTopology !== undefined) {
      if (
        record.admissionCertificate.authorityTopologyHash !==
        witnessAuthorityTopology.topologyHash
      ) {
        pushOperationalStateRecoveryCutAdmissionIssue(issues, {
          code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_certificate_authority_topology_mismatch",
          path: `${path}/admissionCertificate/authorityTopologyHash`,
          message:
            "Recovery-cut admission witness authority-transition admission witness certificate is not bound to the replayed witness authority topology.",
          expected: witnessAuthorityTopology.topologyHash,
          actual:
            record.admissionCertificate.authorityTopologyHash ?? "none",
        });
      }

      const acceptedWitnessIds =
        record.admissionCertificate.acceptedWitnessIds;
      const uniqueAcceptedWitnessIds = new Set(acceptedWitnessIds);
      if (uniqueAcceptedWitnessIds.size !== acceptedWitnessIds.length) {
        pushOperationalStateRecoveryCutAdmissionIssue(issues, {
          code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_duplicate_witness",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Recovery-cut admission witness authority-transition admission witness authority quorum cannot be satisfied by duplicate witness ids.",
          expected: uniqueAcceptedWitnessIds.size,
          actual: acceptedWitnessIds.length,
        });
      }

      let activeAuthorizedWitnessCount = 0;
      for (const witnessId of uniqueAcceptedWitnessIds) {
        const principal = principalById.get(witnessId);
        if (principal === undefined) {
          pushOperationalStateRecoveryCutAdmissionIssue(issues, {
            code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_witness_unknown",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Recovery-cut admission witness authority-transition admission witness certificate names a witness outside the replayed authority topology.",
            expected: witnessAuthorityTopology.topologyHash,
            actual: witnessId,
          });
          continue;
        }
        if (principal.status !== "active") {
          pushOperationalStateRecoveryCutAdmissionIssue(issues, {
            code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_witness_not_active",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Recovery-cut admission witness authority-transition admission witness certificate names a witness that is not active in the replayed authority topology.",
            expected: "active",
            actual: `${witnessId}:${principal.status}`,
          });
          continue;
        }
        activeAuthorizedWitnessCount += 1;
      }

      const requiredAuthorizedWitnesses = Math.max(
        witnessAuthorityTopology.requiredWitnesses ?? 0,
        witnessAuthorityTopology.minimumWitnesses ?? 0,
      );
      if (activeAuthorizedWitnessCount < requiredAuthorizedWitnesses) {
        pushOperationalStateRecoveryCutAdmissionIssue(issues, {
          code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_quorum_not_met",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Recovery-cut admission witness authority-transition admission witness certificate does not satisfy the replayed witness authority topology quorum.",
          expected: requiredAuthorizedWitnesses,
          actual: activeAuthorizedWitnessCount,
        });
      }
    }
    if (!witnessRecordHashValidation.valid) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_record_hash_mismatch",
        path: `${path}/witnessRecordHash`,
        message: `Recovery-cut admission witness authority-transition admission witness record hash ${witnessRecordHashValidation.actualHash} does not match recomputed hash ${witnessRecordHashValidation.expectedHash}.`,
        expected: witnessRecordHashValidation.expectedHash,
        actual: witnessRecordHashValidation.actualHash,
      });
    }

    witnessRecordByAdmissionHash.set(record.admissionRecordHash, record);
    expectedSequence = record.witnessSequence + 1;
    previousWitnessRecordHash = record.witnessRecordHash;
    latestWitnessRecord = record;
  });

  const requiredAdmissionRecord =
    input.requiredAdmissionRecord ?? input.admissionReplay?.latestAdmittedRecord;
  let requiredAdmissionWitnessRecord:
    | OperationalStateRecoveryCutAdmissionWitnessAuthorityTransitionAdmissionWitnessRecord
    | undefined;
  if (requiredAdmissionRecord !== undefined) {
    const admissionRecordHashValidation =
      verifyOperationalStateRecoveryCutAdmissionWitnessAuthorityTransitionAdmissionRecordHash(
        requiredAdmissionRecord,
      );
    if (!admissionRecordHashValidation.valid) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_record_hash_mismatch",
        path: "/requiredAdmissionRecord/admissionRecordHash",
        message: `Required recovery-cut admission witness authority-transition admission hash ${admissionRecordHashValidation.actualHash} does not match recomputed hash ${admissionRecordHashValidation.expectedHash}.`,
        expected: admissionRecordHashValidation.expectedHash,
        actual: admissionRecordHashValidation.actualHash,
      });
    }
    requiredAdmissionWitnessRecord = witnessRecordByAdmissionHash.get(
      requiredAdmissionRecord.admissionRecordHash,
    );
    if (requiredAdmissionWitnessRecord === undefined) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_latest_record_not_witnessed",
        path: "/requiredAdmissionRecord/admissionRecordHash",
        message:
          "Latest recovery-cut admission witness authority-transition admission record has no replayed witness certificate.",
        expected: requiredAdmissionRecord.admissionRecordHash,
      });
    } else if (
      requiredAdmissionWitnessRecord.transitionAdmissionStoreId !==
        requiredAdmissionRecord.transitionAdmissionStoreId ||
      requiredAdmissionWitnessRecord.topologyId !==
        requiredAdmissionRecord.topologyId ||
      requiredAdmissionWitnessRecord.admissionSequence !==
        requiredAdmissionRecord.admissionSequence ||
      requiredAdmissionWitnessRecord.authoritySequence !==
        requiredAdmissionRecord.authoritySequence ||
      requiredAdmissionWitnessRecord.authorityRecordHash !==
        requiredAdmissionRecord.authorityRecordHash ||
      requiredAdmissionWitnessRecord.nextAuthorityTopologyHash !==
        requiredAdmissionRecord.nextAuthorityTopologyHash
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_admission_record_mismatch",
        path: "/requiredAdmissionRecord",
        message:
          "Recovery-cut admission witness authority-transition admission witness record does not match the required admission store, topology, sequence, authority transition hash, and derived topology hash.",
        expected: requiredAdmissionRecord.admissionRecordHash,
        actual: requiredAdmissionWitnessRecord.admissionRecordHash,
      });
    }
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    transitionAdmissionWitnessStoreId:
      input.transitionAdmissionWitnessStoreId,
    transitionAdmissionStoreId: input.transitionAdmissionStoreId,
    topologyId: input.topologyId,
    authorityScope: input.authorityScope,
    witnessedRecordCount: input.records.length,
    ...(latestWitnessRecord !== undefined ? { latestWitnessRecord } : {}),
    ...(requiredAdmissionRecord !== undefined ? { requiredAdmissionRecord } : {}),
    ...(requiredAdmissionWitnessRecord !== undefined
      ? { requiredAdmissionWitnessRecord }
      : {}),
    ...(witnessAuthorityTopology !== undefined
      ? { witnessAuthorityTopology }
      : {}),
    ...(witnessAuthorityTransitionAdmissionReplay !== undefined
      ? { witnessAuthorityTransitionAdmissionReplay }
      : {}),
    issues,
  };
}

export function replayOperationalStateRecoveryCutAdmissionWitnessAuthorityTransitionAdmissionRecords(
  input: OperationalStateRecoveryCutAdmissionWitnessAuthorityTransitionAdmissionReplayInput,
): OperationalStateRecoveryCutAdmissionWitnessAuthorityTransitionAdmissionReplay {
  const issues: OperationalStateRecoveryCutAdmissionIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const admissionHashBySequence = new Map<number, string>();
  const admissionRecordByAuthorityHash = new Map<
    string,
    OperationalStateRecoveryCutAdmissionWitnessAuthorityTransitionAdmissionRecord
  >();
  const admissionWitnessReplay = input.admissionWitnessReplay;
  let expectedAdmissionSequence = 1;
  let expectedAuthoritySequence = 1;
  let previousAdmissionRecordHash: string | undefined;
  let previousAuthorityRecordHash: string | undefined;
  let previousTopology: OperationalStateAuthorityTopology | undefined;
  let latestAdmittedRecord:
    | OperationalStateRecoveryCutAdmissionWitnessAuthorityTransitionAdmissionRecord
    | undefined;
  let latestAdmittedTopology: OperationalStateAuthorityTopology | undefined;

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const recordHashValidation =
      verifyOperationalStateRecoveryCutAdmissionWitnessAuthorityTransitionAdmissionRecordHash(
        record,
      );
    const transitionHashValidation =
      verifyOperationalStateAuthorityTransitionRecordHash(
        record.authorityTransition,
      );
    const certificateHashValidation =
      verifyOperationalStateQuorumCertificateProofCertificateHash(
        record.admissionCertificate,
      );
    const previousAdmissionHashAtSequence = admissionHashBySequence.get(
      record.admissionSequence,
    );

    if (
      previousAdmissionHashAtSequence !== undefined &&
      previousAdmissionHashAtSequence !== record.admissionRecordHash
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_record_sequence_gap",
        path: `${path}/admissionSequence`,
        message: `Recovery-cut admission witness authority-transition admission sequence ${record.admissionSequence} has more than one record hash.`,
        expected: previousAdmissionHashAtSequence,
        actual: record.admissionRecordHash,
      });
    } else if (previousAdmissionHashAtSequence === undefined) {
      admissionHashBySequence.set(
        record.admissionSequence,
        record.admissionRecordHash,
      );
    }

    if (
      record.tenantId !== expectedTenantId ||
      record.authorityTransition.tenantId !== expectedTenantId ||
      record.admissionCertificate.tenantId !== expectedTenantId
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_record_tenant_mismatch",
        path,
        message:
          "Recovery-cut admission witness authority-transition admission record, transition, and certificate must match the replay tenant.",
        expected: expectedTenantId,
      });
    }
    if (record.transitionAdmissionStoreId !== input.transitionAdmissionStoreId) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_record_store_mismatch",
        path: `${path}/transitionAdmissionStoreId`,
        message:
          "Recovery-cut admission witness authority-transition admission record belongs to a different admission store.",
        expected: input.transitionAdmissionStoreId,
        actual: record.transitionAdmissionStoreId,
      });
    }
    if (
      record.topologyId !== input.topologyId ||
      record.authorityTransition.topologyId !== input.topologyId
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_record_scope_mismatch",
        path: `${path}/topologyId`,
        message:
          "Recovery-cut admission witness authority-transition admission record must match the replay topology id.",
        expected: input.topologyId,
        actual: record.topologyId,
      });
    }
    if (
      record.authorityScope !== input.authorityScope ||
      record.authorityTransition.authorityScope !== input.authorityScope ||
      record.admissionCertificate.authorityScope !== input.authorityScope
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_record_scope_mismatch",
        path,
        message:
          "Recovery-cut admission witness authority-transition admission record, transition, and certificate must share the replay authority scope.",
        expected: input.authorityScope,
      });
    }
    if (record.admissionSequence !== expectedAdmissionSequence) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_record_sequence_gap",
        path: `${path}/admissionSequence`,
        message:
          "Recovery-cut admission witness authority-transition admissions must replay as a contiguous admission sequence.",
        expected: expectedAdmissionSequence,
        actual: record.admissionSequence,
      });
    }
    if (record.previousAdmissionRecordHash !== previousAdmissionRecordHash) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_record_previous_hash_mismatch",
        path: `${path}/previousAdmissionRecordHash`,
        message:
          "Recovery-cut admission witness authority-transition admission record does not chain to the previous admission record hash.",
        expected: previousAdmissionRecordHash ?? "none",
        actual: record.previousAdmissionRecordHash ?? "none",
      });
    }
    if (!recordHashValidation.valid) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_record_hash_mismatch",
        path: `${path}/admissionRecordHash`,
        message: `Recovery-cut admission witness authority-transition admission record hash ${recordHashValidation.actualHash} does not match recomputed hash ${recordHashValidation.expectedHash}.`,
        expected: recordHashValidation.expectedHash,
        actual: recordHashValidation.actualHash,
      });
    }
    if (!transitionHashValidation.valid) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_transition_hash_mismatch",
        path: `${path}/authorityTransition/authorityRecordHash`,
        message: `Recovery-cut admission witness authority transition hash ${transitionHashValidation.actualHash} does not match recomputed hash ${transitionHashValidation.expectedHash}.`,
        expected: transitionHashValidation.expectedHash,
        actual: transitionHashValidation.actualHash,
      });
    }
    if (
      record.authoritySequence !==
        record.authorityTransition.authoritySequence ||
      record.authorityRecordHash !==
        record.authorityTransition.authorityRecordHash ||
      record.previousAuthorityRecordHash !==
        record.authorityTransition.previousAuthorityRecordHash
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_transition_mismatch",
        path: `${path}/authorityTransition`,
        message:
          "Recovery-cut admission witness authority-transition admission record does not match its embedded authority transition sequence and hash.",
        expected: record.authorityRecordHash,
        actual: record.authorityTransition.authorityRecordHash,
      });
    }
    if (record.authoritySequence !== expectedAuthoritySequence) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_transition_sequence_gap",
        path: `${path}/authoritySequence`,
        message:
          "Recovery-cut admission witness authority transitions must be admitted in contiguous authority sequence.",
        expected: expectedAuthoritySequence,
        actual: record.authoritySequence,
      });
    }
    if (
      record.authorityTransition.previousAuthorityRecordHash !==
      previousAuthorityRecordHash
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_transition_previous_hash_mismatch",
        path: `${path}/authorityTransition/previousAuthorityRecordHash`,
        message:
          "Recovery-cut admission witness authority transition must hash-chain from the previously admitted authority transition.",
        expected: previousAuthorityRecordHash ?? "none",
        actual:
          record.authorityTransition.previousAuthorityRecordHash ?? "none",
      });
    }
    if (record.authorityTransition.effectiveFromSubjectSequence < 1) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_transition_invalid",
        path: `${path}/authorityTransition/effectiveFromSubjectSequence`,
        message:
          "Recovery-cut admission witness authority transitions must declare a positive effective admission sequence.",
        actual: record.authorityTransition.effectiveFromSubjectSequence,
      });
    }
    if (
      record.authorityTransition.transitionKind === "set_quorum" &&
      ((record.authorityTransition.requiredWitnesses ?? 0) < 1 ||
        (record.authorityTransition.minimumWitnesses ??
          record.authorityTransition.requiredWitnesses ??
          0) < 1 ||
        (record.authorityTransition.minimumWitnesses ??
          record.authorityTransition.requiredWitnesses ??
          0) > (record.authorityTransition.requiredWitnesses ?? 0))
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_transition_invalid",
        path: `${path}/authorityTransition/requiredWitnesses`,
        message:
          "Recovery-cut admission witness authority quorum transitions must declare positive and internally consistent witness thresholds.",
      });
    }
    if (
      [
        "admit_principal",
        "suspend_principal",
        "revoke_principal",
        "rotate_signature_key",
        "mark_equivocated",
      ].includes(record.authorityTransition.transitionKind) &&
      (record.authorityTransition.principalId === undefined ||
        record.authorityTransition.principalId.length === 0)
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_transition_invalid",
        path: `${path}/authorityTransition/principalId`,
        message:
          "Recovery-cut admission witness authority principal transitions must identify the affected principal.",
      });
    }
    if (
      record.authorityTransition.transitionKind === "seal_authority_epoch" &&
      ((record.authorityTransition.sealedThroughSubjectSequence ?? 0) < 1 ||
        record.authorityTransition.sealedQuorumCertificateHash === undefined ||
        record.authorityTransition.sealedQuorumCertificateHash.length === 0)
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_transition_invalid",
        path: `${path}/authorityTransition/sealedQuorumCertificateHash`,
        message:
          "Recovery-cut admission witness authority epoch seals must bind a positive sealed frontier and a quorum certificate hash.",
      });
    }

    const nextTopology = operationalStateAuthorityTopologyFromTransition(
      record.authorityTransition,
      previousTopology,
    );
    if (
      record.nextAuthorityTopologyHash !== nextTopology.topologyHash
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_transition_topology_hash_mismatch",
        path: `${path}/nextAuthorityTopologyHash`,
        message:
          "Recovery-cut admission witness authority-transition admission record does not derive the expected next topology hash.",
        expected: nextTopology.topologyHash,
        actual: record.nextAuthorityTopologyHash,
      });
    }
    if (previousTopology === undefined) {
      if (record.previousAuthorityTopologyHash !== undefined) {
        pushOperationalStateRecoveryCutAdmissionIssue(issues, {
          code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_transition_previous_topology_hash_mismatch",
          path: `${path}/previousAuthorityTopologyHash`,
          message:
            "Genesis recovery-cut admission witness authority transition cannot cite a previous topology hash.",
          actual: record.previousAuthorityTopologyHash,
        });
      }
    } else {
      if (record.previousAuthorityTopologyHash !== previousTopology.topologyHash) {
        pushOperationalStateRecoveryCutAdmissionIssue(issues, {
          code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_transition_previous_topology_hash_mismatch",
          path: `${path}/previousAuthorityTopologyHash`,
          message:
            "Recovery-cut admission witness authority transition admission must bind the previous replayed topology hash.",
          expected: previousTopology.topologyHash,
          actual: record.previousAuthorityTopologyHash ?? "none",
        });
      }
      if (
        record.admissionCertificate.authorityTopologyHash !==
        previousTopology.topologyHash
      ) {
        pushOperationalStateRecoveryCutAdmissionIssue(issues, {
          code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_certificate_authority_topology_mismatch",
          path: `${path}/admissionCertificate/authorityTopologyHash`,
          message:
            "Recovery-cut admission witness authority transition admission certificate must be bound to the previous replayed topology.",
          expected: previousTopology.topologyHash,
          actual:
            record.admissionCertificate.authorityTopologyHash ?? "none",
        });
      }

      const principalById = new Map<
        string,
        OperationalStateAuthorityPrincipalState
      >(
        previousTopology.principals.map((principal) => [
          principal.principalId,
          principal,
        ]),
      );
      const acceptedWitnessIds =
        record.admissionCertificate.acceptedWitnessIds;
      const uniqueAcceptedWitnessIds = new Set(acceptedWitnessIds);
      if (uniqueAcceptedWitnessIds.size !== acceptedWitnessIds.length) {
        pushOperationalStateRecoveryCutAdmissionIssue(issues, {
          code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_authority_duplicate_witness",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Recovery-cut admission witness authority-transition admission cannot be certified by duplicate prior-topology witnesses.",
          expected: uniqueAcceptedWitnessIds.size,
          actual: acceptedWitnessIds.length,
        });
      }

      let activeAuthorizedWitnessCount = 0;
      for (const witnessId of uniqueAcceptedWitnessIds) {
        const principal = principalById.get(witnessId);
        if (principal === undefined) {
          pushOperationalStateRecoveryCutAdmissionIssue(issues, {
            code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_authority_witness_unknown",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Recovery-cut admission witness authority-transition admission certificate names a witness outside the previous replayed topology.",
            expected: previousTopology.topologyHash,
            actual: witnessId,
          });
          continue;
        }
        if (principal.status !== "active") {
          pushOperationalStateRecoveryCutAdmissionIssue(issues, {
            code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_authority_witness_not_active",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Recovery-cut admission witness authority-transition admission certificate names a witness that is not active in the previous replayed topology.",
            expected: "active",
            actual: `${witnessId}:${principal.status}`,
          });
          continue;
        }
        activeAuthorizedWitnessCount += 1;
      }

      const requiredAuthorizedWitnesses = Math.max(
        previousTopology.requiredWitnesses ?? 0,
        previousTopology.minimumWitnesses ?? 0,
      );
      if (activeAuthorizedWitnessCount < requiredAuthorizedWitnesses) {
        pushOperationalStateRecoveryCutAdmissionIssue(issues, {
          code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_authority_quorum_not_met",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Recovery-cut admission witness authority-transition admission certificate does not satisfy previous-topology quorum.",
          expected: requiredAuthorizedWitnesses,
          actual: activeAuthorizedWitnessCount,
        });
      }
    }

    if (!certificateHashValidation.valid) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_certificate_hash_mismatch",
        path: `${path}/admissionCertificate/quorumCertificateHash`,
        message: `Recovery-cut admission witness authority-transition admission certificate hash ${certificateHashValidation.actualHash} does not match recomputed hash ${certificateHashValidation.expectedHash}.`,
        expected: certificateHashValidation.expectedHash,
        actual: certificateHashValidation.actualHash,
      });
    }
    if (
      !record.admissionCertificate.certified ||
      record.admissionCertificate.status !== "certified"
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_certificate_not_certified",
        path: `${path}/admissionCertificate/status`,
        message:
          "Recovery-cut admission witness authority transition cannot become authority through a non-certified admission certificate.",
        expected: "certified",
        actual: record.admissionCertificate.status,
      });
    }
    if (
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.minimumWitnesses ||
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.requiredWitnesses
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_certificate_quorum_not_met",
        path: `${path}/admissionCertificate/acceptedWitnessIds`,
        message:
          "Recovery-cut admission witness authority-transition admission certificate does not satisfy its declared witness quorum.",
        expected: Math.max(
          record.admissionCertificate.requiredWitnesses,
          record.admissionCertificate.minimumWitnesses,
        ),
        actual: record.admissionCertificate.acceptedWitnessIds.length,
      });
    }
    if (
      record.admissionCertificate.subjectKind !==
        OPERATIONAL_STATE_AUTHORITY_TRANSITION_RECORD_SUBJECT_KIND ||
      record.admissionCertificate.subjectId !== record.topologyId ||
      record.admissionCertificate.subjectSequence !==
        record.authoritySequence ||
      record.admissionCertificate.subjectHash !== record.authorityRecordHash
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_certificate_subject_mismatch",
        path: `${path}/admissionCertificate`,
        message:
          "Recovery-cut admission witness authority-transition admission certificate must certify the exact topology id, authority sequence, and authority transition hash.",
        expected: record.authorityRecordHash,
        actual: record.admissionCertificate.subjectHash,
      });
    }
    if (
      input.requiredAuthorityBoundary !== undefined &&
      record.admissionCertificate.authorityBoundary !==
        input.requiredAuthorityBoundary
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_certificate_authority_boundary_mismatch",
        path: `${path}/admissionCertificate/authorityBoundary`,
        message:
          "Recovery-cut admission witness authority-transition admission certificate was admitted under the wrong authority boundary.",
        expected: input.requiredAuthorityBoundary,
        actual: record.admissionCertificate.authorityBoundary,
      });
    }

    admissionRecordByAuthorityHash.set(record.authorityRecordHash, record);
    expectedAdmissionSequence = record.admissionSequence + 1;
    expectedAuthoritySequence = record.authoritySequence + 1;
    previousAdmissionRecordHash = record.admissionRecordHash;
    previousAuthorityRecordHash = record.authorityRecordHash;
    previousTopology = nextTopology;
    latestAdmittedTopology = nextTopology;
    latestAdmittedRecord = record;
  });

  let requiredAuthorityTransitionAdmissionRecord:
    | OperationalStateRecoveryCutAdmissionWitnessAuthorityTransitionAdmissionRecord
    | undefined;
  if (input.requiredAuthorityTransition !== undefined) {
    const requiredTransitionHashValidation =
      verifyOperationalStateAuthorityTransitionRecordHash(
        input.requiredAuthorityTransition,
      );
    if (!requiredTransitionHashValidation.valid) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_transition_hash_mismatch",
        path: "/requiredAuthorityTransition/authorityRecordHash",
        message: `Required recovery-cut admission witness authority transition hash ${requiredTransitionHashValidation.actualHash} does not match recomputed hash ${requiredTransitionHashValidation.expectedHash}.`,
        expected: requiredTransitionHashValidation.expectedHash,
        actual: requiredTransitionHashValidation.actualHash,
      });
    }
    requiredAuthorityTransitionAdmissionRecord =
      admissionRecordByAuthorityHash.get(
        input.requiredAuthorityTransition.authorityRecordHash,
      );
    if (requiredAuthorityTransitionAdmissionRecord === undefined) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_not_admitted",
        path: "/requiredAuthorityTransition/authorityRecordHash",
        message:
          "Required recovery-cut admission witness authority transition has no replayed admission certificate.",
        expected: input.requiredAuthorityTransition.authorityRecordHash,
      });
    }
  }

  if (input.requiredAuthorityTopology !== undefined) {
    const requiredTopologyHashValidation =
      verifyOperationalStateAuthorityTopologyHash(
        input.requiredAuthorityTopology,
      );
    if (!requiredTopologyHashValidation.valid) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_topology_hash_mismatch",
        path: "/requiredAuthorityTopology/topologyHash",
        message: `Required recovery-cut admission witness authority topology hash ${requiredTopologyHashValidation.actualHash} does not match recomputed hash ${requiredTopologyHashValidation.expectedHash}.`,
        expected: requiredTopologyHashValidation.expectedHash,
        actual: requiredTopologyHashValidation.actualHash,
      });
    }
    if (
      latestAdmittedTopology === undefined ||
      !operationalStateAuthorityTopologiesMatch(
        latestAdmittedTopology,
        input.requiredAuthorityTopology,
      )
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/requiredAuthorityTopology",
        message:
          "Recovery-cut admission witness authority-transition admission replay must recover the required authority topology.",
        expected: input.requiredAuthorityTopology.topologyHash,
        actual: latestAdmittedTopology?.topologyHash ?? "none",
      });
    }
    requiredAuthorityTransitionAdmissionRecord =
      admissionRecordByAuthorityHash.get(
        input.requiredAuthorityTopology.authorityRecordHash,
      );
    if (requiredAuthorityTransitionAdmissionRecord === undefined) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_not_admitted",
        path: "/requiredAuthorityTopology/authorityRecordHash",
        message:
          "Required recovery-cut admission witness authority topology is not backed by an admitted authority transition.",
        expected: input.requiredAuthorityTopology.authorityRecordHash,
      });
    }
  }

  if (
    input.requireAdmissionWitness === true ||
    input.requireAdmissionWitnessAuthorityTopology === true
  ) {
    if (admissionWitnessReplay === undefined) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_replay_missing",
        path: "/admissionWitnessReplay",
        message:
          "Recovery-cut admission witness authority-transition admission replay requires witnessed transition-admission records.",
      });
    } else if (!admissionWitnessReplay.valid) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_replay_invalid",
        path: "/admissionWitnessReplay",
        message:
          "Recovery-cut admission witness authority-transition admission replay cannot consume invalid transition-admission witness history.",
        actual: admissionWitnessReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTopology === true &&
      admissionWitnessReplay.witnessAuthorityTopology === undefined
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_topology_missing",
        path: "/admissionWitnessReplay/witnessAuthorityTopology",
        message:
          "Recovery-cut admission witness authority-transition admission replay requires its witness ledger to bind certificates to a replayed witness authority topology.",
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmission === true &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay === undefined
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        path: "/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Recovery-cut admission witness authority-transition admission replay requires its nested transition-admission witness authority topology to replay from admitted authority-transition history.",
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmission === true &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      !admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.valid
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        path: "/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Recovery-cut admission witness authority-transition admission replay cannot consume invalid nested transition-admission witness authority history.",
        actual:
          admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.issues
            .map((issue) => issue.code)
            .join(","),
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmission === true &&
      admissionWitnessReplay.witnessAuthorityTopology !== undefined &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      (admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .latestAdmittedTopology === undefined ||
        !operationalStateAuthorityTopologiesMatch(
          admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology,
          admissionWitnessReplay.witnessAuthorityTopology,
        ))
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Recovery-cut admission witness authority-transition admission replay requires the nested transition-admission witness authority topology to be recovered from admitted authority-transition history.",
        expected: admissionWitnessReplay.witnessAuthorityTopology.topologyHash,
        actual:
          admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology?.topologyHash ?? "none",
      });
    } else if (
      latestAdmittedRecord === undefined ||
      admissionWitnessReplay.requiredAdmissionWitnessRecord === undefined ||
      admissionWitnessReplay.requiredAdmissionWitnessRecord
        .admissionRecordHash !== latestAdmittedRecord.admissionRecordHash
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_latest_record_not_witnessed",
        path: "/admissionWitnessReplay",
        message:
          "Latest recovery-cut admission witness authority-transition admission record is not witnessed by the replayed transition-admission witness ledger.",
        expected: latestAdmittedRecord?.admissionRecordHash ?? "none",
        actual:
          admissionWitnessReplay.requiredAdmissionWitnessRecord
            ?.admissionRecordHash ?? "none",
      });
    }
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    transitionAdmissionStoreId: input.transitionAdmissionStoreId,
    topologyId: input.topologyId,
    authorityScope: input.authorityScope,
    admittedRecordCount: input.records.length,
    ...(latestAdmittedRecord !== undefined ? { latestAdmittedRecord } : {}),
    ...(latestAdmittedTopology !== undefined ? { latestAdmittedTopology } : {}),
    ...(input.requiredAuthorityTopology !== undefined
      ? { requiredAuthorityTopology: input.requiredAuthorityTopology }
      : {}),
    ...(input.requiredAuthorityTransition !== undefined
      ? { requiredAuthorityTransition: input.requiredAuthorityTransition }
      : {}),
    ...(requiredAuthorityTransitionAdmissionRecord !== undefined
      ? { requiredAuthorityTransitionAdmissionRecord }
      : {}),
    ...(admissionWitnessReplay !== undefined ? { admissionWitnessReplay } : {}),
    issues,
  };
}

function pushOperationalStateRecoveryCutAdmissionIssue(
  issues: OperationalStateRecoveryCutAdmissionIssue[],
  issue: OperationalStateRecoveryCutAdmissionIssue,
): void {
  issues.push(issue);
}

export function replayOperationalStateRecoveryCutAdmissionRecords(
  input: OperationalStateRecoveryCutAdmissionReplayInput,
): OperationalStateRecoveryCutAdmissionReplay {
  const issues: OperationalStateRecoveryCutAdmissionIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const recordHashBySequence = new Map<number, string>();
  let expectedSequence = 1;
  let previousAdmissionRecordHash: string | undefined;
  let latestAdmittedRecord:
    | OperationalStateRecoveryCutAdmissionRecord
    | undefined;

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const recordHashValidation =
      verifyOperationalStateRecoveryCutAdmissionRecordHash(record);
    const cutHashValidation = verifyOperationalStateRecoveryCutHash(
      record.recoveryCut,
    );
    const previousRecordHashAtSequence = recordHashBySequence.get(
      record.admissionSequence,
    );

    if (
      previousRecordHashAtSequence !== undefined &&
      previousRecordHashAtSequence !== record.admissionRecordHash
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_record_fork",
        path: `${path}/admissionSequence`,
        message: `Recovery cut admission sequence ${record.admissionSequence} has more than one record hash.`,
        expected: previousRecordHashAtSequence,
        actual: record.admissionRecordHash,
      });
    } else if (previousRecordHashAtSequence === undefined) {
      recordHashBySequence.set(
        record.admissionSequence,
        record.admissionRecordHash,
      );
    }

    if (record.tenantId !== expectedTenantId) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_record_tenant_mismatch",
        path: `${path}/tenantId`,
        message: `Recovery cut admission record tenant ${record.tenantId} does not match replay tenant ${expectedTenantId}.`,
        expected: expectedTenantId,
        actual: record.tenantId,
      });
    }
    if (record.recoveryCut.tenantId !== expectedTenantId) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_record_tenant_mismatch",
        path: `${path}/recoveryCut/tenantId`,
        message: `Recovery cut tenant ${record.recoveryCut.tenantId} does not match replay tenant ${expectedTenantId}.`,
        expected: expectedTenantId,
        actual: record.recoveryCut.tenantId,
      });
    }
    if (record.recoveryCutStoreId !== input.recoveryCutStoreId) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_record_scope_mismatch",
        path: `${path}/recoveryCutStoreId`,
        message: `Recovery cut admission record store ${record.recoveryCutStoreId} does not match replay store ${input.recoveryCutStoreId}.`,
        expected: input.recoveryCutStoreId,
        actual: record.recoveryCutStoreId,
      });
    }
    if (record.authorityScope !== input.authorityScope) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_record_scope_mismatch",
        path: `${path}/authorityScope`,
        message: `Recovery cut admission record scope ${record.authorityScope} does not match replay scope ${input.authorityScope}.`,
        expected: input.authorityScope,
        actual: record.authorityScope,
      });
    }
    if (record.recoveryCut.authorityScope !== input.authorityScope) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_record_scope_mismatch",
        path: `${path}/recoveryCut/authorityScope`,
        message: `Recovery cut scope ${record.recoveryCut.authorityScope} does not match replay scope ${input.authorityScope}.`,
        expected: input.authorityScope,
        actual: record.recoveryCut.authorityScope,
      });
    }
    if (record.admissionSequence !== expectedSequence) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_record_sequence_gap",
        path: `${path}/admissionSequence`,
        message: `Recovery cut admission sequence ${record.admissionSequence} does not match expected replay sequence ${expectedSequence}.`,
        expected: expectedSequence,
        actual: record.admissionSequence,
      });
    }
    if (record.previousAdmissionRecordHash !== previousAdmissionRecordHash) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_record_previous_hash_mismatch",
        path: `${path}/previousAdmissionRecordHash`,
        message:
          "Recovery cut admission record does not chain to the previous admitted record hash.",
        expected: previousAdmissionRecordHash ?? "none",
        actual: record.previousAdmissionRecordHash ?? "none",
      });
    }
    if (!cutHashValidation.valid) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_record_cut_hash_mismatch",
        path: `${path}/recoveryCut/cutHash`,
        message: `Recovery cut admission record contains cut hash ${cutHashValidation.actualHash} but replay recomputed ${cutHashValidation.expectedHash}.`,
        expected: cutHashValidation.expectedHash,
        actual: cutHashValidation.actualHash,
      });
    }
    if (record.recoveryCutHash !== record.recoveryCut.cutHash) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_record_cut_hash_mismatch",
        path: `${path}/recoveryCutHash`,
        message: `Recovery cut admission record hash ${record.recoveryCutHash} does not match embedded recovery cut hash ${record.recoveryCut.cutHash}.`,
        expected: record.recoveryCut.cutHash,
        actual: record.recoveryCutHash,
      });
    }
    if (!recordHashValidation.valid) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_record_hash_mismatch",
        path: `${path}/admissionRecordHash`,
        message: `Recovery cut admission record hash ${recordHashValidation.actualHash} does not match recomputed hash ${recordHashValidation.expectedHash}.`,
        expected: recordHashValidation.expectedHash,
        actual: recordHashValidation.actualHash,
      });
    }

    expectedSequence = record.admissionSequence + 1;
    previousAdmissionRecordHash = record.admissionRecordHash;
    latestAdmittedRecord = record;
  });

  if (input.requiredCut !== undefined) {
    const requiredCutHashValidation = verifyOperationalStateRecoveryCutHash(
      input.requiredCut,
    );
    if (!requiredCutHashValidation.valid) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_required_cut_hash_mismatch",
        path: "/requiredCut/cutHash",
        message: `Required recovery cut hash ${requiredCutHashValidation.actualHash} does not match recomputed hash ${requiredCutHashValidation.expectedHash}.`,
        expected: requiredCutHashValidation.expectedHash,
        actual: requiredCutHashValidation.actualHash,
      });
    }
    if (latestAdmittedRecord === undefined) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_required_cut_missing",
        path: "/records",
        message:
          "Recovery cut admission replay has no records for the required recovery cut.",
      });
    } else if (
      latestAdmittedRecord.recoveryCutHash !== input.requiredCut.cutHash
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_required_cut_hash_mismatch",
        path: "/requiredCut/cutHash",
        message: `Latest recovery cut admission record admits ${latestAdmittedRecord.recoveryCutHash}, not required cut ${input.requiredCut.cutHash}.`,
        expected: input.requiredCut.cutHash,
        actual: latestAdmittedRecord.recoveryCutHash,
      });
    }
  }

  if (
    input.requiredCurrentStateViewIdentityHash !== undefined &&
    latestAdmittedRecord !== undefined &&
    latestAdmittedRecord.currentStateViewIdentityHash !==
      input.requiredCurrentStateViewIdentityHash
  ) {
    pushOperationalStateRecoveryCutAdmissionIssue(issues, {
      code: "operational_state_recovery_cut_admission_view_hash_mismatch",
      path: "/requiredCurrentStateViewIdentityHash",
      message:
        "Latest recovery cut admission record is not bound to the required current-state view identity hash.",
      expected: input.requiredCurrentStateViewIdentityHash,
      actual: latestAdmittedRecord.currentStateViewIdentityHash,
    });
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    recoveryCutStoreId: input.recoveryCutStoreId,
    authorityScope: input.authorityScope,
    admittedRecordCount: input.records.length,
    ...(latestAdmittedRecord !== undefined ? { latestAdmittedRecord } : {}),
    ...(input.requiredCut !== undefined ? { requiredCut: input.requiredCut } : {}),
    issues,
  };
}

export function replayOperationalStateRecoveryCutAdmissionWitnessRecords(
  input: OperationalStateRecoveryCutAdmissionWitnessReplayInput,
): OperationalStateRecoveryCutAdmissionWitnessReplay {
  const issues: OperationalStateRecoveryCutAdmissionIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const witnessHashBySequence = new Map<number, string>();
  const witnessRecordByAdmissionHash = new Map<
    string,
    OperationalStateRecoveryCutAdmissionWitnessRecord
  >();
  const witnessAuthorityTopology = input.witnessAuthorityTopology;
  const witnessAuthorityTransitionAdmissionReplay =
    input.witnessAuthorityTransitionAdmissionReplay;
  const principalById = new Map<string, OperationalStateAuthorityPrincipalState>(
    witnessAuthorityTopology?.principals.map((principal) => [
      principal.principalId,
      principal,
    ]) ?? [],
  );
  let expectedSequence = 1;
  let previousWitnessRecordHash: string | undefined;
  let latestWitnessRecord:
    | OperationalStateRecoveryCutAdmissionWitnessRecord
    | undefined;

  if (input.admissionReplay !== undefined && !input.admissionReplay.valid) {
    pushOperationalStateRecoveryCutAdmissionIssue(issues, {
      code: "operational_state_recovery_cut_admission_witness_admission_replay_invalid",
      path: "/admissionReplay",
      message:
        "Recovery-cut admission witness replay cannot account for an invalid recovery-cut admission replay.",
      actual: input.admissionReplay.issues
        .map((issue) => issue.code)
        .join(","),
    });
  }

  if (
    (input.requireWitnessAuthorityTopology === true ||
      input.requireWitnessAuthorityTransitionAdmission === true) &&
    witnessAuthorityTopology === undefined
  ) {
    pushOperationalStateRecoveryCutAdmissionIssue(issues, {
      code: "operational_state_recovery_cut_admission_witness_authority_topology_missing",
      path: "/witnessAuthorityTopology",
      message:
        "Recovery-cut admission witness replay requires a replayed witness authority topology.",
    });
  }

  if (witnessAuthorityTopology !== undefined) {
    const topologyHashValidation =
      verifyOperationalStateAuthorityTopologyHash(witnessAuthorityTopology);
    if (!topologyHashValidation.valid) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_topology_hash_mismatch",
        path: "/witnessAuthorityTopology/topologyHash",
        message: `Recovery-cut admission witness authority topology hash ${topologyHashValidation.actualHash} does not match recomputed hash ${topologyHashValidation.expectedHash}.`,
        expected: topologyHashValidation.expectedHash,
        actual: topologyHashValidation.actualHash,
      });
    }
    if (witnessAuthorityTopology.tenantId !== expectedTenantId) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_topology_tenant_mismatch",
        path: "/witnessAuthorityTopology/tenantId",
        message:
          "Recovery-cut admission witness authority topology tenant does not match replay tenant.",
        expected: expectedTenantId,
        actual: witnessAuthorityTopology.tenantId,
      });
    }
    if (witnessAuthorityTopology.authorityScope !== input.authorityScope) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_topology_scope_mismatch",
        path: "/witnessAuthorityTopology/authorityScope",
        message:
          "Recovery-cut admission witness authority topology scope does not match replay scope.",
        expected: input.authorityScope,
        actual: witnessAuthorityTopology.authorityScope,
      });
    }
    if (
      witnessAuthorityTopology.requiredWitnesses === undefined ||
      witnessAuthorityTopology.minimumWitnesses === undefined
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_quorum_missing",
        path: "/witnessAuthorityTopology/requiredWitnesses",
        message:
          "Recovery-cut admission witness authority topology must define quorum thresholds.",
      });
    }
  }

  if (
    input.requireWitnessAuthorityTransitionAdmission === true ||
    input.requireWitnessAuthorityTransitionAdmissionWitness === true ||
    input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
      true
  ) {
    if (witnessAuthorityTransitionAdmissionReplay === undefined) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_replay_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Recovery-cut admission witness replay requires admitted recovery-cut witness-authority transition history.",
      });
    } else if (!witnessAuthorityTransitionAdmissionReplay.valid) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_replay_invalid",
        path: "/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Recovery-cut admission witness replay cannot consume invalid recovery-cut witness-authority transition admission history.",
        actual: witnessAuthorityTransitionAdmissionReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      witnessAuthorityTopology !== undefined &&
      (witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology ===
        undefined ||
        !operationalStateAuthorityTopologiesMatch(
          witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology,
          witnessAuthorityTopology,
        ))
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Recovery-cut admission witness authority topology must be recovered from admitted authority-transition history.",
        expected: witnessAuthorityTopology.topologyHash,
        actual:
          witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology
            ?.topologyHash ?? "none",
      });
    }
  }
  if (
    (input.requireWitnessAuthorityTransitionAdmissionWitness === true ||
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    witnessAuthorityTransitionAdmissionReplay !== undefined &&
    witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay === undefined
  ) {
    pushOperationalStateRecoveryCutAdmissionIssue(issues, {
      code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_replay_missing",
      path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
      message:
        "Recovery-cut admission witness replay requires recovery-cut witness-authority transition-admission records to be witnessed.",
    });
  }
  if (
    (input.requireWitnessAuthorityTransitionAdmissionWitness === true ||
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    witnessAuthorityTransitionAdmissionReplay?.admissionWitnessReplay !==
      undefined &&
    !witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay.valid
  ) {
    pushOperationalStateRecoveryCutAdmissionIssue(issues, {
      code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_replay_invalid",
      path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
      message:
        "Recovery-cut admission witness replay cannot consume invalid recovery-cut witness-authority transition-admission witness history.",
      actual: witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay.issues
        .map((issue) => issue.code)
        .join(","),
    });
  }
  if (
    (input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
      true ||
      input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    witnessAuthorityTransitionAdmissionReplay?.admissionWitnessReplay !==
      undefined &&
    witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay
      .witnessAuthorityTopology === undefined
  ) {
    pushOperationalStateRecoveryCutAdmissionIssue(issues, {
      code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_topology_missing",
      path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTopology",
      message:
        "Recovery-cut admission witness replay requires the transition-admission witness ledger to bind certificates to replayed witness authority topology.",
    });
  }
  if (
    input.requireWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
      true &&
    witnessAuthorityTransitionAdmissionReplay?.admissionWitnessReplay !==
      undefined
  ) {
    const transitionAdmissionWitnessReplay =
      witnessAuthorityTransitionAdmissionReplay.admissionWitnessReplay;
    if (
      transitionAdmissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay ===
      undefined
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Recovery-cut admission witness replay requires transition-admission witness authority topology to replay from admitted authority-transition history.",
      });
    } else if (
      !transitionAdmissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .valid
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Recovery-cut admission witness replay cannot consume invalid transition-admission witness authority-transition admission history.",
        actual:
          transitionAdmissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.issues
            .map((issue) => issue.code)
            .join(","),
      });
    } else if (
      transitionAdmissionWitnessReplay.witnessAuthorityTopology !== undefined &&
      (transitionAdmissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .latestAdmittedTopology === undefined ||
        !operationalStateAuthorityTopologiesMatch(
          transitionAdmissionWitnessReplay
            .witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology,
          transitionAdmissionWitnessReplay.witnessAuthorityTopology,
        ))
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Recovery-cut admission witness replay requires transition-admission witness authority topology to match admitted authority-transition history.",
        expected:
          transitionAdmissionWitnessReplay.witnessAuthorityTopology.topologyHash,
        actual:
          transitionAdmissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology?.topologyHash ?? "none",
      });
    }
  }

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const witnessRecordHashValidation =
      verifyOperationalStateRecoveryCutAdmissionWitnessRecordHash(record);
    const certificateHashValidation =
      verifyOperationalStateQuorumCertificateProofCertificateHash(
        record.admissionCertificate,
      );
    const previousWitnessHashAtSequence = witnessHashBySequence.get(
      record.witnessSequence,
    );

    if (
      previousWitnessHashAtSequence !== undefined &&
      previousWitnessHashAtSequence !== record.witnessRecordHash
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_record_fork",
        path: `${path}/witnessSequence`,
        message: `Recovery-cut admission witness sequence ${record.witnessSequence} has more than one witness record hash.`,
        expected: previousWitnessHashAtSequence,
        actual: record.witnessRecordHash,
      });
    } else if (previousWitnessHashAtSequence === undefined) {
      witnessHashBySequence.set(
        record.witnessSequence,
        record.witnessRecordHash,
      );
    }

    if (
      record.tenantId !== expectedTenantId ||
      record.admissionCertificate.tenantId !== expectedTenantId
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_record_tenant_mismatch",
        path,
        message:
          "Recovery-cut admission witness record and certificate must match the replay tenant.",
        expected: expectedTenantId,
      });
    }
    if (
      record.recoveryCutAdmissionWitnessStoreId !==
      input.recoveryCutAdmissionWitnessStoreId
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_record_store_mismatch",
        path: `${path}/recoveryCutAdmissionWitnessStoreId`,
        message:
          "Recovery-cut admission witness record belongs to a different witness store.",
        expected: input.recoveryCutAdmissionWitnessStoreId,
        actual: record.recoveryCutAdmissionWitnessStoreId,
      });
    }
    if (record.recoveryCutStoreId !== input.recoveryCutStoreId) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_record_store_mismatch",
        path: `${path}/recoveryCutStoreId`,
        message:
          "Recovery-cut admission witness record accounts for a different recovery-cut admission store.",
        expected: input.recoveryCutStoreId,
        actual: record.recoveryCutStoreId,
      });
    }
    if (
      record.authorityScope !== input.authorityScope ||
      record.admissionCertificate.authorityScope !== input.authorityScope
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_record_scope_mismatch",
        path,
        message:
          "Recovery-cut admission witness record and certificate must share the replay authority scope.",
        expected: input.authorityScope,
      });
    }
    if (record.witnessSequence !== expectedSequence) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_record_sequence_gap",
        path: `${path}/witnessSequence`,
        message:
          "Recovery-cut admission witness records must replay as a contiguous witness sequence.",
        expected: expectedSequence,
        actual: record.witnessSequence,
      });
    }
    if (record.previousWitnessRecordHash !== previousWitnessRecordHash) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_record_previous_hash_mismatch",
        path: `${path}/previousWitnessRecordHash`,
        message:
          "Recovery-cut admission witness record does not chain to the previous witness record hash.",
        expected: previousWitnessRecordHash ?? "none",
        actual: record.previousWitnessRecordHash ?? "none",
      });
    }
    if (!certificateHashValidation.valid) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_certificate_hash_mismatch",
        path: `${path}/admissionCertificate/quorumCertificateHash`,
        message: `Recovery-cut admission witness certificate hash ${certificateHashValidation.actualHash} does not match recomputed hash ${certificateHashValidation.expectedHash}.`,
        expected: certificateHashValidation.expectedHash,
        actual: certificateHashValidation.actualHash,
      });
    }
    if (
      !record.admissionCertificate.certified ||
      record.admissionCertificate.status !== "certified"
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_certificate_not_certified",
        path: `${path}/admissionCertificate/status`,
        message:
          "Recovery-cut admission cannot become accountable through a non-certified witness certificate.",
        expected: "certified",
        actual: record.admissionCertificate.status,
      });
    }
    if (
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.minimumWitnesses ||
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.requiredWitnesses
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_certificate_quorum_not_met",
        path: `${path}/admissionCertificate/acceptedWitnessIds`,
        message:
          "Recovery-cut admission witness certificate does not satisfy its witness quorum.",
        expected: Math.max(
          record.admissionCertificate.requiredWitnesses,
          record.admissionCertificate.minimumWitnesses,
        ),
        actual: record.admissionCertificate.acceptedWitnessIds.length,
      });
    }
    if (
      record.admissionCertificate.subjectKind !==
        OPERATIONAL_STATE_RECOVERY_CUT_ADMISSION_RECORD_SUBJECT_KIND ||
      record.admissionCertificate.subjectId !== record.recoveryCutStoreId ||
      record.admissionCertificate.subjectSequence !==
        record.admissionSequence ||
      record.admissionCertificate.subjectHash !== record.admissionRecordHash
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_certificate_subject_mismatch",
        path: `${path}/admissionCertificate`,
        message:
          "Recovery-cut admission witness certificate must certify the exact admission store, admission sequence, and admission record hash.",
        expected: record.admissionRecordHash,
        actual: record.admissionCertificate.subjectHash,
      });
    }
    if (
      input.requiredAuthorityBoundary !== undefined &&
      record.admissionCertificate.authorityBoundary !==
        input.requiredAuthorityBoundary
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_certificate_authority_boundary_mismatch",
        path: `${path}/admissionCertificate/authorityBoundary`,
        message:
          "Recovery-cut admission witness certificate was admitted under the wrong authority boundary.",
        expected: input.requiredAuthorityBoundary,
        actual: record.admissionCertificate.authorityBoundary,
      });
    }
    if (witnessAuthorityTopology !== undefined) {
      if (
        record.admissionCertificate.authorityTopologyHash !==
        witnessAuthorityTopology.topologyHash
      ) {
        pushOperationalStateRecoveryCutAdmissionIssue(issues, {
          code: "operational_state_recovery_cut_admission_witness_certificate_authority_topology_mismatch",
          path: `${path}/admissionCertificate/authorityTopologyHash`,
          message:
            "Recovery-cut admission witness certificate is not bound to the replayed witness authority topology.",
          expected: witnessAuthorityTopology.topologyHash,
          actual:
            record.admissionCertificate.authorityTopologyHash ?? "none",
        });
      }

      const acceptedWitnessIds =
        record.admissionCertificate.acceptedWitnessIds;
      const uniqueAcceptedWitnessIds = new Set(acceptedWitnessIds);
      if (uniqueAcceptedWitnessIds.size !== acceptedWitnessIds.length) {
        pushOperationalStateRecoveryCutAdmissionIssue(issues, {
          code: "operational_state_recovery_cut_admission_witness_authority_duplicate_witness",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Recovery-cut admission witness authority quorum cannot be satisfied by duplicate witness ids.",
          expected: uniqueAcceptedWitnessIds.size,
          actual: acceptedWitnessIds.length,
        });
      }

      let activeAuthorizedWitnessCount = 0;
      for (const witnessId of uniqueAcceptedWitnessIds) {
        const principal = principalById.get(witnessId);
        if (principal === undefined) {
          pushOperationalStateRecoveryCutAdmissionIssue(issues, {
            code: "operational_state_recovery_cut_admission_witness_authority_witness_unknown",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Recovery-cut admission witness certificate names a witness that is not present in the replayed authority topology.",
            expected: witnessAuthorityTopology.topologyHash,
            actual: witnessId,
          });
          continue;
        }
        if (principal.status !== "active") {
          pushOperationalStateRecoveryCutAdmissionIssue(issues, {
            code: "operational_state_recovery_cut_admission_witness_authority_witness_not_active",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "Recovery-cut admission witness certificate names a witness that is not active in the replayed authority topology.",
            expected: "active",
            actual: `${witnessId}:${principal.status}`,
          });
          continue;
        }
        activeAuthorizedWitnessCount += 1;
      }

      const requiredAuthorizedWitnesses = Math.max(
        witnessAuthorityTopology.requiredWitnesses ?? 0,
        witnessAuthorityTopology.minimumWitnesses ?? 0,
      );
      if (activeAuthorizedWitnessCount < requiredAuthorizedWitnesses) {
        pushOperationalStateRecoveryCutAdmissionIssue(issues, {
          code: "operational_state_recovery_cut_admission_witness_authority_quorum_not_met",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "Recovery-cut admission witness certificate does not satisfy the replayed witness authority topology quorum.",
          expected: requiredAuthorizedWitnesses,
          actual: activeAuthorizedWitnessCount,
        });
      }
    }
    if (!witnessRecordHashValidation.valid) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_record_hash_mismatch",
        path: `${path}/witnessRecordHash`,
        message: `Recovery-cut admission witness record hash ${witnessRecordHashValidation.actualHash} does not match recomputed hash ${witnessRecordHashValidation.expectedHash}.`,
        expected: witnessRecordHashValidation.expectedHash,
        actual: witnessRecordHashValidation.actualHash,
      });
    }

    witnessRecordByAdmissionHash.set(record.admissionRecordHash, record);
    expectedSequence = record.witnessSequence + 1;
    previousWitnessRecordHash = record.witnessRecordHash;
    latestWitnessRecord = record;
  });

  const requiredAdmissionRecord =
    input.requiredAdmissionRecord ??
    input.admissionReplay?.latestAdmittedRecord;
  let requiredAdmissionWitnessRecord:
    | OperationalStateRecoveryCutAdmissionWitnessRecord
    | undefined;
  if (requiredAdmissionRecord !== undefined) {
    const admissionRecordHashValidation =
      verifyOperationalStateRecoveryCutAdmissionRecordHash(
        requiredAdmissionRecord,
      );
    if (!admissionRecordHashValidation.valid) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_record_hash_mismatch",
        path: "/requiredAdmissionRecord/admissionRecordHash",
        message: `Required recovery-cut admission record hash ${admissionRecordHashValidation.actualHash} does not match recomputed hash ${admissionRecordHashValidation.expectedHash}.`,
        expected: admissionRecordHashValidation.expectedHash,
        actual: admissionRecordHashValidation.actualHash,
      });
    }
    requiredAdmissionWitnessRecord = witnessRecordByAdmissionHash.get(
      requiredAdmissionRecord.admissionRecordHash,
    );
    if (requiredAdmissionWitnessRecord === undefined) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_latest_record_not_witnessed",
        path: "/requiredAdmissionRecord/admissionRecordHash",
        message:
          "Latest recovery-cut admission record has no replayed witness certificate.",
        expected: requiredAdmissionRecord.admissionRecordHash,
      });
    } else if (
      requiredAdmissionWitnessRecord.admissionSequence !==
        requiredAdmissionRecord.admissionSequence ||
      requiredAdmissionWitnessRecord.recoveryCutHash !==
        requiredAdmissionRecord.recoveryCutHash ||
      requiredAdmissionWitnessRecord.currentStateViewIdentityHash !==
        requiredAdmissionRecord.currentStateViewIdentityHash
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_admission_record_mismatch",
        path: "/requiredAdmissionRecord",
        message:
          "Recovery-cut admission witness record does not match the required admitted cut, sequence, and current-state view identity.",
        expected: requiredAdmissionRecord.admissionRecordHash,
        actual: requiredAdmissionWitnessRecord.admissionRecordHash,
      });
    }
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    recoveryCutAdmissionWitnessStoreId:
      input.recoveryCutAdmissionWitnessStoreId,
    recoveryCutStoreId: input.recoveryCutStoreId,
    authorityScope: input.authorityScope,
    witnessedRecordCount: input.records.length,
    ...(latestWitnessRecord !== undefined ? { latestWitnessRecord } : {}),
    ...(requiredAdmissionRecord !== undefined ? { requiredAdmissionRecord } : {}),
    ...(requiredAdmissionWitnessRecord !== undefined
      ? { requiredAdmissionWitnessRecord }
      : {}),
    ...(witnessAuthorityTopology !== undefined
      ? { witnessAuthorityTopology }
      : {}),
    ...(witnessAuthorityTransitionAdmissionReplay !== undefined
      ? { witnessAuthorityTransitionAdmissionReplay }
      : {}),
    issues,
  };
}

export function evaluateOperationalStateRecoveryCutAdmission(
  input: OperationalStateRecoveryCutAdmissionEvaluationInput,
): OperationalStateRecoveryCutAdmissionEvaluation {
  const issues: OperationalStateRecoveryCutAdmissionIssue[] = [];
  const { view } = input;
  const { recoveryCut } = view;

  if (recoveryCut === undefined) {
    pushOperationalStateRecoveryCutAdmissionIssue(issues, {
      code: "operational_state_recovery_cut_admission_cut_missing",
      path: "/recoveryCut",
      message:
        "Recovered operational state cannot be admitted without a recovery cut.",
    });
    return {
      valid: false,
      accepted: false,
      ...(input.admissionReplay !== undefined
        ? { admissionReplay: input.admissionReplay }
        : {}),
      issues,
    };
  }

  if (input.admissionReplay === undefined) {
    pushOperationalStateRecoveryCutAdmissionIssue(issues, {
      code: "operational_state_recovery_cut_admission_replay_missing",
      path: "/recoveryCutAdmission",
      message:
        "Recovered operational state requires replay of durable recovery-cut admission records.",
    });
    return {
      valid: false,
      accepted: false,
      issues,
    };
  }

  if (!input.admissionReplay.valid) {
    pushOperationalStateRecoveryCutAdmissionIssue(issues, {
      code: "operational_state_recovery_cut_admission_replay_invalid",
      path: "/recoveryCutAdmission",
      message:
        "Recovered operational state has an invalid recovery-cut admission replay.",
      actual: input.admissionReplay.issues
        .map((issue) => issue.code)
        .join(","),
    });
  }

  const latestAdmittedRecord = input.admissionReplay.latestAdmittedRecord;
  if (
    latestAdmittedRecord === undefined ||
    latestAdmittedRecord.recoveryCutHash !== recoveryCut.cutHash
  ) {
    pushOperationalStateRecoveryCutAdmissionIssue(issues, {
      code: "operational_state_recovery_cut_admission_cut_not_admitted",
      path: "/recoveryCut/cutHash",
      message:
        "Current recovery cut is not the latest cut admitted by recovery-cut admission replay.",
      expected: recoveryCut.cutHash,
      actual: latestAdmittedRecord?.recoveryCutHash ?? "none",
    });
  }

  const currentStateViewIdentityHash =
    computeCurrentStateViewIdentityHash(view);
  if (
    latestAdmittedRecord !== undefined &&
    latestAdmittedRecord.currentStateViewIdentityHash !==
      currentStateViewIdentityHash
  ) {
    pushOperationalStateRecoveryCutAdmissionIssue(issues, {
      code: "operational_state_recovery_cut_admission_view_hash_mismatch",
      path: "/currentStateViewIdentityHash",
      message:
        "Recovery-cut admission record is bound to a different current-state view identity hash.",
      expected: currentStateViewIdentityHash,
      actual: latestAdmittedRecord.currentStateViewIdentityHash,
    });
  }

  const admissionWitnessReplay = input.admissionWitnessReplay;
  const latestWitnessRecord =
    admissionWitnessReplay?.requiredAdmissionWitnessRecord;
  if (
    input.requireAdmissionWitnessQuorum === true ||
    input.requireAdmissionWitnessAuthorityTopology === true ||
    input.requireAdmissionWitnessAuthorityTransitionAdmission === true ||
    input.requireAdmissionWitnessAuthorityTransitionAdmissionWitness === true ||
    input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
      true
  ) {
    if (admissionWitnessReplay === undefined) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_replay_missing",
        path: "/recoveryCutAdmissionWitness",
        message:
          "Recovered operational state requires replay of witness-certified recovery-cut admission records.",
      });
    } else if (!admissionWitnessReplay.valid) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_replay_invalid",
        path: "/recoveryCutAdmissionWitness",
        message:
          "Recovered operational state has an invalid recovery-cut admission witness replay.",
        actual: admissionWitnessReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      latestAdmittedRecord === undefined ||
      latestWitnessRecord === undefined ||
      latestWitnessRecord.admissionRecordHash !==
        latestAdmittedRecord.admissionRecordHash
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_latest_record_not_witnessed",
        path: "/recoveryCutAdmissionWitness",
        message:
          "Latest recovery-cut admission record is not witnessed by the replayed admission witness quorum.",
        expected: latestAdmittedRecord?.admissionRecordHash ?? "none",
        actual: latestWitnessRecord?.admissionRecordHash ?? "none",
      });
    }
  }
  if (
    (input.requireAdmissionWitnessAuthorityTopology === true ||
      input.requireAdmissionWitnessAuthorityTransitionAdmission === true ||
      input.requireAdmissionWitnessAuthorityTransitionAdmissionWitness === true ||
      input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    admissionWitnessReplay !== undefined &&
    admissionWitnessReplay.witnessAuthorityTopology === undefined
  ) {
    pushOperationalStateRecoveryCutAdmissionIssue(issues, {
      code: "operational_state_recovery_cut_admission_witness_authority_topology_missing",
      path: "/recoveryCutAdmissionWitness/witnessAuthorityTopology",
      message:
        "Recovered operational state requires recovery-cut admission witness replay to bind certificates to replayed witness authority topology.",
    });
  }
  if (
    (input.requireAdmissionWitnessAuthorityTransitionAdmission === true ||
      input.requireAdmissionWitnessAuthorityTransitionAdmissionWitness ===
        true ||
      input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    admissionWitnessReplay !== undefined &&
    admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay ===
      undefined
  ) {
    pushOperationalStateRecoveryCutAdmissionIssue(issues, {
      code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_replay_missing",
      path: "/recoveryCutAdmissionWitness/witnessAuthorityTransitionAdmissionReplay",
      message:
        "Recovered operational state requires recovery-cut admission witness authority topology to replay from admitted authority-transition history.",
    });
  }
  if (
    (input.requireAdmissionWitnessAuthorityTransitionAdmissionWitness === true ||
      input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    admissionWitnessReplay !== undefined &&
    admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
      undefined
  ) {
    const admissionTransitionWitnessReplay =
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .admissionWitnessReplay;
    if (admissionTransitionWitnessReplay === undefined) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_replay_missing",
        path: "/recoveryCutAdmissionWitness/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
        message:
          "Recovered operational state requires recovery-cut admission witness authority-transition admission records to be witnessed.",
      });
    } else if (!admissionTransitionWitnessReplay.valid) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_replay_invalid",
        path: "/recoveryCutAdmissionWitness/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
        message:
          "Recovered operational state cannot consume invalid recovery-cut admission witness authority-transition admission witness history.",
        actual: admissionTransitionWitnessReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      (input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
        input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
          true) &&
      admissionTransitionWitnessReplay.witnessAuthorityTopology === undefined
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_topology_missing",
        path: "/recoveryCutAdmissionWitness/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTopology",
        message:
          "Recovered operational state requires recovery-cut admission witness authority-transition admission witness certificates to bind to a replayed witness authority topology.",
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay ===
        undefined
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        path: "/recoveryCutAdmissionWitness/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Recovered operational state requires recovery-cut transition-admission witness authority topology to replay from admitted authority-transition history.",
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      !admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .valid
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        path: "/recoveryCutAdmissionWitness/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Recovered operational state cannot consume invalid recovery-cut transition-admission witness authority-transition admission history.",
        actual:
          admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.issues
            .map((issue) => issue.code)
            .join(","),
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      admissionTransitionWitnessReplay.witnessAuthorityTopology !== undefined &&
      admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      (admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .latestAdmittedTopology === undefined ||
        !operationalStateAuthorityTopologiesMatch(
          admissionTransitionWitnessReplay
            .witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology,
          admissionTransitionWitnessReplay.witnessAuthorityTopology,
        ))
    ) {
      pushOperationalStateRecoveryCutAdmissionIssue(issues, {
        code: "operational_state_recovery_cut_admission_witness_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/recoveryCutAdmissionWitness/witnessAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Recovered operational state requires recovery-cut transition-admission witness authority topology to match admitted authority-transition history.",
        expected:
          admissionTransitionWitnessReplay.witnessAuthorityTopology.topologyHash,
        actual:
          admissionTransitionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology?.topologyHash ?? "none",
      });
    }
  }

  return {
    valid: issues.length === 0,
    accepted: issues.length === 0,
    admissionReplay: input.admissionReplay,
    ...(admissionWitnessReplay !== undefined ? { admissionWitnessReplay } : {}),
    ...(latestAdmittedRecord !== undefined ? { latestAdmittedRecord } : {}),
    ...(latestWitnessRecord !== undefined ? { latestWitnessRecord } : {}),
    issues,
  };
}

function operationalStateHistoryRootKey(
  root: Pick<
    OperationalStateHistoryRoot,
    "tenantId" | "storeId" | "authorityScope"
  >,
): string {
  return `${root.tenantId}:${root.authorityScope}:${root.storeId}`;
}

function operationalStateHistoryRootSettlementKey(
  root: Pick<
    OperationalStateHistoryRoot,
    | "tenantId"
    | "storeId"
    | "authorityScope"
    | "sequence"
    | "rootCommitmentHash"
  >,
): string {
  return `${root.tenantId}:${root.authorityScope}:${root.storeId}:${root.sequence}:${root.rootCommitmentHash}`;
}

function operationalStateHistoryRootSequenceKey(
  root: Pick<
    OperationalStateHistoryRoot,
    "tenantId" | "storeId" | "authorityScope" | "sequence"
  >,
): string {
  return `${root.tenantId}:${root.authorityScope}:${root.storeId}:${root.sequence}`;
}

export function buildOperationalStateHistoryRoot(
  input: OperationalStateHistoryRootInput,
): OperationalStateHistoryRoot {
  const payload: Omit<OperationalStateHistoryRoot, "rootCommitmentHash"> = {
    tenantId: tenantId(String(input.tenantId)),
    storeId: input.storeId,
    storeKind: input.storeKind,
    authorityScope: input.authorityScope,
    sequence: input.sequence,
    rootHash: input.rootHash,
    recordedAt: input.recordedAt,
  };
  return {
    ...payload,
    rootCommitmentHash:
      computeOperationalStateHistoryRootCommitmentHash(payload),
  };
}

export function computeOperationalStateHistoryRootCommitmentHash(
  root: Omit<OperationalStateHistoryRoot, "rootCommitmentHash">,
): string {
  return fingerprint64(canonicalStringify(root));
}

export function verifyOperationalStateHistoryRootCommitmentHash(
  root: OperationalStateHistoryRoot,
): StateReviewArtifactHashValidation {
  const { rootCommitmentHash, ...payload } = root;
  const expectedHash = computeOperationalStateHistoryRootCommitmentHash(payload);
  return {
    valid: rootCommitmentHash === expectedHash,
    expectedHash,
    actualHash: rootCommitmentHash,
  };
}

export function buildOperationalStateHistoryRootConsistencyProof(
  input: OperationalStateHistoryRootConsistencyProofInput,
): OperationalStateHistoryRootConsistencyProof {
  const payload: Omit<OperationalStateHistoryRootConsistencyProof, "proofHash"> =
    {
      tenantId: tenantId(String(input.tenantId)),
      storeId: input.storeId,
      authorityScope: input.authorityScope,
      fromSequence: input.fromRoot.sequence,
      fromRootHash: input.fromRoot.rootHash,
      fromRootCommitmentHash: input.fromRoot.rootCommitmentHash,
      toSequence: input.toRoot.sequence,
      toRootHash: input.toRoot.rootHash,
      toRootCommitmentHash: input.toRoot.rootCommitmentHash,
    };
  return {
    ...payload,
    proofHash: computeOperationalStateHistoryRootConsistencyProofHash(payload),
  };
}

export function computeOperationalStateHistoryRootConsistencyProofHash(
  proof: Omit<OperationalStateHistoryRootConsistencyProof, "proofHash">,
): string {
  return fingerprint64(canonicalStringify(proof));
}

function verifyOperationalStateHistoryRootConsistencyProof(
  proof: OperationalStateHistoryRootConsistencyProof,
  fromRoot: OperationalStateHistoryRoot,
  toRoot: OperationalStateHistoryRoot,
): boolean {
  const { proofHash, ...payload } = proof;
  return (
    proofHash ===
      computeOperationalStateHistoryRootConsistencyProofHash(payload) &&
    proof.tenantId === fromRoot.tenantId &&
    proof.tenantId === toRoot.tenantId &&
    proof.storeId === fromRoot.storeId &&
    proof.storeId === toRoot.storeId &&
    proof.authorityScope === fromRoot.authorityScope &&
    proof.authorityScope === toRoot.authorityScope &&
    proof.fromSequence === fromRoot.sequence &&
    proof.fromRootHash === fromRoot.rootHash &&
    proof.fromRootCommitmentHash === fromRoot.rootCommitmentHash &&
    proof.toSequence === toRoot.sequence &&
    proof.toRootHash === toRoot.rootHash &&
    proof.toRootCommitmentHash === toRoot.rootCommitmentHash
  );
}

export function buildOperationalStateHistoryRootObservation(
  input: OperationalStateHistoryRootObservationInput,
): OperationalStateHistoryRootObservation {
  const payload: Omit<OperationalStateHistoryRootObservation, "observationHash"> =
    {
      tenantId: tenantId(String(input.tenantId)),
      observerId: input.observerId,
      observedAt: input.observedAt,
      root: input.root,
      ...(input.consistencyProof !== undefined
        ? { consistencyProof: input.consistencyProof }
        : {}),
    };
  return {
    ...payload,
    observationHash:
      computeOperationalStateHistoryRootObservationHash(payload),
  };
}

export function computeOperationalStateHistoryRootObservationHash(
  observation: Omit<
    OperationalStateHistoryRootObservation,
    "observationHash"
  >,
): string {
  return fingerprint64(canonicalStringify(observation));
}

export function verifyOperationalStateHistoryRootObservationHash(
  observation: OperationalStateHistoryRootObservation,
): StateReviewArtifactHashValidation {
  const { observationHash, ...payload } = observation;
  const expectedHash =
    computeOperationalStateHistoryRootObservationHash(payload);
  return {
    valid: observationHash === expectedHash,
    expectedHash,
    actualHash: observationHash,
  };
}

function operationalStateHistoryRootObserverSignaturePayload(
  observation: OperationalStateHistoryRootObservation,
): OperationalStateHistoryRootObserverSignaturePayload {
  return {
    schemaVersion: OPERATIONAL_STATE_HISTORY_ROOT_OBSERVER_SIGNATURE_SCHEMA_VERSION,
    observerRole: "history_root_observer",
    tenantId: observation.tenantId,
    authorityScope: observation.root.authorityScope,
    observerId: observation.observerId,
    storeId: observation.root.storeId,
    storeKind: observation.root.storeKind,
    rootSequence: observation.root.sequence,
    rootHash: observation.root.rootHash,
    rootCommitmentHash: observation.root.rootCommitmentHash,
    observedAt: observation.observedAt,
    observationHash: observation.observationHash,
  };
}

function operationalStateHistoryRootObserverSignaturePayloadFromProof(
  proof: OperationalStateHistoryRootObserverSignatureProof,
): OperationalStateHistoryRootObserverSignaturePayload {
  return {
    schemaVersion: proof.schemaVersion,
    observerRole: proof.observerRole,
    tenantId: proof.tenantId,
    authorityScope: proof.authorityScope,
    observerId: proof.observerId,
    storeId: proof.storeId,
    storeKind: proof.storeKind,
    rootSequence: proof.rootSequence,
    rootHash: proof.rootHash,
    rootCommitmentHash: proof.rootCommitmentHash,
    observedAt: proof.observedAt,
    observationHash: proof.observationHash,
  };
}

export function computeOperationalStateHistoryRootObserverSignaturePayloadHash(
  observation: OperationalStateHistoryRootObservation,
): string {
  return fingerprint64(
    canonicalStringify(
      operationalStateHistoryRootObserverSignaturePayload(observation),
    ),
  );
}

function computeOperationalStateHistoryRootObserverSignatureProofPayloadHash(
  proof: OperationalStateHistoryRootObserverSignatureProof,
): string {
  return fingerprint64(
    canonicalStringify(
      operationalStateHistoryRootObserverSignaturePayloadFromProof(proof),
    ),
  );
}

export function computeOperationalStateHistoryRootObserverSignatureProofHash(
  proof: Omit<
    OperationalStateHistoryRootObserverSignatureProof,
    "observerSignatureProofHash"
  >,
): string {
  return fingerprint64(canonicalStringify(proof));
}

export function buildOperationalStateHistoryRootObserverSignatureProof(
  input: OperationalStateHistoryRootObserverSignatureProofInput,
): OperationalStateHistoryRootObserverSignatureProof {
  const payload = operationalStateHistoryRootObserverSignaturePayload(
    input.observation,
  );
  const observerSignaturePayloadHash =
    computeOperationalStateHistoryRootObserverSignaturePayloadHash(
      input.observation,
    );
  const proofPayload: Omit<
    OperationalStateHistoryRootObserverSignatureProof,
    "observerSignatureProofHash"
  > = {
    ...payload,
    observerSignaturePayloadHash,
    observerKeyBinding: input.observerKeyBinding,
    verifierProof: input.verifierProof,
  };
  return {
    ...proofPayload,
    observerSignatureProofHash:
      computeOperationalStateHistoryRootObserverSignatureProofHash(proofPayload),
  };
}

export function verifyOperationalStateHistoryRootObserverSignatureProofHash(
  proof: OperationalStateHistoryRootObserverSignatureProof,
): StateReviewArtifactHashValidation {
  const { observerSignatureProofHash, ...payload } = proof;
  const expectedHash =
    computeOperationalStateHistoryRootObserverSignatureProofHash(payload);
  return {
    valid: observerSignatureProofHash === expectedHash,
    expectedHash,
    actualHash: observerSignatureProofHash,
  };
}

function pushOperationalStateHistoryRootObserverSignatureIssue(
  issues: OperationalStateHistoryRootObserverSignatureIssue[],
  issue: OperationalStateHistoryRootObserverSignatureIssue,
): void {
  issues.push(issue);
}

export function evaluateOperationalStateHistoryRootObserverSignature(
  input: OperationalStateHistoryRootObserverSignatureEvaluationInput,
): OperationalStateHistoryRootObserverSignatureEvaluation {
  const issues: OperationalStateHistoryRootObserverSignatureIssue[] = [];
  const proof = input.observerSignatureProof;

  if (proof === undefined) {
    return {
      valid: false,
      accepted: false,
      issues: [
        {
          code: "operational_state_history_root_observer_signature_missing",
          path: "/observerSignatureProof",
          message:
            "History-root transparency observations cannot become accountable evidence without a replayable observer signature proof.",
        },
      ],
    };
  }

  const proofHashValidation =
    verifyOperationalStateHistoryRootObserverSignatureProofHash(proof);
  if (!proofHashValidation.valid) {
    pushOperationalStateHistoryRootObserverSignatureIssue(issues, {
      code: "operational_state_history_root_observer_signature_hash_mismatch",
      path: "/observerSignatureProof/observerSignatureProofHash",
      message: `History-root observer signature proof hash ${proofHashValidation.actualHash} does not match recomputed hash ${proofHashValidation.expectedHash}.`,
      expected: proofHashValidation.expectedHash,
      actual: proofHashValidation.actualHash,
    });
  }

  const recomputedPayloadHash =
    computeOperationalStateHistoryRootObserverSignatureProofPayloadHash(proof);
  if (proof.observerSignaturePayloadHash !== recomputedPayloadHash) {
    pushOperationalStateHistoryRootObserverSignatureIssue(issues, {
      code: "operational_state_history_root_observer_signature_payload_mismatch",
      path: "/observerSignatureProof/observerSignaturePayloadHash",
      message:
        "History-root observer signature proof must bind the exact canonical observation payload.",
      expected: recomputedPayloadHash,
      actual: proof.observerSignaturePayloadHash,
    });
  }

  if (input.observation !== undefined) {
    const expectedPayloadHash =
      computeOperationalStateHistoryRootObserverSignaturePayloadHash(
        input.observation,
      );
    if (proof.observerSignaturePayloadHash !== expectedPayloadHash) {
      pushOperationalStateHistoryRootObserverSignatureIssue(issues, {
        code: "operational_state_history_root_observer_signature_payload_mismatch",
        path: "/observation",
        message:
          "History-root observer signature proof does not match the supplied observation.",
        expected: expectedPayloadHash,
        actual: proof.observerSignaturePayloadHash,
      });
    }
    const observationHashValidation =
      verifyOperationalStateHistoryRootObservationHash(input.observation);
    if (
      !observationHashValidation.valid ||
      proof.observationHash !== input.observation.observationHash
    ) {
      pushOperationalStateHistoryRootObserverSignatureIssue(issues, {
        code: "operational_state_history_root_observer_signature_observation_hash_mismatch",
        path: "/observation/observationHash",
        message:
          "History-root observer signature proof must bind the hash-valid supplied observation.",
        expected: observationHashValidation.expectedHash,
        actual: proof.observationHash,
      });
    }
    if (proof.tenantId !== input.observation.tenantId) {
      pushOperationalStateHistoryRootObserverSignatureIssue(issues, {
        code: "operational_state_history_root_observer_signature_tenant_mismatch",
        path: "/observation/tenantId",
        message:
          "History-root observer signature proof tenant must match the supplied observation tenant.",
        expected: input.observation.tenantId,
        actual: proof.tenantId,
      });
    }
    if (proof.authorityScope !== input.observation.root.authorityScope) {
      pushOperationalStateHistoryRootObserverSignatureIssue(issues, {
        code: "operational_state_history_root_observer_signature_scope_mismatch",
        path: "/observation/root/authorityScope",
        message:
          "History-root observer signature proof scope must match the supplied observation root scope.",
        expected: input.observation.root.authorityScope,
        actual: proof.authorityScope,
      });
    }
    if (proof.observerId !== input.observation.observerId) {
      pushOperationalStateHistoryRootObserverSignatureIssue(issues, {
        code: "operational_state_history_root_observer_signature_observer_mismatch",
        path: "/observation/observerId",
        message:
          "History-root observer signature proof observer must match the supplied observation observer.",
        expected: input.observation.observerId,
        actual: proof.observerId,
      });
    }
    if (
      proof.storeId !== input.observation.root.storeId ||
      proof.storeKind !== input.observation.root.storeKind ||
      proof.rootSequence !== input.observation.root.sequence ||
      proof.rootHash !== input.observation.root.rootHash ||
      proof.rootCommitmentHash !==
        input.observation.root.rootCommitmentHash ||
      proof.observedAt !== input.observation.observedAt
    ) {
      pushOperationalStateHistoryRootObserverSignatureIssue(issues, {
        code: "operational_state_history_root_observer_signature_root_mismatch",
        path: "/observation/root",
        message:
          "History-root observer signature proof root fields must match the supplied observation root.",
      });
    }
  }

  if (
    input.expectedTenantId !== undefined &&
    proof.tenantId !== tenantId(String(input.expectedTenantId))
  ) {
    pushOperationalStateHistoryRootObserverSignatureIssue(issues, {
      code: "operational_state_history_root_observer_signature_tenant_mismatch",
      path: "/expectedTenantId",
      message:
        "History-root observer signature proof tenant must match replay context.",
      expected: String(input.expectedTenantId),
      actual: proof.tenantId,
    });
  }
  if (
    input.expectedAuthorityScope !== undefined &&
    proof.authorityScope !== input.expectedAuthorityScope
  ) {
    pushOperationalStateHistoryRootObserverSignatureIssue(issues, {
      code: "operational_state_history_root_observer_signature_scope_mismatch",
      path: "/expectedAuthorityScope",
      message:
        "History-root observer signature proof scope must match replay context.",
      expected: input.expectedAuthorityScope,
      actual: proof.authorityScope,
    });
  }
  if (
    input.expectedObserverId !== undefined &&
    proof.observerId !== input.expectedObserverId
  ) {
    pushOperationalStateHistoryRootObserverSignatureIssue(issues, {
      code: "operational_state_history_root_observer_signature_observer_mismatch",
      path: "/expectedObserverId",
      message:
        "History-root observer signature proof observer must match replay context.",
      expected: input.expectedObserverId,
      actual: proof.observerId,
    });
  }
  if (
    input.expectedObservationHash !== undefined &&
    proof.observationHash !== input.expectedObservationHash
  ) {
    pushOperationalStateHistoryRootObserverSignatureIssue(issues, {
      code: "operational_state_history_root_observer_signature_observation_hash_mismatch",
      path: "/expectedObservationHash",
      message:
        "History-root observer signature proof must bind the expected observation hash.",
      expected: input.expectedObservationHash,
      actual: proof.observationHash,
    });
  }
  if (
    input.allowedObserverIds !== undefined &&
    !input.allowedObserverIds.includes(proof.observerId)
  ) {
    pushOperationalStateHistoryRootObserverSignatureIssue(issues, {
      code: "operational_state_history_root_observer_signature_observer_not_allowed",
      path: "/observerSignatureProof/observerId",
      message:
        "History-root observer is not in the replayed allowed-observer set.",
      expected: input.allowedObserverIds.join(","),
      actual: proof.observerId,
    });
  }

  const keyBinding = proof.observerKeyBinding;
  if (
    keyBinding.tenantId !== proof.tenantId ||
    keyBinding.authorityScope !== proof.authorityScope ||
    keyBinding.principalId !== proof.observerId
  ) {
    pushOperationalStateHistoryRootObserverSignatureIssue(issues, {
      code: "operational_state_history_root_observer_signature_key_binding_mismatch",
      path: "/observerSignatureProof/observerKeyBinding",
      message:
        "History-root observer signature proof key binding must identify the replayed observer principal under the same tenant and scope.",
    });
  }

  const verifierEvaluation = evaluateOperationalStateSignatureVerifierAdapterProof(
    {
      keyBinding,
      proof: proof.verifierProof,
      expectedTenantId: proof.tenantId,
      expectedAuthorityScope: proof.authorityScope,
      expectedPrincipalId: proof.observerId,
      expectedKeyId: keyBinding.keyId,
      expectedAlgorithm: keyBinding.algorithm,
      expectedPayloadHash: proof.observerSignaturePayloadHash,
      expectedSignatureHash:
        input.expectedSignatureHash ?? proof.verifierProof.signatureHash,
      ...(input.allowedVerifierIds !== undefined
        ? { allowedVerifierIds: input.allowedVerifierIds }
        : {}),
    },
  );
  if (!verifierEvaluation.valid) {
    pushOperationalStateHistoryRootObserverSignatureIssue(issues, {
      code: "operational_state_history_root_observer_signature_verifier_proof_invalid",
      path: "/observerSignatureProof/verifierProof",
      message:
        "History-root observer signature must verify through the constrained verifier-proof boundary.",
      actual: verifierEvaluation.issues.map((issue) => issue.code).join(","),
    });
  }

  return {
    valid: issues.length === 0,
    accepted: issues.length === 0 && verifierEvaluation.accepted,
    observerSignatureProof: proof,
    verifierEvaluation,
    observerSignaturePayloadHash: proof.observerSignaturePayloadHash,
    issues,
  };
}

export function computeOperationalStateHistoryRootSettlementAuthorityTransitionAdmissionRecordHash(
  record: Omit<
    OperationalStateHistoryRootSettlementAuthorityTransitionAdmissionRecord,
    "admissionRecordHash"
  >,
): string {
  return fingerprint64(canonicalStringify(record));
}

export function buildOperationalStateHistoryRootSettlementAuthorityTransitionAdmissionRecord(
  input: OperationalStateHistoryRootSettlementAuthorityTransitionAdmissionRecordInput,
): OperationalStateHistoryRootSettlementAuthorityTransitionAdmissionRecord {
  const nextAuthorityTopology = operationalStateAuthorityTopologyFromTransition(
    input.authorityTransition,
    input.previousAuthorityTopology,
  );
  const payload: Omit<
    OperationalStateHistoryRootSettlementAuthorityTransitionAdmissionRecord,
    "admissionRecordHash"
  > = {
    schemaVersion:
      OPERATIONAL_STATE_HISTORY_ROOT_SETTLEMENT_AUTHORITY_TRANSITION_ADMISSION_SCHEMA_VERSION,
    tenantId: tenantId(String(input.tenantId)),
    transitionAdmissionStoreId: input.transitionAdmissionStoreId,
    topologyId: input.topologyId,
    authorityScope: input.authorityScope,
    admissionSequence: input.admissionSequence,
    authoritySequence: input.authorityTransition.authoritySequence,
    authorityRecordHash: input.authorityTransition.authorityRecordHash,
    ...(input.authorityTransition.previousAuthorityRecordHash !== undefined
      ? {
          previousAuthorityRecordHash:
            input.authorityTransition.previousAuthorityRecordHash,
        }
      : {}),
    ...(input.previousAuthorityTopology !== undefined
      ? {
          previousAuthorityTopologyHash:
            input.previousAuthorityTopology.topologyHash,
        }
      : {}),
    nextAuthorityTopologyHash: nextAuthorityTopology.topologyHash,
    authorityTransition: input.authorityTransition,
    admissionCertificate: input.admissionCertificate,
    ...(input.previousAdmissionRecordHash !== undefined
      ? { previousAdmissionRecordHash: input.previousAdmissionRecordHash }
      : {}),
    admittedAt: input.admittedAt,
    admittedBy: input.admittedBy,
    ...(input.admissionReason !== undefined
      ? { admissionReason: input.admissionReason }
      : {}),
  };
  return {
    ...payload,
    admissionRecordHash:
      computeOperationalStateHistoryRootSettlementAuthorityTransitionAdmissionRecordHash(
        payload,
      ),
  };
}

export function verifyOperationalStateHistoryRootSettlementAuthorityTransitionAdmissionRecordHash(
  record: OperationalStateHistoryRootSettlementAuthorityTransitionAdmissionRecord,
): StateReviewArtifactHashValidation {
  const { admissionRecordHash, ...payload } = record;
  const expectedHash =
    computeOperationalStateHistoryRootSettlementAuthorityTransitionAdmissionRecordHash(
      payload,
    );
  return {
    valid: admissionRecordHash === expectedHash,
    expectedHash,
    actualHash: admissionRecordHash,
  };
}

export function operationalStateHistoryRootSettlementAuthorityTransitionAdmissionSubjectId(
  input: Pick<
    OperationalStateHistoryRootSettlementAuthorityTransitionAdmissionRecord,
    "transitionAdmissionStoreId" | "topologyId"
  >,
): string {
  return `${input.transitionAdmissionStoreId}:${input.topologyId}`;
}

export function buildOperationalStateHistoryRootSettlementAuthorityTransitionAdmissionWitnessRecord(
  input: OperationalStateHistoryRootSettlementAuthorityTransitionAdmissionWitnessRecordInput,
): OperationalStateHistoryRootSettlementAuthorityTransitionAdmissionWitnessRecord {
  const payload: Omit<
    OperationalStateHistoryRootSettlementAuthorityTransitionAdmissionWitnessRecord,
    "witnessRecordHash"
  > = {
    schemaVersion:
      OPERATIONAL_STATE_HISTORY_ROOT_SETTLEMENT_AUTHORITY_TRANSITION_ADMISSION_WITNESS_SCHEMA_VERSION,
    tenantId: tenantId(String(input.tenantId)),
    transitionAdmissionWitnessStoreId:
      input.transitionAdmissionWitnessStoreId,
    transitionAdmissionStoreId: input.transitionAdmissionStoreId,
    topologyId: input.topologyId,
    authorityScope: input.authorityScope,
    witnessSequence: input.witnessSequence,
    admissionSequence: input.admissionSequence,
    authoritySequence: input.authoritySequence,
    authorityRecordHash: input.authorityRecordHash,
    admissionRecordHash: input.admissionRecordHash,
    nextAuthorityTopologyHash: input.nextAuthorityTopologyHash,
    admissionCertificate: input.admissionCertificate,
    ...(input.previousWitnessRecordHash !== undefined
      ? { previousWitnessRecordHash: input.previousWitnessRecordHash }
      : {}),
    witnessedAt: input.witnessedAt,
    witnessedBy: input.witnessedBy,
    ...(input.witnessReason !== undefined
      ? { witnessReason: input.witnessReason }
      : {}),
  };
  return {
    ...payload,
    witnessRecordHash:
      computeOperationalStateHistoryRootSettlementAuthorityTransitionAdmissionWitnessRecordHash(
        payload,
      ),
  };
}

export function computeOperationalStateHistoryRootSettlementAuthorityTransitionAdmissionWitnessRecordHash(
  record: Omit<
    OperationalStateHistoryRootSettlementAuthorityTransitionAdmissionWitnessRecord,
    "witnessRecordHash"
  >,
): string {
  return fingerprint64(canonicalStringify(record));
}

export function verifyOperationalStateHistoryRootSettlementAuthorityTransitionAdmissionWitnessRecordHash(
  record: OperationalStateHistoryRootSettlementAuthorityTransitionAdmissionWitnessRecord,
): StateReviewArtifactHashValidation {
  const { witnessRecordHash, ...payload } = record;
  const expectedHash =
    computeOperationalStateHistoryRootSettlementAuthorityTransitionAdmissionWitnessRecordHash(
      payload,
    );
  return {
    valid: witnessRecordHash === expectedHash,
    expectedHash,
    actualHash: witnessRecordHash,
  };
}

export function replayOperationalStateHistoryRootSettlementAuthorityTransitionAdmissionWitnessRecords(
  input: OperationalStateHistoryRootSettlementAuthorityTransitionAdmissionWitnessReplayInput,
): OperationalStateHistoryRootSettlementAuthorityTransitionAdmissionWitnessReplay {
  const issues: OperationalStateHistoryRootTransparencyIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const witnessHashBySequence = new Map<number, string>();
  const witnessRecordByAdmissionHash = new Map<
    string,
    OperationalStateHistoryRootSettlementAuthorityTransitionAdmissionWitnessRecord
  >();
  const witnessAuthorityTopology = input.witnessAuthorityTopology;
  const witnessAuthorityTransitionAdmissionReplay =
    input.witnessAuthorityTransitionAdmissionReplay;
  const principalById = new Map<string, OperationalStateAuthorityPrincipalState>(
    witnessAuthorityTopology?.principals.map((principal) => [
      principal.principalId,
      principal,
    ]) ?? [],
  );
  let expectedSequence = 1;
  let previousWitnessRecordHash: string | undefined;
  let latestWitnessRecord:
    | OperationalStateHistoryRootSettlementAuthorityTransitionAdmissionWitnessRecord
    | undefined;

  if (input.admissionReplay !== undefined && !input.admissionReplay.valid) {
    issues.push({
      code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_admission_replay_invalid",
      path: "/admissionReplay",
      message:
        "History-root settlement authority-transition admission witness replay cannot account for invalid transition-admission history.",
      actual: input.admissionReplay.issues
        .map((issue) => issue.code)
        .join(","),
    });
  }

  if (
    (input.requireWitnessAuthorityTopology === true ||
      input.requireWitnessAuthorityTransitionAdmission === true) &&
    witnessAuthorityTopology === undefined
  ) {
    issues.push({
      code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_authority_topology_missing",
      path: "/witnessAuthorityTopology",
      message:
        "History-root settlement authority-transition admission witness replay requires a replayed witness authority topology.",
    });
  }

  if (witnessAuthorityTopology !== undefined) {
    const topologyHashValidation =
      verifyOperationalStateAuthorityTopologyHash(witnessAuthorityTopology);
    if (!topologyHashValidation.valid) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_authority_topology_hash_mismatch",
        path: "/witnessAuthorityTopology/topologyHash",
        message: `History-root settlement authority-transition admission witness authority topology hash ${topologyHashValidation.actualHash} does not match recomputed hash ${topologyHashValidation.expectedHash}.`,
        expected: topologyHashValidation.expectedHash,
        actual: topologyHashValidation.actualHash,
      });
    }
    if (witnessAuthorityTopology.tenantId !== expectedTenantId) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_authority_topology_tenant_mismatch",
        path: "/witnessAuthorityTopology/tenantId",
        message:
          "History-root settlement authority-transition admission witness authority topology tenant does not match replay tenant.",
        expected: expectedTenantId,
        actual: witnessAuthorityTopology.tenantId,
      });
    }
    if (witnessAuthorityTopology.authorityScope !== input.authorityScope) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_authority_topology_scope_mismatch",
        path: "/witnessAuthorityTopology/authorityScope",
        message:
          "History-root settlement authority-transition admission witness authority topology scope does not match replay scope.",
        expected: input.authorityScope,
        actual: witnessAuthorityTopology.authorityScope,
      });
    }
    if (
      witnessAuthorityTopology.requiredWitnesses === undefined ||
      witnessAuthorityTopology.minimumWitnesses === undefined
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_authority_quorum_missing",
        path: "/witnessAuthorityTopology/requiredWitnesses",
        message:
          "History-root settlement authority-transition admission witness authority topology must define quorum thresholds.",
      });
    }
  }

  if (input.requireWitnessAuthorityTransitionAdmission === true) {
    if (witnessAuthorityTransitionAdmissionReplay === undefined) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        path: "/witnessAuthorityTransitionAdmissionReplay",
        message:
          "History-root settlement authority-transition admission witness replay requires its witness authority topology to replay from admitted authority-transition history.",
      });
    } else if (!witnessAuthorityTransitionAdmissionReplay.valid) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        path: "/witnessAuthorityTransitionAdmissionReplay",
        message:
          "History-root settlement authority-transition admission witness replay cannot consume invalid nested witness-authority transition admission history.",
        actual: witnessAuthorityTransitionAdmissionReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      witnessAuthorityTopology !== undefined &&
      (witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology ===
        undefined ||
        !operationalStateAuthorityTopologiesMatch(
          witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology,
          witnessAuthorityTopology,
        ))
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "History-root settlement transition-admission witness authority topology must be recovered from admitted authority-transition history.",
        expected: witnessAuthorityTopology.topologyHash,
        actual:
          witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology
            ?.topologyHash ?? "none",
      });
    }
  }

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const witnessRecordHashValidation =
      verifyOperationalStateHistoryRootSettlementAuthorityTransitionAdmissionWitnessRecordHash(
        record,
      );
    const certificateHashValidation =
      verifyOperationalStateQuorumCertificateProofCertificateHash(
        record.admissionCertificate,
      );
    const previousWitnessHashAtSequence = witnessHashBySequence.get(
      record.witnessSequence,
    );

    if (
      previousWitnessHashAtSequence !== undefined &&
      previousWitnessHashAtSequence !== record.witnessRecordHash
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_record_fork",
        path: `${path}/witnessSequence`,
        message: `History-root settlement authority-transition admission witness sequence ${record.witnessSequence} has more than one witness record hash.`,
        expected: previousWitnessHashAtSequence,
        actual: record.witnessRecordHash,
      });
    } else if (previousWitnessHashAtSequence === undefined) {
      witnessHashBySequence.set(
        record.witnessSequence,
        record.witnessRecordHash,
      );
    }

    if (
      record.tenantId !== expectedTenantId ||
      record.admissionCertificate.tenantId !== expectedTenantId
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_record_tenant_mismatch",
        path,
        message:
          "History-root settlement authority-transition admission witness record and certificate must match the replay tenant.",
        expected: expectedTenantId,
      });
    }
    if (
      record.transitionAdmissionWitnessStoreId !==
        input.transitionAdmissionWitnessStoreId ||
      record.transitionAdmissionStoreId !== input.transitionAdmissionStoreId
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_record_store_mismatch",
        path,
        message:
          "History-root settlement authority-transition admission witness record must bind the expected witness and transition-admission stores.",
        expected: `${input.transitionAdmissionWitnessStoreId}:${input.transitionAdmissionStoreId}`,
        actual: `${record.transitionAdmissionWitnessStoreId}:${record.transitionAdmissionStoreId}`,
      });
    }
    if (
      record.topologyId !== input.topologyId ||
      record.authorityScope !== input.authorityScope ||
      record.admissionCertificate.authorityScope !== input.authorityScope
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_record_scope_mismatch",
        path,
        message:
          "History-root settlement authority-transition admission witness record must share the replay topology and authority scope.",
        expected: `${input.topologyId}:${input.authorityScope}`,
      });
    }
    if (record.witnessSequence !== expectedSequence) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_record_sequence_gap",
        path: `${path}/witnessSequence`,
        message:
          "History-root settlement authority-transition admission witness records must replay as a contiguous witness sequence.",
        expected: expectedSequence,
        actual: record.witnessSequence,
      });
    }
    if (record.previousWitnessRecordHash !== previousWitnessRecordHash) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_record_previous_hash_mismatch",
        path: `${path}/previousWitnessRecordHash`,
        message:
          "History-root settlement authority-transition admission witness record does not chain to the previous witness record hash.",
        expected: previousWitnessRecordHash ?? "none",
        actual: record.previousWitnessRecordHash ?? "none",
      });
    }
    if (!certificateHashValidation.valid) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_certificate_hash_mismatch",
        path: `${path}/admissionCertificate/quorumCertificateHash`,
        message: `History-root settlement authority-transition admission witness certificate hash ${certificateHashValidation.actualHash} does not match recomputed hash ${certificateHashValidation.expectedHash}.`,
        expected: certificateHashValidation.expectedHash,
        actual: certificateHashValidation.actualHash,
      });
    }
    if (
      !record.admissionCertificate.certified ||
      record.admissionCertificate.status !== "certified"
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_certificate_not_certified",
        path: `${path}/admissionCertificate/status`,
        message:
          "History-root settlement authority-transition admission cannot become accountable through a non-certified witness certificate.",
        expected: "certified",
        actual: record.admissionCertificate.status,
      });
    }
    if (
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.minimumWitnesses ||
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.requiredWitnesses
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_certificate_quorum_not_met",
        path: `${path}/admissionCertificate/acceptedWitnessIds`,
        message:
          "History-root settlement authority-transition admission witness certificate does not satisfy its declared witness quorum.",
        expected: Math.max(
          record.admissionCertificate.requiredWitnesses,
          record.admissionCertificate.minimumWitnesses,
        ),
        actual: record.admissionCertificate.acceptedWitnessIds.length,
      });
    }
    if (
      record.admissionCertificate.subjectKind !==
        OPERATIONAL_STATE_HISTORY_ROOT_SETTLEMENT_AUTHORITY_TRANSITION_ADMISSION_RECORD_SUBJECT_KIND ||
      record.admissionCertificate.subjectId !==
        `${record.transitionAdmissionStoreId}:${record.topologyId}` ||
      record.admissionCertificate.subjectSequence !==
        record.admissionSequence ||
      record.admissionCertificate.subjectHash !== record.admissionRecordHash
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_certificate_subject_mismatch",
        path: `${path}/admissionCertificate`,
        message:
          "History-root settlement authority-transition admission witness certificate must certify the exact transition-admission store, topology id, admission sequence, and admission record hash.",
        expected: record.admissionRecordHash,
        actual: record.admissionCertificate.subjectHash,
      });
    }
    if (
      input.requiredAuthorityBoundary !== undefined &&
      record.admissionCertificate.authorityBoundary !==
        input.requiredAuthorityBoundary
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_certificate_authority_boundary_mismatch",
        path: `${path}/admissionCertificate/authorityBoundary`,
        message:
          "History-root settlement authority-transition admission witness certificate was admitted under the wrong authority boundary.",
        expected: input.requiredAuthorityBoundary,
        actual: record.admissionCertificate.authorityBoundary,
      });
    }
    if (witnessAuthorityTopology !== undefined) {
      if (
        record.admissionCertificate.authorityTopologyHash !==
        witnessAuthorityTopology.topologyHash
      ) {
        issues.push({
          code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_certificate_authority_topology_mismatch",
          path: `${path}/admissionCertificate/authorityTopologyHash`,
          message:
            "History-root settlement authority-transition admission witness certificate is not bound to the replayed witness authority topology.",
          expected: witnessAuthorityTopology.topologyHash,
          actual:
            record.admissionCertificate.authorityTopologyHash ?? "none",
        });
      }

      const acceptedWitnessIds =
        record.admissionCertificate.acceptedWitnessIds;
      const uniqueAcceptedWitnessIds = new Set(acceptedWitnessIds);
      if (uniqueAcceptedWitnessIds.size !== acceptedWitnessIds.length) {
        issues.push({
          code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_authority_duplicate_witness",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "History-root settlement authority-transition admission witness authority quorum cannot be satisfied by duplicate witness ids.",
          expected: uniqueAcceptedWitnessIds.size,
          actual: acceptedWitnessIds.length,
        });
      }

      let activeAuthorizedWitnessCount = 0;
      for (const witnessId of uniqueAcceptedWitnessIds) {
        const principal = principalById.get(witnessId);
        if (principal === undefined) {
          issues.push({
            code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_authority_witness_unknown",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "History-root settlement authority-transition admission witness certificate names a witness outside the replayed authority topology.",
            expected: witnessAuthorityTopology.topologyHash,
            actual: witnessId,
          });
          continue;
        }
        if (principal.status !== "active") {
          issues.push({
            code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_authority_witness_not_active",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "History-root settlement authority-transition admission witness certificate names a witness that is not active in the replayed authority topology.",
            expected: "active",
            actual: `${witnessId}:${principal.status}`,
          });
          continue;
        }
        activeAuthorizedWitnessCount += 1;
      }

      const requiredAuthorizedWitnesses = Math.max(
        witnessAuthorityTopology.requiredWitnesses ?? 0,
        witnessAuthorityTopology.minimumWitnesses ?? 0,
      );
      if (activeAuthorizedWitnessCount < requiredAuthorizedWitnesses) {
        issues.push({
          code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_authority_quorum_not_met",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "History-root settlement authority-transition admission witness certificate does not satisfy the replayed witness authority topology quorum.",
          expected: requiredAuthorizedWitnesses,
          actual: activeAuthorizedWitnessCount,
        });
      }
    }
    if (!witnessRecordHashValidation.valid) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_record_hash_mismatch",
        path: `${path}/witnessRecordHash`,
        message: `History-root settlement authority-transition admission witness record hash ${witnessRecordHashValidation.actualHash} does not match recomputed hash ${witnessRecordHashValidation.expectedHash}.`,
        expected: witnessRecordHashValidation.expectedHash,
        actual: witnessRecordHashValidation.actualHash,
      });
    }

    witnessRecordByAdmissionHash.set(record.admissionRecordHash, record);
    expectedSequence = record.witnessSequence + 1;
    previousWitnessRecordHash = record.witnessRecordHash;
    latestWitnessRecord = record;
  });

  const requiredAdmissionRecord =
    input.requiredAdmissionRecord ?? input.admissionReplay?.latestAdmittedRecord;
  let requiredAdmissionWitnessRecord:
    | OperationalStateHistoryRootSettlementAuthorityTransitionAdmissionWitnessRecord
    | undefined;
  if (requiredAdmissionRecord !== undefined) {
    const admissionRecordHashValidation =
      verifyOperationalStateHistoryRootSettlementAuthorityTransitionAdmissionRecordHash(
        requiredAdmissionRecord,
      );
    if (!admissionRecordHashValidation.valid) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_record_hash_mismatch",
        path: "/requiredAdmissionRecord/admissionRecordHash",
        message: `Required history-root settlement authority-transition admission hash ${admissionRecordHashValidation.actualHash} does not match recomputed hash ${admissionRecordHashValidation.expectedHash}.`,
        expected: admissionRecordHashValidation.expectedHash,
        actual: admissionRecordHashValidation.actualHash,
      });
    }
    requiredAdmissionWitnessRecord = witnessRecordByAdmissionHash.get(
      requiredAdmissionRecord.admissionRecordHash,
    );
    if (requiredAdmissionWitnessRecord === undefined) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_latest_record_not_witnessed",
        path: "/requiredAdmissionRecord/admissionRecordHash",
        message:
          "Latest history-root settlement authority-transition admission record has no replayed witness certificate.",
        expected: requiredAdmissionRecord.admissionRecordHash,
      });
    } else if (
      requiredAdmissionWitnessRecord.transitionAdmissionStoreId !==
        requiredAdmissionRecord.transitionAdmissionStoreId ||
      requiredAdmissionWitnessRecord.topologyId !==
        requiredAdmissionRecord.topologyId ||
      requiredAdmissionWitnessRecord.admissionSequence !==
        requiredAdmissionRecord.admissionSequence ||
      requiredAdmissionWitnessRecord.authoritySequence !==
        requiredAdmissionRecord.authoritySequence ||
      requiredAdmissionWitnessRecord.authorityRecordHash !==
        requiredAdmissionRecord.authorityRecordHash ||
      requiredAdmissionWitnessRecord.nextAuthorityTopologyHash !==
        requiredAdmissionRecord.nextAuthorityTopologyHash
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_admission_record_mismatch",
        path: "/requiredAdmissionRecord",
        message:
          "History-root settlement authority-transition admission witness record does not match the required admission store, topology, sequence, authority transition hash, and derived topology hash.",
        expected: requiredAdmissionRecord.admissionRecordHash,
        actual: requiredAdmissionWitnessRecord.admissionRecordHash,
      });
    }
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    transitionAdmissionWitnessStoreId:
      input.transitionAdmissionWitnessStoreId,
    transitionAdmissionStoreId: input.transitionAdmissionStoreId,
    topologyId: input.topologyId,
    authorityScope: input.authorityScope,
    witnessedRecordCount: input.records.length,
    ...(latestWitnessRecord !== undefined ? { latestWitnessRecord } : {}),
    ...(requiredAdmissionRecord !== undefined ? { requiredAdmissionRecord } : {}),
    ...(requiredAdmissionWitnessRecord !== undefined
      ? { requiredAdmissionWitnessRecord }
      : {}),
    ...(witnessAuthorityTopology !== undefined
      ? { witnessAuthorityTopology }
      : {}),
    ...(witnessAuthorityTransitionAdmissionReplay !== undefined
      ? { witnessAuthorityTransitionAdmissionReplay }
      : {}),
    issues,
  };
}

export function replayOperationalStateHistoryRootSettlementAuthorityTransitionAdmissionRecords(
  input: OperationalStateHistoryRootSettlementAuthorityTransitionAdmissionReplayInput,
): OperationalStateHistoryRootSettlementAuthorityTransitionAdmissionReplay {
  const issues: OperationalStateHistoryRootTransparencyIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const admissionHashBySequence = new Map<number, string>();
  const admissionRecordByAuthorityHash = new Map<
    string,
    OperationalStateHistoryRootSettlementAuthorityTransitionAdmissionRecord
  >();
  const admissionWitnessReplay = input.admissionWitnessReplay;
  let expectedAdmissionSequence = 1;
  let expectedAuthoritySequence = 1;
  let previousAdmissionRecordHash: string | undefined;
  let previousAuthorityRecordHash: string | undefined;
  let previousTopology: OperationalStateAuthorityTopology | undefined;
  let latestAdmittedRecord:
    | OperationalStateHistoryRootSettlementAuthorityTransitionAdmissionRecord
    | undefined;
  let latestAdmittedTopology: OperationalStateAuthorityTopology | undefined;

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const recordHashValidation =
      verifyOperationalStateHistoryRootSettlementAuthorityTransitionAdmissionRecordHash(
        record,
      );
    const transitionHashValidation =
      verifyOperationalStateAuthorityTransitionRecordHash(
        record.authorityTransition,
      );
    const certificateHashValidation =
      verifyOperationalStateQuorumCertificateProofCertificateHash(
        record.admissionCertificate,
      );
    const previousAdmissionHashAtSequence = admissionHashBySequence.get(
      record.admissionSequence,
    );

    if (
      previousAdmissionHashAtSequence !== undefined &&
      previousAdmissionHashAtSequence !== record.admissionRecordHash
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_record_sequence_gap",
        path: `${path}/admissionSequence`,
        message: `History-root settlement authority-transition admission sequence ${record.admissionSequence} has more than one record hash.`,
        expected: previousAdmissionHashAtSequence,
        actual: record.admissionRecordHash,
      });
    } else if (previousAdmissionHashAtSequence === undefined) {
      admissionHashBySequence.set(
        record.admissionSequence,
        record.admissionRecordHash,
      );
    }

    if (
      record.tenantId !== expectedTenantId ||
      record.authorityTransition.tenantId !== expectedTenantId ||
      record.admissionCertificate.tenantId !== expectedTenantId
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_record_tenant_mismatch",
        path,
        message:
          "History-root settlement authority-transition admission record, transition, and certificate must match the replay tenant.",
        expected: expectedTenantId,
      });
    }
    if (record.transitionAdmissionStoreId !== input.transitionAdmissionStoreId) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_record_store_mismatch",
        path: `${path}/transitionAdmissionStoreId`,
        message:
          "History-root settlement authority-transition admission record belongs to a different admission store.",
        expected: input.transitionAdmissionStoreId,
        actual: record.transitionAdmissionStoreId,
      });
    }
    if (
      record.topologyId !== input.topologyId ||
      record.authorityTransition.topologyId !== input.topologyId
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_record_scope_mismatch",
        path: `${path}/topologyId`,
        message:
          "History-root settlement authority-transition admission record must match the replay topology id.",
        expected: input.topologyId,
        actual: record.topologyId,
      });
    }
    if (
      record.authorityScope !== input.authorityScope ||
      record.authorityTransition.authorityScope !== input.authorityScope ||
      record.admissionCertificate.authorityScope !== input.authorityScope
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_record_scope_mismatch",
        path,
        message:
          "History-root settlement authority-transition admission record, transition, and certificate must share the replay authority scope.",
        expected: input.authorityScope,
      });
    }
    if (record.admissionSequence !== expectedAdmissionSequence) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_record_sequence_gap",
        path: `${path}/admissionSequence`,
        message:
          "History-root settlement authority-transition admissions must replay as a contiguous admission sequence.",
        expected: expectedAdmissionSequence,
        actual: record.admissionSequence,
      });
    }
    if (record.previousAdmissionRecordHash !== previousAdmissionRecordHash) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_record_previous_hash_mismatch",
        path: `${path}/previousAdmissionRecordHash`,
        message:
          "History-root settlement authority-transition admission record does not chain to the previous admission record hash.",
        expected: previousAdmissionRecordHash ?? "none",
        actual: record.previousAdmissionRecordHash ?? "none",
      });
    }
    if (!recordHashValidation.valid) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_record_hash_mismatch",
        path: `${path}/admissionRecordHash`,
        message: `History-root settlement authority-transition admission record hash ${recordHashValidation.actualHash} does not match recomputed hash ${recordHashValidation.expectedHash}.`,
        expected: recordHashValidation.expectedHash,
        actual: recordHashValidation.actualHash,
      });
    }
    if (!transitionHashValidation.valid) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_transition_hash_mismatch",
        path: `${path}/authorityTransition/authorityRecordHash`,
        message: `History-root settlement authority transition hash ${transitionHashValidation.actualHash} does not match recomputed hash ${transitionHashValidation.expectedHash}.`,
        expected: transitionHashValidation.expectedHash,
        actual: transitionHashValidation.actualHash,
      });
    }
    if (
      record.authoritySequence !==
        record.authorityTransition.authoritySequence ||
      record.authorityRecordHash !==
        record.authorityTransition.authorityRecordHash ||
      record.previousAuthorityRecordHash !==
        record.authorityTransition.previousAuthorityRecordHash
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_transition_mismatch",
        path: `${path}/authorityTransition`,
        message:
          "History-root settlement authority-transition admission record does not match its embedded authority transition sequence and hash.",
        expected: record.authorityRecordHash,
        actual: record.authorityTransition.authorityRecordHash,
      });
    }
    if (record.authoritySequence !== expectedAuthoritySequence) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_transition_sequence_gap",
        path: `${path}/authoritySequence`,
        message:
          "History-root settlement authority transitions must be admitted in contiguous authority sequence.",
        expected: expectedAuthoritySequence,
        actual: record.authoritySequence,
      });
    }
    if (
      record.authorityTransition.previousAuthorityRecordHash !==
      previousAuthorityRecordHash
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_transition_previous_hash_mismatch",
        path: `${path}/authorityTransition/previousAuthorityRecordHash`,
        message:
          "History-root settlement authority transition must hash-chain from the previously admitted authority transition.",
        expected: previousAuthorityRecordHash ?? "none",
        actual:
          record.authorityTransition.previousAuthorityRecordHash ?? "none",
      });
    }
    if (record.authorityTransition.effectiveFromSubjectSequence < 1) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_transition_invalid",
        path: `${path}/authorityTransition/effectiveFromSubjectSequence`,
        message:
          "History-root settlement authority transitions must declare a positive effective settlement sequence.",
        actual: record.authorityTransition.effectiveFromSubjectSequence,
      });
    }
    if (
      record.authorityTransition.transitionKind === "set_quorum" &&
      ((record.authorityTransition.requiredWitnesses ?? 0) < 1 ||
        (record.authorityTransition.minimumWitnesses ??
          record.authorityTransition.requiredWitnesses ??
          0) < 1 ||
        (record.authorityTransition.minimumWitnesses ??
          record.authorityTransition.requiredWitnesses ??
          0) > (record.authorityTransition.requiredWitnesses ?? 0))
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_transition_invalid",
        path: `${path}/authorityTransition/requiredWitnesses`,
        message:
          "History-root settlement authority quorum transitions must declare positive and internally consistent witness thresholds.",
      });
    }
    if (
      [
        "admit_principal",
        "suspend_principal",
        "revoke_principal",
        "rotate_signature_key",
        "mark_equivocated",
      ].includes(record.authorityTransition.transitionKind) &&
      (record.authorityTransition.principalId === undefined ||
        record.authorityTransition.principalId.length === 0)
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_transition_invalid",
        path: `${path}/authorityTransition/principalId`,
        message:
          "History-root settlement authority principal transitions must identify the affected principal.",
      });
    }
    if (
      record.authorityTransition.transitionKind === "seal_authority_epoch" &&
      ((record.authorityTransition.sealedThroughSubjectSequence ?? 0) < 1 ||
        record.authorityTransition.sealedQuorumCertificateHash === undefined ||
        record.authorityTransition.sealedQuorumCertificateHash.length === 0)
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_transition_invalid",
        path: `${path}/authorityTransition/sealedQuorumCertificateHash`,
        message:
          "History-root settlement authority epoch seals must bind a positive sealed frontier and a quorum certificate hash.",
      });
    }

    const nextTopology = operationalStateAuthorityTopologyFromTransition(
      record.authorityTransition,
      previousTopology,
    );
    if (record.nextAuthorityTopologyHash !== nextTopology.topologyHash) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_transition_topology_hash_mismatch",
        path: `${path}/nextAuthorityTopologyHash`,
        message:
          "History-root settlement authority-transition admission record does not derive the expected next topology hash.",
        expected: nextTopology.topologyHash,
        actual: record.nextAuthorityTopologyHash,
      });
    }
    if (previousTopology === undefined) {
      if (record.previousAuthorityTopologyHash !== undefined) {
        issues.push({
          code: "operational_state_transparency_root_settlement_authority_transition_admission_transition_previous_topology_hash_mismatch",
          path: `${path}/previousAuthorityTopologyHash`,
          message:
            "Genesis history-root settlement authority transition cannot cite a previous topology hash.",
          actual: record.previousAuthorityTopologyHash,
        });
      }
    } else {
      if (
        record.previousAuthorityTopologyHash !== previousTopology.topologyHash
      ) {
        issues.push({
          code: "operational_state_transparency_root_settlement_authority_transition_admission_transition_previous_topology_hash_mismatch",
          path: `${path}/previousAuthorityTopologyHash`,
          message:
            "History-root settlement authority transition admission must bind the previous replayed topology hash.",
          expected: previousTopology.topologyHash,
          actual: record.previousAuthorityTopologyHash ?? "none",
        });
      }
      if (
        record.admissionCertificate.authorityTopologyHash !==
        previousTopology.topologyHash
      ) {
        issues.push({
          code: "operational_state_transparency_root_settlement_authority_transition_admission_certificate_authority_topology_mismatch",
          path: `${path}/admissionCertificate/authorityTopologyHash`,
          message:
            "History-root settlement authority transition admission certificate must be bound to the previous replayed topology.",
          expected: previousTopology.topologyHash,
          actual:
            record.admissionCertificate.authorityTopologyHash ?? "none",
        });
      }

      const principalById = new Map<
        string,
        OperationalStateAuthorityPrincipalState
      >(
        previousTopology.principals.map((principal) => [
          principal.principalId,
          principal,
        ]),
      );
      const acceptedWitnessIds =
        record.admissionCertificate.acceptedWitnessIds;
      const uniqueAcceptedWitnessIds = new Set(acceptedWitnessIds);
      if (uniqueAcceptedWitnessIds.size !== acceptedWitnessIds.length) {
        issues.push({
          code: "operational_state_transparency_root_settlement_authority_transition_admission_authority_duplicate_witness",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "History-root settlement authority-transition admission cannot be certified by duplicate prior-topology witnesses.",
          expected: uniqueAcceptedWitnessIds.size,
          actual: acceptedWitnessIds.length,
        });
      }

      let activeAuthorizedWitnessCount = 0;
      for (const witnessId of uniqueAcceptedWitnessIds) {
        const principal = principalById.get(witnessId);
        if (principal === undefined) {
          issues.push({
            code: "operational_state_transparency_root_settlement_authority_transition_admission_authority_witness_unknown",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "History-root settlement authority-transition admission certificate names a witness outside the previous replayed topology.",
            expected: previousTopology.topologyHash,
            actual: witnessId,
          });
          continue;
        }
        if (principal.status !== "active") {
          issues.push({
            code: "operational_state_transparency_root_settlement_authority_transition_admission_authority_witness_not_active",
            path: `${path}/admissionCertificate/acceptedWitnessIds`,
            message:
              "History-root settlement authority-transition admission certificate names a witness that is not active in the previous replayed topology.",
            expected: "active",
            actual: `${witnessId}:${principal.status}`,
          });
          continue;
        }
        activeAuthorizedWitnessCount += 1;
      }

      const requiredAuthorizedWitnesses = Math.max(
        previousTopology.requiredWitnesses ?? 0,
        previousTopology.minimumWitnesses ?? 0,
      );
      if (activeAuthorizedWitnessCount < requiredAuthorizedWitnesses) {
        issues.push({
          code: "operational_state_transparency_root_settlement_authority_transition_admission_authority_quorum_not_met",
          path: `${path}/admissionCertificate/acceptedWitnessIds`,
          message:
            "History-root settlement authority-transition admission certificate does not satisfy previous-topology quorum.",
          expected: requiredAuthorizedWitnesses,
          actual: activeAuthorizedWitnessCount,
        });
      }
    }

    if (!certificateHashValidation.valid) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_certificate_hash_mismatch",
        path: `${path}/admissionCertificate/quorumCertificateHash`,
        message: `History-root settlement authority-transition admission certificate hash ${certificateHashValidation.actualHash} does not match recomputed hash ${certificateHashValidation.expectedHash}.`,
        expected: certificateHashValidation.expectedHash,
        actual: certificateHashValidation.actualHash,
      });
    }
    if (
      !record.admissionCertificate.certified ||
      record.admissionCertificate.status !== "certified"
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_certificate_not_certified",
        path: `${path}/admissionCertificate/status`,
        message:
          "History-root settlement authority transition cannot become authority through a non-certified admission certificate.",
        expected: "certified",
        actual: record.admissionCertificate.status,
      });
    }
    if (
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.minimumWitnesses ||
      record.admissionCertificate.acceptedWitnessIds.length <
        record.admissionCertificate.requiredWitnesses
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_certificate_quorum_not_met",
        path: `${path}/admissionCertificate/acceptedWitnessIds`,
        message:
          "History-root settlement authority-transition admission certificate does not satisfy its declared witness quorum.",
        expected: Math.max(
          record.admissionCertificate.requiredWitnesses,
          record.admissionCertificate.minimumWitnesses,
        ),
        actual: record.admissionCertificate.acceptedWitnessIds.length,
      });
    }
    if (
      record.admissionCertificate.subjectKind !==
        OPERATIONAL_STATE_AUTHORITY_TRANSITION_RECORD_SUBJECT_KIND ||
      record.admissionCertificate.subjectId !== record.topologyId ||
      record.admissionCertificate.subjectSequence !==
        record.authoritySequence ||
      record.admissionCertificate.subjectHash !== record.authorityRecordHash
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_certificate_subject_mismatch",
        path: `${path}/admissionCertificate`,
        message:
          "History-root settlement authority-transition admission certificate must certify the exact topology id, authority sequence, and authority transition hash.",
        expected: record.authorityRecordHash,
        actual: record.admissionCertificate.subjectHash,
      });
    }
    if (
      input.requiredAuthorityBoundary !== undefined &&
      record.admissionCertificate.authorityBoundary !==
        input.requiredAuthorityBoundary
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_certificate_authority_boundary_mismatch",
        path: `${path}/admissionCertificate/authorityBoundary`,
        message:
          "History-root settlement authority-transition admission certificate was admitted under the wrong authority boundary.",
        expected: input.requiredAuthorityBoundary,
        actual: record.admissionCertificate.authorityBoundary,
      });
    }

    admissionRecordByAuthorityHash.set(record.authorityRecordHash, record);
    expectedAdmissionSequence = record.admissionSequence + 1;
    expectedAuthoritySequence = record.authoritySequence + 1;
    previousAdmissionRecordHash = record.admissionRecordHash;
    previousAuthorityRecordHash = record.authorityRecordHash;
    previousTopology = nextTopology;
    latestAdmittedTopology = nextTopology;
    latestAdmittedRecord = record;
  });

  let requiredAuthorityTransitionAdmissionRecord:
    | OperationalStateHistoryRootSettlementAuthorityTransitionAdmissionRecord
    | undefined;
  if (input.requiredAuthorityTransition !== undefined) {
    const requiredTransitionHashValidation =
      verifyOperationalStateAuthorityTransitionRecordHash(
        input.requiredAuthorityTransition,
      );
    if (!requiredTransitionHashValidation.valid) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_transition_hash_mismatch",
        path: "/requiredAuthorityTransition/authorityRecordHash",
        message: `Required history-root settlement authority transition hash ${requiredTransitionHashValidation.actualHash} does not match recomputed hash ${requiredTransitionHashValidation.expectedHash}.`,
        expected: requiredTransitionHashValidation.expectedHash,
        actual: requiredTransitionHashValidation.actualHash,
      });
    }
    requiredAuthorityTransitionAdmissionRecord =
      admissionRecordByAuthorityHash.get(
        input.requiredAuthorityTransition.authorityRecordHash,
      );
    if (requiredAuthorityTransitionAdmissionRecord === undefined) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_not_admitted",
        path: "/requiredAuthorityTransition/authorityRecordHash",
        message:
          "Required history-root settlement authority transition has no replayed admission certificate.",
        expected: input.requiredAuthorityTransition.authorityRecordHash,
      });
    }
  }

  if (input.requiredAuthorityTopology !== undefined) {
    const requiredTopologyHashValidation =
      verifyOperationalStateAuthorityTopologyHash(
        input.requiredAuthorityTopology,
      );
    if (!requiredTopologyHashValidation.valid) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_topology_hash_mismatch",
        path: "/requiredAuthorityTopology/topologyHash",
        message: `Required history-root settlement authority topology hash ${requiredTopologyHashValidation.actualHash} does not match recomputed hash ${requiredTopologyHashValidation.expectedHash}.`,
        expected: requiredTopologyHashValidation.expectedHash,
        actual: requiredTopologyHashValidation.actualHash,
      });
    }
    if (
      latestAdmittedTopology === undefined ||
      !operationalStateAuthorityTopologiesMatch(
        latestAdmittedTopology,
        input.requiredAuthorityTopology,
      )
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_topology_mismatch",
        path: "/requiredAuthorityTopology",
        message:
          "History-root settlement authority-transition admission replay must recover the required authority topology.",
        expected: input.requiredAuthorityTopology.topologyHash,
        actual: latestAdmittedTopology?.topologyHash ?? "none",
      });
    }
    requiredAuthorityTransitionAdmissionRecord =
      admissionRecordByAuthorityHash.get(
        input.requiredAuthorityTopology.authorityRecordHash,
      );
    if (requiredAuthorityTransitionAdmissionRecord === undefined) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_not_admitted",
        path: "/requiredAuthorityTopology/authorityRecordHash",
        message:
          "Required history-root settlement authority topology is not backed by an admitted authority transition.",
        expected: input.requiredAuthorityTopology.authorityRecordHash,
      });
    }
  }

  if (
    input.requireAdmissionWitness === true ||
    input.requireAdmissionWitnessAuthorityTopology === true
  ) {
    if (admissionWitnessReplay === undefined) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_replay_missing",
        path: "/admissionWitnessReplay",
        message:
          "History-root settlement authority-transition admission replay requires witnessed transition-admission records.",
      });
    } else if (!admissionWitnessReplay.valid) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_replay_invalid",
        path: "/admissionWitnessReplay",
        message:
          "History-root settlement authority-transition admission replay cannot consume invalid transition-admission witness history.",
        actual: admissionWitnessReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      latestAdmittedRecord === undefined ||
      admissionWitnessReplay.requiredAdmissionWitnessRecord === undefined ||
      admissionWitnessReplay.requiredAdmissionWitnessRecord
        .admissionRecordHash !== latestAdmittedRecord.admissionRecordHash
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_latest_record_not_witnessed",
        path: "/admissionWitnessReplay",
        message:
          "Latest history-root settlement authority-transition admission record is not witnessed by the replayed transition-admission witness ledger.",
        expected: latestAdmittedRecord?.admissionRecordHash ?? "none",
        actual:
          admissionWitnessReplay.requiredAdmissionWitnessRecord
            ?.admissionRecordHash ?? "none",
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTopology === true &&
      admissionWitnessReplay.witnessAuthorityTopology === undefined
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_authority_topology_missing",
        path: "/admissionWitnessReplay/witnessAuthorityTopology",
        message:
          "History-root settlement authority-transition admission replay requires its witness history to bind certificates to replayed witness authority topology.",
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmission === true &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay ===
        undefined
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        path: "/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "History-root settlement authority-transition admission replay requires its nested transition-admission witness authority topology to replay from admitted authority-transition history.",
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmission === true &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      !admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.valid
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        path: "/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "History-root settlement authority-transition admission replay cannot consume invalid nested transition-admission witness authority history.",
        actual:
          admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.issues
            .map((issue) => issue.code)
            .join(","),
      });
    } else if (
      input.requireAdmissionWitnessAuthorityTransitionAdmission === true &&
      admissionWitnessReplay.witnessAuthorityTopology !== undefined &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      (admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .latestAdmittedTopology === undefined ||
        !operationalStateAuthorityTopologiesMatch(
          admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology,
          admissionWitnessReplay.witnessAuthorityTopology,
        ))
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "History-root settlement authority-transition admission replay requires the nested transition-admission witness authority topology to be recovered from admitted authority-transition history.",
        expected: admissionWitnessReplay.witnessAuthorityTopology.topologyHash,
        actual:
          admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology?.topologyHash ?? "none",
      });
    }
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    transitionAdmissionStoreId: input.transitionAdmissionStoreId,
    topologyId: input.topologyId,
    authorityScope: input.authorityScope,
    admittedRecordCount: input.records.length,
    ...(latestAdmittedRecord !== undefined ? { latestAdmittedRecord } : {}),
    ...(latestAdmittedTopology !== undefined ? { latestAdmittedTopology } : {}),
    ...(input.requiredAuthorityTopology !== undefined
      ? { requiredAuthorityTopology: input.requiredAuthorityTopology }
      : {}),
    ...(input.requiredAuthorityTransition !== undefined
      ? { requiredAuthorityTransition: input.requiredAuthorityTransition }
      : {}),
    ...(requiredAuthorityTransitionAdmissionRecord !== undefined
      ? { requiredAuthorityTransitionAdmissionRecord }
      : {}),
    ...(admissionWitnessReplay !== undefined ? { admissionWitnessReplay } : {}),
    issues,
  };
}

export function buildOperationalStateHistoryRootSettlementRecord(
  input: OperationalStateHistoryRootSettlementRecordInput,
): OperationalStateHistoryRootSettlementRecord {
  const payload: Omit<
    OperationalStateHistoryRootSettlementRecord,
    "settlementRecordHash"
  > = {
    schemaVersion: OPERATIONAL_STATE_HISTORY_ROOT_SETTLEMENT_SCHEMA_VERSION,
    tenantId: tenantId(String(input.tenantId)),
    rootSettlementStoreId: input.rootSettlementStoreId,
    authorityScope: input.authorityScope,
    settlementSequence: input.settlementSequence,
    storeId: input.root.storeId,
    storeKind: input.root.storeKind,
    rootSequence: input.root.sequence,
    rootHash: input.root.rootHash,
    rootCommitmentHash: input.root.rootCommitmentHash,
    root: input.root,
    settlementCertificate: input.settlementCertificate,
    ...(input.previousSettlementRecordHash !== undefined
      ? { previousSettlementRecordHash: input.previousSettlementRecordHash }
      : {}),
    settledAt: input.settledAt,
    settledBy: input.settledBy,
    ...(input.settlementReason !== undefined
      ? { settlementReason: input.settlementReason }
      : {}),
  };
  return {
    ...payload,
    settlementRecordHash:
      computeOperationalStateHistoryRootSettlementRecordHash(payload),
  };
}

export function computeOperationalStateHistoryRootSettlementRecordHash(
  record: Omit<
    OperationalStateHistoryRootSettlementRecord,
    "settlementRecordHash"
  >,
): string {
  return fingerprint64(canonicalStringify(record));
}

export function verifyOperationalStateHistoryRootSettlementRecordHash(
  record: OperationalStateHistoryRootSettlementRecord,
): StateReviewArtifactHashValidation {
  const { settlementRecordHash, ...payload } = record;
  const expectedHash =
    computeOperationalStateHistoryRootSettlementRecordHash(payload);
  return {
    valid: settlementRecordHash === expectedHash,
    expectedHash,
    actualHash: settlementRecordHash,
  };
}

export function replayOperationalStateHistoryRootSettlementRecords(
  input: OperationalStateHistoryRootSettlementReplayInput,
): OperationalStateHistoryRootSettlementReplay {
  const issues: OperationalStateHistoryRootTransparencyIssue[] = [];
  const expectedTenantId = tenantId(String(input.tenantId));
  const recordHashBySequence = new Map<number, string>();
  const rootCommitmentBySequenceKey = new Map<string, string>();
  const settlementRecordByRootKey = new Map<
    string,
    OperationalStateHistoryRootSettlementRecord
  >();
  const settlementAuthorityTopology = input.settlementAuthorityTopology;
  const settlementAuthorityTransitionAdmissionReplay =
    input.settlementAuthorityTransitionAdmissionReplay;
  const principalById = new Map<string, OperationalStateAuthorityPrincipalState>(
    settlementAuthorityTopology?.principals.map((principal) => [
      principal.principalId,
      principal,
    ]) ?? [],
  );
  const settledRoots: OperationalStateHistoryRoot[] = [];
  let expectedSequence = 1;
  let previousSettlementRecordHash: string | undefined;
  let latestSettlementRecord:
    | OperationalStateHistoryRootSettlementRecord
    | undefined;

  if (
    (input.requireSettlementAuthorityTopology === true ||
      input.requireSettlementAuthorityTransitionAdmission === true ||
      input.requireSettlementAuthorityTransitionAdmissionWitness === true ||
      input.requireSettlementAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input.requireSettlementAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    settlementAuthorityTopology === undefined
  ) {
    issues.push({
      code: "operational_state_transparency_root_settlement_authority_topology_missing",
      path: "/settlementAuthorityTopology",
      message:
        "History-root settlement replay requires a replayed settlement authority topology.",
    });
  }

  if (settlementAuthorityTopology !== undefined) {
    const topologyHashValidation =
      verifyOperationalStateAuthorityTopologyHash(settlementAuthorityTopology);
    if (!topologyHashValidation.valid) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_topology_hash_mismatch",
        path: "/settlementAuthorityTopology/topologyHash",
        message: `History-root settlement authority topology hash ${topologyHashValidation.actualHash} does not match recomputed hash ${topologyHashValidation.expectedHash}.`,
        expected: topologyHashValidation.expectedHash,
        actual: topologyHashValidation.actualHash,
      });
    }
    if (settlementAuthorityTopology.tenantId !== expectedTenantId) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_topology_tenant_mismatch",
        path: "/settlementAuthorityTopology/tenantId",
        message:
          "History-root settlement authority topology tenant does not match replay tenant.",
        expected: expectedTenantId,
        actual: settlementAuthorityTopology.tenantId,
      });
    }
    if (settlementAuthorityTopology.authorityScope !== input.authorityScope) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_topology_scope_mismatch",
        path: "/settlementAuthorityTopology/authorityScope",
        message:
          "History-root settlement authority topology scope does not match replay scope.",
        expected: input.authorityScope,
        actual: settlementAuthorityTopology.authorityScope,
      });
    }
    if (
      settlementAuthorityTopology.requiredWitnesses === undefined ||
      settlementAuthorityTopology.minimumWitnesses === undefined
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_quorum_missing",
        path: "/settlementAuthorityTopology/requiredWitnesses",
        message:
          "History-root settlement authority topology must define quorum thresholds.",
      });
    }
  }

  if (
    input.requireSettlementAuthorityTransitionAdmission === true ||
    input.requireSettlementAuthorityTransitionAdmissionWitness === true ||
    input.requireSettlementAuthorityTransitionAdmissionWitnessAuthorityTopology ===
      true ||
    input.requireSettlementAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
      true
  ) {
    if (settlementAuthorityTransitionAdmissionReplay === undefined) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_replay_missing",
        path: "/settlementAuthorityTransitionAdmissionReplay",
        message:
          "History-root settlement replay requires admitted settlement-authority transition history.",
      });
    } else if (!settlementAuthorityTransitionAdmissionReplay.valid) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_replay_invalid",
        path: "/settlementAuthorityTransitionAdmissionReplay",
        message:
          "History-root settlement replay cannot consume invalid settlement-authority transition admission history.",
        actual: settlementAuthorityTransitionAdmissionReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      settlementAuthorityTopology !== undefined &&
      (settlementAuthorityTransitionAdmissionReplay.latestAdmittedTopology ===
        undefined ||
        !operationalStateAuthorityTopologiesMatch(
          settlementAuthorityTransitionAdmissionReplay.latestAdmittedTopology,
          settlementAuthorityTopology,
        ))
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_topology_mismatch",
        path: "/settlementAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "History-root settlement authority topology must be recovered from admitted authority-transition history.",
        expected: settlementAuthorityTopology.topologyHash,
        actual:
          settlementAuthorityTransitionAdmissionReplay.latestAdmittedTopology
            ?.topologyHash ?? "none",
      });
    }
  }
  if (
    (input.requireSettlementAuthorityTransitionAdmissionWitness === true ||
      input.requireSettlementAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input.requireSettlementAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    settlementAuthorityTransitionAdmissionReplay !== undefined
  ) {
    if (
      settlementAuthorityTransitionAdmissionReplay.admissionWitnessReplay ===
      undefined
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_replay_missing",
        path: "/settlementAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
        message:
          "History-root settlement replay requires settlement authority-transition admission records to be witnessed.",
      });
    } else if (
      !settlementAuthorityTransitionAdmissionReplay.admissionWitnessReplay.valid
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_replay_invalid",
        path: "/settlementAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
        message:
          "History-root settlement replay cannot consume invalid settlement authority-transition admission witness history.",
        actual:
          settlementAuthorityTransitionAdmissionReplay.admissionWitnessReplay.issues
            .map((issue) => issue.code)
            .join(","),
      });
    } else if (
      (input.requireSettlementAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
        input.requireSettlementAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
          true) &&
      settlementAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTopology === undefined
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_authority_topology_missing",
        path: "/settlementAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTopology",
        message:
          "History-root settlement replay requires settlement authority-transition admission witness certificates to bind to replayed witness authority topology.",
      });
    } else if (
      input.requireSettlementAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      settlementAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTransitionAdmissionReplay === undefined
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        path: "/settlementAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "History-root settlement replay requires settlement authority-transition admission witness authority topology to replay from admitted authority-transition history.",
      });
    } else if (
      input.requireSettlementAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      settlementAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTransitionAdmissionReplay !== undefined &&
      !settlementAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTransitionAdmissionReplay.valid
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        path: "/settlementAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "History-root settlement replay cannot consume invalid nested settlement authority-transition admission witness authority history.",
        actual:
          settlementAuthorityTransitionAdmissionReplay.admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.issues
            .map((issue) => issue.code)
            .join(","),
      });
    } else if (
      input.requireSettlementAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      settlementAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTopology !== undefined &&
      settlementAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTransitionAdmissionReplay !== undefined &&
      (settlementAuthorityTransitionAdmissionReplay.admissionWitnessReplay
        .witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology ===
        undefined ||
        !operationalStateAuthorityTopologiesMatch(
          settlementAuthorityTransitionAdmissionReplay.admissionWitnessReplay
            .witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology,
          settlementAuthorityTransitionAdmissionReplay.admissionWitnessReplay
            .witnessAuthorityTopology,
        ))
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/settlementAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "History-root settlement replay requires settlement authority-transition admission witness authority topology to be recovered from admitted authority-transition history.",
        expected:
          settlementAuthorityTransitionAdmissionReplay.admissionWitnessReplay
            .witnessAuthorityTopology.topologyHash,
        actual:
          settlementAuthorityTransitionAdmissionReplay.admissionWitnessReplay
            .witnessAuthorityTransitionAdmissionReplay.latestAdmittedTopology
            ?.topologyHash ?? "none",
      });
    }
  }

  input.records.forEach((record, index) => {
    const path = `/records/${index}`;
    const settlementRecordHashValidation =
      verifyOperationalStateHistoryRootSettlementRecordHash(record);
    const rootHashValidation = verifyOperationalStateHistoryRootCommitmentHash(
      record.root,
    );
    const certificateHashValidation =
      verifyOperationalStateQuorumCertificateProofCertificateHash(
        record.settlementCertificate,
      );
    const previousRecordHashAtSequence = recordHashBySequence.get(
      record.settlementSequence,
    );
    const sequenceKey = operationalStateHistoryRootSequenceKey(record.root);
    const previousRootCommitmentAtSequence =
      rootCommitmentBySequenceKey.get(sequenceKey);

    if (
      previousRecordHashAtSequence !== undefined &&
      previousRecordHashAtSequence !== record.settlementRecordHash
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_record_fork",
        path: `${path}/settlementSequence`,
        message: `History-root settlement sequence ${record.settlementSequence} has more than one record hash.`,
        expected: previousRecordHashAtSequence,
        actual: record.settlementRecordHash,
      });
    } else if (previousRecordHashAtSequence === undefined) {
      recordHashBySequence.set(
        record.settlementSequence,
        record.settlementRecordHash,
      );
    }

    if (
      previousRootCommitmentAtSequence !== undefined &&
      previousRootCommitmentAtSequence !== record.rootCommitmentHash
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_record_fork",
        path: `${path}/rootCommitmentHash`,
        message:
          "History-root settlement cannot settle two different root commitments for the same store sequence.",
        expected: previousRootCommitmentAtSequence,
        actual: record.rootCommitmentHash,
      });
    } else if (previousRootCommitmentAtSequence === undefined) {
      rootCommitmentBySequenceKey.set(sequenceKey, record.rootCommitmentHash);
    }

    if (
      record.tenantId !== expectedTenantId ||
      record.root.tenantId !== expectedTenantId ||
      record.settlementCertificate.tenantId !== expectedTenantId
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_record_tenant_mismatch",
        path,
        message:
          "History-root settlement record, embedded root, and certificate must match the replay tenant.",
        expected: expectedTenantId,
      });
    }
    if (record.rootSettlementStoreId !== input.rootSettlementStoreId) {
      issues.push({
        code: "operational_state_transparency_root_settlement_record_store_mismatch",
        path: `${path}/rootSettlementStoreId`,
        message:
          "History-root settlement record belongs to a different settlement store.",
        expected: input.rootSettlementStoreId,
        actual: record.rootSettlementStoreId,
      });
    }
    if (
      record.authorityScope !== input.authorityScope ||
      record.root.authorityScope !== input.authorityScope ||
      record.settlementCertificate.authorityScope !== input.authorityScope
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_record_scope_mismatch",
        path,
        message:
          "History-root settlement record, root, and certificate must share the replay authority scope.",
        expected: input.authorityScope,
      });
    }
    if (record.settlementSequence !== expectedSequence) {
      issues.push({
        code: "operational_state_transparency_root_settlement_record_sequence_gap",
        path: `${path}/settlementSequence`,
        message:
          "History-root settlement records must replay as a contiguous settlement sequence.",
        expected: expectedSequence,
        actual: record.settlementSequence,
      });
    }
    if (record.previousSettlementRecordHash !== previousSettlementRecordHash) {
      issues.push({
        code: "operational_state_transparency_root_settlement_record_previous_hash_mismatch",
        path: `${path}/previousSettlementRecordHash`,
        message:
          "History-root settlement record does not chain to the previous settlement record hash.",
        expected: previousSettlementRecordHash ?? "none",
        actual: record.previousSettlementRecordHash ?? "none",
      });
    }
    if (
      !rootHashValidation.valid ||
      record.storeId !== record.root.storeId ||
      record.storeKind !== record.root.storeKind ||
      record.rootSequence !== record.root.sequence ||
      record.rootHash !== record.root.rootHash ||
      record.rootCommitmentHash !== record.root.rootCommitmentHash
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_record_root_hash_mismatch",
        path: `${path}/root`,
        message:
          "History-root settlement must hash-bind the exact embedded root commitment.",
        expected: rootHashValidation.expectedHash,
        actual: record.rootCommitmentHash,
      });
    }
    if (!certificateHashValidation.valid) {
      issues.push({
        code: "operational_state_transparency_root_settlement_certificate_hash_mismatch",
        path: `${path}/settlementCertificate/quorumCertificateHash`,
        message: `History-root settlement certificate hash ${certificateHashValidation.actualHash} does not match recomputed hash ${certificateHashValidation.expectedHash}.`,
        expected: certificateHashValidation.expectedHash,
        actual: certificateHashValidation.actualHash,
      });
    }
    if (
      !record.settlementCertificate.certified ||
      record.settlementCertificate.status !== "certified"
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_certificate_not_certified",
        path: `${path}/settlementCertificate/status`,
        message:
          "History-root settlement cannot be established by a non-certified settlement certificate.",
        expected: "certified",
        actual: record.settlementCertificate.status,
      });
    }
    if (
      record.settlementCertificate.acceptedWitnessIds.length <
        record.settlementCertificate.minimumWitnesses ||
      record.settlementCertificate.acceptedWitnessIds.length <
        record.settlementCertificate.requiredWitnesses
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_certificate_quorum_not_met",
        path: `${path}/settlementCertificate/acceptedWitnessIds`,
        message:
          "History-root settlement certificate does not satisfy its witness quorum.",
        expected: Math.max(
          record.settlementCertificate.requiredWitnesses,
          record.settlementCertificate.minimumWitnesses,
        ),
        actual: record.settlementCertificate.acceptedWitnessIds.length,
      });
    }
    if (
      record.settlementCertificate.subjectKind !==
        OPERATIONAL_STATE_HISTORY_ROOT_SETTLEMENT_SUBJECT_KIND ||
      record.settlementCertificate.subjectId !== record.storeId ||
      record.settlementCertificate.subjectSequence !== record.rootSequence ||
      record.settlementCertificate.subjectHash !== record.rootCommitmentHash
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_certificate_subject_mismatch",
        path: `${path}/settlementCertificate`,
        message:
          "History-root settlement certificate must certify the exact store id, root sequence, and root commitment hash.",
        expected: record.rootCommitmentHash,
        actual: record.settlementCertificate.subjectHash,
      });
    }
    if (
      input.requiredAuthorityBoundary !== undefined &&
      record.settlementCertificate.authorityBoundary !==
        input.requiredAuthorityBoundary
    ) {
      issues.push({
        code: "operational_state_transparency_root_settlement_certificate_authority_boundary_mismatch",
        path: `${path}/settlementCertificate/authorityBoundary`,
        message:
          "History-root settlement certificate was admitted under the wrong authority boundary.",
        expected: input.requiredAuthorityBoundary,
        actual: record.settlementCertificate.authorityBoundary,
      });
    }
    if (settlementAuthorityTopology !== undefined) {
      if (
        record.settlementCertificate.authorityTopologyHash !==
        settlementAuthorityTopology.topologyHash
      ) {
        issues.push({
          code: "operational_state_transparency_root_settlement_certificate_authority_topology_mismatch",
          path: `${path}/settlementCertificate/authorityTopologyHash`,
          message:
            "History-root settlement certificate is not bound to the replayed settlement authority topology.",
          expected: settlementAuthorityTopology.topologyHash,
          actual:
            record.settlementCertificate.authorityTopologyHash ?? "none",
        });
      }

      const acceptedWitnessIds =
        record.settlementCertificate.acceptedWitnessIds;
      const uniqueAcceptedWitnessIds = new Set(acceptedWitnessIds);
      if (uniqueAcceptedWitnessIds.size !== acceptedWitnessIds.length) {
        issues.push({
          code: "operational_state_transparency_root_settlement_authority_duplicate_witness",
          path: `${path}/settlementCertificate/acceptedWitnessIds`,
          message:
            "History-root settlement authority quorum cannot be satisfied by duplicate witness ids.",
          expected: uniqueAcceptedWitnessIds.size,
          actual: acceptedWitnessIds.length,
        });
      }

      let activeAuthorizedWitnessCount = 0;
      for (const witnessId of uniqueAcceptedWitnessIds) {
        const principal = principalById.get(witnessId);
        if (principal === undefined) {
          issues.push({
            code: "operational_state_transparency_root_settlement_authority_witness_unknown",
            path: `${path}/settlementCertificate/acceptedWitnessIds`,
            message:
              "History-root settlement certificate names a witness that is not present in the replayed authority topology.",
            expected: settlementAuthorityTopology.topologyHash,
            actual: witnessId,
          });
          continue;
        }
        if (principal.status !== "active") {
          issues.push({
            code: "operational_state_transparency_root_settlement_authority_witness_not_active",
            path: `${path}/settlementCertificate/acceptedWitnessIds`,
            message:
              "History-root settlement certificate names a witness that is not active in the replayed authority topology.",
            expected: "active",
            actual: `${witnessId}:${principal.status}`,
          });
          continue;
        }
        activeAuthorizedWitnessCount += 1;
      }

      const requiredAuthorizedWitnesses = Math.max(
        settlementAuthorityTopology.requiredWitnesses ?? 0,
        settlementAuthorityTopology.minimumWitnesses ?? 0,
      );
      if (activeAuthorizedWitnessCount < requiredAuthorizedWitnesses) {
        issues.push({
          code: "operational_state_transparency_root_settlement_authority_quorum_not_met",
          path: `${path}/settlementCertificate/acceptedWitnessIds`,
          message:
            "History-root settlement certificate does not satisfy the replayed settlement authority topology quorum.",
          expected: requiredAuthorizedWitnesses,
          actual: activeAuthorizedWitnessCount,
        });
      }
    }
    if (!settlementRecordHashValidation.valid) {
      issues.push({
        code: "operational_state_transparency_root_settlement_record_hash_mismatch",
        path: `${path}/settlementRecordHash`,
        message: `History-root settlement record hash ${settlementRecordHashValidation.actualHash} does not match recomputed hash ${settlementRecordHashValidation.expectedHash}.`,
        expected: settlementRecordHashValidation.expectedHash,
        actual: settlementRecordHashValidation.actualHash,
      });
    }

    settlementRecordByRootKey.set(
      operationalStateHistoryRootSettlementKey(record.root),
      record,
    );
    settledRoots.push(record.root);
    expectedSequence = record.settlementSequence + 1;
    previousSettlementRecordHash = record.settlementRecordHash;
    latestSettlementRecord = record;
  });

  const requiredSettlementRecords: OperationalStateHistoryRootSettlementRecord[] =
    [];
  input.requiredRoots?.forEach((root, index) => {
    const record = settlementRecordByRootKey.get(
      operationalStateHistoryRootSettlementKey(root),
    );
    if (record === undefined) {
      issues.push({
        code: "operational_state_transparency_required_root_not_settled",
        path: `/requiredRoots/${index}`,
        message:
          "Required history root has no replayed settlement record.",
        expected: root.rootCommitmentHash,
      });
      return;
    }
    requiredSettlementRecords.push(record);
  });

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    rootSettlementStoreId: input.rootSettlementStoreId,
    authorityScope: input.authorityScope,
    settledRecordCount: input.records.length,
    settledRoots,
    ...(latestSettlementRecord !== undefined
      ? { latestSettlementRecord }
      : {}),
    requiredSettlementRecords,
    ...(settlementAuthorityTopology !== undefined
      ? { settlementAuthorityTopology }
      : {}),
    ...(settlementAuthorityTransitionAdmissionReplay !== undefined
      ? { settlementAuthorityTransitionAdmissionReplay }
      : {}),
    issues,
  };
}

export function replayOperationalStateHistoryRootObservations(
  input: OperationalStateHistoryRootTransparencyReplayInput,
): OperationalStateHistoryRootTransparencyReplay {
  const issues: OperationalStateHistoryRootTransparencyIssue[] = [];
  const latestRootByKey = new Map<string, OperationalStateHistoryRoot>();
  const acceptedRoots: OperationalStateHistoryRoot[] = [];
  const signatureProofByObservationHash = new Map<
    string,
    OperationalStateHistoryRootObserverSignatureProof
  >();
  let signedObservationCount = 0;

  input.observerSignatureProofs?.forEach((proof) => {
    if (!signatureProofByObservationHash.has(proof.observationHash)) {
      signatureProofByObservationHash.set(proof.observationHash, proof);
    }
  });

  input.observations.forEach((observation, index) => {
    const path = `/observations/${index}`;
    const observationHashValidation =
      verifyOperationalStateHistoryRootObservationHash(observation);
    const rootHashValidation =
      verifyOperationalStateHistoryRootCommitmentHash(observation.root);

    if (observation.tenantId !== input.tenantId) {
      issues.push({
        code: "operational_state_transparency_observation_tenant_mismatch",
        path: `${path}/tenantId`,
        message: `Operational state transparency observation tenant ${observation.tenantId} does not match replay tenant ${input.tenantId}.`,
        expected: String(input.tenantId),
        actual: observation.tenantId,
      });
    }
    if (observation.root.tenantId !== input.tenantId) {
      issues.push({
        code: "operational_state_transparency_observation_tenant_mismatch",
        path: `${path}/root/tenantId`,
        message: `Operational state history root tenant ${observation.root.tenantId} does not match replay tenant ${input.tenantId}.`,
        expected: String(input.tenantId),
        actual: observation.root.tenantId,
      });
    }
    if (!observationHashValidation.valid) {
      issues.push({
        code: "operational_state_transparency_observation_hash_mismatch",
        path: `${path}/observationHash`,
        message: `Operational state transparency observation hash ${observationHashValidation.actualHash} does not match recomputed hash ${observationHashValidation.expectedHash}.`,
        expected: observationHashValidation.expectedHash,
        actual: observationHashValidation.actualHash,
      });
    }
    if (!rootHashValidation.valid) {
      issues.push({
        code: "operational_state_transparency_root_commitment_mismatch",
        path: `${path}/root/rootCommitmentHash`,
        message: `Operational state history root commitment ${rootHashValidation.actualHash} does not match recomputed hash ${rootHashValidation.expectedHash}.`,
        expected: rootHashValidation.expectedHash,
        actual: rootHashValidation.actualHash,
      });
    }
    if (observation.root.rootHash.trim().length === 0) {
      issues.push({
        code: "operational_state_transparency_root_hash_missing",
        path: `${path}/root/rootHash`,
        message: `Operational state history root for ${observation.root.storeId} has no root hash.`,
      });
    }

    if (input.requireObserverSignatures === true) {
      const observerSignatureProof = signatureProofByObservationHash.get(
        observation.observationHash,
      );
      if (observerSignatureProof === undefined) {
        issues.push({
          code: "operational_state_transparency_observer_signature_missing",
          path: `${path}/observerSignatureProof`,
          message: `Operational state transparency observation by ${observation.observerId} has no observer signature proof.`,
          actual: observation.observationHash,
        });
        return;
      }

      const signatureEvaluation =
        evaluateOperationalStateHistoryRootObserverSignature({
          observation,
          observerSignatureProof,
          expectedTenantId: input.tenantId,
          expectedAuthorityScope: observation.root.authorityScope,
          expectedObserverId: observation.observerId,
          expectedObservationHash: observation.observationHash,
          ...(input.allowedObserverIds !== undefined
            ? { allowedObserverIds: input.allowedObserverIds }
            : {}),
          ...(input.allowedVerifierIds !== undefined
            ? { allowedVerifierIds: input.allowedVerifierIds }
            : {}),
        });

      if (!signatureEvaluation.accepted) {
        issues.push({
          code: "operational_state_transparency_observer_signature_invalid",
          path: `${path}/observerSignatureProof`,
          message: `Operational state transparency observation by ${observation.observerId} has an invalid observer signature proof.`,
          actual: signatureEvaluation.issues
            .map((issue) => issue.code)
            .join(","),
        });
        return;
      }
      signedObservationCount += 1;
    }

    const key = operationalStateHistoryRootKey(observation.root);
    const latestRoot = latestRootByKey.get(key);
    if (latestRoot === undefined) {
      latestRootByKey.set(key, observation.root);
      acceptedRoots.push(observation.root);
      return;
    }

    if (observation.root.sequence < latestRoot.sequence) {
      issues.push({
        code: "operational_state_transparency_root_regression",
        path: `${path}/root/sequence`,
        message: `Operational state history root ${observation.root.storeId} regressed from sequence ${latestRoot.sequence} to ${observation.root.sequence}.`,
        expected: latestRoot.sequence,
        actual: observation.root.sequence,
      });
      return;
    }

    if (observation.root.sequence === latestRoot.sequence) {
      if (observation.root.rootHash !== latestRoot.rootHash) {
        issues.push({
          code: "operational_state_transparency_split_history",
          path: `${path}/root/rootHash`,
          message: `Operational state history root ${observation.root.storeId} has a same-sequence split view.`,
          expected: latestRoot.rootHash,
          actual: observation.root.rootHash,
        });
      }
      return;
    }

    if (observation.consistencyProof === undefined) {
      issues.push({
        code: "operational_state_transparency_consistency_proof_missing",
        path: `${path}/consistencyProof`,
        message: `Operational state history root ${observation.root.storeId} advanced from sequence ${latestRoot.sequence} to ${observation.root.sequence} without a consistency proof.`,
        expected: latestRoot.sequence,
        actual: observation.root.sequence,
      });
      return;
    }

    if (
      !verifyOperationalStateHistoryRootConsistencyProof(
        observation.consistencyProof,
        latestRoot,
        observation.root,
      )
    ) {
      issues.push({
        code: "operational_state_transparency_consistency_proof_invalid",
        path: `${path}/consistencyProof`,
        message: `Operational state history root ${observation.root.storeId} supplied an invalid consistency proof.`,
        expected: latestRoot.rootHash,
        actual: observation.root.rootHash,
      });
      return;
    }

    latestRootByKey.set(key, observation.root);
    acceptedRoots.push(observation.root);
  });

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    observations: input.observations,
    observerSignatureRequired: input.requireObserverSignatures === true,
    signedObservationCount,
    acceptedRoots,
    latestRoots: [...latestRootByKey.values()],
    issues,
  };
}

export function evaluateOperationalStateRecoveryCutTransparency(
  input: OperationalStateRecoveryCutTransparencyEvaluationInput,
): OperationalStateRecoveryCutTransparencyEvaluation {
  const issues: OperationalStateRecoveryCutTransparencyIssue[] = [];
  let checkedLaneCount = 0;
  let witnessedLaneCount = 0;
  let settledLaneCount = 0;

  if (input.transparencyReplay === undefined) {
    return {
      valid: false,
      checkedLaneCount: 0,
      witnessedLaneCount: 0,
      settledLaneCount: 0,
      issues: [
        {
          code: "operational_state_recovery_transparency_replay_missing",
          path: "/recoveryTransparency",
          message:
            "Recovered operational state cannot use store-root lanes without a transparency replay when recovery transparency is required.",
        },
      ],
    };
  }

  if (!input.transparencyReplay.valid) {
    issues.push({
      code: "operational_state_recovery_transparency_replay_invalid",
      path: "/recoveryTransparency",
      message:
        "Recovered operational state has an invalid transparency replay for its witnessed store roots.",
      actual: input.transparencyReplay.issues.map((issue) => issue.code).join(","),
    });
  }
  if (
    input.requireObserverSignatures === true &&
    input.transparencyReplay.observerSignatureRequired !== true
  ) {
    issues.push({
      code: "operational_state_recovery_transparency_observer_signature_required",
      path: "/recoveryTransparency/observerSignatureRequired",
      message:
        "Recovered operational state requires transparency replay to admit only signed observer observations.",
      expected: "true",
      actual: String(input.transparencyReplay.observerSignatureRequired),
    });
  }

  if (input.cut === undefined) {
    return {
      valid: issues.length === 0,
      checkedLaneCount,
      witnessedLaneCount,
      settledLaneCount,
      issues,
    };
  }

  const latestRootByKey = new Map<string, OperationalStateHistoryRoot>();
  input.transparencyReplay.latestRoots.forEach((root) => {
    latestRootByKey.set(operationalStateHistoryRootKey(root), root);
  });
  const settledRootByKey = new Map<string, OperationalStateHistoryRoot>();
  input.rootSettlementReplay?.settledRoots.forEach((root) => {
    settledRootByKey.set(operationalStateHistoryRootSettlementKey(root), root);
  });

  if (
    input.requireRootSettlement === true ||
    input.requireRootSettlementAuthorityTopology === true ||
    input.requireRootSettlementAuthorityTransitionAdmission === true ||
    input.requireRootSettlementAuthorityTransitionAdmissionWitness === true ||
    input.requireRootSettlementAuthorityTransitionAdmissionWitnessAuthorityTopology ===
      true ||
    input.requireRootSettlementAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
      true
  ) {
    if (input.rootSettlementReplay === undefined) {
      issues.push({
        code: "operational_state_recovery_transparency_root_settlement_replay_missing",
        path: "/recoveryTransparency/rootSettlement",
        message:
          "Recovered operational state requires replay of settled history-root certificates.",
      });
    } else if (!input.rootSettlementReplay.valid) {
      issues.push({
        code: "operational_state_recovery_transparency_root_settlement_replay_invalid",
        path: "/recoveryTransparency/rootSettlement",
        message:
          "Recovered operational state has an invalid history-root settlement replay.",
        actual: input.rootSettlementReplay.issues
          .map((issue) => issue.code)
        .join(","),
      });
    }
  }
  if (
    (input.requireRootSettlementAuthorityTopology === true ||
      input.requireRootSettlementAuthorityTransitionAdmission === true ||
      input.requireRootSettlementAuthorityTransitionAdmissionWitness === true ||
      input.requireRootSettlementAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input.requireRootSettlementAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    input.rootSettlementReplay !== undefined &&
    input.rootSettlementReplay.settlementAuthorityTopology === undefined
  ) {
    issues.push({
      code: "operational_state_recovery_transparency_root_settlement_authority_topology_missing",
      path: "/recoveryTransparency/rootSettlement/settlementAuthorityTopology",
      message:
        "Recovered operational state requires history-root settlement replay to bind certificates to replayed settlement authority topology.",
    });
  }
  if (
    (input.requireRootSettlementAuthorityTransitionAdmission === true ||
      input.requireRootSettlementAuthorityTransitionAdmissionWitness === true ||
      input.requireRootSettlementAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input.requireRootSettlementAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    input.rootSettlementReplay !== undefined &&
    input.rootSettlementReplay.settlementAuthorityTransitionAdmissionReplay ===
      undefined
  ) {
    issues.push({
      code: "operational_state_recovery_transparency_root_settlement_authority_transition_admission_replay_missing",
      path: "/recoveryTransparency/rootSettlement/settlementAuthorityTransitionAdmissionReplay",
      message:
        "Recovered operational state requires history-root settlement authority topology to come from admitted authority-transition history.",
    });
  }
  if (
    (input.requireRootSettlementAuthorityTransitionAdmissionWitness === true ||
      input.requireRootSettlementAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input.requireRootSettlementAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true) &&
    input.rootSettlementReplay !== undefined &&
    input.rootSettlementReplay.settlementAuthorityTransitionAdmissionReplay !==
      undefined
  ) {
    const admissionWitnessReplay =
      input.rootSettlementReplay.settlementAuthorityTransitionAdmissionReplay
        .admissionWitnessReplay;
    if (admissionWitnessReplay === undefined) {
      issues.push({
        code: "operational_state_recovery_transparency_root_settlement_authority_transition_admission_witness_replay_missing",
        path: "/recoveryTransparency/rootSettlement/settlementAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
        message:
          "Recovered operational state requires history-root settlement authority-transition admission records to be witnessed.",
      });
    } else if (!admissionWitnessReplay.valid) {
      issues.push({
        code: "operational_state_recovery_transparency_root_settlement_replay_invalid",
        path: "/recoveryTransparency/rootSettlement/settlementAuthorityTransitionAdmissionReplay/admissionWitnessReplay",
        message:
          "Recovered operational state cannot consume invalid history-root settlement authority-transition admission witness history.",
        actual: admissionWitnessReplay.issues
          .map((issue) => issue.code)
          .join(","),
      });
    } else if (
      (input.requireRootSettlementAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
        input.requireRootSettlementAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
          true) &&
      admissionWitnessReplay.witnessAuthorityTopology === undefined
    ) {
      issues.push({
        code: "operational_state_recovery_transparency_root_settlement_authority_transition_admission_witness_authority_topology_missing",
        path: "/recoveryTransparency/rootSettlement/settlementAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTopology",
        message:
          "Recovered operational state requires history-root settlement authority-transition admission witness certificates to bind to replayed witness authority topology.",
      });
    } else if (
      input.requireRootSettlementAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay ===
        undefined
    ) {
      issues.push({
        code: "operational_state_recovery_transparency_root_settlement_authority_transition_admission_witness_authority_transition_admission_replay_missing",
        path: "/recoveryTransparency/rootSettlement/settlementAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Recovered operational state requires history-root settlement authority-transition admission witness authority topology to replay from admitted authority-transition history.",
      });
    } else if (
      input.requireRootSettlementAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      !admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.valid
    ) {
      issues.push({
        code: "operational_state_recovery_transparency_root_settlement_authority_transition_admission_witness_authority_transition_admission_replay_invalid",
        path: "/recoveryTransparency/rootSettlement/settlementAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay",
        message:
          "Recovered operational state cannot consume invalid nested history-root settlement authority-transition admission witness authority history.",
        actual:
          admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay.issues
            .map((issue) => issue.code)
            .join(","),
      });
    } else if (
      input.requireRootSettlementAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true &&
      admissionWitnessReplay.witnessAuthorityTopology !== undefined &&
      admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay !==
        undefined &&
      (admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
        .latestAdmittedTopology === undefined ||
        !operationalStateAuthorityTopologiesMatch(
          admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology,
          admissionWitnessReplay.witnessAuthorityTopology,
        ))
    ) {
      issues.push({
        code: "operational_state_recovery_transparency_root_settlement_authority_transition_admission_witness_authority_transition_admission_topology_mismatch",
        path: "/recoveryTransparency/rootSettlement/settlementAuthorityTransitionAdmissionReplay/admissionWitnessReplay/witnessAuthorityTransitionAdmissionReplay/latestAdmittedTopology",
        message:
          "Recovered operational state requires history-root settlement authority-transition admission witness authority topology to be recovered from admitted authority-transition history.",
        expected: admissionWitnessReplay.witnessAuthorityTopology.topologyHash,
        actual:
          admissionWitnessReplay.witnessAuthorityTransitionAdmissionReplay
            .latestAdmittedTopology?.topologyHash ?? "none",
      });
    }
  }

  input.cut.lanes.forEach((lane, index) => {
    if (
      !lane.required ||
      lane.storeRootHash === undefined ||
      (input.requireWitnessedStoreRoots ?? true) === false
    ) {
      return;
    }
    checkedLaneCount += 1;
    const path = `/recoveryCut/lanes/${index}`;
    if (lane.storeId === undefined || lane.storeId.trim().length === 0) {
      issues.push({
        code: "operational_state_recovery_transparency_lane_store_id_missing",
        path: `${path}/storeId`,
        message: `Recovery lane ${lane.laneId} cites a store root hash but has no store id for transparency lookup.`,
      });
      return;
    }
    const root = latestRootByKey.get(
      `${input.cut!.tenantId}:${lane.authorityScope}:${lane.storeId}`,
    );
    if (root === undefined) {
      issues.push({
        code: "operational_state_recovery_transparency_lane_root_unwitnessed",
        path: `${path}/storeRootHash`,
        message: `Recovery lane ${lane.laneId} store root ${lane.storeRootHash} is not witnessed in transparency replay.`,
        actual: lane.storeRootHash,
      });
      return;
    }
    if (lane.sequence !== undefined && root.sequence < lane.sequence) {
      issues.push({
        code: "operational_state_recovery_transparency_lane_root_stale",
        path: `${path}/sequence`,
        message: `Recovery lane ${lane.laneId} requires store sequence ${lane.sequence}, but witnessed root is only ${root.sequence}.`,
        expected: lane.sequence,
        actual: root.sequence,
      });
      return;
    }
    if (root.rootHash !== lane.storeRootHash) {
      issues.push({
        code: "operational_state_recovery_transparency_lane_root_mismatch",
        path: `${path}/storeRootHash`,
        message: `Recovery lane ${lane.laneId} store root ${lane.storeRootHash} does not match witnessed root ${root.rootHash}.`,
        expected: lane.storeRootHash,
        actual: root.rootHash,
      });
      return;
    }
    witnessedLaneCount += 1;
    if (
      input.requireRootSettlement === true ||
      input.requireRootSettlementAuthorityTopology === true ||
      input.requireRootSettlementAuthorityTransitionAdmission === true ||
      input.requireRootSettlementAuthorityTransitionAdmissionWitness === true ||
      input.requireRootSettlementAuthorityTransitionAdmissionWitnessAuthorityTopology ===
        true ||
      input.requireRootSettlementAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmission ===
        true
    ) {
      const settledRoot = settledRootByKey.get(
        operationalStateHistoryRootSettlementKey(root),
      );
      if (settledRoot === undefined) {
        issues.push({
          code: "operational_state_recovery_transparency_lane_root_unsettled",
          path: `${path}/storeRootHash`,
          message: `Recovery lane ${lane.laneId} cites root ${root.rootHash}, but that root is not settled by replayed history-root settlement records.`,
          expected: root.rootCommitmentHash,
          actual: lane.storeRootHash,
        });
        return;
      }
      settledLaneCount += 1;
    }
  });

  return {
    valid: issues.length === 0,
    checkedLaneCount,
    witnessedLaneCount,
    settledLaneCount,
    issues,
  };
}

export function evaluateProjectionReplayCertificate(
  view: CurrentStateView,
  options: ProjectionReplayCertificateEvaluationOptions = {},
): ProjectionReplayCertificateEvaluation {
  const certificate = view.replayCertificate;
  if (certificate === undefined) {
    return {
      valid: false,
      issues: [
        {
          code: "projection_replay_certificate_missing",
          path: "/replayCertificate",
          message:
            "CurrentStateView cannot authorize action without a replay certificate when replay proof is required.",
          ref: view.subject,
        },
      ],
    };
  }
  return evaluateProjectionReplayCertificateAgainstView(
    certificate,
    view,
    options,
  );
}

export function evaluateProjectionReplayCertificateAgainstView(
  certificate: ProjectionReplayCertificate,
  view: CurrentStateView,
  options: ProjectionReplayCertificateEvaluationOptions = {},
): ProjectionReplayCertificateEvaluation {
  const issues: ProjectionReplayCertificateIssue[] = [];
  const hashValidation = verifyProjectionReplayCertificateHash(certificate);

  if (!hashValidation.valid) {
    issues.push({
      code: "projection_replay_certificate_hash_mismatch",
      path: "/replayCertificate/certificateHash",
      message: `Projection replay certificate hash ${hashValidation.actualHash} does not match recomputed hash ${hashValidation.expectedHash}.`,
      ref: view.subject,
    });
  }
  if (certificate.tenantId !== view.tenantId) {
    issues.push({
      code: "projection_replay_tenant_mismatch",
      path: "/replayCertificate/tenantId",
      message: `Projection replay certificate tenant ${certificate.tenantId} does not match current state view tenant ${view.tenantId}.`,
      ref: view.subject,
    });
  }
  if (!sameStateRef(certificate.subject, view.subject)) {
    issues.push({
      code: "projection_replay_subject_mismatch",
      path: "/replayCertificate/subject",
      message: `Projection replay certificate subject ${formatStateRef(certificate.subject)} does not match current state view subject ${formatStateRef(view.subject)}.`,
      ref: certificate.subject,
    });
  }
  if (certificate.projectionVersion !== view.projectionVersion) {
    issues.push({
      code: "projection_replay_version_mismatch",
      path: "/replayCertificate/projectionVersion",
      message: `Projection replay certificate version ${certificate.projectionVersion} does not match current state view version ${view.projectionVersion}.`,
      ref: view.subject,
    });
  }

  const expectedAuthorityScope =
    options.expectedAuthorityScope ?? view.authorityRule;
  if (certificate.authorityScope !== expectedAuthorityScope) {
    issues.push({
      code: "projection_replay_authority_scope_mismatch",
      path: "/replayCertificate/authorityScope",
      message: `Projection replay certificate authority scope ${certificate.authorityScope} does not match expected scope ${expectedAuthorityScope}.`,
      ref: view.subject,
    });
  }

  if (!sameStateRefSet(certificate.sourceRefs, view.sourceRefs)) {
    issues.push({
      code: "projection_replay_source_refs_mismatch",
      path: "/replayCertificate/sourceRefs",
      message:
        "Projection replay certificate source refs do not match the current state view source refs.",
      ref: view.subject,
    });
  }

  const projectionHash = computeCurrentStateViewIdentityHash(view);
  if (certificate.projectionHash !== projectionHash) {
    issues.push({
      code: "projection_replay_projection_hash_mismatch",
      path: "/replayCertificate/projectionHash",
      message: `Projection replay certificate projection hash ${certificate.projectionHash} does not match current state view projection hash ${projectionHash}.`,
      ref: view.subject,
    });
  }

  const transitionHistoryHash =
    computeProjectionReplayTransitionHistoryHash(certificate.transitionRefs);
  if (certificate.transitionHistoryHash !== transitionHistoryHash) {
    issues.push({
      code: "projection_replay_transition_history_hash_mismatch",
      path: "/replayCertificate/transitionHistoryHash",
      message: `Projection replay certificate transition history hash ${certificate.transitionHistoryHash} does not match recomputed hash ${transitionHistoryHash}.`,
      ref: view.subject,
    });
  }

  if (certificate.transitionRefs.length === 0) {
    issues.push({
      code: "projection_replay_transition_history_empty",
      path: "/replayCertificate/transitionRefs",
      message:
        "Projection replay certificate must cite at least one admitted transition ref.",
      ref: view.subject,
    });
  }
  for (const [index, transition] of certificate.transitionRefs.entries()) {
    if (!isProjectionReplayTransitionRefKind(transition.ref.kind)) {
      issues.push({
        code: "projection_replay_transition_kind_invalid",
        path: `/replayCertificate/transitionRefs/${index}/ref/kind`,
        message: `Projection replay transition ref kind ${transition.ref.kind} is not an admitted transition kind.`,
        ref: transition.ref,
      });
    }
    if (
      options.requireTransitionContentHash === true &&
      (transition.contentHash === undefined ||
        transition.contentHash.trim() === "")
    ) {
      issues.push({
        code: "projection_replay_transition_hash_missing",
        path: `/replayCertificate/transitionRefs/${index}/contentHash`,
        message:
          "Projection replay transition ref requires a content hash under the configured replay policy.",
        ref: transition.ref,
      });
    }
  }

  if (
    options.minimumReplayPosition !== undefined &&
    (certificate.replayedToPosition === undefined ||
      certificate.replayedToPosition < options.minimumReplayPosition)
  ) {
    issues.push({
      code: "projection_replay_position_regression",
      path: "/replayCertificate/replayedToPosition",
      message: `Projection replay certificate position ${certificate.replayedToPosition ?? "unknown"} is behind required position ${options.minimumReplayPosition}.`,
      ref: view.subject,
    });
  }

  return {
    certificateId: certificate.certificateId,
    valid: issues.length === 0,
    issues,
  };
}

export function buildProjectionReplayCertificateRef(
  certificate: ProjectionReplayCertificate,
  input: {
    readonly checkedAt: Timestamp | string;
    readonly projectionName?: string;
    readonly storeSequence?: number;
    readonly storeEntryHash?: string;
    readonly storeRootHash?: string;
  },
): ProjectionReplayCertificateRef {
  const projectionName = certificate.projectionName;
  if (projectionName === undefined || projectionName.trim() === "") {
    throw new Error(
      `projection replay certificate ${certificate.certificateId} cannot form a write ref without projectionName`,
    );
  }
  if (
    input.projectionName !== undefined &&
    input.projectionName !== projectionName
  ) {
    throw new Error(
      `projection replay certificate ${certificate.certificateId} projectionName ${projectionName} does not match requested ref projectionName ${input.projectionName}`,
    );
  }
  if (certificate.projectionVersion === undefined) {
    throw new Error(
      `projection replay certificate ${certificate.certificateId} cannot form a write ref without projectionVersion`,
    );
  }
  if (certificate.replayedToPosition === undefined) {
    throw new Error(
      `projection replay certificate ${certificate.certificateId} cannot form a write ref without replayedToPosition`,
    );
  }

  return {
    certificateId: certificate.certificateId,
    certificateHash: certificate.certificateHash,
    projectionName,
    projectionVersion: certificate.projectionVersion,
    authorityScope: certificate.authorityScope,
    replayedToPosition: certificate.replayedToPosition,
    transitionHistoryHash: certificate.transitionHistoryHash,
    projectionHash: certificate.projectionHash,
    ...(input.storeSequence !== undefined
      ? { certificateStoreSequence: input.storeSequence }
      : {}),
    ...(input.storeEntryHash !== undefined
      ? { certificateStoreEntryHash: input.storeEntryHash }
      : {}),
    ...(input.storeRootHash !== undefined
      ? { certificateStoreRootHash: input.storeRootHash }
      : {}),
    checkedAt: input.checkedAt,
  };
}

export function buildProjectionReplayCertificateRefFromRecord(
  record: ProjectionReplayCertificateRecord,
  input: {
    readonly checkedAt: Timestamp | string;
  },
): ProjectionReplayCertificateRef {
  return buildProjectionReplayCertificateRef(record.certificate, {
    checkedAt: input.checkedAt,
    ...(record.storeSequence !== undefined
      ? { storeSequence: record.storeSequence }
      : {}),
    ...(record.storeEntryHash !== undefined
      ? { storeEntryHash: record.storeEntryHash }
      : {}),
    ...(record.storeRootHash !== undefined
      ? { storeRootHash: record.storeRootHash }
      : {}),
  });
}

export function buildProjectionReplayCertificateRecord(
  input: ProjectionReplayCertificateRecordInput,
): ProjectionReplayCertificateRecord {
  const { certificate } = input;
  const hashValidation = verifyProjectionReplayCertificateHash(certificate);
  if (!hashValidation.valid) {
    throw new Error(
      `projection replay certificate ${certificate.certificateId} failed hash validation: ${hashValidation.actualHash} !== ${hashValidation.expectedHash}`,
    );
  }

  const projectionName = certificate.projectionName;
  if (projectionName === undefined || projectionName.trim() === "") {
    throw new Error(
      `projection replay certificate ${certificate.certificateId} requires projectionName before durable admission`,
    );
  }
  if (
    input.projectionName !== undefined &&
    input.projectionName !== projectionName
  ) {
    throw new Error(
      `projection replay certificate ${certificate.certificateId} projectionName ${projectionName} does not match durable record projectionName ${input.projectionName}`,
    );
  }
  if (certificate.projectionVersion === undefined) {
    throw new Error(
      `projection replay certificate ${certificate.certificateId} requires projectionVersion before durable admission`,
    );
  }
  if (certificate.replayedToPosition === undefined) {
    throw new Error(
      `projection replay certificate ${certificate.certificateId} requires replayedToPosition before durable admission`,
    );
  }

  return {
    tenantId: certificate.tenantId,
    certificateId: certificate.certificateId,
    certificateHash: certificate.certificateHash,
    projectionName,
    subject: certificate.subject,
    authorityScope: certificate.authorityScope,
    projectionVersion: certificate.projectionVersion,
    replayedToPosition: certificate.replayedToPosition,
    transitionHistoryHash: certificate.transitionHistoryHash,
    projectionHash: certificate.projectionHash,
    certificate,
    recordedAt: input.recordedAt ?? certificate.replayedAt,
  };
}

export function buildProjectionReplayCertificateStoreEntry(
  record: ProjectionReplayCertificateRecord,
  input: {
    readonly sequence: number;
    readonly previousEntryHash?: string;
    readonly recordedAt?: Timestamp | string;
  },
): ProjectionReplayCertificateStoreEntry {
  if (!Number.isInteger(input.sequence) || input.sequence <= 0) {
    throw new Error(
      `projection replay certificate store entry sequence must be a positive integer`,
    );
  }
  if (input.sequence === 1 && input.previousEntryHash !== undefined) {
    throw new Error(
      "first projection replay certificate store entry cannot cite a previous hash",
    );
  }
  if (input.sequence > 1 && input.previousEntryHash === undefined) {
    throw new Error(
      "projection replay certificate store entry after the first requires a previous hash",
    );
  }

  const payload: Omit<ProjectionReplayCertificateStoreEntry, "entryHash"> = {
    tenantId: record.tenantId,
    sequence: input.sequence,
    certificateId: record.certificateId,
    certificateHash: record.certificateHash,
    projectionName: record.projectionName,
    projectionVersion: record.projectionVersion,
    replayedToPosition: record.replayedToPosition,
    transitionHistoryHash: record.transitionHistoryHash,
    projectionHash: record.projectionHash,
    ...(input.previousEntryHash !== undefined
      ? { previousEntryHash: input.previousEntryHash }
      : {}),
    recordedAt: input.recordedAt ?? record.recordedAt,
  };

  return {
    ...payload,
    entryHash: computeProjectionReplayCertificateStoreEntryHash(payload),
  };
}

export function computeProjectionReplayCertificateStoreEntryHash(
  entry: Omit<ProjectionReplayCertificateStoreEntry, "entryHash">,
): string {
  return fingerprint64(canonicalStringify(entry));
}

export function projectionReplayCertificateStoreRootFromEntry(
  entry: ProjectionReplayCertificateStoreEntry,
): ProjectionReplayCertificateStoreRoot {
  return {
    tenantId: entry.tenantId,
    sequence: entry.sequence,
    rootHash: entry.entryHash,
    ...(entry.previousEntryHash !== undefined
      ? { previousRootHash: entry.previousEntryHash }
      : {}),
    recordedAt: entry.recordedAt,
  };
}

export function attachProjectionReplayCertificateStoreEntry(
  record: ProjectionReplayCertificateRecord,
  entry: ProjectionReplayCertificateStoreEntry,
): ProjectionReplayCertificateRecord {
  return {
    ...record,
    storeSequence: entry.sequence,
    ...(entry.previousEntryHash !== undefined
      ? { storePreviousEntryHash: entry.previousEntryHash }
      : {}),
    storeEntryHash: entry.entryHash,
    storeRootHash: entry.entryHash,
    storeRecordedAt: entry.recordedAt,
  };
}

export function projectionReplayCertificateStoreEntryFromRecord(
  record: ProjectionReplayCertificateRecord,
): ProjectionReplayCertificateStoreEntry | undefined {
  if (
    record.storeSequence === undefined ||
    record.storeEntryHash === undefined ||
    record.storeRootHash === undefined ||
    record.storeRecordedAt === undefined
  ) {
    return undefined;
  }
  return {
    tenantId: record.tenantId,
    sequence: record.storeSequence,
    certificateId: record.certificateId,
    certificateHash: record.certificateHash,
    projectionName: record.projectionName,
    projectionVersion: record.projectionVersion,
    replayedToPosition: record.replayedToPosition,
    transitionHistoryHash: record.transitionHistoryHash,
    projectionHash: record.projectionHash,
    ...(record.storePreviousEntryHash !== undefined
      ? { previousEntryHash: record.storePreviousEntryHash }
      : {}),
    recordedAt: record.storeRecordedAt,
    entryHash: record.storeEntryHash,
  };
}

export function verifyProjectionReplayCertificateStoreEntries(input: {
  readonly tenantId: TenantId | string;
  readonly entries: readonly ProjectionReplayCertificateStoreEntry[];
  readonly expectedRoot?: ProjectionReplayCertificateStoreRoot;
  readonly previousRoot?: ProjectionReplayCertificateStoreRoot;
}): ProjectionReplayCertificateStoreChainVerification {
  const issues: ProjectionReplayCertificateStoreChainIssue[] = [];
  const tenant = String(input.tenantId);
  const entries = [...input.entries].sort((a, b) => a.sequence - b.sequence);
  if (entries.length === 0) {
    issues.push({
      code: "projection_replay_certificate_store_chain_empty",
      path: "/entries",
      message: "projection replay certificate store proof contains no entries",
    });
    return { valid: false, issues };
  }

  let expectedSequence =
    input.previousRoot === undefined ? 1 : input.previousRoot.sequence + 1;
  let expectedPreviousHash = input.previousRoot?.rootHash;

  for (const [index, entry] of entries.entries()) {
    if (String(entry.tenantId) !== tenant) {
      issues.push({
        code: "projection_replay_certificate_store_chain_tenant_mismatch",
        path: `/entries/${index}/tenantId`,
        message: "projection replay certificate store entry tenant mismatch",
        expected: tenant,
        actual: String(entry.tenantId),
      });
    }
    if (entry.sequence !== expectedSequence) {
      issues.push({
        code: "projection_replay_certificate_store_chain_sequence_gap",
        path: `/entries/${index}/sequence`,
        message:
          "projection replay certificate store entries must be contiguous",
        expected: expectedSequence,
        actual: entry.sequence,
      });
    }
    if ((entry.previousEntryHash ?? "") !== (expectedPreviousHash ?? "")) {
      issues.push({
        code: "projection_replay_certificate_store_chain_previous_hash_mismatch",
        path: `/entries/${index}/previousEntryHash`,
        message:
          "projection replay certificate store entry does not chain to the prior root",
        expected: expectedPreviousHash ?? "",
        actual: entry.previousEntryHash ?? "",
      });
    }

    const { entryHash: actualHash, ...entryPayload } = entry;
    const expectedEntryHash =
      computeProjectionReplayCertificateStoreEntryHash(entryPayload);
    if (actualHash !== expectedEntryHash) {
      issues.push({
        code: "projection_replay_certificate_store_chain_entry_hash_mismatch",
        path: `/entries/${index}/entryHash`,
        message:
          "projection replay certificate store entry hash does not match its body",
        expected: expectedEntryHash,
        actual: actualHash,
      });
    }

    expectedSequence = entry.sequence + 1;
    expectedPreviousHash = entry.entryHash;
  }

  const latest = entries[entries.length - 1]!;
  const root = projectionReplayCertificateStoreRootFromEntry(latest);
  if (
    input.expectedRoot !== undefined &&
    (input.expectedRoot.sequence !== root.sequence ||
      input.expectedRoot.rootHash !== root.rootHash ||
      String(input.expectedRoot.tenantId) !== String(root.tenantId))
  ) {
    issues.push({
      code: "projection_replay_certificate_store_chain_root_mismatch",
      path: "/expectedRoot",
      message:
        "projection replay certificate store proof does not end at the expected root",
      expected: input.expectedRoot.rootHash,
      actual: root.rootHash,
    });
  }

  return {
    valid: issues.length === 0,
    root,
    issues,
  };
}

export function verifyProjectionReplayCertificateStoreConsistencyProof(
  proof: ProjectionReplayCertificateStoreConsistencyProof,
): ProjectionReplayCertificateStoreChainVerification {
  return verifyProjectionReplayCertificateStoreEntries({
    tenantId: proof.tenantId,
    entries: proof.entries,
    expectedRoot: proof.toRoot,
    ...(proof.fromRoot !== undefined ? { previousRoot: proof.fromRoot } : {}),
  });
}

export function evaluateProjectionReplayCertificateStoreRootObservation(input: {
  readonly observation: ProjectionReplayCertificateStoreRootObservationInput;
  readonly knownRoots: readonly ProjectionReplayCertificateStoreRoot[];
}): ProjectionReplayCertificateStoreRootWitnessDecision {
  const { observation } = input;
  const tenant = String(observation.tenantId);
  const observedRoot = observation.root;
  const knownRoots = sortedProjectionReplayCertificateStoreRoots(
    input.knownRoots.filter((root) => String(root.tenantId) === tenant),
  );
  const latestRoot = knownRoots[knownRoots.length - 1];

  if (String(observedRoot.tenantId) !== tenant) {
    return obstructProjectionReplayCertificateStoreRootObservation({
      observation,
      ...(latestRoot !== undefined ? { latestRoot } : {}),
      issues: [
        {
          code: "projection_replay_certificate_store_root_tenant_mismatch",
          path: "/root/tenantId",
          message:
            "projection replay certificate store root tenant does not match the observation tenant",
          expected: tenant,
          actual: String(observedRoot.tenantId),
        },
      ],
    });
  }

  const knownAtSequence = knownRoots.find(
    (root) => root.sequence === observedRoot.sequence,
  );
  if (knownAtSequence !== undefined) {
    if (knownAtSequence.rootHash === observedRoot.rootHash) {
      return acceptedProjectionReplayCertificateStoreRootObservation({
        observation,
        status: "accepted_duplicate",
        latestRoot: latestRoot ?? observedRoot,
        acceptedRoots: [observedRoot],
      });
    }
    return obstructProjectionReplayCertificateStoreRootObservation({
      observation,
      ...(latestRoot !== undefined ? { latestRoot } : {}),
      conflictingRoot: knownAtSequence,
      issues: [
        {
          code: "projection_replay_certificate_store_root_fork",
          path: "/root/rootHash",
          message:
            "projection replay certificate store root conflicts with an already witnessed root at the same sequence",
          expected: knownAtSequence.rootHash,
          actual: observedRoot.rootHash,
        },
      ],
    });
  }

  if (latestRoot === undefined) {
    if (observedRoot.sequence === 1) {
      return acceptedProjectionReplayCertificateStoreRootObservation({
        observation,
        status: "accepted_initial",
        latestRoot: observedRoot,
        acceptedRoots: [observedRoot],
      });
    }
    const proof = observation.consistencyProof;
    if (proof === undefined) {
      return obstructProjectionReplayCertificateStoreRootObservation({
        observation,
        issues: [
          {
            code: "projection_replay_certificate_store_root_consistency_proof_missing",
            path: "/consistencyProof",
            message:
              "first witness observation after sequence 1 requires a consistency proof from the beginning of the certificate store",
            expected: 1,
            actual: observedRoot.sequence,
          },
        ],
      });
    }
    const proofIssues = validateProjectionReplayCertificateStoreRootWitnessProof({
      tenant,
      observedRoot,
      proof,
    });
    if (proofIssues.length > 0) {
      return obstructProjectionReplayCertificateStoreRootObservation({
        observation,
        issues: proofIssues,
      });
    }
    return acceptedProjectionReplayCertificateStoreRootObservation({
      observation,
      status: "accepted_initial",
      latestRoot: observedRoot,
      acceptedRoots: rootsFromProjectionReplayCertificateStoreProof(proof),
    });
  }

  if (observedRoot.sequence < latestRoot.sequence) {
    return obstructProjectionReplayCertificateStoreRootObservation({
      observation,
      latestRoot,
      issues: [
        {
          code: "projection_replay_certificate_store_root_regression",
          path: "/root/sequence",
          message:
            "projection replay certificate store root regresses behind the latest witnessed root without matching an already witnessed sequence",
          expected: latestRoot.sequence,
          actual: observedRoot.sequence,
        },
      ],
    });
  }

  const proof = observation.consistencyProof;
  if (proof === undefined) {
    return obstructProjectionReplayCertificateStoreRootObservation({
      observation,
      latestRoot,
      issues: [
        {
          code: "projection_replay_certificate_store_root_consistency_proof_missing",
          path: "/consistencyProof",
          message:
            "projection replay certificate store root advance requires a consistency proof from the latest witnessed root",
          expected: latestRoot.sequence,
          actual: observedRoot.sequence,
        },
      ],
    });
  }

  const proofIssues = validateProjectionReplayCertificateStoreRootWitnessProof({
    tenant,
    observedRoot,
    proof,
    expectedFromRoot: latestRoot,
  });
  if (proofIssues.length > 0) {
    return obstructProjectionReplayCertificateStoreRootObservation({
      observation,
      latestRoot,
      issues: proofIssues,
    });
  }

  return acceptedProjectionReplayCertificateStoreRootObservation({
    observation,
    status: "accepted_advance",
    latestRoot: observedRoot,
    acceptedRoots: rootsFromProjectionReplayCertificateStoreProof(proof),
  });
}

function validateProjectionReplayCertificateStoreRootWitnessProof(input: {
  readonly tenant: string;
  readonly observedRoot: ProjectionReplayCertificateStoreRoot;
  readonly proof: ProjectionReplayCertificateStoreConsistencyProof;
  readonly expectedFromRoot?: ProjectionReplayCertificateStoreRoot;
}): ProjectionReplayCertificateStoreRootWitnessIssue[] {
  const issues: ProjectionReplayCertificateStoreRootWitnessIssue[] = [];
  const { proof } = input;

  if (String(proof.tenantId) !== input.tenant) {
    issues.push({
      code: "projection_replay_certificate_store_root_consistency_proof_invalid",
      path: "/consistencyProof/tenantId",
      message:
        "projection replay certificate store consistency proof tenant does not match the root observation",
      expected: input.tenant,
      actual: String(proof.tenantId),
    });
  }
  if (!sameProjectionReplayCertificateStoreRoot(proof.toRoot, input.observedRoot)) {
    issues.push({
      code: "projection_replay_certificate_store_root_consistency_proof_invalid",
      path: "/consistencyProof/toRoot",
      message:
        "projection replay certificate store consistency proof does not end at the observed root",
      expected: input.observedRoot.rootHash,
      actual: proof.toRoot.rootHash,
    });
  }
  if (
    input.expectedFromRoot === undefined &&
    proof.fromRoot !== undefined
  ) {
    issues.push({
      code: "projection_replay_certificate_store_root_consistency_proof_invalid",
      path: "/consistencyProof/fromRoot",
      message:
        "first witness observation must prove the root from the beginning of the certificate store",
      actual: proof.fromRoot.rootHash,
    });
  }
  if (
    input.expectedFromRoot !== undefined &&
    !sameProjectionReplayCertificateStoreRoot(
      proof.fromRoot,
      input.expectedFromRoot,
    )
  ) {
    issues.push({
      code: "projection_replay_certificate_store_root_consistency_proof_invalid",
      path: "/consistencyProof/fromRoot",
      message:
        "projection replay certificate store consistency proof must start at the latest witnessed root",
      expected: input.expectedFromRoot.rootHash,
      actual: proof.fromRoot?.rootHash ?? "",
    });
  }

  const chainVerification = verifyProjectionReplayCertificateStoreConsistencyProof(
    proof,
  );
  if (!chainVerification.valid) {
    issues.push({
      code: "projection_replay_certificate_store_root_consistency_proof_invalid",
      path: "/consistencyProof/entries",
      message: `projection replay certificate store consistency proof failed chain verification: ${chainVerification.issues
        .map((issue) => issue.code)
        .join(", ")}`,
    });
  }

  return issues;
}

function acceptedProjectionReplayCertificateStoreRootObservation(input: {
  readonly observation: ProjectionReplayCertificateStoreRootObservationInput;
  readonly status: Exclude<
    ProjectionReplayCertificateStoreRootWitnessStatus,
    "obstructed"
  >;
  readonly latestRoot: ProjectionReplayCertificateStoreRoot;
  readonly acceptedRoots: readonly ProjectionReplayCertificateStoreRoot[];
}): ProjectionReplayCertificateStoreRootWitnessDecision {
  return {
    accepted: true,
    status: input.status,
    observerId: input.observation.observerId,
    observedRoot: input.observation.root,
    latestRoot: input.latestRoot,
    acceptedRoots: sortedProjectionReplayCertificateStoreRoots(input.acceptedRoots),
    issues: [],
  };
}

function obstructProjectionReplayCertificateStoreRootObservation(input: {
  readonly observation: ProjectionReplayCertificateStoreRootObservationInput;
  readonly latestRoot?: ProjectionReplayCertificateStoreRoot;
  readonly conflictingRoot?: ProjectionReplayCertificateStoreRoot;
  readonly issues: readonly ProjectionReplayCertificateStoreRootWitnessIssue[];
}): ProjectionReplayCertificateStoreRootWitnessDecision {
  const obstruction = buildProjectionReplayCertificateStoreRootObstruction(input);
  return {
    accepted: false,
    status: "obstructed",
    observerId: input.observation.observerId,
    observedRoot: input.observation.root,
    ...(input.latestRoot !== undefined ? { latestRoot: input.latestRoot } : {}),
    acceptedRoots: [],
    issues: input.issues,
    obstruction,
  };
}

function buildProjectionReplayCertificateStoreRootObstruction(input: {
  readonly observation: ProjectionReplayCertificateStoreRootObservationInput;
  readonly latestRoot?: ProjectionReplayCertificateStoreRoot;
  readonly conflictingRoot?: ProjectionReplayCertificateStoreRoot;
  readonly issues: readonly ProjectionReplayCertificateStoreRootWitnessIssue[];
}): ProjectionReplayCertificateStoreRootObstructionArtifact {
  const payload = {
    tenantId: input.observation.tenantId,
    observerId: input.observation.observerId,
    observedRoot: input.observation.root,
    ...(input.latestRoot !== undefined ? { latestRoot: input.latestRoot } : {}),
    ...(input.conflictingRoot !== undefined
      ? { conflictingRoot: input.conflictingRoot }
      : {}),
    issues: input.issues,
  };
  return {
    artifactId: `projection_replay_root_obstruction_${fingerprint64(
      canonicalStringify(payload),
    )}`,
    tenantId: input.observation.root.tenantId,
    generatedAt: input.observation.observedAt,
    observerId: input.observation.observerId,
    observedRoot: input.observation.root,
    ...(input.latestRoot !== undefined ? { latestRoot: input.latestRoot } : {}),
    ...(input.conflictingRoot !== undefined
      ? { conflictingRoot: input.conflictingRoot }
      : {}),
    issues: input.issues,
    allowedAction: "request_root_consistency_proof",
  };
}

function rootsFromProjectionReplayCertificateStoreProof(
  proof: ProjectionReplayCertificateStoreConsistencyProof,
): readonly ProjectionReplayCertificateStoreRoot[] {
  return sortedProjectionReplayCertificateStoreRoots(
    proof.entries.map((entry) =>
      projectionReplayCertificateStoreRootFromEntry(entry),
    ),
  );
}

function sortedProjectionReplayCertificateStoreRoots(
  roots: readonly ProjectionReplayCertificateStoreRoot[],
): ProjectionReplayCertificateStoreRoot[] {
  return [...roots].sort((a, b) => {
    if (a.sequence !== b.sequence) return a.sequence - b.sequence;
    return a.rootHash.localeCompare(b.rootHash);
  });
}

function mergeProjectionReplayCertificateStoreRoots(
  existing: readonly ProjectionReplayCertificateStoreRoot[],
  additions: readonly ProjectionReplayCertificateStoreRoot[],
): ProjectionReplayCertificateStoreRoot[] {
  const bySequenceAndHash = new Map<string, ProjectionReplayCertificateStoreRoot>();
  for (const root of [...existing, ...additions]) {
    bySequenceAndHash.set(
      `${String(root.tenantId)}:${root.sequence}:${root.rootHash}`,
      root,
    );
  }
  return sortedProjectionReplayCertificateStoreRoots([
    ...bySequenceAndHash.values(),
  ]);
}

function sameProjectionReplayCertificateStoreRoot(
  left: ProjectionReplayCertificateStoreRoot | undefined,
  right: ProjectionReplayCertificateStoreRoot | undefined,
): boolean {
  return (
    left !== undefined &&
    right !== undefined &&
    String(left.tenantId) === String(right.tenantId) &&
    left.sequence === right.sequence &&
    left.rootHash === right.rootHash
  );
}

function sortedProjectionReplayCertificateStoreRootWitnessSettlementStoreHeads(
  heads: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead[],
): ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead[] {
  return [...heads].sort((a, b) => {
    if (a.settlementSequence !== b.settlementSequence) {
      return a.settlementSequence - b.settlementSequence;
    }
    return a.settlementRecordHash.localeCompare(b.settlementRecordHash);
  });
}

function mergeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeads(
  existing: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead[],
  additions: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead[],
): ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead[] {
  const bySequenceAndHash = new Map<
    string,
    ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead
  >();
  for (const head of [...existing, ...additions]) {
    bySequenceAndHash.set(
      `${String(head.tenantId)}:${head.settlementSequence}:${head.settlementRecordHash}:${head.headHash}`,
      head,
    );
  }
  return sortedProjectionReplayCertificateStoreRootWitnessSettlementStoreHeads([
    ...bySequenceAndHash.values(),
  ]);
}

function sameProjectionReplayCertificateStoreRootWitnessSettlementStoreHead(
  left:
    | ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead
    | undefined,
  right:
    | ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead
    | undefined,
): boolean {
  return (
    left !== undefined &&
    right !== undefined &&
    String(left.tenantId) === String(right.tenantId) &&
    left.settlementSequence === right.settlementSequence &&
    left.settlementRecordHash === right.settlementRecordHash &&
    left.headHash === right.headHash
  );
}

function sortedProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeads(
  heads: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHead[],
): ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHead[] {
  return [...heads].sort((a, b) => {
    if (a.pruningTombstoneSequence !== b.pruningTombstoneSequence) {
      return a.pruningTombstoneSequence - b.pruningTombstoneSequence;
    }
    return a.pruningTombstoneRecordHash.localeCompare(
      b.pruningTombstoneRecordHash,
    );
  });
}

function mergeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeads(
  existing: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHead[],
  additions: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHead[],
): ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHead[] {
  const bySequenceAndHash = new Map<
    string,
    ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHead
  >();
  for (const head of [...existing, ...additions]) {
    bySequenceAndHash.set(
      `${String(head.tenantId)}:${head.pruningTombstoneSequence}:${head.pruningTombstoneRecordHash}:${head.headHash}`,
      head,
    );
  }
  return sortedProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeads(
    [...bySequenceAndHash.values()],
  );
}

function sameProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHead(
  left:
    | ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHead
    | undefined,
  right:
    | ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHead
    | undefined,
): boolean {
  return (
    left !== undefined &&
    right !== undefined &&
    String(left.tenantId) === String(right.tenantId) &&
    left.pruningTombstoneSequence === right.pruningTombstoneSequence &&
    left.pruningTombstoneRecordHash === right.pruningTombstoneRecordHash &&
    left.headHash === right.headHash
  );
}

function sortedProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeads(
  heads: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHead[],
): ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHead[] {
  return [...heads].sort((a, b) => {
    if (a.pruningTombstoneSequence !== b.pruningTombstoneSequence) {
      return a.pruningTombstoneSequence - b.pruningTombstoneSequence;
    }
    return a.pruningTombstoneRecordHash.localeCompare(
      b.pruningTombstoneRecordHash,
    );
  });
}

function mergeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeads(
  existing: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHead[],
  additions: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHead[],
): ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHead[] {
  const bySequenceAndHash = new Map<
    string,
    ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHead
  >();
  for (const head of [...existing, ...additions]) {
    bySequenceAndHash.set(
      `${String(head.tenantId)}:${head.pruningTombstoneSequence}:${head.pruningTombstoneRecordHash}:${head.headHash}`,
      head,
    );
  }
  return sortedProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeads(
    [...bySequenceAndHash.values()],
  );
}

function sameProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHead(
  left:
    | ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHead
    | undefined,
  right:
    | ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHead
    | undefined,
): boolean {
  return (
    left !== undefined &&
    right !== undefined &&
    String(left.tenantId) === String(right.tenantId) &&
    left.pruningTombstoneSequence === right.pruningTombstoneSequence &&
    left.pruningTombstoneRecordHash === right.pruningTombstoneRecordHash &&
    left.headHash === right.headHash
  );
}

function sameProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHead(
  left:
    | ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHead
    | undefined,
  right:
    | ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHead
    | undefined,
): boolean {
  return (
    left !== undefined &&
    right !== undefined &&
    String(left.tenantId) === String(right.tenantId) &&
    left.pruningTombstoneSequence === right.pruningTombstoneSequence &&
    left.pruningTombstoneRecordHash === right.pruningTombstoneRecordHash &&
    left.headHash === right.headHash
  );
}

export function buildProjectionReplayCertificateStoreRootWitnessRecord(
  input: ProjectionReplayCertificateStoreRootWitnessRecordInput,
): ProjectionReplayCertificateStoreRootWitnessRecord {
  const payload: Omit<
    ProjectionReplayCertificateStoreRootWitnessRecord,
    "observationHash"
  > = {
    tenantId: tenantId(String(input.observation.tenantId)),
    witnessSequence: input.witnessSequence,
	    observerId: input.observation.observerId,
	    observedAt: input.observation.observedAt,
	    root: input.observation.root,
	    ...(input.observation.consistencyProof !== undefined
	      ? { consistencyProof: input.observation.consistencyProof }
	      : {}),
	    decision: input.decision,
	    accepted: input.decision.accepted,
	    status: input.decision.status,
    ...(input.previousObservationHash !== undefined
      ? { previousObservationHash: input.previousObservationHash }
      : {}),
    recordedAt: input.recordedAt ?? input.observation.observedAt,
  };

  return {
    ...payload,
    observationHash:
      computeProjectionReplayCertificateStoreRootWitnessRecordHash(payload),
  };
}

export function computeProjectionReplayCertificateStoreRootWitnessRecordHash(
  record: Omit<
    ProjectionReplayCertificateStoreRootWitnessRecord,
    "observationHash"
  >,
): string {
  return fingerprint64(canonicalStringify(record));
}

export function replayProjectionReplayCertificateStoreRootWitnessRecords(input: {
  readonly tenantId: TenantId | string;
  readonly records: readonly ProjectionReplayCertificateStoreRootWitnessRecord[];
}): ProjectionReplayCertificateStoreRootWitnessLedgerReplay {
  const tenant = String(input.tenantId);
  const records = [...input.records].sort(
    (a, b) => a.witnessSequence - b.witnessSequence,
  );
  const issues: ProjectionReplayCertificateStoreRootWitnessLedgerIssue[] = [];
  let expectedSequence = 1;
  let expectedPreviousHash: string | undefined;
  let acceptedRoots: readonly ProjectionReplayCertificateStoreRoot[] = [];

  for (const [index, record] of records.entries()) {
    const issueCountBefore = issues.length;
    if (String(record.tenantId) !== tenant) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_ledger_tenant_mismatch",
        path: `/records/${index}/tenantId`,
        message:
          "projection replay certificate store root witness record tenant mismatch",
        expected: tenant,
        actual: String(record.tenantId),
      });
    }
    if (record.witnessSequence !== expectedSequence) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_ledger_sequence_gap",
        path: `/records/${index}/witnessSequence`,
        message:
          "projection replay certificate store root witness records must be contiguous",
        expected: expectedSequence,
        actual: record.witnessSequence,
      });
    }
    if (
      (record.previousObservationHash ?? "") !==
      (expectedPreviousHash ?? "")
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_ledger_previous_hash_mismatch",
        path: `/records/${index}/previousObservationHash`,
        message:
          "projection replay certificate store root witness record does not chain to the prior observation",
        expected: expectedPreviousHash ?? "",
        actual: record.previousObservationHash ?? "",
      });
    }

    const { observationHash, ...recordPayload } = record;
    const expectedObservationHash =
      computeProjectionReplayCertificateStoreRootWitnessRecordHash(
        recordPayload,
      );
    if (observationHash !== expectedObservationHash) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_ledger_hash_mismatch",
        path: `/records/${index}/observationHash`,
        message:
          "projection replay certificate store root witness record hash does not match its body",
        expected: expectedObservationHash,
        actual: observationHash,
      });
    }

    const expectedDecision =
      evaluateProjectionReplayCertificateStoreRootObservation({
        observation: projectionReplayCertificateStoreRootObservationFromRecord(
          record,
        ),
        knownRoots: acceptedRoots,
      });
    if (
      canonicalStringify(record.decision) !== canonicalStringify(expectedDecision)
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_ledger_decision_mismatch",
        path: `/records/${index}/decision`,
        message:
          "projection replay certificate store root witness record decision does not replay from prior accepted observations",
      });
    }

    if (issues.length === issueCountBefore && record.decision.accepted) {
      acceptedRoots = mergeProjectionReplayCertificateStoreRoots(
        acceptedRoots,
        record.decision.acceptedRoots,
      );
    }
    expectedSequence = record.witnessSequence + 1;
    expectedPreviousHash = record.observationHash;
  }

  const sortedAcceptedRoots =
    sortedProjectionReplayCertificateStoreRoots(acceptedRoots);
  const latestRoot = sortedAcceptedRoots[sortedAcceptedRoots.length - 1];
  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    records,
    acceptedRoots: sortedAcceptedRoots,
    ...(latestRoot !== undefined ? { latestRoot } : {}),
    issues,
  };
}

export function buildProjectionReplayCertificateStoreRootWitnessAuthorityTransition(
  input: ProjectionReplayCertificateStoreRootWitnessAuthorityTransitionInput,
): ProjectionReplayCertificateStoreRootWitnessAuthorityTransition {
  const payload: Omit<
    ProjectionReplayCertificateStoreRootWitnessAuthorityTransition,
    "authorityHash"
  > = {
    tenantId: tenantId(String(input.tenantId)),
    authoritySequence: input.authoritySequence,
    transitionId: input.transitionId,
    transitionKind: input.transitionKind,
    recordedAt: input.recordedAt,
    recordedBy: input.recordedBy,
    effectiveFromRootSequence: input.effectiveFromRootSequence,
    ...(input.witnessId !== undefined ? { witnessId: input.witnessId } : {}),
	    ...(input.requiredWitnesses !== undefined
	      ? { requiredWitnesses: input.requiredWitnesses }
	      : {}),
	    ...(input.minimumWitnesses !== undefined
	      ? { minimumWitnesses: input.minimumWitnesses }
	      : {}),
	    ...(input.reason !== undefined ? { reason: input.reason } : {}),
	    ...(input.previousAuthorityHash !== undefined
	      ? { previousAuthorityHash: input.previousAuthorityHash }
	      : {}),
  };

  return {
    ...payload,
    authorityHash:
      computeProjectionReplayCertificateStoreRootWitnessAuthorityTransitionHash(
        payload,
      ),
  };
}

export function computeProjectionReplayCertificateStoreRootWitnessAuthorityTransitionHash(
  transition: Omit<
    ProjectionReplayCertificateStoreRootWitnessAuthorityTransition,
    "authorityHash"
  >,
): string {
  return fingerprint64(canonicalStringify(transition));
}

export function replayProjectionReplayCertificateStoreRootWitnessAuthorityTransitions(input: {
  readonly tenantId: TenantId | string;
  readonly rootSequence: number;
  readonly transitions: readonly ProjectionReplayCertificateStoreRootWitnessAuthorityTransition[];
}): ProjectionReplayCertificateStoreRootWitnessAuthorityTopology {
  const tenant = String(input.tenantId);
  const transitions = [...input.transitions].sort(
    (a, b) => a.authoritySequence - b.authoritySequence,
  );
  const issues: ProjectionReplayCertificateStoreRootWitnessAuthorityIssue[] = [];
  const principals = new Map<
    string,
    ProjectionReplayCertificateStoreRootWitnessPrincipalState
  >();
  let requiredWitnesses: number | undefined;
  let minimumWitnesses: number | undefined;
  let expectedSequence = 1;
  let expectedPreviousHash: string | undefined;
  let latestAuthorityHash: string | undefined;

  if (!Number.isInteger(input.rootSequence) || input.rootSequence < 1) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_authority_transition_invalid",
      path: "/rootSequence",
      message:
        "projection replay root witness authority topology requires a positive root sequence",
      expected: 1,
      actual: input.rootSequence,
    });
  }

  for (const [index, transition] of transitions.entries()) {
    const issueCountBefore = issues.length;
    if (String(transition.tenantId) !== tenant) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_authority_tenant_mismatch",
        path: `/transitions/${index}/tenantId`,
        message:
          "projection replay root witness authority transition tenant mismatch",
        expected: tenant,
        actual: String(transition.tenantId),
      });
    }
    if (transition.authoritySequence !== expectedSequence) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_authority_sequence_gap",
        path: `/transitions/${index}/authoritySequence`,
        message:
          "projection replay root witness authority transitions must be contiguous",
        expected: expectedSequence,
        actual: transition.authoritySequence,
      });
    }
    if (
      (transition.previousAuthorityHash ?? "") !==
      (expectedPreviousHash ?? "")
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_authority_previous_hash_mismatch",
        path: `/transitions/${index}/previousAuthorityHash`,
        message:
          "projection replay root witness authority transition does not chain to the prior transition",
        expected: expectedPreviousHash ?? "",
        actual: transition.previousAuthorityHash ?? "",
      });
    }
    const { authorityHash, ...transitionPayload } = transition;
    const expectedAuthorityHash =
      computeProjectionReplayCertificateStoreRootWitnessAuthorityTransitionHash(
        transitionPayload,
      );
    if (authorityHash !== expectedAuthorityHash) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_authority_hash_mismatch",
        path: `/transitions/${index}/authorityHash`,
        message:
          "projection replay root witness authority transition hash does not match its body",
        expected: expectedAuthorityHash,
        actual: authorityHash,
      });
    }
    if (
      !Number.isInteger(transition.effectiveFromRootSequence) ||
      transition.effectiveFromRootSequence < 1
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_authority_transition_invalid",
        path: `/transitions/${index}/effectiveFromRootSequence`,
        message:
          "projection replay root witness authority transition requires a positive effective root sequence",
        expected: 1,
        actual: transition.effectiveFromRootSequence,
      });
    }

    const transitionIssuesStart = issues.length;
    if (transition.transitionKind === "set_quorum") {
      if (
        !Number.isInteger(transition.requiredWitnesses) ||
        (transition.requiredWitnesses ?? 0) < 1
      ) {
        issues.push({
          code: "projection_replay_certificate_store_root_witness_authority_quorum_invalid",
          path: `/transitions/${index}/requiredWitnesses`,
          message:
            "projection replay root witness authority quorum requires at least one required witness",
          expected: 1,
          actual: transition.requiredWitnesses ?? 0,
        });
      }
      if (
        transition.minimumWitnesses !== undefined &&
        (!Number.isInteger(transition.minimumWitnesses) ||
          transition.minimumWitnesses < 1)
      ) {
        issues.push({
          code: "projection_replay_certificate_store_root_witness_authority_quorum_invalid",
          path: `/transitions/${index}/minimumWitnesses`,
          message:
            "projection replay root witness authority quorum requires a positive minimum witness count",
          expected: 1,
          actual: transition.minimumWitnesses,
        });
      }
      if (
        transition.minimumWitnesses !== undefined &&
        transition.requiredWitnesses !== undefined &&
        transition.minimumWitnesses > transition.requiredWitnesses
      ) {
        issues.push({
          code: "projection_replay_certificate_store_root_witness_authority_quorum_invalid",
          path: `/transitions/${index}/minimumWitnesses`,
          message:
            "projection replay root witness authority quorum minimum cannot exceed required witnesses",
          expected: transition.requiredWitnesses,
          actual: transition.minimumWitnesses,
        });
      }
    } else if (transition.witnessId === undefined || transition.witnessId === "") {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_authority_witness_missing",
        path: `/transitions/${index}/witnessId`,
        message:
          "projection replay root witness authority transition requires a witness id",
      });
    }

    if (
      issues.length === transitionIssuesStart &&
      issues.length === issueCountBefore &&
      transition.effectiveFromRootSequence <= input.rootSequence
    ) {
      applyProjectionReplayCertificateStoreRootWitnessAuthorityTransition({
        transition,
        principals,
        setQuorum: (required, minimum) => {
          requiredWitnesses = required;
          minimumWitnesses = minimum;
        },
      });
    }

    expectedSequence = transition.authoritySequence + 1;
    expectedPreviousHash = transition.authorityHash;
    latestAuthorityHash = transition.authorityHash;
  }

  if (requiredWitnesses === undefined) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_authority_quorum_missing",
      path: "/transitions",
      message:
        "projection replay root witness authority topology requires an effective quorum transition",
    });
  }

  const principalStates = [...principals.values()].sort((a, b) =>
    a.witnessId.localeCompare(b.witnessId),
  );
  const eligibleWitnessIds = principalStates
    .filter(
      (principal) =>
        principal.status === "active" &&
        principal.validFromRootSequence <= input.rootSequence,
    )
    .map((principal) => principal.witnessId)
    .sort((a, b) => a.localeCompare(b));

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    rootSequence: input.rootSequence,
    ...(requiredWitnesses !== undefined ? { requiredWitnesses } : {}),
    ...(minimumWitnesses !== undefined ? { minimumWitnesses } : {}),
    eligibleWitnessIds,
    principals: principalStates,
    transitions,
    ...(latestAuthorityHash !== undefined ? { latestAuthorityHash } : {}),
    issues,
  };
}

function applyProjectionReplayCertificateStoreRootWitnessAuthorityTransition(input: {
  readonly transition: ProjectionReplayCertificateStoreRootWitnessAuthorityTransition;
  readonly principals: Map<
    string,
    ProjectionReplayCertificateStoreRootWitnessPrincipalState
  >;
  readonly setQuorum: (required: number, minimum?: number) => void;
}): void {
  const { transition } = input;
  if (transition.transitionKind === "set_quorum") {
    input.setQuorum(
      transition.requiredWitnesses!,
      transition.minimumWitnesses ?? 1,
    );
    return;
  }
  const witnessId = transition.witnessId!;
  const existing = input.principals.get(witnessId);
  const status = projectionReplayCertificateStoreRootWitnessAuthorityStatusFromTransition(
    transition.transitionKind,
  );
  input.principals.set(witnessId, {
    tenantId: tenantId(String(transition.tenantId)),
    witnessId,
    status,
    validFromRootSequence:
      transition.transitionKind === "admit_witness"
        ? transition.effectiveFromRootSequence
        : existing?.validFromRootSequence ?? transition.effectiveFromRootSequence,
    changedAtAuthoritySequence: transition.authoritySequence,
    ...(transition.transitionKind === "admit_witness"
      ? {
          admittedAt: transition.recordedAt,
          admittedBy: transition.recordedBy,
        }
      : existing?.admittedAt !== undefined
        ? { admittedAt: existing.admittedAt }
        : {}),
    ...(transition.transitionKind !== "admit_witness"
      ? {
          statusChangedAt: transition.recordedAt,
          statusChangedBy: transition.recordedBy,
        }
      : existing?.statusChangedAt !== undefined
        ? {
            statusChangedAt: existing.statusChangedAt,
            ...(existing.statusChangedBy !== undefined
              ? { statusChangedBy: existing.statusChangedBy }
              : {}),
          }
        : {}),
    ...(transition.transitionKind !== "admit_witness" &&
    existing?.admittedBy !== undefined
      ? { admittedBy: existing.admittedBy }
      : {}),
    ...(transition.reason !== undefined ? { reason: transition.reason } : {}),
  });
}

function projectionReplayCertificateStoreRootWitnessAuthorityStatusFromTransition(
  transitionKind: ProjectionReplayCertificateStoreRootWitnessAuthorityTransitionKind,
): ProjectionReplayCertificateStoreRootWitnessPrincipalStatus {
  switch (transitionKind) {
    case "admit_witness":
      return "active";
    case "suspend_witness":
      return "suspended";
    case "revoke_witness":
      return "revoked";
    case "mark_equivocated":
      return "equivocated";
    case "set_quorum":
      return "active";
  }
}

export function evaluateProjectionReplayCertificateStoreRootWitnessSettlement(input: {
  readonly tenantId: TenantId | string;
  readonly root: ProjectionReplayCertificateStoreRoot;
  readonly witnessLedgers: readonly ProjectionReplayCertificateStoreRootWitnessLedgerSnapshot[];
  readonly policy?: ProjectionReplayCertificateStoreRootWitnessSettlementPolicy;
  readonly authorityTopology?: ProjectionReplayCertificateStoreRootWitnessAuthorityTopology;
}): ProjectionReplayCertificateStoreRootWitnessSettlement {
  const tenant = String(input.tenantId);
  const requestedRequiredWitnesses =
    input.authorityTopology?.requiredWitnesses ??
    input.policy?.requiredWitnesses ??
    1;
  const requestedMinimumWitnesses =
    input.authorityTopology?.minimumWitnesses ??
    input.policy?.minimumWitnesses ??
    1;
  const requiredWitnesses = Number.isInteger(requestedRequiredWitnesses)
    ? Math.max(1, requestedRequiredWitnesses)
    : 1;
  const minimumWitnesses = Number.isInteger(requestedMinimumWitnesses)
    ? Math.max(1, requestedMinimumWitnesses)
    : 1;
  const issues: ProjectionReplayCertificateStoreRootWitnessSettlementIssue[] = [];
  const acceptedWitnessIds = new Set<string>();
  const obstructingWitnessIds = new Set<string>();
  const invalidWitnessIds = new Set<string>();
  const validWitnessIds = new Set<string>();
  const countedWitnessIds = new Set<string>();
  const topology = input.authorityTopology;
  const topologyEligibleWitnessIds = new Set(topology?.eligibleWitnessIds ?? []);
  let authorityTopologyInvalid = false;

  if (!Number.isInteger(requestedRequiredWitnesses) || requestedRequiredWitnesses < 1) {
    issues.push({
      code: "projection_replay_certificate_store_root_settlement_invalid_policy",
      path: "/policy/requiredWitnesses",
      message:
        "projection replay root witness settlement requires at least one required witness",
      expected: 1,
      actual: requestedRequiredWitnesses,
    });
  }
  if (!Number.isInteger(requestedMinimumWitnesses) || requestedMinimumWitnesses < 1) {
    issues.push({
      code: "projection_replay_certificate_store_root_settlement_invalid_policy",
      path: "/policy/minimumWitnesses",
      message:
        "projection replay root witness settlement requires at least one minimum witness",
      expected: 1,
      actual: requestedMinimumWitnesses,
    });
  }
  if (
    Number.isInteger(requestedRequiredWitnesses) &&
    Number.isInteger(requestedMinimumWitnesses) &&
    requestedMinimumWitnesses > requestedRequiredWitnesses
  ) {
    issues.push({
      code: "projection_replay_certificate_store_root_settlement_invalid_policy",
      path: "/policy/minimumWitnesses",
      message:
        "projection replay root witness settlement minimum cannot exceed required witnesses",
      expected: requestedRequiredWitnesses,
      actual: requestedMinimumWitnesses,
    });
  }
  if (String(input.root.tenantId) !== tenant) {
    issues.push({
      code: "projection_replay_certificate_store_root_settlement_root_tenant_mismatch",
      path: "/root/tenantId",
      message:
        "projection replay root witness settlement root tenant does not match the settlement tenant",
      expected: tenant,
      actual: String(input.root.tenantId),
    });
  }
  if (topology !== undefined) {
    if (!topology.valid) {
      authorityTopologyInvalid = true;
      issues.push({
        code: "projection_replay_certificate_store_root_settlement_authority_topology_invalid",
        path: "/authorityTopology",
        message:
          "projection replay root witness settlement cannot use an invalid witness authority topology",
        actual: topology.issues.map((issue) => issue.code).join(", "),
      });
    }
    if (String(topology.tenantId) !== tenant) {
      authorityTopologyInvalid = true;
      issues.push({
        code: "projection_replay_certificate_store_root_settlement_authority_topology_invalid",
        path: "/authorityTopology/tenantId",
        message:
          "projection replay root witness settlement authority topology tenant does not match the settlement tenant",
        expected: tenant,
        actual: String(topology.tenantId),
      });
    }
    if (topology.rootSequence !== input.root.sequence) {
      authorityTopologyInvalid = true;
      issues.push({
        code: "projection_replay_certificate_store_root_settlement_authority_topology_invalid",
        path: "/authorityTopology/rootSequence",
        message:
          "projection replay root witness settlement authority topology must be replayed for the root sequence being settled",
        expected: input.root.sequence,
        actual: topology.rootSequence,
      });
    }
    if (
      input.policy !== undefined &&
      (input.policy.requiredWitnesses !== topology.requiredWitnesses ||
        (input.policy.minimumWitnesses ?? 1) !==
          (topology.minimumWitnesses ?? 1))
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_settlement_policy_authority_mismatch",
        path: "/policy",
        message:
          "projection replay root witness settlement policy must match the replayed witness authority topology",
        expected: `${topology.requiredWitnesses ?? ""}:${
          topology.minimumWitnesses ?? 1
        }`,
        actual: `${input.policy.requiredWitnesses}:${
          input.policy.minimumWitnesses ?? 1
        }`,
      });
    }
  }

  for (const [index, witness] of input.witnessLedgers.entries()) {
    const witnessId = witness.witnessId;
    const countWitness = !countedWitnessIds.has(witnessId);
    if (!countWitness) {
      issues.push({
        code: "projection_replay_certificate_store_root_settlement_duplicate_witness",
        path: `/witnessLedgers/${index}/witnessId`,
        message:
          "projection replay root witness settlement cannot count the same witness twice",
        actual: witnessId,
      });
    }
    countedWitnessIds.add(witnessId);

    if (authorityTopologyInvalid) {
      invalidWitnessIds.add(witnessId);
      continue;
    }
    if (
      topology !== undefined &&
      (!topologyEligibleWitnessIds.has(witnessId) || !countWitness)
    ) {
      invalidWitnessIds.add(witnessId);
      if (countWitness) {
        issues.push({
          code: "projection_replay_certificate_store_root_settlement_witness_not_authorized",
          path: `/witnessLedgers/${index}/witnessId`,
          message:
            "projection replay root witness settlement cannot count a witness outside the replayed authority topology",
          expected: topology.eligibleWitnessIds.join(", "),
          actual: witnessId,
        });
      }
      continue;
    }

    if (!witness.replay.valid) {
      invalidWitnessIds.add(witnessId);
      issues.push({
        code: "projection_replay_certificate_store_root_settlement_witness_replay_invalid",
        path: `/witnessLedgers/${index}/replay`,
        message:
          "projection replay root witness settlement cannot count a witness ledger that fails replay",
        actual: witness.replay.issues.map((issue) => issue.code).join(", "),
      });
      continue;
    }
    if (String(witness.replay.tenantId) !== tenant) {
      invalidWitnessIds.add(witnessId);
      issues.push({
        code: "projection_replay_certificate_store_root_settlement_witness_tenant_mismatch",
        path: `/witnessLedgers/${index}/replay/tenantId`,
        message:
          "projection replay root witness settlement cannot count a witness ledger from another tenant",
        expected: tenant,
        actual: String(witness.replay.tenantId),
      });
      continue;
    }

    validWitnessIds.add(witnessId);
    const acceptedTarget = witness.replay.acceptedRoots.some((root) =>
      sameProjectionReplayCertificateStoreRoot(root, input.root),
    );
    const conflictingAcceptedRoot = witness.replay.acceptedRoots.find((root) =>
      conflictsWithProjectionReplayCertificateStoreRoot(root, input.root),
    );
    const forkObstruction = witness.replay.records.find((record) =>
      projectionReplayCertificateStoreRootWitnessRecordObstructsSettlement({
        record,
        root: input.root,
      }),
    );

    if (conflictingAcceptedRoot !== undefined || forkObstruction !== undefined) {
      const conflictingRootHash =
        conflictingAcceptedRoot?.rootHash ??
        forkObstruction?.decision.obstruction?.conflictingRoot?.rootHash ??
        forkObstruction?.root.rootHash ??
        "";
      obstructingWitnessIds.add(witnessId);
      issues.push({
        code: "projection_replay_certificate_store_root_settlement_conflicting_root",
        path: `/witnessLedgers/${index}/replay/acceptedRoots`,
        message:
          "projection replay root witness settlement found a valid witness history for a conflicting root at the same sequence",
        expected: input.root.rootHash,
        actual: conflictingRootHash,
      });
    }

    if (acceptedTarget && countWitness) {
      acceptedWitnessIds.add(witnessId);
    }
  }

  if (validWitnessIds.size === 0) {
    issues.push({
      code: "projection_replay_certificate_store_root_settlement_no_valid_witnesses",
      path: "/witnessLedgers",
      message:
        "projection replay root witness settlement requires at least one valid replayed witness ledger",
      expected: 1,
      actual: 0,
    });
  }

  const invalidPolicy = issues.some(
    (issue) =>
      issue.code ===
        "projection_replay_certificate_store_root_settlement_invalid_policy" ||
      issue.code ===
        "projection_replay_certificate_store_root_settlement_policy_authority_mismatch",
  );
  const tenantMismatch = issues.some(
    (issue) =>
      issue.code ===
      "projection_replay_certificate_store_root_settlement_root_tenant_mismatch",
  );
  const acceptedCount = acceptedWitnessIds.size;
  const quorumMet = acceptedCount >= requiredWitnesses;
  if (
    !invalidPolicy &&
    !tenantMismatch &&
    obstructingWitnessIds.size === 0 &&
    !quorumMet
  ) {
    issues.push({
      code: "projection_replay_certificate_store_root_settlement_quorum_not_met",
      path: "/acceptedWitnessIds",
      message:
        "projection replay root witness settlement has not reached the required witness quorum",
      expected: requiredWitnesses,
      actual: acceptedCount,
    });
  }

  const status: ProjectionReplayCertificateStoreRootWitnessSettlementStatus =
    invalidPolicy ||
    tenantMismatch ||
    authorityTopologyInvalid ||
    obstructingWitnessIds.size > 0
      ? "obstructed"
      : quorumMet
        ? "settled"
        : acceptedCount >= minimumWitnesses
          ? "witnessed"
          : "provisional";

  const allowedAction:
    | ProjectionReplayCertificateStoreRootWitnessSettlementAllowedAction
    | undefined =
    authorityTopologyInvalid
      ? "correct_authority_topology"
      : invalidPolicy || tenantMismatch
      ? "correct_settlement_policy"
      : obstructingWitnessIds.size > 0
        ? "resolve_root_conflict"
        : status === "settled"
          ? undefined
          : "collect_more_witnesses";

  return buildProjectionReplayCertificateStoreRootWitnessSettlement({
    tenantId: tenantId(tenant),
    root: input.root,
    status,
    acceptedWitnessIds: sortedUniqueStrings([...acceptedWitnessIds]),
    obstructingWitnessIds: sortedUniqueStrings([...obstructingWitnessIds]),
    invalidWitnessIds: sortedUniqueStrings([...invalidWitnessIds]),
    ...(topology !== undefined
      ? {
          eligibleWitnessIds: sortedUniqueStrings([...topologyEligibleWitnessIds]),
        }
      : {}),
    ...(topology?.latestAuthorityHash !== undefined
      ? { authorityTopologyHash: topology.latestAuthorityHash }
      : {}),
    requiredWitnesses,
    minimumWitnesses,
    issues,
    authorityBoundary:
      "projection_replay_certificate_store_root_witness_settlement",
    ...(allowedAction !== undefined ? { allowedAction } : {}),
  });
}

function buildProjectionReplayCertificateStoreRootWitnessSettlement(
  input: Omit<
    ProjectionReplayCertificateStoreRootWitnessSettlement,
    "settlementHash"
  >,
): ProjectionReplayCertificateStoreRootWitnessSettlement {
  return {
    ...input,
    settlementHash:
      computeProjectionReplayCertificateStoreRootWitnessSettlementHash(input),
  };
}

export function computeProjectionReplayCertificateStoreRootWitnessSettlementHash(
  settlement: Omit<
    ProjectionReplayCertificateStoreRootWitnessSettlement,
    "settlementHash"
  >,
): string {
  return fingerprint64(canonicalStringify(settlement));
}

export function buildProjectionReplayCertificateStoreRootWitnessSettlementRecord(
  input: ProjectionReplayCertificateStoreRootWitnessSettlementRecordInput,
): ProjectionReplayCertificateStoreRootWitnessSettlementRecord {
  const payload: Omit<
    ProjectionReplayCertificateStoreRootWitnessSettlementRecord,
    "settlementRecordHash"
  > = {
    tenantId: tenantId(String(input.settlement.tenantId)),
    settlementSequence: input.settlementSequence,
    root: input.settlement.root,
    settlement: input.settlement,
    ...(input.previousSettlementRecordHash !== undefined
      ? { previousSettlementRecordHash: input.previousSettlementRecordHash }
      : {}),
    recordedAt: input.recordedAt ?? input.settlement.root.recordedAt,
  };

  return {
    ...payload,
    settlementRecordHash:
      computeProjectionReplayCertificateStoreRootWitnessSettlementRecordHash(
        payload,
      ),
  };
}

export function computeProjectionReplayCertificateStoreRootWitnessSettlementRecordHash(
  record: Omit<
    ProjectionReplayCertificateStoreRootWitnessSettlementRecord,
    "settlementRecordHash"
  >,
): string {
  return fingerprint64(canonicalStringify(record));
}

export function projectionReplayCertificateStoreRootWitnessSettlementStoreHeadFromRecord(
  record: ProjectionReplayCertificateStoreRootWitnessSettlementRecord,
): ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead {
  const payload: Omit<
    ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead,
    "headHash"
  > = {
    tenantId: record.tenantId,
    settlementSequence: record.settlementSequence,
    settlementRecordHash: record.settlementRecordHash,
    recordedAt: record.recordedAt,
  };
  return {
    ...payload,
    headHash:
      computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadHash(
        payload,
      ),
  };
}

export function computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadHash(
  head: Omit<
    ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead,
    "headHash"
  >,
): string {
  return fingerprint64(canonicalStringify(head));
}

export function verifyProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadConsistencyProof(
  proof: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadConsistencyProof,
): {
  readonly valid: boolean;
  readonly issues: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessIssue[];
  readonly acceptedHeads: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead[];
} {
  const issues: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessIssue[] =
    [];
  const tenant = String(proof.tenantId);
  const records = [...proof.records].sort(
    (a, b) => a.settlementSequence - b.settlementSequence,
  );
  if (String(proof.toHead.tenantId) !== tenant) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_consistency_proof_invalid",
      path: "/toHead/tenantId",
      message:
        "projection replay settlement store head consistency proof toHead tenant mismatch",
      expected: tenant,
      actual: String(proof.toHead.tenantId),
    });
  }
  if (
    proof.fromHead !== undefined &&
    String(proof.fromHead.tenantId) !== tenant
  ) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_consistency_proof_invalid",
      path: "/fromHead/tenantId",
      message:
        "projection replay settlement store head consistency proof fromHead tenant mismatch",
      expected: tenant,
      actual: String(proof.fromHead.tenantId),
    });
  }
  const toHeadHash = computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadHash(
    {
      tenantId: proof.toHead.tenantId,
      settlementSequence: proof.toHead.settlementSequence,
      settlementRecordHash: proof.toHead.settlementRecordHash,
      recordedAt: proof.toHead.recordedAt,
    },
  );
  if (proof.toHead.headHash !== toHeadHash) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_hash_mismatch",
      path: "/toHead/headHash",
      message:
        "projection replay settlement store head hash does not match its body",
      expected: toHeadHash,
      actual: proof.toHead.headHash,
    });
  }
  if (proof.fromHead !== undefined) {
    const fromHeadHash =
      computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadHash(
        {
          tenantId: proof.fromHead.tenantId,
          settlementSequence: proof.fromHead.settlementSequence,
          settlementRecordHash: proof.fromHead.settlementRecordHash,
          recordedAt: proof.fromHead.recordedAt,
        },
      );
    if (proof.fromHead.headHash !== fromHeadHash) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_hash_mismatch",
        path: "/fromHead/headHash",
        message:
          "projection replay settlement store head fromHead hash does not match its body",
        expected: fromHeadHash,
        actual: proof.fromHead.headHash,
      });
    }
  }
  if (records.length === 0) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_consistency_proof_invalid",
      path: "/records",
      message:
        "projection replay settlement store head consistency proof contains no settlement records",
    });
    return { valid: false, issues, acceptedHeads: [] };
  }

  let expectedSequence =
    proof.fromHead === undefined ? 1 : proof.fromHead.settlementSequence + 1;
  let expectedPreviousHash = proof.fromHead?.settlementRecordHash;
  const acceptedHeads: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead[] =
    [];

  for (const [index, record] of records.entries()) {
    const recordPath = `/records/${index}`;
    if (String(record.tenantId) !== tenant) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_consistency_proof_invalid",
        path: `${recordPath}/tenantId`,
        message:
          "projection replay settlement store head consistency proof record tenant mismatch",
        expected: tenant,
        actual: String(record.tenantId),
      });
    }
    if (String(record.settlement.tenantId) !== tenant) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_consistency_proof_invalid",
        path: `${recordPath}/settlement/tenantId`,
        message:
          "projection replay settlement store head consistency proof cannot contain a settlement for another tenant",
        expected: tenant,
        actual: String(record.settlement.tenantId),
      });
    }
    if (record.settlementSequence !== expectedSequence) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_consistency_proof_invalid",
        path: `${recordPath}/settlementSequence`,
        message:
          "projection replay settlement store head consistency proof records must be contiguous",
        expected: expectedSequence,
        actual: record.settlementSequence,
      });
    }
    if (
      (record.previousSettlementRecordHash ?? "") !==
      (expectedPreviousHash ?? "")
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_consistency_proof_invalid",
        path: `${recordPath}/previousSettlementRecordHash`,
        message:
          "projection replay settlement store head consistency proof record does not chain to the prior head",
        expected: expectedPreviousHash ?? "",
        actual: record.previousSettlementRecordHash ?? "",
      });
    }
    if (!sameProjectionReplayCertificateStoreRoot(record.root, record.settlement.root)) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_consistency_proof_invalid",
        path: `${recordPath}/root`,
        message:
          "projection replay settlement store head consistency proof record root must match settlement root",
        expected: record.settlement.root.rootHash,
        actual: record.root.rootHash,
      });
    }

    const { settlementHash, ...settlementPayload } = record.settlement;
    const expectedSettlementHash =
      computeProjectionReplayCertificateStoreRootWitnessSettlementHash(
        settlementPayload,
      );
    if (settlementHash !== expectedSettlementHash) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_consistency_proof_invalid",
        path: `${recordPath}/settlement/settlementHash`,
        message:
          "projection replay settlement store head consistency proof settlement hash mismatch",
        expected: expectedSettlementHash,
        actual: settlementHash,
      });
    }

    const { settlementRecordHash, ...recordPayload } = record;
    const expectedRecordHash =
      computeProjectionReplayCertificateStoreRootWitnessSettlementRecordHash(
        recordPayload,
      );
    if (settlementRecordHash !== expectedRecordHash) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_consistency_proof_invalid",
        path: `${recordPath}/settlementRecordHash`,
        message:
          "projection replay settlement store head consistency proof record hash mismatch",
        expected: expectedRecordHash,
        actual: settlementRecordHash,
      });
    }

    acceptedHeads.push(
      projectionReplayCertificateStoreRootWitnessSettlementStoreHeadFromRecord(
        record,
      ),
    );
    expectedSequence = record.settlementSequence + 1;
    expectedPreviousHash = record.settlementRecordHash;
  }

  const lastHead = acceptedHeads[acceptedHeads.length - 1];
  if (
    lastHead === undefined ||
    !sameProjectionReplayCertificateStoreRootWitnessSettlementStoreHead(
      lastHead,
      proof.toHead,
    )
  ) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_consistency_proof_invalid",
      path: "/toHead",
      message:
        "projection replay settlement store head consistency proof does not end at the declared toHead",
      expected: `${proof.toHead.settlementSequence}:${proof.toHead.settlementRecordHash}`,
      actual:
        lastHead === undefined
          ? ""
          : `${lastHead.settlementSequence}:${lastHead.settlementRecordHash}`,
    });
  }

  return {
    valid: issues.length === 0,
    issues,
    acceptedHeads,
  };
}

export function evaluateProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservation(input: {
  readonly observation: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservationInput;
  readonly knownHeads: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead[];
}): ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessDecision {
  const { observation } = input;
  const tenant = String(observation.tenantId);
  const observedHead = observation.head;
  const knownHeads =
    sortedProjectionReplayCertificateStoreRootWitnessSettlementStoreHeads(
      input.knownHeads.filter((head) => String(head.tenantId) === tenant),
    );
  const latestHead = knownHeads[knownHeads.length - 1];
  const observedHeadHash =
    computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadHash({
      tenantId: observedHead.tenantId,
      settlementSequence: observedHead.settlementSequence,
      settlementRecordHash: observedHead.settlementRecordHash,
      recordedAt: observedHead.recordedAt,
    });

  if (String(observedHead.tenantId) !== tenant) {
    return obstructProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservation(
      {
        observation,
        ...(latestHead !== undefined ? { latestHead } : {}),
        issues: [
          {
            code: "projection_replay_certificate_store_root_witness_settlement_store_head_tenant_mismatch",
            path: "/head/tenantId",
            message:
              "projection replay settlement store head tenant does not match the observation tenant",
            expected: tenant,
            actual: String(observedHead.tenantId),
          },
        ],
      },
    );
  }
  if (observedHead.headHash !== observedHeadHash) {
    return obstructProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservation(
      {
        observation,
        ...(latestHead !== undefined ? { latestHead } : {}),
        issues: [
          {
            code: "projection_replay_certificate_store_root_witness_settlement_store_head_hash_mismatch",
            path: "/head/headHash",
            message:
              "projection replay settlement store head hash does not match its body",
            expected: observedHeadHash,
            actual: observedHead.headHash,
          },
        ],
      },
    );
  }

  const knownAtSequence = knownHeads.find(
    (head) => head.settlementSequence === observedHead.settlementSequence,
  );
  if (knownAtSequence !== undefined) {
    if (
      sameProjectionReplayCertificateStoreRootWitnessSettlementStoreHead(
        knownAtSequence,
        observedHead,
      )
    ) {
      if (
        latestHead !== undefined &&
        observedHead.settlementSequence < latestHead.settlementSequence
      ) {
        return obstructProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservation(
          {
            observation,
            latestHead,
            issues: [
              {
                code: "projection_replay_certificate_store_root_witness_settlement_store_head_regression",
                path: "/head/settlementSequence",
                message:
                  "projection replay settlement store head is older than the latest witnessed settlement head",
                expected: latestHead.settlementSequence,
                actual: observedHead.settlementSequence,
              },
            ],
          },
        );
      }
      return acceptedProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservation(
        {
          observation,
          status: "accepted_duplicate",
          latestHead: latestHead ?? observedHead,
          acceptedHeads: [observedHead],
        },
      );
    }
    return obstructProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservation(
      {
        observation,
        ...(latestHead !== undefined ? { latestHead } : {}),
        conflictingHead: knownAtSequence,
        issues: [
          {
            code: "projection_replay_certificate_store_root_witness_settlement_store_head_fork",
            path: "/head/settlementRecordHash",
            message:
              "projection replay settlement store head conflicts with an already witnessed head at the same settlement sequence",
            expected: knownAtSequence.settlementRecordHash,
            actual: observedHead.settlementRecordHash,
          },
        ],
      },
    );
  }

  if (latestHead === undefined) {
    const proof = observation.consistencyProof;
    if (observedHead.settlementSequence === 1 && proof === undefined) {
      return acceptedProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservation(
        {
          observation,
          status: "accepted_initial",
          latestHead: observedHead,
          acceptedHeads: [observedHead],
        },
      );
    }
    if (proof === undefined) {
      return obstructProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservation(
        {
          observation,
          issues: [
            {
              code: "projection_replay_certificate_store_root_witness_settlement_store_head_consistency_proof_missing",
              path: "/consistencyProof",
              message:
                "first settlement store head observation after sequence 1 requires a consistency proof from the beginning of the settlement store",
              expected: 1,
              actual: observedHead.settlementSequence,
            },
          ],
        },
      );
    }
    const proofIssues =
      validateProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadProof({
        tenant,
        observedHead,
        proof,
      });
    if (proofIssues.length > 0) {
      return obstructProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservation(
        { observation, issues: proofIssues },
      );
    }
    const proofVerification =
      verifyProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadConsistencyProof(
        proof,
      );
    return acceptedProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservation(
      {
        observation,
        status: "accepted_initial",
        latestHead: observedHead,
        acceptedHeads: proofVerification.acceptedHeads,
      },
    );
  }

  if (observedHead.settlementSequence < latestHead.settlementSequence) {
    return obstructProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservation(
      {
        observation,
        latestHead,
        issues: [
          {
            code: "projection_replay_certificate_store_root_witness_settlement_store_head_regression",
            path: "/head/settlementSequence",
            message:
              "projection replay settlement store head regresses behind the latest witnessed settlement head",
            expected: latestHead.settlementSequence,
            actual: observedHead.settlementSequence,
          },
        ],
      },
    );
  }

  const proof = observation.consistencyProof;
  if (proof === undefined) {
    return obstructProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservation(
      {
        observation,
        latestHead,
        issues: [
          {
            code: "projection_replay_certificate_store_root_witness_settlement_store_head_consistency_proof_missing",
            path: "/consistencyProof",
            message:
              "projection replay settlement store head advance requires a consistency proof from the latest witnessed settlement head",
            expected: latestHead.settlementSequence,
            actual: observedHead.settlementSequence,
          },
        ],
      },
    );
  }

  const proofIssues =
    validateProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadProof({
      tenant,
      observedHead,
      proof,
      expectedFromHead: latestHead,
    });
  if (proofIssues.length > 0) {
    return obstructProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservation(
      {
        observation,
        latestHead,
        issues: proofIssues,
      },
    );
  }

  const proofVerification =
    verifyProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadConsistencyProof(
      proof,
    );
  return acceptedProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservation(
    {
      observation,
      status: "accepted_advance",
      latestHead: observedHead,
      acceptedHeads: proofVerification.acceptedHeads,
    },
  );
}

function validateProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadProof(input: {
  readonly tenant: string;
  readonly observedHead: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead;
  readonly proof: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadConsistencyProof;
  readonly expectedFromHead?: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead;
}): ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessIssue[] {
  const issues: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessIssue[] =
    [];
  const { proof } = input;

  if (String(proof.tenantId) !== input.tenant) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_consistency_proof_invalid",
      path: "/consistencyProof/tenantId",
      message:
        "projection replay settlement store head consistency proof tenant does not match the head observation",
      expected: input.tenant,
      actual: String(proof.tenantId),
    });
  }
  if (
    !sameProjectionReplayCertificateStoreRootWitnessSettlementStoreHead(
      proof.toHead,
      input.observedHead,
    )
  ) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_consistency_proof_invalid",
      path: "/consistencyProof/toHead",
      message:
        "projection replay settlement store head consistency proof does not end at the observed head",
      expected: input.observedHead.headHash,
      actual: proof.toHead.headHash,
    });
  }
  if (
    input.expectedFromHead === undefined &&
    proof.fromHead !== undefined
  ) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_consistency_proof_invalid",
      path: "/consistencyProof/fromHead",
      message:
        "first settlement store head witness observation must prove the head from the beginning of the settlement store",
      actual: proof.fromHead.headHash,
    });
  }
  if (
    input.expectedFromHead !== undefined &&
    !sameProjectionReplayCertificateStoreRootWitnessSettlementStoreHead(
      proof.fromHead,
      input.expectedFromHead,
    )
  ) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_consistency_proof_invalid",
      path: "/consistencyProof/fromHead",
      message:
        "projection replay settlement store head consistency proof must start at the latest witnessed settlement head",
      expected: input.expectedFromHead.headHash,
      actual: proof.fromHead?.headHash ?? "",
    });
  }

  const proofVerification =
    verifyProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadConsistencyProof(
      proof,
    );
  if (!proofVerification.valid) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_consistency_proof_invalid",
      path: "/consistencyProof/records",
      message: `projection replay settlement store head consistency proof failed record verification: ${proofVerification.issues
        .map((issue) => issue.code)
        .join(", ")}`,
    });
  }

  return issues;
}

function acceptedProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservation(input: {
  readonly observation: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservationInput;
  readonly status: Exclude<
    ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessStatus,
    "obstructed"
  >;
  readonly latestHead: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead;
  readonly acceptedHeads: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead[];
}): ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessDecision {
  return {
    accepted: true,
    status: input.status,
    observerId: input.observation.observerId,
    observedHead: input.observation.head,
    latestHead: input.latestHead,
    acceptedHeads:
      sortedProjectionReplayCertificateStoreRootWitnessSettlementStoreHeads(
        input.acceptedHeads,
      ),
    issues: [],
  };
}

function obstructProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservation(input: {
  readonly observation: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservationInput;
  readonly latestHead?: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead;
  readonly conflictingHead?: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead;
  readonly issues: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessIssue[];
}): ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessDecision {
  const obstruction =
    buildProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObstruction(
      input,
    );
  return {
    accepted: false,
    status: "obstructed",
    observerId: input.observation.observerId,
    observedHead: input.observation.head,
    ...(input.latestHead !== undefined ? { latestHead: input.latestHead } : {}),
    acceptedHeads: [],
    issues: input.issues,
    obstruction,
  };
}

function buildProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObstruction(input: {
  readonly observation: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservationInput;
  readonly latestHead?: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead;
  readonly conflictingHead?: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead;
  readonly issues: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessIssue[];
}): ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObstructionArtifact {
  const payload = {
    tenantId: input.observation.tenantId,
    observerId: input.observation.observerId,
    observedHead: input.observation.head,
    ...(input.latestHead !== undefined ? { latestHead: input.latestHead } : {}),
    ...(input.conflictingHead !== undefined
      ? { conflictingHead: input.conflictingHead }
      : {}),
    issues: input.issues,
  };
  return {
    artifactId: `projection_replay_settlement_store_head_obstruction_${fingerprint64(
      canonicalStringify(payload),
    )}`,
    tenantId: input.observation.head.tenantId,
    generatedAt: input.observation.observedAt,
    observerId: input.observation.observerId,
    observedHead: input.observation.head,
    ...(input.latestHead !== undefined ? { latestHead: input.latestHead } : {}),
    ...(input.conflictingHead !== undefined
      ? { conflictingHead: input.conflictingHead }
      : {}),
    issues: input.issues,
    allowedAction: "request_settlement_store_head_consistency_proof",
  };
}

export function buildProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessRecord(
  input: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessRecordInput,
): ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessRecord {
  const payload: Omit<
    ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessRecord,
    "observationHash"
  > = {
	    tenantId: tenantId(String(input.observation.tenantId)),
	    witnessSequence: input.witnessSequence,
	    observerId: input.observation.observerId,
	    observedAt: input.observation.observedAt,
	    head: input.observation.head,
	    ...(input.observation.consistencyProof !== undefined
	      ? { consistencyProof: input.observation.consistencyProof }
	      : {}),
	    ...(input.observation.signature !== undefined
	      ? { signature: input.observation.signature }
	      : {}),
	    decision: input.decision,
	    accepted: input.decision.accepted,
	    status: input.decision.status,
    ...(input.previousObservationHash !== undefined
      ? { previousObservationHash: input.previousObservationHash }
      : {}),
    recordedAt: input.recordedAt ?? input.observation.observedAt,
  };

  return {
    ...payload,
    observationHash:
      computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessRecordHash(
        payload,
      ),
  };
}

export function computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessRecordHash(
  record: Omit<
    ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessRecord,
    "observationHash"
  >,
): string {
  return fingerprint64(canonicalStringify(record));
}

export function computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessObservationSignaturePayloadHash(
  observation: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservationInput,
): string {
  return fingerprint64(
    canonicalStringify({
      tenantId: tenantId(String(observation.tenantId)),
      observerId: observation.observerId,
      observedAt: observation.observedAt,
      head: observation.head,
      ...(observation.consistencyProof !== undefined
        ? { consistencyProof: observation.consistencyProof }
        : {}),
    }),
  );
}

export function replayProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessRecords(input: {
  readonly tenantId: TenantId | string;
  readonly records: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessRecord[];
  readonly signaturePolicy?: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessSignaturePolicy;
  readonly compactionCheckpoint?: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionCheckpoint;
  readonly compactionCheckpointAdmission?: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionCheckpointAdmissionCertificate;
}): ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessLedgerReplay {
  const tenant = String(input.tenantId);
  const records = [...input.records].sort(
    (a, b) => a.witnessSequence - b.witnessSequence,
  );
  const issues: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessLedgerIssue[] =
    [];
  let expectedSequence = 1;
  let expectedPreviousHash: string | undefined;
  let acceptedHeads: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead[] =
    [];
  const witnessCheckpoint = input.compactionCheckpoint?.witnessLedger;
  if (witnessCheckpoint !== undefined) {
    const admissionValidation =
      validateProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionCheckpointAdmission(
        {
          tenantId: input.tenantId,
          checkpoint: input.compactionCheckpoint!,
          ...(input.compactionCheckpointAdmission !== undefined
            ? { admission: input.compactionCheckpointAdmission }
            : {}),
          ...(input.signaturePolicy !== undefined
            ? { signaturePolicy: input.signaturePolicy }
            : {}),
        },
      );
    if (!admissionValidation.valid) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_ledger_compaction_checkpoint_invalid",
        path: "/compactionCheckpointAdmission",
        message: admissionValidation.message,
      });
    }
    const checkpointValidation =
      verifyProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionCheckpointHash(
        input.compactionCheckpoint!,
      );
    if (!checkpointValidation.valid) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_ledger_compaction_checkpoint_invalid",
        path: "/compactionCheckpoint/checkpointHash",
        message:
          "projection replay settlement-store head witness ledger compaction checkpoint hash does not match its body",
        expected: checkpointValidation.expectedHash,
        actual: input.compactionCheckpoint!.checkpointHash,
      });
    }
    if (
      String(input.compactionCheckpoint!.tenantId) !== tenant ||
      String(witnessCheckpoint.tenantId) !== tenant
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_ledger_compaction_checkpoint_invalid",
        path: "/compactionCheckpoint/tenantId",
        message:
          "projection replay settlement-store head witness ledger compaction checkpoint tenant mismatch",
        expected: tenant,
        actual: String(input.compactionCheckpoint!.tenantId),
      });
    }
    if (
      !Number.isInteger(witnessCheckpoint.compactedThroughWitnessSequence) ||
      witnessCheckpoint.compactedThroughWitnessSequence < 1 ||
      witnessCheckpoint.compactedThroughObservationHash === ""
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_ledger_compaction_checkpoint_invalid",
        path: "/compactionCheckpoint/witnessLedger",
        message:
          "projection replay settlement-store head witness ledger compaction checkpoint requires a positive compacted witness sequence and observation hash",
        actual: `${witnessCheckpoint.compactedThroughWitnessSequence}:${witnessCheckpoint.compactedThroughObservationHash}`,
      });
    }
    if (issues.length === 0) {
      expectedSequence =
        witnessCheckpoint.compactedThroughWitnessSequence + 1;
      expectedPreviousHash =
        witnessCheckpoint.compactedThroughObservationHash;
      acceptedHeads = witnessCheckpoint.acceptedHeads;
    }
  }

  for (const [index, record] of records.entries()) {
    const issueCountBefore = issues.length;
    if (String(record.tenantId) !== tenant) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_ledger_tenant_mismatch",
        path: `/records/${index}/tenantId`,
        message:
          "projection replay settlement store head witness record tenant mismatch",
        expected: tenant,
        actual: String(record.tenantId),
      });
    }
    if (record.witnessSequence !== expectedSequence) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_ledger_sequence_gap",
        path: `/records/${index}/witnessSequence`,
        message:
          "projection replay settlement store head witness records must be contiguous",
        expected: expectedSequence,
        actual: record.witnessSequence,
      });
    }
    if (
      (record.previousObservationHash ?? "") !==
      (expectedPreviousHash ?? "")
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_ledger_previous_hash_mismatch",
        path: `/records/${index}/previousObservationHash`,
        message:
          "projection replay settlement store head witness record does not chain to the prior observation",
        expected: expectedPreviousHash ?? "",
        actual: record.previousObservationHash ?? "",
      });
    }

    const { observationHash, ...recordPayload } = record;
    const expectedObservationHash =
      computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessRecordHash(
        recordPayload,
      );
    if (observationHash !== expectedObservationHash) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_ledger_hash_mismatch",
        path: `/records/${index}/observationHash`,
        message:
          "projection replay settlement store head witness record hash does not match its body",
        expected: expectedObservationHash,
        actual: observationHash,
      });
    }

    const expectedDecision =
      evaluateProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservation(
        {
          observation:
            projectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservationFromRecord(
              record,
            ),
          knownHeads: acceptedHeads,
        },
      );
    if (
      canonicalStringify(record.decision) !== canonicalStringify(expectedDecision)
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_ledger_decision_mismatch",
        path: `/records/${index}/decision`,
        message:
          "projection replay settlement store head witness record decision does not replay from prior accepted observations",
      });
    }

    appendProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessRecordSignatureIssues(
      {
        issues,
        path: `/records/${index}/signature`,
        tenantId: tenant,
        record,
        ...(input.signaturePolicy !== undefined
          ? { signaturePolicy: input.signaturePolicy }
          : {}),
      },
    );

    if (issues.length === issueCountBefore && record.decision.accepted) {
      acceptedHeads =
        mergeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeads(
          acceptedHeads,
          record.decision.acceptedHeads,
        );
    }
    expectedSequence = record.witnessSequence + 1;
    expectedPreviousHash = record.observationHash;
  }

  const sortedAcceptedHeads =
    sortedProjectionReplayCertificateStoreRootWitnessSettlementStoreHeads(
      acceptedHeads,
    );
  const latestHead = sortedAcceptedHeads[sortedAcceptedHeads.length - 1];
  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    records,
    acceptedHeads: sortedAcceptedHeads,
    ...(latestHead !== undefined ? { latestHead } : {}),
    issues,
  };
}

function appendProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessRecordSignatureIssues(input: {
  readonly issues: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessLedgerIssue[];
  readonly path: string;
  readonly tenantId: TenantId | string;
  readonly record: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessRecord;
  readonly signaturePolicy?: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessSignaturePolicy;
}): void {
  const policy = input.signaturePolicy;
  if (policy === undefined) {
    return;
  }
  const signature = input.record.signature;
  if (signature === undefined) {
    if (policy.required) {
      input.issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_ledger_signature_missing",
        path: input.path,
        message:
          "projection replay settlement-store head witness record requires a witness principal signature",
      });
    }
    return;
  }

  if (signature.principalId !== input.record.observerId) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_ledger_signature_principal_mismatch",
      path: `${input.path}/principalId`,
      message:
        "projection replay settlement-store head witness record signature principal must match the observer id",
      expected: input.record.observerId,
      actual: signature.principalId,
    });
  }

  const expectedPayloadHash =
    computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessObservationSignaturePayloadHash(
      projectionReplayCertificateStoreRootWitnessSettlementStoreHeadObservationFromRecord(
        input.record,
      ),
    );
  if (signature.payloadHash !== expectedPayloadHash) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_ledger_signature_payload_mismatch",
      path: `${input.path}/payloadHash`,
      message:
        "projection replay settlement-store head witness record signature payload hash does not match the observation body",
      expected: expectedPayloadHash,
      actual: signature.payloadHash,
    });
  }

  const principal = policy.authorityTopology?.principals.find(
    (candidate) =>
      candidate.witnessId === input.record.observerId &&
      candidate.status === "active" &&
      candidate.validFromSettlementSequence <=
        input.record.head.settlementSequence,
  );
  if (policy.authorityTopology !== undefined && principal === undefined) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_ledger_signature_principal_not_authorized",
      path: `${input.path}/principalId`,
      message:
        "projection replay settlement-store head witness record signature principal is not active in the replayed authority topology",
      actual: signature.principalId,
    });
  }
  if (
    principal !== undefined &&
    principal.signatureKeyStatus !== undefined &&
    principal.signatureKeyStatus !== "active"
  ) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_ledger_signature_key_not_current",
      path: `${input.path}/keyId`,
      message:
        "projection replay settlement-store head witness record signature key is not current in the replayed authority topology",
      expected: "active",
      actual: principal.signatureKeyStatus,
    });
  }
  if (
    principal !== undefined &&
    principal.signatureKeyId === undefined &&
    policy.required
  ) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_ledger_signature_key_not_current",
      path: `${input.path}/keyId`,
      message:
        "projection replay settlement-store head witness record signature has no active admitted key in the replayed authority topology",
      expected: "active admitted key",
      actual: signature.keyId,
    });
  }
  if (
    principal !== undefined &&
    principal.signatureKeyId !== undefined &&
    signature.keyId !== principal.signatureKeyId
  ) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_ledger_signature_key_mismatch",
      path: `${input.path}/keyId`,
      message:
        "projection replay settlement-store head witness record signature key does not match the admitted witness principal key",
      expected: principal.signatureKeyId,
      actual: signature.keyId,
    });
  }
  if (
    principal !== undefined &&
    principal.signatureAlgorithm !== undefined &&
    signature.algorithm !== principal.signatureAlgorithm
  ) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_ledger_signature_key_mismatch",
      path: `${input.path}/algorithm`,
      message:
        "projection replay settlement-store head witness record signature algorithm does not match the admitted witness principal algorithm",
      expected: principal.signatureAlgorithm,
      actual: signature.algorithm,
    });
  }

  const verified = policy.verifier({
    tenantId: input.tenantId,
    principalId: signature.principalId,
    keyId: signature.keyId,
    algorithm: signature.algorithm,
    payloadHash: signature.payloadHash,
    signature: signature.signature,
    ...(signature.signedAt !== undefined ? { signedAt: signature.signedAt } : {}),
  });
  if (!verified) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_ledger_signature_invalid",
      path: `${input.path}/signature`,
      message:
        "projection replay settlement-store head witness record signature verifier rejected the signature",
    });
  }
}

export function replayProjectionReplayCertificateStoreRootWitnessSettlementRecords(input: {
  readonly tenantId: TenantId | string;
  readonly records: readonly ProjectionReplayCertificateStoreRootWitnessSettlementRecord[];
}): ProjectionReplayCertificateStoreRootWitnessSettlementRecordReplay {
  const tenant = String(input.tenantId);
  const records = [...input.records].sort(
    (a, b) => a.settlementSequence - b.settlementSequence,
  );
  const issues: ProjectionReplayCertificateStoreRootWitnessSettlementRecordIssue[] =
    [];
  let expectedSequence = 1;
  let expectedPreviousHash: string | undefined;
  let settledRoots: readonly ProjectionReplayCertificateStoreRoot[] = [];

  for (const [index, record] of records.entries()) {
    const issueCountBefore = issues.length;
    if (String(record.tenantId) !== tenant) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_record_tenant_mismatch",
        path: `/records/${index}/tenantId`,
        message:
          "projection replay root witness settlement record tenant mismatch",
        expected: tenant,
        actual: String(record.tenantId),
      });
    }
    if (String(record.settlement.tenantId) !== tenant) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_record_tenant_mismatch",
        path: `/records/${index}/settlement/tenantId`,
        message:
          "projection replay root witness settlement record cannot contain a settlement for another tenant",
        expected: tenant,
        actual: String(record.settlement.tenantId),
      });
    }
    if (record.settlementSequence !== expectedSequence) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_record_sequence_gap",
        path: `/records/${index}/settlementSequence`,
        message:
          "projection replay root witness settlement records must be contiguous",
        expected: expectedSequence,
        actual: record.settlementSequence,
      });
    }
    if (
      (record.previousSettlementRecordHash ?? "") !==
      (expectedPreviousHash ?? "")
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_record_previous_hash_mismatch",
        path: `/records/${index}/previousSettlementRecordHash`,
        message:
          "projection replay root witness settlement record does not chain to the prior settlement record",
        expected: expectedPreviousHash ?? "",
        actual: record.previousSettlementRecordHash ?? "",
      });
    }
    if (
      !sameProjectionReplayCertificateStoreRoot(
        record.root,
        record.settlement.root,
      )
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_record_root_mismatch",
        path: `/records/${index}/root`,
        message:
          "projection replay root witness settlement record root must match the settlement root",
        expected: record.settlement.root.rootHash,
        actual: record.root.rootHash,
      });
    }

    const { settlementHash, ...settlementPayload } = record.settlement;
    const expectedSettlementHash =
      computeProjectionReplayCertificateStoreRootWitnessSettlementHash(
        settlementPayload,
      );
    if (settlementHash !== expectedSettlementHash) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_record_settlement_hash_mismatch",
        path: `/records/${index}/settlement/settlementHash`,
        message:
          "projection replay root witness settlement record contains a settlement hash that does not match its body",
        expected: expectedSettlementHash,
        actual: settlementHash,
      });
    }

    const { settlementRecordHash, ...recordPayload } = record;
    const expectedRecordHash =
      computeProjectionReplayCertificateStoreRootWitnessSettlementRecordHash(
        recordPayload,
      );
    if (settlementRecordHash !== expectedRecordHash) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_record_hash_mismatch",
        path: `/records/${index}/settlementRecordHash`,
        message:
          "projection replay root witness settlement record hash does not match its body",
        expected: expectedRecordHash,
        actual: settlementRecordHash,
      });
    }

    if (
      issues.length === issueCountBefore &&
      record.settlement.status === "settled"
    ) {
      settledRoots = mergeProjectionReplayCertificateStoreRoots(settledRoots, [
        record.root,
      ]);
    }
    expectedSequence = record.settlementSequence + 1;
    expectedPreviousHash = record.settlementRecordHash;
  }

  const sortedSettledRoots =
    sortedProjectionReplayCertificateStoreRoots(settledRoots);
  const latestSettledRoot = sortedSettledRoots[sortedSettledRoots.length - 1];
  const latestRecord = records[records.length - 1];
  const settlementStoreHead =
    issues.length === 0 && latestRecord !== undefined
      ? projectionReplayCertificateStoreRootWitnessSettlementStoreHeadFromRecord(
          latestRecord,
        )
      : undefined;
  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    records,
    settledRoots: sortedSettledRoots,
    ...(latestSettledRoot !== undefined ? { latestSettledRoot } : {}),
    ...(settlementStoreHead !== undefined ? { settlementStoreHead } : {}),
    issues,
  };
}

export function projectionReplayCertificateStoreRootWitnessSettlementRefFromRecord(
  record: ProjectionReplayCertificateStoreRootWitnessSettlementRecord,
  input: {
    readonly checkedAt?: Timestamp | string;
  } = {},
): ProjectionReplayCertificateStoreRootWitnessSettlementRef | undefined {
  if (record.settlement.status !== "settled") return undefined;
  return {
    rootSequence: record.root.sequence,
    rootHash: record.root.rootHash,
    settlementSequence: record.settlementSequence,
    settlementStatus: "settled",
    settlementHash: record.settlement.settlementHash,
    settlementRecordHash: record.settlementRecordHash,
    ...(record.settlement.authorityTopologyHash !== undefined
      ? { authorityTopologyHash: record.settlement.authorityTopologyHash }
      : {}),
    checkedAt: input.checkedAt ?? record.recordedAt,
  };
}

export function verifyProjectionReplayCertificateStoreRootWitnessSettlementRef(input: {
  readonly tenantId: TenantId | string;
  readonly ref: ProjectionReplayCertificateStoreRootWitnessSettlementRef;
  readonly records: readonly ProjectionReplayCertificateStoreRootWitnessSettlementRecord[];
  readonly root?: ProjectionReplayCertificateStoreRoot;
  readonly currentnessPolicy?: ProjectionReplayCertificateStoreRootWitnessSettlementCurrentnessPolicy;
}): ProjectionReplayCertificateStoreRootWitnessSettlementRefVerification {
  const replay = replayProjectionReplayCertificateStoreRootWitnessSettlementRecords({
    tenantId: input.tenantId,
    records: input.records,
  });
  const issues: ProjectionReplayCertificateStoreRootWitnessSettlementRefIssue[] =
    [];
  if (!replay.valid) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_ref_ledger_invalid",
      path: "/records",
      message:
        "projection replay root witness settlement ref cannot be verified against an invalid settlement ledger",
      actual: replay.issues.map((issue) => issue.code).join(", "),
    });
  }

  const record = replay.records.find(
    (candidate) =>
      candidate.settlementSequence === input.ref.settlementSequence &&
      candidate.settlementRecordHash === input.ref.settlementRecordHash,
  );
  if (record === undefined) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_ref_missing",
      path: "/ref/settlementRecordHash",
      message:
        "projection replay root witness settlement ref does not resolve to an admitted settlement record",
      actual: input.ref.settlementRecordHash,
    });
    return {
      valid: false,
      ref: input.ref,
      replay,
      issues,
    };
  }

  if (input.root !== undefined && !sameProjectionReplayCertificateStoreRoot(record.root, input.root)) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_ref_root_mismatch",
      path: "/root",
      message:
        "projection replay root witness settlement ref does not match the required certificate-store root",
      expected: input.root.rootHash,
      actual: record.root.rootHash,
    });
  }
  if (
    record.root.sequence !== input.ref.rootSequence ||
    record.root.rootHash !== input.ref.rootHash
  ) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_ref_mismatch",
      path: "/ref/root",
      message:
        "projection replay root witness settlement ref root does not match the admitted settlement record",
      expected: `${record.root.sequence}:${record.root.rootHash}`,
      actual: `${input.ref.rootSequence}:${input.ref.rootHash}`,
    });
  }
  if (record.settlement.status !== "settled") {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_ref_not_settled",
      path: "/record/settlement/status",
      message:
        "projection replay root witness settlement ref requires an admitted settled settlement record",
      expected: "settled",
      actual: record.settlement.status,
    });
  }
  if (
    input.ref.settlementStatus !== "settled" ||
    input.ref.settlementHash !== record.settlement.settlementHash ||
    input.ref.authorityTopologyHash !== record.settlement.authorityTopologyHash
  ) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_ref_mismatch",
      path: "/ref/settlement",
      message:
        "projection replay root witness settlement ref does not match the admitted settlement body",
      expected: record.settlement.settlementHash,
      actual: input.ref.settlementHash,
    });
  }

  const currentnessPolicy = input.currentnessPolicy;
  if (currentnessPolicy !== undefined && replay.valid) {
    const minimumSettlementSequence =
      currentnessPolicy.minimumSettlementSequence;
    if (
      minimumSettlementSequence !== undefined &&
      record.settlementSequence < minimumSettlementSequence
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_ref_below_currentness_frontier",
        path: "/ref/settlementSequence",
        message:
          "projection replay root witness settlement ref is older than the required settlement frontier",
        expected: minimumSettlementSequence,
        actual: record.settlementSequence,
      });
    }

    const requiredAuthorityTopologyHash =
      currentnessPolicy.requiredAuthorityTopologyHash;
    if (
      requiredAuthorityTopologyHash !== undefined &&
      record.settlement.authorityTopologyHash !== requiredAuthorityTopologyHash
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_ref_authority_topology_mismatch",
        path: "/record/settlement/authorityTopologyHash",
        message:
          "projection replay root witness settlement ref was admitted under a different witness authority topology",
        expected: requiredAuthorityTopologyHash,
        actual: record.settlement.authorityTopologyHash ?? "",
      });
    }

    const requiredSettlementStoreHead =
      currentnessPolicy.requiredSettlementStoreHead;
    if (
      requiredSettlementStoreHead !== undefined &&
      !sameProjectionReplayCertificateStoreRootWitnessSettlementStoreHead(
        replay.settlementStoreHead,
        requiredSettlementStoreHead,
      )
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_ref_store_head_mismatch",
        path: "/currentnessPolicy/requiredSettlementStoreHead",
        message:
          "projection replay root witness settlement ref was verified against a settlement store head that does not match the required witnessed head",
        expected: `${requiredSettlementStoreHead.settlementSequence}:${requiredSettlementStoreHead.settlementRecordHash}:${requiredSettlementStoreHead.headHash}`,
        actual:
          replay.settlementStoreHead === undefined
            ? ""
            : `${replay.settlementStoreHead.settlementSequence}:${replay.settlementStoreHead.settlementRecordHash}:${replay.settlementStoreHead.headHash}`,
      });
    }

    if (
      currentnessPolicy.requireLatestSettledRoot === true &&
      replay.latestSettledRoot !== undefined &&
      !sameProjectionReplayCertificateStoreRoot(
        record.root,
        replay.latestSettledRoot,
      )
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_ref_stale",
        path: "/ref/root",
        message:
          "projection replay root witness settlement ref does not cite the latest settled certificate-store root",
        expected: `${replay.latestSettledRoot.sequence}:${replay.latestSettledRoot.rootHash}`,
        actual: `${record.root.sequence}:${record.root.rootHash}`,
      });
    }

    const laterSameRootRecord = replay.records.find(
      (candidate) =>
        candidate.settlementSequence > record.settlementSequence &&
        sameProjectionReplayCertificateStoreRoot(candidate.root, record.root),
    );
    if (
      currentnessPolicy.requireLatestSettlementForRoot === true &&
      laterSameRootRecord !== undefined
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_ref_stale",
        path: "/ref/settlementSequence",
        message:
          "projection replay root witness settlement ref has been superseded by a later settlement record for the same root",
        expected: laterSameRootRecord.settlementSequence,
        actual: record.settlementSequence,
      });
    }

    const laterConflictingRootRecord = replay.records.find(
      (candidate) =>
        candidate.settlementSequence > record.settlementSequence &&
        conflictsWithProjectionReplayCertificateStoreRoot(
          candidate.root,
          record.root,
        ),
    );
    if (
      currentnessPolicy.disallowLaterConflictingRoot === true &&
      laterConflictingRootRecord !== undefined
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_ref_conflict",
        path: "/records",
        message:
          "projection replay root witness settlement ref is followed by a conflicting same-sequence root record",
        expected: `${record.root.sequence}:${record.root.rootHash}`,
        actual: `${laterConflictingRootRecord.root.sequence}:${laterConflictingRootRecord.root.rootHash}`,
      });
    }

    const laterObstructionRecord = replay.records.find(
      (candidate) =>
        candidate.settlementSequence > record.settlementSequence &&
        candidate.settlement.status === "obstructed",
    );
    if (
      currentnessPolicy.disallowLaterObstruction === true &&
      laterObstructionRecord !== undefined
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_ref_stale",
        path: "/records",
        message:
          "projection replay root witness settlement ref is followed by an obstructed settlement record",
        expected: "no later obstruction",
        actual: `${laterObstructionRecord.settlementSequence}:${laterObstructionRecord.root.rootHash}`,
      });
    }
  }

  return {
    valid: issues.length === 0,
    ref: input.ref,
    record,
    replay,
    issues,
  };
}

export function buildProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityTransition(
  input: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityTransitionInput,
): ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityTransition {
  const payload: Omit<
    ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityTransition,
    "authorityHash"
  > = {
    tenantId: tenantId(String(input.tenantId)),
    authoritySequence: input.authoritySequence,
    transitionId: input.transitionId,
    transitionKind: input.transitionKind,
    recordedAt: input.recordedAt,
    recordedBy: input.recordedBy,
    effectiveFromSettlementSequence: input.effectiveFromSettlementSequence,
    ...(input.witnessId !== undefined ? { witnessId: input.witnessId } : {}),
    ...(input.requiredWitnesses !== undefined
      ? { requiredWitnesses: input.requiredWitnesses }
      : {}),
    ...(input.minimumWitnesses !== undefined
      ? { minimumWitnesses: input.minimumWitnesses }
      : {}),
    ...(input.sealedThroughSettlementSequence !== undefined
      ? { sealedThroughSettlementSequence: input.sealedThroughSettlementSequence }
      : {}),
    ...(input.sealedAuthorityTopologyHash !== undefined
      ? { sealedAuthorityTopologyHash: input.sealedAuthorityTopologyHash }
      : {}),
    ...(input.sealedQuorumCertificateHash !== undefined
      ? { sealedQuorumCertificateHash: input.sealedQuorumCertificateHash }
      : {}),
    ...(input.signatureKeyId !== undefined
      ? { signatureKeyId: input.signatureKeyId }
      : {}),
    ...(input.signatureAlgorithm !== undefined
      ? { signatureAlgorithm: input.signatureAlgorithm }
      : {}),
    ...(input.signaturePublicKeyFingerprint !== undefined
      ? { signaturePublicKeyFingerprint: input.signaturePublicKeyFingerprint }
      : {}),
    ...(input.signature !== undefined ? { signature: input.signature } : {}),
    ...(input.reason !== undefined ? { reason: input.reason } : {}),
    ...(input.previousAuthorityHash !== undefined
      ? { previousAuthorityHash: input.previousAuthorityHash }
      : {}),
  };

  return {
    ...payload,
    authorityHash:
      computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityTransitionHash(
        payload,
      ),
  };
}

export function computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityTransitionHash(
  transition: Omit<
    ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityTransition,
    "authorityHash"
  >,
): string {
  return fingerprint64(canonicalStringify(transition));
}

export function computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityTransitionSignaturePayloadHash(
  transition: Omit<
    ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityTransition,
    "authorityHash" | "signature"
  >,
): string {
  return fingerprint64(canonicalStringify(transition));
}

export function replayProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityTransitions(input: {
  readonly tenantId: TenantId | string;
  readonly settlementSequence: number;
  readonly transitions: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityTransition[];
  readonly signaturePolicy?: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessSignaturePolicy;
  readonly compactionCheckpoint?: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionCheckpoint;
  readonly compactionCheckpointAdmission?: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionCheckpointAdmissionCertificate;
}): ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityTopology {
  const tenant = String(input.tenantId);
  const transitions = [...input.transitions].sort(
    (a, b) => a.authoritySequence - b.authoritySequence,
  );
  const issues: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityIssue[] =
    [];
  const principals = new Map<
    string,
    ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessPrincipalState
  >();
  const validAuthorityTransitions: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityTransition[] =
    [];
  const authorityEpochSeals: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityEpochSeal[] =
    [];
  let requiredWitnesses: number | undefined;
  let minimumWitnesses: number | undefined;
  let effectiveAuthorityHash: string | undefined;
  let sealedThroughSettlementSequence: number | undefined;
  let expectedSequence = 1;
  let expectedPreviousHash: string | undefined;
  let latestAuthorityHash: string | undefined;
  const authorityCheckpoint = input.compactionCheckpoint?.authorityTopology;

  if (
    !Number.isInteger(input.settlementSequence) ||
    input.settlementSequence < 1
  ) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_transition_invalid",
      path: "/settlementSequence",
      message:
        "projection replay settlement-store head witness authority topology requires a positive settlement sequence",
      expected: 1,
      actual: input.settlementSequence,
    });
  }
  if (authorityCheckpoint !== undefined) {
    const admissionValidation =
      validateProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionCheckpointAdmission(
        {
          tenantId: input.tenantId,
          checkpoint: input.compactionCheckpoint!,
          ...(input.compactionCheckpointAdmission !== undefined
            ? { admission: input.compactionCheckpointAdmission }
            : {}),
          ...(input.signaturePolicy !== undefined
            ? { signaturePolicy: input.signaturePolicy }
            : {}),
        },
      );
    if (!admissionValidation.valid) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_compaction_checkpoint_invalid",
        path: "/compactionCheckpointAdmission",
        message: admissionValidation.message,
      });
    }
    const checkpointValidation =
      verifyProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionCheckpointHash(
        input.compactionCheckpoint!,
      );
    if (!checkpointValidation.valid) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_compaction_checkpoint_invalid",
        path: "/compactionCheckpoint/checkpointHash",
        message:
          "projection replay settlement-store head witness authority compaction checkpoint hash does not match its body",
        expected: checkpointValidation.expectedHash,
        actual: input.compactionCheckpoint!.checkpointHash,
      });
    }
    if (
      String(input.compactionCheckpoint!.tenantId) !== tenant ||
      String(authorityCheckpoint.tenantId) !== tenant
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_compaction_checkpoint_invalid",
        path: "/compactionCheckpoint/tenantId",
        message:
          "projection replay settlement-store head witness authority compaction checkpoint tenant mismatch",
        expected: tenant,
        actual: String(input.compactionCheckpoint!.tenantId),
      });
    }
    if (authorityCheckpoint.settlementSequence !== input.settlementSequence) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_compaction_checkpoint_invalid",
        path: "/compactionCheckpoint/authorityTopology/settlementSequence",
        message:
          "projection replay settlement-store head witness authority compaction checkpoint must target the replay settlement sequence",
        expected: input.settlementSequence,
        actual: authorityCheckpoint.settlementSequence,
      });
    }
    if (
      !Number.isInteger(authorityCheckpoint.compactedThroughAuthoritySequence) ||
      authorityCheckpoint.compactedThroughAuthoritySequence < 1 ||
      authorityCheckpoint.compactedThroughAuthorityHash === ""
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_compaction_checkpoint_invalid",
        path: "/compactionCheckpoint/authorityTopology",
        message:
          "projection replay settlement-store head witness authority compaction checkpoint requires a positive compacted authority sequence and authority hash",
        actual: `${authorityCheckpoint.compactedThroughAuthoritySequence}:${authorityCheckpoint.compactedThroughAuthorityHash}`,
      });
    }
    if (issues.length === 0) {
      expectedSequence =
        authorityCheckpoint.compactedThroughAuthoritySequence + 1;
      expectedPreviousHash =
        authorityCheckpoint.compactedThroughAuthorityHash;
      latestAuthorityHash = authorityCheckpoint.compactedThroughAuthorityHash;
      requiredWitnesses = authorityCheckpoint.requiredWitnesses;
      minimumWitnesses = authorityCheckpoint.minimumWitnesses;
      effectiveAuthorityHash = authorityCheckpoint.effectiveAuthorityHash;
      sealedThroughSettlementSequence =
        authorityCheckpoint.sealedThroughSettlementSequence;
      for (const principal of authorityCheckpoint.principals) {
        principals.set(principal.witnessId, principal);
      }
      authorityEpochSeals.push(...authorityCheckpoint.authorityEpochSeals);
    }
  }

  for (const [index, transition] of transitions.entries()) {
    const issueCountBefore = issues.length;
    if (String(transition.tenantId) !== tenant) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_tenant_mismatch",
        path: `/transitions/${index}/tenantId`,
        message:
          "projection replay settlement-store head witness authority transition tenant mismatch",
        expected: tenant,
        actual: String(transition.tenantId),
      });
    }
    if (transition.authoritySequence !== expectedSequence) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_sequence_gap",
        path: `/transitions/${index}/authoritySequence`,
        message:
          "projection replay settlement-store head witness authority transitions must be contiguous",
        expected: expectedSequence,
        actual: transition.authoritySequence,
      });
    }
    if (
      (transition.previousAuthorityHash ?? "") !==
      (expectedPreviousHash ?? "")
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_previous_hash_mismatch",
        path: `/transitions/${index}/previousAuthorityHash`,
        message:
          "projection replay settlement-store head witness authority transition does not chain to the prior transition",
        expected: expectedPreviousHash ?? "",
        actual: transition.previousAuthorityHash ?? "",
      });
    }
    const { authorityHash, ...transitionPayload } = transition;
    const expectedAuthorityHash =
      computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityTransitionHash(
        transitionPayload,
      );
    if (authorityHash !== expectedAuthorityHash) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_hash_mismatch",
        path: `/transitions/${index}/authorityHash`,
        message:
          "projection replay settlement-store head witness authority transition hash does not match its body",
        expected: expectedAuthorityHash,
        actual: authorityHash,
      });
    }
    if (
      !Number.isInteger(transition.effectiveFromSettlementSequence) ||
      transition.effectiveFromSettlementSequence < 1
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_transition_invalid",
        path: `/transitions/${index}/effectiveFromSettlementSequence`,
        message:
          "projection replay settlement-store head witness authority transition requires a positive effective settlement sequence",
        expected: 1,
        actual: transition.effectiveFromSettlementSequence,
      });
    }

    const transitionIssuesStart = issues.length;
    if (transition.transitionKind === "seal_authority_epoch") {
      if (
        !Number.isInteger(transition.sealedThroughSettlementSequence) ||
        (transition.sealedThroughSettlementSequence ?? 0) < 1
      ) {
        issues.push({
          code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_epoch_seal_invalid",
          path: `/transitions/${index}/sealedThroughSettlementSequence`,
          message:
            "projection replay settlement-store head witness authority epoch seal requires a positive sealed settlement sequence",
          expected: 1,
          actual: transition.sealedThroughSettlementSequence ?? 0,
        });
      }
      if (
        transition.sealedThroughSettlementSequence !== undefined &&
        transition.effectiveFromSettlementSequence !==
          transition.sealedThroughSettlementSequence
      ) {
        issues.push({
          code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_epoch_seal_invalid",
          path: `/transitions/${index}/effectiveFromSettlementSequence`,
          message:
            "projection replay settlement-store head witness authority epoch seal must be effective at the sealed settlement sequence",
          expected: transition.sealedThroughSettlementSequence,
          actual: transition.effectiveFromSettlementSequence,
        });
      }
      if (
        transition.sealedThroughSettlementSequence !== undefined &&
        sealedThroughSettlementSequence !== undefined &&
        transition.sealedThroughSettlementSequence <=
          sealedThroughSettlementSequence
      ) {
        issues.push({
          code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_epoch_seal_invalid",
          path: `/transitions/${index}/sealedThroughSettlementSequence`,
          message:
            "projection replay settlement-store head witness authority epoch seals must advance monotonically",
          expected: sealedThroughSettlementSequence + 1,
          actual: transition.sealedThroughSettlementSequence,
        });
      }
      const expectedSealedAuthorityHash =
        transition.sealedThroughSettlementSequence === undefined
          ? undefined
          : ([...validAuthorityTransitions]
              .reverse()
              .find(
                (priorTransition) =>
                  priorTransition.transitionKind !== "seal_authority_epoch" &&
                  priorTransition.effectiveFromSettlementSequence <=
                    transition.sealedThroughSettlementSequence!,
              )?.authorityHash ?? authorityCheckpoint?.effectiveAuthorityHash);
      if (
        expectedSealedAuthorityHash === undefined ||
        transition.sealedAuthorityTopologyHash !==
          expectedSealedAuthorityHash
      ) {
        issues.push({
          code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_epoch_seal_invalid",
          path: `/transitions/${index}/sealedAuthorityTopologyHash`,
          message:
            "projection replay settlement-store head witness authority epoch seal must bind the effective authority topology hash",
          expected: expectedSealedAuthorityHash ?? "",
          actual: transition.sealedAuthorityTopologyHash ?? "",
        });
      }
      if (
        transition.sealedQuorumCertificateHash === undefined ||
        transition.sealedQuorumCertificateHash === ""
      ) {
        issues.push({
          code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_epoch_seal_invalid",
          path: `/transitions/${index}/sealedQuorumCertificateHash`,
          message:
            "projection replay settlement-store head witness authority epoch seal requires the quorum certificate hash it finalizes",
        });
      }
      appendProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityTransitionSignatureIssues(
        {
          issues,
          path: `/transitions/${index}/signature`,
          tenantId: tenant,
          transition,
          principals,
          ...(input.signaturePolicy !== undefined
            ? { signaturePolicy: input.signaturePolicy }
            : {}),
        },
      );
    } else if (
      sealedThroughSettlementSequence !== undefined &&
      transition.effectiveFromSettlementSequence <=
        sealedThroughSettlementSequence
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_retroactive_transition",
        path: `/transitions/${index}/effectiveFromSettlementSequence`,
        message:
          "projection replay settlement-store head witness authority transition cannot modify a sealed settlement epoch",
        expected: sealedThroughSettlementSequence + 1,
        actual: transition.effectiveFromSettlementSequence,
      });
    } else if (transition.transitionKind === "set_quorum") {
      if (
        !Number.isInteger(transition.requiredWitnesses) ||
        (transition.requiredWitnesses ?? 0) < 1
      ) {
        issues.push({
          code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_quorum_invalid",
          path: `/transitions/${index}/requiredWitnesses`,
          message:
            "projection replay settlement-store head witness authority quorum requires at least one required witness",
          expected: 1,
          actual: transition.requiredWitnesses ?? 0,
        });
      }
      if (
        transition.minimumWitnesses !== undefined &&
        (!Number.isInteger(transition.minimumWitnesses) ||
          transition.minimumWitnesses < 1)
      ) {
        issues.push({
          code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_quorum_invalid",
          path: `/transitions/${index}/minimumWitnesses`,
          message:
            "projection replay settlement-store head witness authority quorum requires a positive minimum witness count",
          expected: 1,
          actual: transition.minimumWitnesses,
        });
      }
      if (
        transition.minimumWitnesses !== undefined &&
        transition.requiredWitnesses !== undefined &&
        transition.minimumWitnesses > transition.requiredWitnesses
      ) {
        issues.push({
          code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_quorum_invalid",
          path: `/transitions/${index}/minimumWitnesses`,
          message:
            "projection replay settlement-store head witness authority quorum minimum cannot exceed required witnesses",
          expected: transition.requiredWitnesses,
          actual: transition.minimumWitnesses,
        });
      }
    } else if (
      transition.transitionKind === "rotate_signature_key" ||
      transition.transitionKind === "revoke_signature_key"
    ) {
      if (transition.witnessId === undefined || transition.witnessId === "") {
        issues.push({
          code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_witness_missing",
          path: `/transitions/${index}/witnessId`,
          message:
            "projection replay settlement-store head witness signature-key transition requires a witness id",
        });
      }
      const principal =
        transition.witnessId === undefined
          ? undefined
          : principals.get(transition.witnessId);
      if (
        transition.effectiveFromSettlementSequence <= input.settlementSequence &&
        (principal === undefined ||
          principal.status !== "active" ||
          principal.validFromSettlementSequence >
            transition.effectiveFromSettlementSequence)
      ) {
        issues.push({
          code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_signature_key_transition_invalid",
          path: `/transitions/${index}/witnessId`,
          message:
            "projection replay settlement-store head witness signature-key transition must target an active admitted principal",
          actual: transition.witnessId ?? "",
        });
      }
      if (
        transition.transitionKind === "rotate_signature_key" &&
        (transition.signatureKeyId === undefined ||
          transition.signatureKeyId === "" ||
          transition.signatureAlgorithm === undefined ||
          transition.signatureAlgorithm === "")
      ) {
        issues.push({
          code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_signature_key_transition_invalid",
          path: `/transitions/${index}/signatureKeyId`,
          message:
            "projection replay settlement-store head witness key rotation requires a new signature key id and algorithm",
        });
      }
      if (
        transition.transitionKind === "revoke_signature_key" &&
        (transition.signatureKeyId === undefined ||
          transition.signatureKeyId === "")
      ) {
        issues.push({
          code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_signature_key_transition_invalid",
          path: `/transitions/${index}/signatureKeyId`,
          message:
            "projection replay settlement-store head witness key revocation requires the revoked signature key id",
        });
      }
      if (
        transition.transitionKind === "revoke_signature_key" &&
        principal !== undefined &&
        principal.signatureKeyId !== undefined &&
        transition.signatureKeyId !== principal.signatureKeyId
      ) {
        issues.push({
          code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_signature_key_transition_invalid",
          path: `/transitions/${index}/signatureKeyId`,
          message:
            "projection replay settlement-store head witness key revocation must target the currently admitted signature key",
          expected: principal.signatureKeyId,
          actual: transition.signatureKeyId ?? "",
        });
      }
    } else if (transition.witnessId === undefined || transition.witnessId === "") {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_witness_missing",
        path: `/transitions/${index}/witnessId`,
        message:
          "projection replay settlement-store head witness authority transition requires a witness id",
      });
    }

    if (
      issues.length === transitionIssuesStart &&
      issues.length === issueCountBefore &&
      transition.transitionKind === "seal_authority_epoch"
    ) {
      const seal: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityEpochSeal =
        {
          tenantId: tenantId(String(transition.tenantId)),
          authoritySequence: transition.authoritySequence,
          transitionId: transition.transitionId,
          recordedAt: transition.recordedAt,
          recordedBy: transition.recordedBy,
          sealedThroughSettlementSequence:
            transition.sealedThroughSettlementSequence!,
          sealedAuthorityTopologyHash: transition.sealedAuthorityTopologyHash!,
          sealedQuorumCertificateHash: transition.sealedQuorumCertificateHash!,
          authorityHash: transition.authorityHash,
        };
      sealedThroughSettlementSequence = seal.sealedThroughSettlementSequence;
      authorityEpochSeals.push(seal);
    } else if (
      issues.length === transitionIssuesStart &&
      issues.length === issueCountBefore
    ) {
      validAuthorityTransitions.push(transition);
      if (transition.effectiveFromSettlementSequence <= input.settlementSequence) {
        applyProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityTransition(
          {
            transition,
            principals,
            setQuorum: (required, minimum) => {
              requiredWitnesses = required;
              minimumWitnesses = minimum;
            },
          },
        );
        effectiveAuthorityHash = transition.authorityHash;
      }
    }

    expectedSequence = transition.authoritySequence + 1;
    expectedPreviousHash = transition.authorityHash;
    latestAuthorityHash = transition.authorityHash;
  }

  if (requiredWitnesses === undefined) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_quorum_missing",
      path: "/transitions",
      message:
        "projection replay settlement-store head witness authority topology requires an effective quorum transition",
    });
  }

  const principalStates = [...principals.values()].sort((a, b) =>
    a.witnessId.localeCompare(b.witnessId),
  );
  const eligibleWitnessIds = principalStates
    .filter(
      (principal) =>
        principal.status === "active" &&
        principal.validFromSettlementSequence <= input.settlementSequence,
    )
    .map((principal) => principal.witnessId)
    .sort((a, b) => a.localeCompare(b));

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    settlementSequence: input.settlementSequence,
    ...(requiredWitnesses !== undefined ? { requiredWitnesses } : {}),
    ...(minimumWitnesses !== undefined ? { minimumWitnesses } : {}),
    ...(effectiveAuthorityHash !== undefined ? { effectiveAuthorityHash } : {}),
    ...(sealedThroughSettlementSequence !== undefined
      ? { sealedThroughSettlementSequence }
      : {}),
    eligibleWitnessIds,
    principals: principalStates,
    authorityEpochSeals,
    transitions,
    ...(latestAuthorityHash !== undefined ? { latestAuthorityHash } : {}),
    issues,
  };
}

function appendProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityTransitionSignatureIssues(input: {
  readonly issues: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityIssue[];
  readonly path: string;
  readonly tenantId: TenantId | string;
  readonly transition: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityTransition;
  readonly principals: ReadonlyMap<
    string,
    ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessPrincipalState
  >;
  readonly signaturePolicy?: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessSignaturePolicy;
}): void {
  const policy = input.signaturePolicy;
  if (policy === undefined) {
    return;
  }
  const signature = input.transition.signature;
  if (signature === undefined) {
    if (policy.required) {
      input.issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_signature_missing",
        path: input.path,
        message:
          "projection replay settlement-store head witness authority epoch seal requires a finalizer principal signature",
      });
    }
    return;
  }
  const principal = input.principals.get(signature.principalId);
  if (
    principal === undefined ||
    principal.status !== "active" ||
    principal.validFromSettlementSequence >
      input.transition.effectiveFromSettlementSequence
  ) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_signature_principal_not_authorized",
      path: `${input.path}/principalId`,
      message:
        "projection replay settlement-store head witness authority epoch seal signature principal is not active in the replayed authority topology",
      actual: signature.principalId,
    });
  }
  if (
    principal !== undefined &&
    principal.signatureKeyId !== undefined &&
    signature.keyId !== principal.signatureKeyId
  ) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_signature_key_mismatch",
      path: `${input.path}/keyId`,
      message:
        "projection replay settlement-store head witness authority epoch seal signature key does not match the admitted principal key",
      expected: principal.signatureKeyId,
      actual: signature.keyId,
    });
  }
  if (
    principal !== undefined &&
    principal.signatureKeyStatus !== undefined &&
    principal.signatureKeyStatus !== "active"
  ) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_signature_key_not_current",
      path: `${input.path}/keyId`,
      message:
        "projection replay settlement-store head witness authority epoch seal signature key is not current in the replayed authority topology",
      expected: "active",
      actual: principal.signatureKeyStatus,
    });
  }
  if (
    principal !== undefined &&
    principal.signatureKeyId === undefined &&
    policy.required
  ) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_signature_key_not_current",
      path: `${input.path}/keyId`,
      message:
        "projection replay settlement-store head witness authority epoch seal signature has no active admitted key in the replayed authority topology",
      expected: "active admitted key",
      actual: signature.keyId,
    });
  }
  if (
    principal !== undefined &&
    principal.signatureAlgorithm !== undefined &&
    signature.algorithm !== principal.signatureAlgorithm
  ) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_signature_key_mismatch",
      path: `${input.path}/algorithm`,
      message:
        "projection replay settlement-store head witness authority epoch seal signature algorithm does not match the admitted principal algorithm",
      expected: principal.signatureAlgorithm,
      actual: signature.algorithm,
    });
  }
  const { authorityHash, signature: _signature, ...signaturePayload } =
    input.transition;
  const expectedPayloadHash =
    computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityTransitionSignaturePayloadHash(
      signaturePayload,
    );
  if (signature.payloadHash !== expectedPayloadHash) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_signature_payload_mismatch",
      path: `${input.path}/payloadHash`,
      message:
        "projection replay settlement-store head witness authority epoch seal signature payload hash does not match the transition body",
      expected: expectedPayloadHash,
      actual: signature.payloadHash,
    });
  }
  const verified = policy.verifier({
    tenantId: input.tenantId,
    principalId: signature.principalId,
    keyId: signature.keyId,
    algorithm: signature.algorithm,
    payloadHash: signature.payloadHash,
    signature: signature.signature,
    ...(signature.signedAt !== undefined ? { signedAt: signature.signedAt } : {}),
  });
  if (!verified) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_authority_signature_invalid",
      path: `${input.path}/signature`,
      message:
        "projection replay settlement-store head witness authority epoch seal signature verifier rejected the signature",
    });
  }
}

function applyProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityTransition(input: {
  readonly transition: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityTransition;
  readonly principals: Map<
    string,
    ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessPrincipalState
  >;
  readonly setQuorum: (required: number, minimum?: number) => void;
}): void {
  const { transition } = input;
  if (transition.transitionKind === "seal_authority_epoch") {
    return;
  }
  if (transition.transitionKind === "set_quorum") {
    input.setQuorum(
      transition.requiredWitnesses!,
      transition.minimumWitnesses ?? 1,
    );
    return;
  }
  const witnessId = transition.witnessId!;
  const existing = input.principals.get(witnessId);
  const status =
    transition.transitionKind === "rotate_signature_key" ||
    transition.transitionKind === "revoke_signature_key"
      ? existing?.status ?? "active"
      : projectionReplayCertificateStoreRootWitnessAuthorityStatusFromTransition(
          transition.transitionKind,
        );
  const isSignatureKeyTransition =
    transition.transitionKind === "rotate_signature_key" ||
    transition.transitionKind === "revoke_signature_key";
  const signatureKeyStatus:
    | ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessSignatureKeyStatus
    | undefined =
    transition.transitionKind === "revoke_signature_key"
      ? "revoked"
      : transition.transitionKind === "rotate_signature_key" ||
          (transition.transitionKind === "admit_witness" &&
            transition.signatureKeyId !== undefined)
        ? "active"
        : existing?.signatureKeyStatus;
  input.principals.set(witnessId, {
    tenantId: tenantId(String(transition.tenantId)),
    witnessId,
    status,
    validFromSettlementSequence:
      transition.transitionKind === "admit_witness"
        ? transition.effectiveFromSettlementSequence
        : existing?.validFromSettlementSequence ??
          transition.effectiveFromSettlementSequence,
    changedAtAuthoritySequence: transition.authoritySequence,
    ...(transition.transitionKind === "admit_witness"
      ? {
          admittedAt: transition.recordedAt,
          admittedBy: transition.recordedBy,
        }
      : existing?.admittedAt !== undefined
        ? { admittedAt: existing.admittedAt }
        : {}),
    ...(transition.transitionKind !== "admit_witness"
      ? {
          statusChangedAt: transition.recordedAt,
          statusChangedBy: transition.recordedBy,
        }
      : existing?.statusChangedAt !== undefined
        ? {
            statusChangedAt: existing.statusChangedAt,
            ...(existing.statusChangedBy !== undefined
              ? { statusChangedBy: existing.statusChangedBy }
              : {}),
          }
        : {}),
    ...(transition.transitionKind !== "admit_witness" &&
    existing?.admittedBy !== undefined
      ? { admittedBy: existing.admittedBy }
      : {}),
    ...(transition.signatureKeyId !== undefined
      ? { signatureKeyId: transition.signatureKeyId }
      : existing?.signatureKeyId !== undefined
        ? { signatureKeyId: existing.signatureKeyId }
        : {}),
    ...(transition.signatureAlgorithm !== undefined
      ? { signatureAlgorithm: transition.signatureAlgorithm }
      : existing?.signatureAlgorithm !== undefined
        ? { signatureAlgorithm: existing.signatureAlgorithm }
        : {}),
    ...(transition.signaturePublicKeyFingerprint !== undefined
      ? {
          signaturePublicKeyFingerprint:
            transition.signaturePublicKeyFingerprint,
        }
      : existing?.signaturePublicKeyFingerprint !== undefined
        ? {
            signaturePublicKeyFingerprint:
              existing.signaturePublicKeyFingerprint,
          }
        : {}),
    ...(signatureKeyStatus !== undefined ? { signatureKeyStatus } : {}),
    ...(isSignatureKeyTransition || transition.transitionKind === "admit_witness"
      ? {
          signatureKeyChangedAtAuthoritySequence:
            transition.authoritySequence,
          signatureKeyChangedAt: transition.recordedAt,
          signatureKeyChangedBy: transition.recordedBy,
        }
      : existing?.signatureKeyChangedAtAuthoritySequence !== undefined
        ? {
            signatureKeyChangedAtAuthoritySequence:
              existing.signatureKeyChangedAtAuthoritySequence,
            ...(existing.signatureKeyChangedAt !== undefined
              ? { signatureKeyChangedAt: existing.signatureKeyChangedAt }
              : {}),
            ...(existing.signatureKeyChangedBy !== undefined
              ? { signatureKeyChangedBy: existing.signatureKeyChangedBy }
              : {}),
          }
        : {}),
    ...(transition.reason !== undefined ? { reason: transition.reason } : {}),
  });
}

export function evaluateProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessQuorumCertificate(input: {
  readonly tenantId: TenantId | string;
  readonly head: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHead;
  readonly witnessReplay: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessLedgerReplay;
  readonly policy?: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessQuorumPolicy;
  readonly authorityTopology?: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessAuthorityTopology;
}): ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessQuorumCertificate {
  const tenant = String(input.tenantId);
  const requestedRequiredWitnesses =
    input.authorityTopology?.requiredWitnesses ??
    input.policy?.requiredWitnesses ??
    1;
  const requestedMinimumWitnesses =
    input.authorityTopology?.minimumWitnesses ??
    input.policy?.minimumWitnesses ??
    1;
  const requiredWitnesses = Number.isInteger(requestedRequiredWitnesses)
    ? Math.max(1, requestedRequiredWitnesses)
    : 1;
  const minimumWitnesses = Number.isInteger(requestedMinimumWitnesses)
    ? Math.max(1, requestedMinimumWitnesses)
    : 1;
  const issues: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessQuorumCertificateIssue[] =
    [];
  const acceptedWitnessIds = new Set<string>();
  const obstructingWitnessIds = new Set<string>();
  const invalidWitnessIds = new Set<string>();
  const validWitnessIds = new Set<string>();
  const topology = input.authorityTopology;
  const topologyEligibleWitnessIds = new Set(topology?.eligibleWitnessIds ?? []);
  let authorityTopologyInvalid = false;

  if (!Number.isInteger(requestedRequiredWitnesses) || requestedRequiredWitnesses < 1) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_quorum_invalid_policy",
      path: "/policy/requiredWitnesses",
      message:
        "projection replay settlement-store head witness quorum requires at least one required witness",
      expected: 1,
      actual: requestedRequiredWitnesses,
    });
  }
  if (!Number.isInteger(requestedMinimumWitnesses) || requestedMinimumWitnesses < 1) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_quorum_invalid_policy",
      path: "/policy/minimumWitnesses",
      message:
        "projection replay settlement-store head witness quorum requires at least one minimum witness",
      expected: 1,
      actual: requestedMinimumWitnesses,
    });
  }
  if (
    Number.isInteger(requestedRequiredWitnesses) &&
    Number.isInteger(requestedMinimumWitnesses) &&
    requestedMinimumWitnesses > requestedRequiredWitnesses
  ) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_quorum_invalid_policy",
      path: "/policy/minimumWitnesses",
      message:
        "projection replay settlement-store head witness quorum minimum cannot exceed required witnesses",
      expected: requestedRequiredWitnesses,
      actual: requestedMinimumWitnesses,
    });
  }
  if (String(input.head.tenantId) !== tenant) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_quorum_head_tenant_mismatch",
      path: "/head/tenantId",
      message:
        "projection replay settlement-store head witness quorum head tenant does not match the quorum tenant",
      expected: tenant,
      actual: String(input.head.tenantId),
    });
  }
  if (!input.witnessReplay.valid) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_quorum_witness_replay_invalid",
      path: "/witnessReplay",
      message:
        "projection replay settlement-store head witness quorum cannot use a witness replay that fails replay verification",
      actual: input.witnessReplay.issues.map((issue) => issue.code).join(", "),
    });
  }
  if (String(input.witnessReplay.tenantId) !== tenant) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_quorum_witness_tenant_mismatch",
      path: "/witnessReplay/tenantId",
      message:
        "projection replay settlement-store head witness quorum cannot count witness records from another tenant",
      expected: tenant,
      actual: String(input.witnessReplay.tenantId),
    });
  }
  if (topology !== undefined) {
    if (!topology.valid) {
      authorityTopologyInvalid = true;
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_quorum_authority_topology_invalid",
        path: "/authorityTopology",
        message:
          "projection replay settlement-store head witness quorum cannot use an invalid witness authority topology",
        actual: topology.issues.map((issue) => issue.code).join(", "),
      });
    }
    if (String(topology.tenantId) !== tenant) {
      authorityTopologyInvalid = true;
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_quorum_authority_topology_invalid",
        path: "/authorityTopology/tenantId",
        message:
          "projection replay settlement-store head witness authority topology tenant does not match the quorum tenant",
        expected: tenant,
        actual: String(topology.tenantId),
      });
    }
    if (topology.settlementSequence !== input.head.settlementSequence) {
      authorityTopologyInvalid = true;
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_quorum_authority_topology_invalid",
        path: "/authorityTopology/settlementSequence",
        message:
          "projection replay settlement-store head witness authority topology must be replayed for the observed head sequence",
        expected: input.head.settlementSequence,
        actual: topology.settlementSequence,
      });
    }
    if (
      input.policy !== undefined &&
      (input.policy.requiredWitnesses !== topology.requiredWitnesses ||
        (input.policy.minimumWitnesses ?? 1) !==
          (topology.minimumWitnesses ?? 1))
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_quorum_policy_authority_mismatch",
        path: "/policy",
        message:
          "projection replay settlement-store head witness quorum policy must match the replayed witness authority topology",
        expected: `${topology.requiredWitnesses ?? ""}:${
          topology.minimumWitnesses ?? 1
        }`,
        actual: `${input.policy.requiredWitnesses}:${
          input.policy.minimumWitnesses ?? 1
        }`,
      });
    }
  }

  if (
    input.witnessReplay.valid &&
    String(input.witnessReplay.tenantId) === tenant &&
    !authorityTopologyInvalid
  ) {
    for (const [index, record] of input.witnessReplay.records.entries()) {
      if (!record.accepted) {
        continue;
      }
      const witnessId = record.observerId;
      const acceptedTarget = record.decision.acceptedHeads.some((head) =>
        sameProjectionReplayCertificateStoreRootWitnessSettlementStoreHead(
          head,
          input.head,
        ),
      );
      const conflictingAcceptedHead = record.decision.acceptedHeads.find(
        (head) =>
          head.settlementSequence === input.head.settlementSequence &&
          !sameProjectionReplayCertificateStoreRootWitnessSettlementStoreHead(
            head,
            input.head,
          ),
      );
      if (conflictingAcceptedHead !== undefined) {
        obstructingWitnessIds.add(witnessId);
        issues.push({
          code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_quorum_conflicting_head",
          path: `/witnessReplay/records/${index}/decision/acceptedHeads`,
          message:
            "projection replay settlement-store head witness quorum found a witness record accepting a conflicting head at the same settlement sequence",
          expected: input.head.settlementRecordHash,
          actual: conflictingAcceptedHead.settlementRecordHash,
        });
        continue;
      }
      if (!acceptedTarget) {
        continue;
      }
      validWitnessIds.add(witnessId);
      if (
        topology !== undefined &&
        !topologyEligibleWitnessIds.has(witnessId)
      ) {
        invalidWitnessIds.add(witnessId);
        issues.push({
          code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_quorum_witness_not_authorized",
          path: `/witnessReplay/records/${index}/observerId`,
          message:
            "projection replay settlement-store head witness quorum cannot count a witness outside the replayed authority topology",
          expected: topology.eligibleWitnessIds.join(", "),
          actual: witnessId,
        });
        continue;
      }
      acceptedWitnessIds.add(witnessId);
    }
  }

  if (
    input.witnessReplay.valid &&
    validWitnessIds.size === 0 &&
    !authorityTopologyInvalid
  ) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_quorum_no_valid_witnesses",
      path: "/witnessReplay/records",
      message:
        "projection replay settlement-store head witness quorum requires at least one accepted witness record for the head",
      expected: 1,
      actual: 0,
    });
  }

  const invalidPolicy = issues.some(
    (issue) =>
      issue.code ===
        "projection_replay_certificate_store_root_witness_settlement_store_head_witness_quorum_invalid_policy" ||
      issue.code ===
        "projection_replay_certificate_store_root_witness_settlement_store_head_witness_quorum_policy_authority_mismatch",
  );
  const tenantMismatch = issues.some(
    (issue) =>
      issue.code ===
        "projection_replay_certificate_store_root_witness_settlement_store_head_witness_quorum_head_tenant_mismatch" ||
      issue.code ===
        "projection_replay_certificate_store_root_witness_settlement_store_head_witness_quorum_witness_tenant_mismatch",
  );
  const acceptedCount = acceptedWitnessIds.size;
  const quorumMet = acceptedCount >= requiredWitnesses;
  if (
    !invalidPolicy &&
    !tenantMismatch &&
    !authorityTopologyInvalid &&
    obstructingWitnessIds.size === 0 &&
    !quorumMet
  ) {
    issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_quorum_not_met",
      path: "/acceptedWitnessIds",
      message:
        "projection replay settlement-store head witness quorum has not reached the required witness threshold",
      expected: requiredWitnesses,
      actual: acceptedCount,
    });
  }

  const replayInvalid = issues.some(
    (issue) =>
      issue.code ===
      "projection_replay_certificate_store_root_witness_settlement_store_head_witness_quorum_witness_replay_invalid",
  );
  const status: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessQuorumCertificateStatus =
    invalidPolicy ||
    tenantMismatch ||
    replayInvalid ||
    authorityTopologyInvalid ||
    obstructingWitnessIds.size > 0
      ? "obstructed"
      : quorumMet
        ? "certified"
        : acceptedCount >= minimumWitnesses
          ? "witnessed"
          : "provisional";

  const allowedAction:
    | ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessQuorumCertificateAllowedAction
    | undefined =
    authorityTopologyInvalid
      ? "correct_head_witness_authority_topology"
      : invalidPolicy || tenantMismatch || replayInvalid
        ? "correct_head_witness_policy"
        : obstructingWitnessIds.size > 0
          ? "resolve_settlement_store_head_conflict"
          : status === "certified"
            ? undefined
            : "collect_more_head_witnesses";

  return buildProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessQuorumCertificate(
    {
      tenantId: tenantId(tenant),
      head: input.head,
      status,
      acceptedWitnessIds: sortedUniqueStrings([...acceptedWitnessIds]),
      obstructingWitnessIds: sortedUniqueStrings([...obstructingWitnessIds]),
      invalidWitnessIds: sortedUniqueStrings([...invalidWitnessIds]),
      ...(topology !== undefined
        ? {
            eligibleWitnessIds: sortedUniqueStrings([
              ...topologyEligibleWitnessIds,
            ]),
          }
        : {}),
      ...(topology?.latestAuthorityHash !== undefined
        ? {
            authorityTopologyHash:
              topology.effectiveAuthorityHash ?? topology.latestAuthorityHash,
          }
        : {}),
      requiredWitnesses,
      minimumWitnesses,
      issues,
      authorityBoundary:
        "projection_replay_settlement_store_head_witness_quorum",
      ...(allowedAction !== undefined ? { allowedAction } : {}),
    },
  );
}

function buildProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessQuorumCertificate(
  input: Omit<
    ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessQuorumCertificate,
    "certified" | "quorumCertificateHash"
  >,
): ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessQuorumCertificate {
  const certificate = {
    ...input,
    certified: input.status === "certified",
  };
  return {
    ...certificate,
    quorumCertificateHash:
      computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessQuorumCertificateHash(
        certificate,
      ),
  };
}

export function computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessQuorumCertificateHash(
  certificate: Omit<
    ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessQuorumCertificate,
    "quorumCertificateHash"
  >,
): string {
  return fingerprint64(canonicalStringify(certificate));
}

