function projectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneFrontiersFromCheckpoint(input: {
  readonly checkpoint: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionCheckpoint;
  readonly lanes: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningLane[];
}): readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneLaneFrontier[] {
  const frontiers: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneLaneFrontier[] =
    [];
  for (const lane of input.lanes) {
    if (lane === "witness_ledger" && input.checkpoint.witnessLedger !== undefined) {
      frontiers.push({
        lane,
        compactedThroughSequence:
          input.checkpoint.witnessLedger.compactedThroughWitnessSequence,
        compactedThroughHash:
          input.checkpoint.witnessLedger.compactedThroughObservationHash,
      });
    }
    if (
      lane === "authority_topology" &&
      input.checkpoint.authorityTopology !== undefined
    ) {
      frontiers.push({
        lane,
        compactedThroughSequence:
          input.checkpoint.authorityTopology.compactedThroughAuthoritySequence,
        compactedThroughHash:
          input.checkpoint.authorityTopology.compactedThroughAuthorityHash,
      });
    }
    if (
      lane === "quorum_certificate_records" &&
      input.checkpoint.quorumCertificateRecords !== undefined
    ) {
      frontiers.push({
        lane,
        compactedThroughSequence:
          input.checkpoint.quorumCertificateRecords
            .compactedThroughQuorumCertificateSequence,
        compactedThroughHash:
          input.checkpoint.quorumCertificateRecords
            .compactedThroughQuorumCertificateRecordHash,
      });
    }
  }
  return frontiers.sort((a, b) => a.lane.localeCompare(b.lane));
}

function projectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneFrontierForLane(
  record: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneRecord,
  lane: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningLane,
):
  | ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneLaneFrontier
  | undefined {
  return record.prunedFrontiers.find((frontier) => frontier.lane === lane);
}

function projectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneSuffixCountForLane(
  admission: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningAdmission,
  lane: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningLane,
): number {
  if (lane === "witness_ledger") return admission.witnessSuffixRecordCount;
  if (lane === "authority_topology") return admission.authoritySuffixTransitionCount;
  return admission.quorumCertificateSuffixRecordCount;
}

