export function replayProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneRecords(input: {
  readonly tenantId: TenantId | string;
  readonly records: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneRecord[];
  readonly signaturePolicy: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessSignaturePolicy;
}): ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneRecordReplay {
  const tenant = String(input.tenantId);
  const records = [...input.records].sort(
    (a, b) => a.pruningTombstoneSequence - b.pruningTombstoneSequence,
  );
  const issues: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneRecordIssue[] =
    [];
  let expectedSequence = 1;
  let expectedPreviousHash: string | undefined;
  let latestTombstoneRecord:
    | ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneRecord
    | undefined;
  const latestFrontierByLane = new Map<
    ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningLane,
    ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneLaneFrontier
  >();

  for (const [index, record] of records.entries()) {
    const issueCountBefore = issues.length;
    const path = `/records/${index}`;
    if (String(record.tenantId) !== tenant) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_tenant_mismatch",
        path: `${path}/tenantId`,
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness compaction pruning tombstone tenant mismatch",
        expected: tenant,
        actual: String(record.tenantId),
      });
    }
    if (
      String(record.checkpointAdmissionRecord.tenantId) !== tenant ||
      String(record.pruningAdmission.tenantId) !== tenant
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_tenant_mismatch",
        path,
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness compaction pruning tombstone embedded admission tenant mismatch",
        expected: tenant,
        actual: `${record.checkpointAdmissionRecord.tenantId}:${record.pruningAdmission.tenantId}`,
      });
    }
    if (record.pruningTombstoneSequence !== expectedSequence) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_sequence_gap",
        path: `${path}/pruningTombstoneSequence`,
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness compaction pruning tombstones must be contiguous",
        expected: expectedSequence,
        actual: record.pruningTombstoneSequence,
      });
    }
    if (
      (record.previousPruningTombstoneRecordHash ?? "") !==
      (expectedPreviousHash ?? "")
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_previous_hash_mismatch",
        path: `${path}/previousPruningTombstoneRecordHash`,
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness compaction pruning tombstone does not chain to the prior record",
        expected: expectedPreviousHash ?? "",
        actual: record.previousPruningTombstoneRecordHash ?? "",
      });
    }

    const { pruningAdmissionHash, ...admissionPayload } =
      record.pruningAdmission;
    const expectedPruningAdmissionHash =
      computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningAdmissionHash(
        admissionPayload,
      );
    if (
      record.pruningAdmission.pruningAdmissionHash !==
      expectedPruningAdmissionHash
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_pruning_admission_hash_mismatch",
        path: `${path}/pruningAdmission/pruningAdmissionHash`,
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness compaction pruning tombstone admission hash does not match its body",
        expected: expectedPruningAdmissionHash,
        actual: record.pruningAdmission.pruningAdmissionHash,
      });
    }
    if (!record.pruningAdmission.admitted) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_pruning_admission_not_admitted",
        path: `${path}/pruningAdmission/status`,
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness compaction pruning tombstone requires an admitted pruning admission",
        expected: "admitted",
        actual: record.pruningAdmission.status,
      });
    }

    const { checkpointAdmissionRecordHash, ...checkpointRecordPayload } =
      record.checkpointAdmissionRecord;
    const expectedCheckpointAdmissionRecordHash =
      computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionCheckpointAdmissionRecordHash(
        checkpointRecordPayload,
      );
    if (
      record.checkpointAdmissionRecord.checkpointAdmissionRecordHash !==
      expectedCheckpointAdmissionRecordHash
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_checkpoint_admission_record_hash_mismatch",
        path: `${path}/checkpointAdmissionRecord/checkpointAdmissionRecordHash`,
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness compaction pruning tombstone checkpoint admission record hash does not match its body",
        expected: expectedCheckpointAdmissionRecordHash,
        actual:
          record.checkpointAdmissionRecord.checkpointAdmissionRecordHash,
      });
    }

    const checkpointAdmissionValidation =
      validateProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionCheckpointAdmission(
        {
          tenantId: input.tenantId,
          checkpoint: record.checkpointAdmissionRecord.checkpoint,
          admission: record.checkpointAdmissionRecord.admission,
          signaturePolicy: input.signaturePolicy,
        },
      );
    if (!checkpointAdmissionValidation.valid) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_checkpoint_admission_invalid",
        path: `${path}/checkpointAdmissionRecord/admission`,
        message: checkpointAdmissionValidation.message,
      });
    }

    if (
      record.pruningAdmission.checkpointAdmissionRecordHash !==
      record.checkpointAdmissionRecord.checkpointAdmissionRecordHash
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_checkpoint_admission_mismatch",
        path: `${path}/pruningAdmission/checkpointAdmissionRecordHash`,
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness compaction pruning tombstone admission must bind the checkpoint admission record",
        expected: record.checkpointAdmissionRecord.checkpointAdmissionRecordHash,
        actual: record.pruningAdmission.checkpointAdmissionRecordHash,
      });
    }
    if (
      record.pruningAdmission.checkpointHash !==
        record.checkpointAdmissionRecord.checkpoint.checkpointHash ||
      record.pruningAdmission.checkpointId !==
        record.checkpointAdmissionRecord.checkpoint.checkpointId
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_checkpoint_admission_mismatch",
        path: `${path}/pruningAdmission/checkpointHash`,
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness compaction pruning tombstone admission must bind the checkpoint frontier",
        expected: record.checkpointAdmissionRecord.checkpoint.checkpointHash,
        actual: record.pruningAdmission.checkpointHash,
      });
    }

    const expectedFrontiers =
      projectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneFrontiersFromCheckpoint(
        {
          checkpoint: record.checkpointAdmissionRecord.checkpoint,
          lanes: record.pruningAdmission.lanes,
        },
      );
    if (
      canonicalStringify(record.prunedFrontiers) !==
      canonicalStringify(expectedFrontiers)
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_frontier_mismatch",
        path: `${path}/prunedFrontiers`,
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness compaction pruning tombstone frontiers must match the admitted checkpoint snapshots",
        expected: canonicalStringify(expectedFrontiers),
        actual: canonicalStringify(record.prunedFrontiers),
      });
    }

    for (const frontier of record.prunedFrontiers) {
      const priorFrontier = latestFrontierByLane.get(frontier.lane);
      if (
        priorFrontier !== undefined &&
        frontier.compactedThroughSequence <=
          priorFrontier.compactedThroughSequence
      ) {
        issues.push({
          code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_frontier_regression",
          path: `${path}/prunedFrontiers/${frontier.lane}/compactedThroughSequence`,
          message:
            "projection replay pruning tombstone-head pruning tombstone-store head witness compaction pruning tombstone cannot regress or duplicate a lane frontier",
          expected: priorFrontier.compactedThroughSequence + 1,
          actual: frontier.compactedThroughSequence,
        });
      }
    }

    const { pruningTombstoneRecordHash, ...recordPayload } = record;
    const expectedRecordHash =
      computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneRecordHash(
        recordPayload,
      );
    if (record.pruningTombstoneRecordHash !== expectedRecordHash) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_hash_mismatch",
        path: `${path}/pruningTombstoneRecordHash`,
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness compaction pruning tombstone hash does not match its body",
        expected: expectedRecordHash,
        actual: record.pruningTombstoneRecordHash,
      });
    }

    if (issues.length === issueCountBefore) {
      latestTombstoneRecord = record;
      for (const frontier of record.prunedFrontiers) {
        latestFrontierByLane.set(frontier.lane, frontier);
      }
    }
    expectedSequence = record.pruningTombstoneSequence + 1;
    expectedPreviousHash = record.pruningTombstoneRecordHash;
  }

  const latestPrunedFrontiers = [...latestFrontierByLane.values()].sort((a, b) =>
    a.lane.localeCompare(b.lane),
  );
  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    records,
    ...(latestTombstoneRecord !== undefined
      ? { latestTombstoneRecord }
      : {}),
    latestPrunedFrontiers,
    issues,
  };
}

