              code: "projection_replay_pruning_tombstone_history_store_head_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_consistency_proof_missing",
              path: "/consistencyProof",
              message:
                "first history-store-head pruning tombstone-store head pruning-tombstone-store head observation after sequence 1 requires a consistency proof from the beginning of the pruning tombstone history",
              expected: 1,
              actual: observedHead.pruningTombstoneSequence,
