export class StoreBackedProjectionReplayPruningTombstoneHistoryStoreHeadWitnessQuorumCertifier {
  constructor(
    private readonly authorityTransitionStore: ProjectionReplayPruningTombstoneHistoryStoreHeadWitnessAuthorityTransitionStore,
    private readonly witnessLedger: ProjectionReplayPruningTombstoneHistoryStoreHeadWitnessLedger,
  ) {}

  async certifyProjectionReplayPruningTombstoneHistoryStoreHead(input: {
    readonly tenantId: TenantId | string;
    readonly head: ProjectionReplayPruningTombstoneHistoryStoreHead;
    readonly signaturePolicy: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessSignaturePolicy;
    readonly policy?: ProjectionReplayPruningTombstoneHistoryStoreHeadWitnessQuorumPolicy;
  }): Promise<ProjectionReplayPruningTombstoneHistoryStoreHeadWitnessQuorumCertificate> {
    const transitions =
      await this.authorityTransitionStore.listProjectionReplayPruningTombstoneHistoryStoreHeadWitnessAuthorityTransitions(
        {
          tenantId: input.tenantId,
        },
      );
    const authorityTopology =
      replayProjectionReplayPruningTombstoneHistoryStoreHeadWitnessAuthorityTransitions(
        {
          tenantId: input.tenantId,
          pruningTombstoneSequence: input.head.pruningTombstoneSequence,
          transitions,
        },
      );
    const witnessRecords =
      await this.witnessLedger.listProjectionReplayPruningTombstoneHistoryStoreHeadWitnessRecords(
        {
          tenantId: input.tenantId,
        },
      );
    const signaturePolicy = {
      ...input.signaturePolicy,
      pruningTombstoneHistoryStoreHeadAuthorityTopology: authorityTopology,
    };
    const witnessReplay =
      replayProjectionReplayPruningTombstoneHistoryStoreHeadWitnessRecords({
        tenantId: input.tenantId,
        records: witnessRecords,
        signaturePolicy,
      });
    return evaluateProjectionReplayPruningTombstoneHistoryStoreHeadWitnessQuorumCertificate(
      {
        tenantId: input.tenantId,
        head: input.head,
        witnessReplay,
        authorityTopology,
        signaturePolicy,
        ...(input.policy !== undefined ? { policy: input.policy } : {}),
      },
    );
  }
}

